-- Poems batch 404
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-572','水龙吟','张炎','宋','宋词','song-ci','水龙吟','[]','乱红飞已无多，艳游终是如今少。',127,'宋词/ci.song.18000.json','["乱红飞已无多，艳游终是如今少。", "一番雨过，一番春减，催人渐老。", "倚槛调莺，卷帘收燕，故园空杳。", "奈关愁不住，悠悠万里，浑恰似、天涯草。", "不拟相逢古道。", "才疑梦、又还惊觉。", "清风在柳，江摇白浪，舟行趁晓。", "遮莫重来，不如休去，怎堪怀抱。", "那知又、五柳门荒，曾听得、鹃啼了。"]'),
('song-ci-573','一萼红','张炎','宋','宋词','song-ci','一萼红','[]','倚阑干。',133,'宋词/ci.song.18000.json','["倚阑干。", "问绿华何事，偷饵九还丹。", "浣锦溪边，餐霞竹里，翠袖不倚天寒。", "照芳树、晴光泛晓，护么凤、无处认冰颜。", "露洗春腴，风摇醉魄，听笛江南。", "树挂珊瑚冷月，叹玉奴妆褪，仙掾诗悭。", "谩觅花云，不同梨梦，推篷恍记孤山。", "步夜雪、前村问酒，几消凝、把做杏花看。", "得似古桃流水，不到人间。"]'),
('song-ci-574','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','水痕深，花信足，寂寞汉南树。',95,'宋词/ci.song.18000.json','["水痕深，花信足，寂寞汉南树。", "转首青阴，芳事顿如许。", "不知多少消魂，夜来风雨。", "犹梦到、断红流处。", "最无据。", "长年息影空山，愁入庾郎句。", "玉老田荒，心事已迟暮。", "几回听得啼鹃，不如归去。", "终不似、旧时鹦鹉。"]'),
('song-ci-575','月下笛','张炎','宋','宋词','song-ci','月下笛','["\u5b8b\u8bcd\u4e09\u767e\u9996"]','万里孤云，清游渐远，故人何处。',123,'宋词/ci.song.18000.json','["万里孤云，清游渐远，故人何处。", "寒窗梦里，犹记经行旧时路。", "连昌约略无多柳，第一是、难听夜雨。", "谩惊回凄悄，相看烛影，拥衾谁语。", "张绪。", "归何暮。", "半零落，依依断桥鸥鹭。", "天涯倦旅。", "此时心事良苦。", "只愁重洒西州泪，问杜曲、人家在否。", "恐翠袖、正天寒，犹倚梅花那树。"]'),
('song-ci-576','水龙吟','张炎','宋','宋词','song-ci','水龙吟','[]','几番问竹平安，雁书不尽相思字。',127,'宋词/ci.song.18000.json','["几番问竹平安，雁书不尽相思字。", "篱根半树，村深孤艇，阑干屡倚。", "远草兼云，冻河胶雪，此时行李。", "望去程无数，并州回首，还又渡、桑乾水。", "笑我曾游万里。", "甚匆匆、便成归计。", "江空岁晚，栖迟犹在，吴头楚尾。", "疏柳经寒，断槎浮月，依然憔悴。", "待相逢、说与相思，想亦在、相思里。"]'),
('song-ci-577','绮罗香','张炎','宋','宋词','song-ci','绮罗香','[]','万里飞霜，千林落木，寒艳不招春妒。',128,'宋词/ci.song.18000.json','["万里飞霜，千林落木，寒艳不招春妒。", "枫冷吴江，独客又吟愁句。", "正船舣、流水孤村，似花绕、斜阳归路。", "甚荒沟、一片凄凉，载情不去载愁去。", "长安谁问倦旅。", "羞见衰颜借酒，飘零如许。", "谩倚新妆，不入洛阳花谱。", "为回风、起舞尊前，尽化作、断霞千缕。", "记阴阴、绿遍江南，夜窗听暗雨。"]'),
('song-ci-578','洞仙歌','张炎','宋','宋词','song-ci','洞仙歌','[]','野鹃啼月，便角巾还第。',101,'宋词/ci.song.18000.json','["野鹃啼月，便角巾还第。", "轻掷诗瓢付流水。", "最无端、小院寂历春空，门自掩，柳发离离如此。", "可惜欢娱地。", "雨冷云昏，不见当时谱银字。", "旧曲怯重翻，总是离愁，泪痕洒、一帘花碎。", "梦沈沈、知道不归来，尚错问桃根，醉魂醒未。"]'),
('song-ci-579','新雁过妆楼','张炎','宋','宋词','song-ci','新雁过妆楼','[]','风雨不来，深院悄、清事正满东篱。',119,'宋词/ci.song.18000.json','["风雨不来，深院悄、清事正满东篱。", "杖藜重到，秋气冉冉吹衣。", "瘦碧飘萧摇露便，腻黄秀野拂霜枝。", "忆芳时。", "翠微唤酒，江雁初飞。", "湘潭无人吊楚，叹落英自采，谁寄相思。", "淡泊生涯，聊伴老圃斜晖。", "寒香应遍故里，想鹤怨山空犹未归。", "归何晚，问径松不语，只有花知。"]'),
('song-ci-580','江神子・江城子','张炎','宋','宋词','song-ci','江神子・江城子','[]','奇峰相对接球庭。',86,'宋词/ci.song.18000.json','["奇峰相对接球庭。", "乍微晴，又微阴。", "舍北江东，如盖自亭亭。", "翻笑天台连雁荡，隔一片、不逢君。", "此中幽趣许谁邻。", "境双清。", "人独清。", "采药难寻，童子语山深。", "绝似醉翁游乐意，林壑静、听泉声。"]'),
('song-ci-581','塞翁吟','张炎','宋','宋词','song-ci','塞翁吟','[]','交到无心处，出岫细话幽期。',115,'宋词/ci.song.18000.json','["交到无心处，出岫细话幽期。", "看流水、意俱迟。", "且淡薄相依。", "凌霄未肯从龙去，物外共鹤忘机。", "迷古洞，掩晴晖。", "翠影湿行衣。", "飞飞。", "垂天翼，飘然万里，愁日暮、佳人未归。", "尚记得、巴山夜雨，耿无语、共说生平，都付陶诗。", "休题五朵，莫梦阳台，不赠相思。"]'),
('song-ci-582','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','占宽闲，锄浩渺。',95,'宋词/ci.song.18000.json','["占宽闲，锄浩渺。", "船舣水村悄。", "非雾非烟，生气覆瑶草。", "蒙茸数亩春阴，梦魂落寞，知踏碎、梨花多少。", "听孤啸。", "山浅种玉人归，缥缈度晴峭。", "鹤下芝田，五色散微照。", "笑他隔浦谁家，半江疏雨，空吟断、一犁清晓。"]'),
('song-ci-583','风入松','张炎','宋','宋词','song-ci','风入松','[]','卷舒无意入虚玄。',90,'宋词/ci.song.18000.json','["卷舒无意入虚玄。", "丘壑伴云烟。", "石根清气千年润，覆孤松、深护啼猿。", "霭霭静随仙隐，悠悠闲对僧眠。", "傍花懒向小溪边。", "空谷覆流泉。", "浮踪自感今如此，已无心、万里行天。", "记得晋人归去，御风飞过斜川。"]'),
('song-ci-584','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','带雨春潮。',118,'宋词/ci.song.18000.json','["带雨春潮。", "人不渡、沙外晓色迨遥。", "自横深静，谁见隔柳停桡。", "知我知鱼未是乐，转篷闲趁白鸥招。", "任风飘。", "夜来酒醒，何处江皋。", "泛宅浮家更好，度菰蒲影里，濯足吹箫。", "坐阅千帆，空竞万里波涛。", "他年五湖访隐，第一是吴淞第四桥。", "玄真子、共游烟水，人月俱高。"]'),
('song-ci-585','疏影','张炎','宋','宋词','song-ci','疏影','[]','黄昏片月。',134,'宋词/ci.song.18000.json','["黄昏片月。", "似碎阴满地，还更清绝。", "枝北枝南，疑有疑无，几度背灯难折。", "依稀倩女离魂处，缓步出、前村时节。", "看夜深、竹外横斜，应妒过云明灭。", "窥镜蛾眉淡抹。", "为容不在貌，独抱孤洁。", "莫是花光，描取春痕，不怕丽谯吹彻。", "还惊海上然犀去，照水底、珊瑚如活。", "做弄得、酒醒天寒，空对一庭香雪。"]'),
('song-ci-586','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','采芳洲薜荔，流水外、白鸥前。',126,'宋词/ci.song.18000.json','["采芳洲薜荔，流水外、白鸥前。", "度万壑千岩，晴岚暖翠，心目娟娟。", "山川。", "自今自古，怕依然。", "认得米家船。", "明月闲延夜语，落花静拥春眠。", "吟边。", "象笔蛮笺。", "清绝处、小留连。", "正寂寂江潭，树犹如此，那更啼鹃。", "居廛。", "闭门隐几，好林泉。", "都在卧游边。", "记得当时旧事，误人却是桃源。"]'),
('song-ci-587','风入松','张炎','宋','宋词','song-ci','风入松','[]','小窗晴碧飐帘波。',90,'宋词/ci.song.18000.json','["小窗晴碧飐帘波。", "昼影舞飞梭。", "惜春休问花多少，柳成阴、春已无多。", "金字初寻小扇，铢衣早试轻罗。", "园林未肯受清和。", "人醉牡丹坡。", "啸歌且尽平生事，问东风、毕竟如何。", "燕子寻常巷陌，酒边莫唱西河。"]'),
('song-ci-588','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','云多不记山深浅，人行半天岩壑。',123,'宋词/ci.song.18000.json','["云多不记山深浅，人行半天岩壑。", "旷野飞声，虚空倒影，松挂危峰疑落。", "流泉喷薄。", "自窈窕寻源，引瓢孤酌。", "倦倚高寒，少年游事老方觉。", "幽寻闲院邃阁。", "树凉僧坐夏，翻笑行乐。", "近竹惊秋，穿萝误晚，都把尘缘消却。", "东林似昨。", "待学取当年，晋人曾约。", "童子何知，故山空放鹤。"]'),
('song-ci-589','还京乐','张炎','宋','宋词','song-ci','还京乐','[]','醉吟处。',125,'宋词/ci.song.18000.json','["醉吟处。", "都是琴尊，竟日松下语。", "有笔床茶灶，瘦筇相引，逢花须住。", "正翠阴迷路。", "年光荏苒成孤旅。", "待趁燕樯，休忘了、玄都前度。", "渐烟波远，怕五湖凄冷，佳人袖薄，修竹依依日暮。", "知他甚处重逢，便匆匆、背潮归去。", "莫因循、误了幽期，应孤旧雨。", "伫立山风晚，月明摇碎江树。"]'),
('song-ci-590','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','一窗烟雨不除草。',123,'宋词/ci.song.18000.json','["一窗烟雨不除草。", "移家静藏深窈。", "东晋图书，南山杞菊，谁识幽居怀抱。", "疏阴未扫。", "叹乔木犹存，易分残照。", "慷慨悲歌，故人多向近来老。", "相逢何事欠早。", "爱吟心共苦，此意难表。", "野水无鸥，闲门断柳，不满清风一笑。", "荷衣制了。", "待寻壑经丘，溯云孤啸。", "学取渊明，抱琴归去好。"]'),
('song-ci-591','梅子黄时雨','张炎','宋','宋词','song-ci','梅子黄时雨','[]','流水孤村，爱尘事顿消，来访深隐。',113,'宋词/ci.song.18000.json','["流水孤村，爱尘事顿消，来访深隐。", "向醉里谁扶，满身花影。", "鸥鹭相看如瘦，近来不是伤春病。", "嗟流景。", "竹外野桥，犹系烟艇。", "谁引。", "斜川归兴。", "便啼鹃纵少，无奈时听。", "待棹击空明，鱼波千顷。", "弹到琵琶留不住，最愁人是黄昏近。", "江风紧。", "一行柳阴吹暝。"]'),
('song-ci-592','西子妆慢・西子妆','张炎','宋','宋词','song-ci','西子妆慢・西子妆','[]','白浪摇天，青阴涨地，一片野怀幽意。',120,'宋词/ci.song.18000.json','["白浪摇天，青阴涨地，一片野怀幽意。", "杨花点点是春心，替风前、万花吹泪。", "遥岑寸碧。", "有谁识、朝来清气。", "自沈吟、甚流光轻掷，繁华如此。", "斜阳外。", "隐约孤村，隔坞闲门闭。", "渔舟何似莫归来，想桃源、路通人世。", "危桥静倚。", "千年事、都消一醉。", "谩依依，愁落鹃声万里。"]'),
('song-ci-593','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','门当竹径，鹭管苔矶，烟波自有闲人。',119,'宋词/ci.song.18000.json','["门当竹径，鹭管苔矶，烟波自有闲人。", "棹入孤村，落照正满寒汀。", "桃花远迷洞口，想如今、方信无秦。", "醉梦醒，向沧浪容与，净濯兰缨。", "欸乃一声归去，对笔床茶灶，寄傲幽情。", "雨笠风蓑，古意谩说玄真。", "知鱼淡然自乐，钓清名、空在丝纶。", "笑未已，笑严陵、还笑渭滨。"]'),
('song-ci-594','湘月・念奴娇','张炎','宋','宋词','song-ci','湘月・念奴娇','[]','行行且止。',120,'宋词/ci.song.18000.json','["行行且止。", "把乾坤收入，篷窗深里。", "星散白鸥三四点，数笔横塘秋意。", "岸觜冲波，篱根受叶，野径通村市。", "疏风迎面，湿衣原是空翠。", "堪叹敲雪门荒，争棋墅冷。", "苦竹鸣山鬼。", "纵使如今犹有晋，无复清游如此。", "落日黄沙，远天云淡，弄影芦花外。", "几时归去，翦取一半烟水。"]'),
('song-ci-595','长亭怨・长亭怨慢','张炎','宋','宋词','song-ci','长亭怨・长亭怨慢','[]','笑海上、白鸥盟冷。',122,'宋词/ci.song.18000.json','["笑海上、白鸥盟冷。", "飞过前滩，又顾秋影。", "似我知鱼，乱蒲流水动清饮。", "岁华空老，犹一缕、柔丝恋顶。", "慵忆鸳行，想应是、朝回花径。", "人静。", "怅离群日暮，都把野情消尽。", "山中旧隐。", "料独树、尚悬苍暝。", "引残梦、直上青天，又何处、溪风吹醒。", "定莫负、归舟同载，烟波千顷。"]'),
('song-ci-596','徵招','张炎','宋','宋词','song-ci','徵招','[]','秋风吹碎江南树，石床自听流水。',117,'宋词/ci.song.18000.json','["秋风吹碎江南树，石床自听流水。", "别鹤不归来，引悲风千里。", "馀音犹在耳。", "有谁识、醉翁深意。", "去国情怀，草枯沙远，尚鸣山鬼。", "客里。", "可消忧，人间世、寥寥几年无此。", "杏老古坛荒，把凄凉空指。", "心尘聊更洗。", "傍何处、竹边松底。", "共良夜，白月纷纷，领一天清气。"]'),
('song-ci-597','法曲献仙音','张炎','宋','宋词','song-ci','法曲献仙音','["\u897f\u6e56"]','云隐山晖，树分溪影，未放妆台帘卷。',114,'宋词/ci.song.18000.json','["云隐山晖，树分溪影，未放妆台帘卷。", "篝密笼香，镜圆窥粉，花深自然寒浅。", "正人在、银屏底，琵琶半遮面。", "语声软。", "且休弹、玉关愁怨。", "怕唤起西湖，那时春感。", "杨柳古湾头，记小怜、隔水曾见。", "听到无声，谩赢得、情绪难翦。", "把一襟心事，散入落梅千点。"]'),
('song-ci-598','渡江云','张炎','宋','宋词','song-ci','渡江云','[]','江山居未定，貂裘已敝，空自带愁归。',124,'宋词/ci.song.18000.json','["江山居未定，貂裘已敝，空自带愁归。", "乱花流水外，访里寻邻，都是可怜时。", "桥边燕子，似软语、斜日江篱。", "休问我、如今心事，错认镜中谁。", "还思。", "新烟惊换，旧雨难招，做不成春意。", "浑未省、谁家芳草，犹梦吟诗。", "一株古柳观鱼港，傍清深、足可幽栖。", "闲趣好，白鸥尚识天随。"]'),
('song-ci-599','斗婵娟・霜叶飞','张炎','宋','宋词','song-ci','斗婵娟・霜叶飞','[]','旧家池沼。',134,'宋词/ci.song.18000.json','["旧家池沼。", "寻芳处、从教飞燕频绕。", "一湾柳护水房春，看镜鸾窥晓。", "晕宿酒、双蛾淡扫。", "罗襦飘带腰围小。", "尽醉方归去，又暗约明朝斗草。", "谁解先到。", "心绪乱若晴丝，那回游处，坠红争恋残照。", "近来心事渐无多，尚被莺声恼。", "便白发、如今纵少。", "情怀不似前时好。", "谩伫立、东风外，愁极还醒，背花一笑。"]'),
('song-ci-600','暗香','张炎','宋','宋词','song-ci','暗香','[]','羽音辽邈。',120,'宋词/ci.song.18000.json','["羽音辽邈。", "怪四檐昼悄，近来无鹊。", "木叶吹寒，极目凝思倚江阁。", "不信相如便老，犹未减、当时游乐。", "但趁他、斗草筹花，终是带离索。", "忆昨。", "更情恶。", "谩认著梅花，是君还错。", "石床冷落。", "闲扫松阴与谁酌。", "一自飘零去远，几误了、灯前深约。", "纵到此、归未得，几曾忘却。"]'),
('song-ci-601','玉漏迟','张炎','宋','宋词','song-ci','玉漏迟','[]','竹多尘自扫。',115,'宋词/ci.song.18000.json','["竹多尘自扫。", "幽通径曲，禅房深窈。", "空翠吹衣，坐对闲云舒啸。", "寒木犹悬故叶，又过了、一番残照。", "经院悄。", "诗梦正迷，独怜衰草。", "幽趣尽属闲僧，浑未识人间，落花啼鸟。", "呼酒凭高，莫问四愁三笑。", "可惜秦山晋水，甚却向、此时登眺。", "清趣少。", "那更好游人老。"]'),
('song-ci-602','长亭怨・长亭怨慢','张炎','宋','宋词','song-ci','长亭怨・长亭怨慢','[]','记横笛、玉关高处。',121,'宋词/ci.song.18000.json','["记横笛、玉关高处。", "万里沙寒，雪深无路。", "破却貂裘，远游归后与谁谱。", "故人何许。", "浑忘了、江南旧雨。", "不拟重逢，应笑我、飘零如羽。", "同去。", "钓珊瑚海树。", "底事又成行旅。", "烟篷断浦。", "更几点、恋人飞絮。", "如今又、京洛寻春，定应被、薇花留住。", "且莫把孤愁，说与当时歌舞。"]'),
('song-ci-603','西河','张炎','宋','宋词','song-ci','西河','["\u897f\u6e56"]','花最盛。',126,'宋词/ci.song.18000.json','["花最盛。", "西湖曾泛烟艇。", "闹红深处小秦筝，断桥夜饮。", "鸳鸯水宿不知寒，如今翻被惊醒。", "那时事、都倦省。", "阑干来此闲凭。", "是谁分得半边机云，恍疑昼锦。", "想当飞燕皱裙时，舞盘微堕珠粉。", "软波不翦素练净。", "碧盈盈、移下秋影。", "醉里玉书难认。", "且脱巾露发，飘然乘兴。", "一叶浮香天风冷。"]'),
('song-ci-604','玲珑四犯','张炎','宋','宋词','song-ci','玲珑四犯','[]','流水人家，乍过了斜阳，一片苍树。',122,'宋词/ci.song.18000.json','["流水人家，乍过了斜阳，一片苍树。", "怕听秋声，却是旧愁来处。", "因甚尚客殊乡，自笑我、被谁留住。", "问种桃、莫是前度。", "不拟桃花轻误。", "少年未识相思苦。", "最难禁、此时情绪。", "行云暗与风流散，方信别泪如雨。", "何况夜鹤帐空，怎奈向、如今归去。", "更可怜，闲里白了头，还知否。"]'),
('song-ci-605','凄凉犯','张炎','宋','宋词','song-ci','凄凉犯','[]','西风暗翦荷衣碎，柔丝不解重缉。',115,'宋词/ci.song.18000.json','["西风暗翦荷衣碎，柔丝不解重缉。", "荒烟断浦，晴晖历乱，半山摇碧。", "悠悠望极。", "忍独听、秋声渐急。", "更怜他、萧条柳发，相与动秋色。", "老态今如此，犹自留连，醉筇游屐。", "不堪瘦影，渺天涯、尽成行客。", "因甚忘归，谩吹裂、山阳夜笛。", "梦三十六陂流水，去未得。"]'),
('song-ci-606','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','山风古道，海国轻车，相逢只在东瀛。',119,'宋词/ci.song.18000.json','["山风古道，海国轻车，相逢只在东瀛。", "淡薄秋光，恰似此日游情。", "休嗟鬓丝断雪，喜闲身、重渡西泠。", "又溯远，趁回潮拍岸，断浦扬舲。", "莫向长亭折柳，正纷纷落叶，同是飘零。", "旧隐新招。", "知住第几层云。", "疏篱尚存晋菊，想依然、认得渊明。", "待去也，最愁人，犹恋故人。"]'),
('song-ci-607','烛影摇红','张炎','宋','宋词','song-ci','烛影摇红','["\u897f\u6e56"]','舟舣鸥波，访邻寻里愁都散。',116,'宋词/ci.song.18000.json','["舟舣鸥波，访邻寻里愁都散。", "老来犹似柳风流，先露看花眼。", "闲把花枝试拣。", "笑盈盈，和香待翦。", "也应回首，紫曲门荒，当年游惯。", "箫鼓黄昏，动人心处情无限。", "锦街不甚月明多，早已骄尘满。", "才过风柔夜暖。", "渐迤逦、芳程递趱。", "向西湖去，那里人家，依然莺燕。"]'),
('song-ci-608','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','记凝妆倚扇，笑眼窥帘，曾款芳尊。',124,'宋词/ci.song.18000.json','["记凝妆倚扇，笑眼窥帘，曾款芳尊。", "步屧交枝径，引生香不断，流水中分。", "忘了牡丹名字，和露拨花根。", "甚杜牧重来，买栽无地，都是消魂。", "空存。", "断肠草，伴几摺眉痕，几点啼痕。", "镜里芙蓉老，问如今何处，绾绿梳云。", "拍有旧时归燕，犹自识黄昏。", "待说与羁愁，遥知路隔杨柳门。"]'),
('song-ci-609','春从天上来','张炎','宋','宋词','song-ci','春从天上来','[]','海上回槎。',131,'宋词/ci.song.18000.json','["海上回槎。", "认旧时鸥鹭，犹恋蒹葭。", "影散香消，水流云在，疏树十里寒沙。", "难问钱塘苏小，都不见、擘竹分茶。", "更堪嗟。", "似荻花江上，谁弄琵琶。", "烟霞。", "自延晚照，尽换了西林，窈窕纹纱。", "蝴蝶飞来，不知是梦，犹疑春在邻家。", "一掬幽怀难写，春何处、春已天涯。", "减繁华。", "是山中杜宇，不是杨花。"]'),
('song-ci-610','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','看涓涓、两水自东西，中有百花庄。',118,'宋词/ci.song.18000.json','["看涓涓、两水自东西，中有百花庄。", "步交枝径里，帘分昼影，窗聚春香。", "依约谁教鹦鹉，列屋带垂杨。", "方喜闲居好，翻为诗忙。", "多少周情柳思，向一丘一壑，留恋年光。", "又何心逐鹿，蕉梦正钱塘。", "且休将扇尘轻障，万山深、不是旧河阳。", "无人识，牡丹开处，重见韩湘。"]'),
('song-ci-611','庆清朝','张炎','宋','宋词','song-ci','庆清朝','[]','浅草犹霜。',117,'宋词/ci.song.18000.json','["浅草犹霜。", "融泥未燕，晴梢润叶初乾。", "闲扶短策，邻家小聚清欢。", "错认篱根是雪，梅花过了一番寒。", "风还峭，较迟芳信，恰是春残。", "此境此时此意，待移琴独去，石冷慵弹。", "飘飘爽气，飞鸟相与俱还。", "醉里不知何处，好诗尽在夕阳山。", "山深杳，更无人到，流水花间。"]'),
('song-ci-612','真珠帘','张炎','宋','宋词','song-ci','真珠帘','[]','绿房几夜迎清晓，光摇动、素月溶溶如水。',123,'宋词/ci.song.18000.json','["绿房几夜迎清晓，光摇动、素月溶溶如水。", "惆怅一枝寒，记东阑闲倚。", "近日花边无旧雨，便寂寞、何曾吹泪。", "烛外。", "谩羞得红妆，而今犹睡。", "琪树皎立风前，万尘空、独挹飘然清气。", "雅淡不成娇，拥玲珑春意。", "落寞云深诗梦浅，但一似、唐昌宫里。", "元是。", "是分明错认，当时玉蕊。"]'),
('song-ci-613','探春慢','张炎','宋','宋词','song-ci','探春慢','[]','银浦流云，绿房迎晓，一抹墙腰月淡。',125,'宋词/ci.song.18000.json','["银浦流云，绿房迎晓，一抹墙腰月淡。", "暖玉生烟，悬冰解冻，碎滴瑶阶如霰。", "才放些晴意，早瘦了、梅花一半。", "也知不做花看，东风何事吹散。", "摇落似成秋苑。", "甚酿得春来，怕教春见。", "野渡舟回，前村门掩，应是不胜清怨。", "次第寻芳去，灞桥外、蕙香波暖。", "犹妒檐声，看灯人在深院。"]'),
('song-ci-614','风入松','张炎','宋','宋词','song-ci','风入松','[]','一春不是不寻春。',90,'宋词/ci.song.18000.json','["一春不是不寻春。", "终是不忺人。", "好怀渐向中年减，对歌钟、浑没心情。", "短帽怕黏飞絮，轻衫压扑游尘。", "暖香十里软莺声。", "小舫绿杨阴。", "梦随蝴蝶飘零后，尚依依、花月关心。", "惆怅一株梨雪，明年甚处清明。"]'),
('song-ci-615','渡江云','张炎','宋','宋词','song-ci','渡江云','[]','锦香缭绕地，深灯挂壁，帘影浪花斜。',124,'宋词/ci.song.18000.json','["锦香缭绕地，深灯挂壁，帘影浪花斜。", "酒船归去后，转首河桥，那处认纹纱。", "重盟镜约，还记得、前度秦嘉。", "惟只有、叶题堪寄，流不到天涯。", "惊嗟。", "十年心事，几曲阑干，想萧娘声价。", "闲过了、黄昏时候，疏柳啼鸦。", "浦潮夜涌平沙白，问断鸿、知落谁家。", "书又远，空江片月芦花。"]'),
('song-ci-616','探芳信','张炎','宋','宋词','song-ci','探芳信','[]','坐清昼。',108,'宋词/ci.song.18000.json','["坐清昼。", "正冶思萦花，馀酲倦酒。", "甚采芳人老，芳心尚如旧。", "消魂忍说铜驼事，不是因春瘦。", "向西园，竹扫颓垣，蔓萝荒甃。", "风雨夜来骤。", "叹歌冷莺帘，恨凝蛾岫。", "愁到今年，多似去年否。", "旧情懒听山阳笛，目极空搔首。", "我何堪，老却江潭汉柳。"]'),
('song-ci-617','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','烟堤小舫，雨屋深灯，春衫惯染京尘。',120,'宋词/ci.song.18000.json','["烟堤小舫，雨屋深灯，春衫惯染京尘。", "舞柳歌桃，心事暗恼东邻。", "浑疑夜窗梦蝶，到如今、犹宿花阴。", "待唤起，甚江蓠摇落，化作秋声。", "回首曲终人远，黯消魂、忍看朵朵芳云。", "润墨空题，惆怅醉魄难醒。", "独怜水楼赋笔，有斜阳、不怕登临。", "愁未了，听残莺、、啼过柳阴。"]'),
('song-ci-618','徵招','张炎','宋','宋词','song-ci','徵招','[]','可怜张绪门前柳，相看顿非年少。',116,'宋词/ci.song.18000.json','["可怜张绪门前柳，相看顿非年少。", "三径已荒凉，更如今怀抱。", "薄游浑是感，满烟水、东风残照。", "古调谁弹，古音谁赏，岁华空老。", "京洛染缁尘，悠然意，独对南山一笑。", "只在此山中，甚相逢不早。", "瘦吟心共苦，知几度、翦灯窗小。", "何时更、听雨巴山，赋草池春晓。"]'),
('song-ci-619','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','记天风、飞佩紫霞边，顾曲万花深。',119,'宋词/ci.song.18000.json','["记天风、飞佩紫霞边，顾曲万花深。", "甚相如情倦，少陵愁老，还叹飘零。", "短梦恍然今昔，故国十年心。", "回首三三径，松竹成阴。", "不恨片篷南浦，恨翦灯听雨，谁伴孤吟。", "料瘦筇归后，闲锁北山云。", "是几番、柳边行色，是几番、同醉古园林。", "烟波远，笔床茶灶，何处逢君。"]'),
('song-ci-620','一萼红','张炎','宋','宋词','song-ci','一萼红','[]','制荷衣。',133,'宋词/ci.song.18000.json','["制荷衣。", "傍山窗卜隐，雅志可闲时。", "款竹门深，移花槛小，动人芳意菲菲。", "怕冷落、苹洲夜月，想时将、渔笛静中吹。", "尘外柴桑，灯前儿女，笑语忘归。", "分得烟霞数亩，乍扫苔寻径，拨叶通池。", "放鹤幽情，吟莺欢事，老去却愿春迟。", "爱吾庐、琴书自乐，好襟怀、初不要人知。", "长日一帘芳草，一卷新诗。"]'),
('song-ci-621','高阳台','张炎','宋','宋词','song-ci','高阳台','[]','古木迷鸦，虚堂起燕，欢游转眼惊心。',122,'宋词/ci.song.18000.json','["古木迷鸦，虚堂起燕，欢游转眼惊心。", "南圃东窗，酸风扫尽芳尘。", "鬓貂飞入平原草，最可怜、浑是秋阴。", "夜沈沈。", "不信归魂，不到花深。", "吹箫踏叶幽寻去，任船依断石，袖裹寒云。", "老桂悬香，珊瑚碎击无声。", "故园已是愁如许，抚残碑，却又伤今。", "更关情。", "秋水人家，斜照西泠。"]'),
('song-ci-622','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','["\u897f\u6e56"]','郎吟未了西湖酒，惊心又歌南浦。',123,'宋词/ci.song.18000.json','["郎吟未了西湖酒，惊心又歌南浦。", "折柳官桥，呼船野渡，还听垂虹风雨。", "漂流最苦。", "况如此江山，此时情绪。", "怕有鸱夷，笑人何事载诗去。", "荒台只今在否。", "登临休望远，都是愁处。", "暗草埋沙，明波洗月，谁念天涯羁旅。", "荷阴未暑。", "快料理归程，再盟鸥鹭。", "只恐空山，近来无杜宇。"]'),
('song-ci-623','桂枝香','张炎','宋','宋词','song-ci','桂枝香','[]','晴江迥阔。',124,'宋词/ci.song.18000.json','["晴江迥阔。", "又客里天涯，还叹轻别。", "万里潮生一棹，柳丝犹结。", "荷衣好向山中补，共飘零、几年霜雪。", "赋归何晚，依依径菊，弄香时节。", "料此去、清游未歇。", "引一片秋声，都付吟箧。", "落叶长安，古意对人休说。", "相思只在相留处，有孤芳、可怜空折。", "旧怀难写，山阳怨笛，夜凉吹月。"]'),
('song-ci-624','庆春宫・高阳台','张炎','宋','宋词','song-ci','庆春宫・高阳台','[]','蟾窟研霜，蜂房点蜡，一枝曾伴凉宵。',126,'宋词/ci.song.18000.json','["蟾窟研霜，蜂房点蜡，一枝曾伴凉宵。", "清气初生，丹心未折，浓艳到此都消。", "避风归去，贮金屋、妆成汉娇。", "栗肌微润，和露吹香，直与秋高。", "小山旧隐重招。", "记得相逢，古道迢遥。", "把酒长歌，插花短舞，谁在水国吹箫。", "馀音何处，看万里、星河动摇。", "广庭人散，月淡天心，鹤下银桥。"]'),
('song-ci-625','长亭怨・长亭怨慢','张炎','宋','宋词','song-ci','长亭怨・长亭怨慢','[]','望花外、小桥流水，门巷愔愔，玉箫声绝。',119,'宋词/ci.song.18000.json','["望花外、小桥流水，门巷愔愔，玉箫声绝。", "鹤去台空，佩环何处弄明月。", "十年前事，愁千折、心情顿别。", "露粉风香谁为主，都成消歇。", "凄咽。", "晓窗分袂处，同把带鸳亲结。", "江空岁晚，便忘了、尊前曾说。", "恨西风不庇寒蝉，便扫尽、一林残叶。", "谢杨柳多情，还有绿阴时节。"]'),
('song-ci-626','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','望涓涓、一水隐芙蓉，几被暮云遮。',118,'宋词/ci.song.18000.json','["望涓涓、一水隐芙蓉，几被暮云遮。", "正凭高送目，西风断雁，残月平沙。", "未觉丹枫尽老，摇落已堪嗟。", "无避秋声处，愁满天涯。", "一自盟鸥别后，甚酒瓢诗锦，轻误年华。", "料荷衣初暖，不忍负烟霞。", "记前度翦灯一笑，再相逢、知在那人家。", "空山远，白云休赠，只赠梅花。"]'),
('song-ci-627','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','隔花窥半面，带天香、吹动一天秋。',119,'宋词/ci.song.18000.json','["隔花窥半面，带天香、吹动一天秋。", "叹行云流水，寒枝夜鹊，杨柳湾头。", "浪打石城风急，难系莫愁舟。", "未了笙歌梦，倚棹西州。", "重省寻春乐事，奈如今老去，鬓改花羞。", "指斜阳巷陌，都是旧曾游。", "凭寄与、采芳俦侣，且不须、容易说风流。", "争得似、桃根桃叶，明月妆楼。"]'),
('song-ci-628','疏影','张炎','宋','宋词','song-ci','疏影','[]','雪空四野，照归心万里，千峰独立。',134,'宋词/ci.song.18000.json','["雪空四野，照归心万里，千峰独立。", "身与天游，一洗襟怀，海镜倒涌秋白。", "相逢懒问盈亏事，但脉脉、此情无极。", "是几番、飞盖追随，桂底露衣香湿。", "闲款楼台夜色。", "料水光未许，人世先得。", "影里分明，认得山河，一笑乱山横碧。", "乾坤许大须容我，浑忘了、醉乡犹客。", "待倩谁、招下清风，共结岁寒三益。"]'),
('song-ci-629','湘月・念奴娇','张炎','宋','宋词','song-ci','湘月・念奴娇','[]','随风万里。',120,'宋词/ci.song.18000.json','["随风万里。", "已无心出岫，浮游天地。", "为问山中何所有，此意不堪持寄。", "淡薄相依，行藏自适，一片松阴外。", "石根苍润，飘飘元是清气。", "长伴暗谷泉生，晴光潋滟，湿影摇花碎。", "浊浊波涛江汉里，忽见清流如此。", "枝上瓢空，鸥前沙净，欲洗幽人耳。", "白苹洲上，浩歌一棹春水。"]'),
('song-ci-630','真珠帘','张炎','宋','宋词','song-ci','真珠帘','[]','云深别有深庭宇。',123,'宋词/ci.song.18000.json','["云深别有深庭宇。", "小帘栊、占取芳菲多处。", "花暗水房春，润几番酥雨。", "见说苏堤晴未稳，便懒趁、踏青人去。", "休去。", "且料理琴书，夷犹今古。", "谁见静里闲心，纵荷衣未茸，雪巢堪赋。", "醉醒一乾坤，任此情何许。", "茂树石床同坐久，又却被、清风留住。", "欲住。", "奈帘影妆楼，翦灯人语。"]'),
('song-ci-631','大圣乐','张炎','宋','宋词','song-ci','大圣乐','[]','隐市山林，傍家池馆，顿成佳趣。',131,'宋词/ci.song.18000.json','["隐市山林，傍家池馆，顿成佳趣。", "是几番临水看云，就树揽香，诗满阑干横处。", "翠径小车行花影，听一片春声人笑语。", "深庭宇。", "对清昼渐长，闲教鹦鹉。", "芳情缓寻细数。", "爱碧草平烟红自雨。", "任燕来莺去，香凝翠暖，歌酒清时钟鼓。", "二十四帘冰壶里，有谁在箫台犹醉舞。", "吹笙侣。", "倚高寒、半天风露。"]'),
('song-ci-632','瑞鹤仙','张炎','宋','宋词','song-ci','瑞鹤仙','[]','楚云分断雨。',127,'宋词/ci.song.18000.json','["楚云分断雨。", "问那回、因甚琴心先许。", "匆匆话离绪。", "正花房蜂闹，著春无处。", "残歌剩舞。", "尚隐约、当时院宇。", "黯消凝、铜雀深深，忍把小乔轻误。", "休赋。", "玉尊别后，老叶沈沟，暗珠还浦。", "欢游再数。", "能几日、采芳去。", "最无端做了，霎时娇梦，不道风流恁苦。", "把馀情、付与秋蛩，夜长自语。"]'),
('song-ci-633','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','水西船，山北酒，多为买春去。',95,'宋词/ci.song.18000.json','["水西船，山北酒，多为买春去。", "事与云消，飞过旧时雨。", "谩留一掬相思，待题红叶，奈红叶、更无题处。", "正延伫。", "乱花浑不知名，娇小未成语。", "短棹轻装，逢迎段桥路。", "那知杨柳风流，柳犹如此，更休道、少年张绪。"]'),
('song-ci-634','恋绣衾','张炎','宋','宋词','song-ci','恋绣衾','[]','一枝凉玉敧路尘。',68,'宋词/ci.song.18000.json','["一枝凉玉敧路尘。", "下瑶台、疑是梦云。", "怕趁取、西风去，被何人、拈住皱裙。", "温柔只在秋波里，这些儿、真个动心。", "再同饮、花前酒，莫都忘、今夜夜深。"]'),
('song-ci-635','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','记当年、紫曲戏分花，帘影最深深。',119,'宋词/ci.song.18000.json','["记当年、紫曲戏分花，帘影最深深。", "听惺忪语笑，香寻古字，谱掐新声。", "散尽黄金歌舞，那处著春情。", "梦醒方知梦，梦岂无凭。", "几点别馀清泪，尽化作妆楼，断雨残云。", "指梢头旧恨，豆蔻结愁心。", "都休问、北来南去，但依依、同是可怜人。", "还飘泊，何时尊酒，却说如今。"]'),
('song-ci-636','浣溪纱・浣溪沙','张炎','宋','宋词','song-ci','浣溪纱・浣溪沙','[]','犀押重帘水院深。',48,'宋词/ci.song.18000.json','["犀押重帘水院深。", "柳绵扑帐昼愔愔。", "梦回孤蝶弄春阴。", "乍减楚衣收带眼，初匀商鼎熨香心。", "燕归摇动护花铃。"]'),
('song-ci-637','菩萨蛮','张炎','宋','宋词','song-ci','菩萨蛮','[]','蕊香不恋琵琶结。',52,'宋词/ci.song.18000.json','["蕊香不恋琵琶结。", "舞衣折损藏花蝶。", "春梦未堪凭。", "几时春梦真。", "愁把残更数。", "泪落灯前雨。", "歌酒可曾忺。", "情怀似去年。"]'),
('song-ci-638','四字令・醉太平','张炎','宋','宋词','song-ci','四字令・醉太平','[]','莺吟翠屏。',46,'宋词/ci.song.18000.json','["莺吟翠屏。", "帘吹絮云。", "东风也怕花瞋。", "带飞花赶春。", "邻娃笑迎。", "嬉游趁晴。", "明朝何处相寻。", "那人家柳阴。"]'),
('song-ci-639','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','穿花省路，傍竹寻邻，如何故隐都荒。',119,'宋词/ci.song.18000.json','["穿花省路，傍竹寻邻，如何故隐都荒。", "问取堤边，因甚减却垂杨。", "消磨纵然未尽，满烟波、添了斜阳。", "空叹息，又翻成无限，杜老凄凉。", "一舸清风何处，把秦山晋水，分贮诗囊。", "发已飘飘，休问岁晚空江。", "松陵试招旧隐，怕白鸥、犹识清狂。", "渐溯远，望并州、却是故乡。"]'),
('song-ci-640','杏花天','张炎','宋','宋词','song-ci','杏花天','[]','湘罗几翦黏新巧。',65,'宋词/ci.song.18000.json','["湘罗几翦黏新巧。", "似过雨、胭脂全少。", "不教枝上春痕闹。", "都被海棠分了。", "带柳色、愁眉暗恼。", "谩遥指、孤村自好。", "深巷明朝休起早。", "空等卖花人到。"]'),
('song-ci-641','醉落魄・一斛珠','张炎','宋','宋词','song-ci','醉落魄・一斛珠','[]','柳侵阑角。',67,'宋词/ci.song.18000.json','["柳侵阑角。", "画帘风软红香泊。", "引人蝴蝶翻轻薄。", "已自关情，和梦近来恶。", "眉梢轻把闲愁著。", "如今愁重眉梢弱。", "双眉不画愁消却。", "不道愁痕，来傍眼边觉。"]'),
('song-ci-642','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','过千岩万壑古蓬莱，招隐竟忘还。',118,'宋词/ci.song.18000.json','["过千岩万壑古蓬莱，招隐竟忘还。", "想乾坤清气，霏霏冉冉，却在阑干。", "洞户来时不锁，归水映花关。", "只可自怡悦，持寄应难。", "狂客如今何处，甚酒船去后，烟水空寒。", "正黄尘没马，林下一身闲。", "几消凝、此图谁画，细看来、元不是终南。", "无心好、休教出岫，只在深山。"]'),
('song-ci-643','小重山','张炎','宋','宋词','song-ci','小重山','[]','清气飞来望似空。',70,'宋词/ci.song.18000.json','["清气飞来望似空。", "数椽何用草，膝堪容。", "卷将一片当帘栊。", "难持赠，只在此山中。", "鱼影倦随风。", "无心成雨意，又西东。", "都缘窗户自玲珑。", "江枫外，不隔夜深钟。"]'),
('song-ci-644','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','晴光转树，晓气分岚，何人野渡横舟。',119,'宋词/ci.song.18000.json','["晴光转树，晓气分岚，何人野渡横舟。", "断柳枯蝉，凉意正满西州。", "匆匆载花载酒，便无情、也自风流。", "芳昼短，奈不堪深夜，秉烛来游。", "谁识山中朝暮，向白云一笑，今古无愁。", "散发吟商，此兴万里悠悠。", "清狂未应似我，倚高寒、隔水呼鸥。", "须待月，冼多清、都付与秋。"]'),
('song-ci-645','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','幽栖身懒动，邃庭悄、日偏长。',124,'宋词/ci.song.18000.json','["幽栖身懒动，邃庭悄、日偏长。", "甚不隐山林，不喧车马，不断生香。", "澄心淡然止水，笑东风、引得落花忙。", "慵对鱼翻暗藻，闲留莺管垂杨。", "徜徉。", "净几明窗。", "穿窈窕、染芬芳。", "看白鹤无声，苍云息影，物外行藏。", "桃源去尘更远，问当年、何事识渔郎。", "争似重门昼掩，自看生意池塘。"]'),
('song-ci-646','玉蝴蝶','张炎','宋','宋词','song-ci','玉蝴蝶','[]','留得一团和气，此花开尽，春已规圆。',123,'宋词/ci.song.18000.json','["留得一团和气，此花开尽，春已规圆。", "虚白窗深，恍讶碧落星悬。", "颺芳丛、低翻雪羽，凝素艳、争簇冰蝉。", "向西园。", "几回错认，明月秋千。", "欲觅生香何处，盈盈一水，空对娟娟。", "待折归来，倩谁偷解玉连环。", "试结取、鸳鸯锦带，好移傍、鹦鹉珠帘。", "晚阶前。", "落梅无数，因甚啼鹃。"]'),
('song-ci-647','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','一片赤城霞。',74,'宋词/ci.song.18000.json','["一片赤城霞。", "无心恋海涯。", "远飞来、乔木人家。", "且向琴书深处隐，终胜似、听琵琶。", "休近七香车。", "年华已破瓜。", "怕依然、刘阮桃花。", "欲问长生何处好，金鼎内、转丹砂。"]'),
('song-ci-648','国香','张炎','宋','宋词','song-ci','国香','[]','空谷幽人。',121,'宋词/ci.song.18000.json','["空谷幽人。", "曳冰簪雾带，古色生春。", "结根未同萧艾，独抱孤贞。", "自分生涯淡薄，隐蓬蒿、甘老山林。", "风烟伴憔悴，冷落吴宫，草暗花深。", "霁痕消蕙雪，向崖阴饮露，应是知心。", "所思何处，愁满楚水湘云。", "肯信遗芳千古，尚依依、泽畔行吟。", "香痕已成梦，短操谁弹，月冷瑶琴。"]'),
('song-ci-649','探春慢','张炎','宋','宋词','song-ci','探春慢','[]','列屋烘炉，深门响竹，催残客里时序。',125,'宋词/ci.song.18000.json','["列屋烘炉，深门响竹，催残客里时序。", "投老情怀，薄游滋味，消得几多凄楚。", "听雁听风雨，更听过、数声柔舻。", "暗将一点归心，试托醉乡分付。", "借问西楼在否。", "休忘了盈盈，端正窥户。", "铁马春冰，柳蛾晴雪，次第满城箫鼓。", "闲见谁家月，浑不记、旧游何处。", "伴我微吟，恰有梅花一树。"]'),
('song-ci-650','烛影摇红','张炎','宋','宋词','song-ci','烛影摇红','[]','隔水呼舟，采香何处追游好。',58,'宋词/ci.song.18000.json','["隔水呼舟，采香何处追游好。", "一年春事二分花，犹有花多少。", "容易繁华过了。", "趁园林、飞红未扫。", "旧酲新醉，几日不来，绿阴芳草。"]'),
('song-ci-651','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','万花深处隐，安一点、世尘无。',124,'宋词/ci.song.18000.json','["万花深处隐，安一点、世尘无。", "步翠麓幽寻，白云自在，流水萦纡。", "携歌缓游细赏，倩何人、重写辋川图。", "迟日香生草木，淡风声和琴书。", "安居。", "歌引巾车。", "童放鹤、我知鱼。", "看静里闲中，醒来醉后，乐意偏殊。", "桃源带春去远，有园林、如此更何如。", "回首丹光满谷，恍然却是蓬壶。"]'),
('song-ci-652','意难忘','张炎','宋','宋词','song-ci','意难忘','[]','风月吴娃。',114,'宋词/ci.song.18000.json','["风月吴娃。", "柳阴中认得，第二香车。", "春深妆减艳，波转影流花。", "莺语滑，透纹纱。", "有低唱人夸。", "怕误却，周郎醉眼，倚扇佯遮。", "底须拍碎红牙。", "听曲终奏雅，可是堪嗟。", "无人知此意，明月又谁家。", "尘滚滚，老年华。", "付情在琵琶。", "更叹我，黄芦苦竹，万里天涯。"]'),
('song-ci-653','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','瘦筇访隐，正繁阴闲锁，一壶幽绿。',120,'宋词/ci.song.18000.json','["瘦筇访隐，正繁阴闲锁，一壶幽绿。", "乔木苍寒图画古，窈窕行人韦曲。", "鹤响天高，水流花净，笑语通华屋。", "虚堂松外，夜深凉气吹烛。", "乐事杨柳楼心，瑶台月下，有生香堪掬。", "谁理商声帘外悄，萧瑟悬珰鸣玉。", "一笑难逢，四愁休赋，任我云边宿。", "倚阑歌罢，露萤飞上秋竹。"]'),
('song-ci-654','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','穿幽透密，傍园林宴乐，清时钟鼓。',120,'宋词/ci.song.18000.json','["穿幽透密，傍园林宴乐，清时钟鼓。", "帘隔波纹分昼影，融得一壶春聚。", "篆径通花，花多迷径，难省来时路。", "缓寻深静，野云松下无数。", "空翠暗湿荷衣，夷犹舒啸，日涉成佳趣。", "香雪因风晴更落，知是山中何树。", "响石横琴，悬崖拥槛，待月慵归去。", "忽来诗思，水田飞下白鹭。"]'),
('song-ci-655','清波引','张炎','宋','宋词','song-ci','清波引','[]','江涛如许。',99,'宋词/ci.song.18000.json','["江涛如许。", "更一夜听风听雨。", "短篷容与。", "盘礴那堪数。", "弭节澄江树。", "不为莼鲈归去。", "怕教冷落芦花，谁招得旧鸥鹭。", "寒汀古溆。", "尽日无人唤渡。", "此中清楚。", "寄情在谭麈。", "难觅真闲处。", "肯被水云留住。", "泠然棹入川流，去天尺五。"]'),
('song-ci-656','暗香','张炎','宋','宋词','song-ci','暗香','[]','猗兰声歇。',120,'宋词/ci.song.18000.json','["猗兰声歇。", "抱孤琴思远，几番弹彻。", "洗耳无人，寂寂行歌古时月。", "一笑东风又急。", "黯消凝、恨听啼鴂。", "想少陵、还叹飘零，遣兴在吟箧。", "愁绝。", "更离别。", "待款语迟留，赋归心切。", "故园梦接。", "花影闲门掩春蝶。", "重访山中旧隐，有羁怀、未须轻说。", "莫相忘，堤上柳、此时共折。"]'),
('song-ci-657','一萼红','张炎','宋','宋词','song-ci','一萼红','[]','舣孤篷。',133,'宋词/ci.song.18000.json','["舣孤篷。", "正丛篁护碧，流水曲池通。", "伛偻穿岩，纡盘寻径，忽见倒影凌空。", "拥一片、花阴无地，细看来、犹带古春风。", "胜事园林，旧家陶谢，诗酒相逢。", "眼底烟霞无数，料神仙即我，何处崆峒。", "清气分来，生香不断，洞户自有云封。", "认奇字、摩挲峭石，聚万景、只在此山中。", "人倚虚阑唤鹤，月白千峰。"]'),
('song-ci-658','霜叶飞','张炎','宋','宋词','song-ci','霜叶飞','[]','故园空杳。',133,'宋词/ci.song.18000.json','["故园空杳。", "霜风劲、南塘吹断瑶草。", "已无清气碍云山，奈此时怀抱。", "尚记得、修门赋晓。", "杜陵花竹归来早。", "傍雅亭幽榭，惯款语英游，好怀无限欢笑。", "不见换羽移商，杏梁尘远，可怜都付残照。", "坐中泣下最谁多，叹赏音人少。", "怅一夜、梅花顿老。", "今年因甚无诗到。", "待唤起清魂□，说与凄凉，定应愁了。"]'),
('song-ci-659','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','记琼筵卜夜，锦槛移春，同恼莺娇。',123,'宋词/ci.song.18000.json','["记琼筵卜夜，锦槛移春，同恼莺娇。", "暗水流花径，正无风院落，银烛迟销。", "闹枝浅压髫髻，香脸泛红潮。", "甚如此游情，还将乐事，轻趁冰消。", "飘零又成梦，但长歌袅袅，柳色迢迢。", "一叶江心冷，望美人不见，隔浦难招。", "认得旧时鸥鹭，重过月明桥。", "溯万里天风，清声谩忆何处箫。"]'),
('song-ci-660','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','水痕吹杏雨，正人在、隔江船。',124,'宋词/ci.song.18000.json','["水痕吹杏雨，正人在、隔江船。", "看燕集春芜，渔栖暗竹，湿影浮烟。", "馀寒尚犹恋柳，怕东风、未肯擘晴绵。", "愁重迟教醉醒，梦长催得诗圆。", "楼前。", "笑语当年。", "情款密、思留连。", "记白月依弦，青天堕酒，衮衮山川。", "垂髫至今在否，倚飞台、谁掷买花钱。", "不是寻春较晚，都缘听得啼鹃。"]'),
('song-ci-661','潇潇雨・踏莎行','张炎','宋','宋词','song-ci','潇潇雨・踏莎行','[]','空山弹古瑟，掬长流、洗耳复谁听。',119,'宋词/ci.song.18000.json','["空山弹古瑟，掬长流、洗耳复谁听。", "倚阑干不语，江潭树老，风挟波鸣。", "愁里不须啼鴂，花落石床平。", "岁月鸥前梦，耿耿离情。", "记得相逢竹外，看词源倒泻，一雪尘缨。", "笑匆匆呼酒，飞雨夜行舟。", "又天涯、零落如此，掩闲门、得似晋人清。", "相思恨，趁杨花去，错到长亭。"]'),
('song-ci-662','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','分明柳上春风眼，曾看少年人老。',123,'宋词/ci.song.18000.json','["分明柳上春风眼，曾看少年人老。", "雁拂沙黄，天垂海白，野艇谁家昏晓。", "惊心梦觉。", "谩慷慨悲歌，赋归不早。", "想得相如，此时终是倦游了。", "经行几度怨别，酒痕消未尽，空被花恼。", "茂苑重来，竹溪深隐，还胜飘零多少。", "羁怀顿扫。", "尚识得妆楼，那回苏小。", "寄语盟鸥，问春何处好。"]'),
('song-ci-663','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','[]','目光牛背上，更时把、汉书看。',124,'宋词/ci.song.18000.json','["目光牛背上，更时把、汉书看。", "记落叶江城，孤云海树，漂泊忘还。", "悬知偶然是梦，梦醒来、未必是邯郸。", "笑指萤灯借暖，愁怜镜雪惊寒。", "投闲。", "寄傲怡颜。", "要一似、白鸥闲。", "且旋缉荷衣，琴尊客里，岁月人间。", "菟裘渐营瘦竹，任重门、近水隔花关。", "数亩清风自足，元来不在深山。"]'),
('song-ci-664','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','秋水涓涓。',119,'宋词/ci.song.18000.json','["秋水涓涓。", "人正远、鱼雁待拂吟笺。", "也知游意，多在第二桥边。", "花底鸳鸯深处影，柳阴淡隔里湖船。", "路绵绵。", "梦吹旧笛，如此山川。", "平生几谢屐，任放歌自得，直上风烟。", "峭壁谁家，长啸竟落松前。", "十年孤剑万里，又何似、畦分抱瓮泉。", "山中酒，且醉餐石髓，白眼青天。"]'),
('song-ci-665','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','["\u957f\u6c5f", "\u897f\u6e56"]','想西湖、段桥疏树。',140,'宋词/ci.song.18000.json','["想西湖、段桥疏树。", "梅花多是风雨。", "如今见说闲云散，烟水少逢鸥鹭。", "归未许。", "又款竹谁家，远思愁□庾。", "重游倦旅。", "纵认得乡山，长江滚滚，隔浦正延伫。", "垂杨渡。", "握手荒城旧侣。", "不知来自何处。", "春窗翦韭青灯夜，疑与梦中相语。", "阑屡拊。", "甚转眼流光，短发真堪数。", "从教醉舞。", "试借地看花，挥毫赋雪，孤艇且休去。"]'),
('song-ci-666','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','海山缥缈。',120,'宋词/ci.song.18000.json','["海山缥缈。", "算人间自有，移来蓬岛。", "一粒粟中生倒景，日月光融丹灶。", "玉洞分春，雪巢不夜，心寂凝虚照。", "鹤溪游处，肯将琴剑同调。", "休问挂树瓢空，窗前清意，赢得不除草。", "只恐渔郎曾误入，翻被桃花一笑。", "润色茶经，评量山水，如此闲方好。", "神仙陆地，长房应未知道。"]'),
('song-ci-667','风入松','张炎','宋','宋词','song-ci','风入松','[]','危楼古镜影犹寒。',90,'宋词/ci.song.18000.json','["危楼古镜影犹寒。", "倒景忽相看。", "桃花不识东西晋，想如今、也梦邯郸。", "缥缈神仙海上，飘零图画人间。", "宝光丹气共回环。", "水弱小舟闲。", "秋风难老三珠树，尚依依、脆管清弹。", "说与霓裳莫舞，银桥不到深山。"]'),
('song-ci-668','数花风・凤凰阁','张炎','宋','宋词','song-ci','数花风・凤凰阁','[]','好游人老，秋鬓芦花共色。',82,'宋词/ci.song.18000.json','["好游人老，秋鬓芦花共色。", "征衣犹恋去年客。", "古道依然黄叶。", "谁家萧瑟。", "自笑我、如何是得。", "酒楼仍在，流落天涯醉白。", "孤城寒树美人隔。", "烟水此程应远，须寻梅驿。", "又渐数、花风第一。"]'),
('song-ci-669','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','风雨怯殊乡。',74,'宋词/ci.song.18000.json','["风雨怯殊乡。", "梧桐又小窗。", "甚秋声、今夜偏长。", "忆著旧时歌舞地，谁得似、牧之狂。", "茉莉拥钗梁。", "云窝一枕香。", "醉瞢腾、多少思量。", "明月半床人睡觉，听说道、夜深凉。"]'),
('song-ci-670','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','重整旧渔蓑。',74,'宋词/ci.song.18000.json','["重整旧渔蓑。", "江湖风雨多。", "好襟怀、近日消磨。", "流水桃花随处有，终不似、隐烟萝。", "南浦又渔歌。", "桃云泛远波。", "想孤山、山下经过。", "见说梅花都老尽，恁为问、是如何。"]'),
('song-ci-671','淡黄柳','张炎','宋','宋词','song-ci','淡黄柳','[]','楚腰一捻。',78,'宋词/ci.song.18000.json','["楚腰一捻。", "羞翦青丝结。", "力未胜春娇怯怯。", "暗托莺声细说。", "愁蹙眉心斗双叶。", "正情切。", "柔枝未堪折。", "应不解、管离别。", "奈如今已入东风睫。", "望断章台，马蹄何处，闲了黄昏淡月。"]'),
('song-ci-672','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','候蛩凄断。',54,'宋词/ci.song.18000.json','["候蛩凄断。", "人语西风岸。", "月落沙平江似练。", "望尽芦花无雁。", "暗教愁损兰成，可怜夜夜关情。", "只有一枝梧叶，不知多少秋声。"]'),
('song-ci-673','虞美人','张炎','宋','宋词','song-ci','虞美人','[]','修眉刷翠春痕聚。',66,'宋词/ci.song.18000.json','["修眉刷翠春痕聚。", "难翦愁来处。", "断丝无力绾韶华。", "也学落红流水、到天涯。", "那回错认章台下。", "却是阳关也。", "待将新恨趁杨花。", "不识相思一点、在谁家。"]'),
('song-ci-674','减字木兰花','张炎','宋','宋词','song-ci','减字木兰花','[]','锁香亭榭。',52,'宋词/ci.song.18000.json','["锁香亭榭。", "花艳烘春曾卜夜。", "空想芳游。", "不到秋凉不信愁。", "酒迟歌缓。", "月色平分窗一半。", "谁伴孤吟。", "手擘黄花碎却心。"]'),
('song-ci-675','踏莎行','张炎','宋','宋词','song-ci','踏莎行','[]','柳未三眠，风才一讯。',68,'宋词/ci.song.18000.json','["柳未三眠，风才一讯。", "催人步屧吹笙径。", "可曾中酒似当时，如今却是看花病。", "老愿春迟，愁嫌昼静。", "秋千院落寒犹剩。", "卷帘休问海棠开，相传燕子归来近。"]'),
('song-ci-676','南乡子','张炎','宋','宋词','song-ci','南乡子','[]','歌扇锦连枝。',66,'宋词/ci.song.18000.json','["歌扇锦连枝。", "问著东风已不知。", "怪底楼前多种柳，相思。", "那叶浑如旧样眉。", "醉里眼都迷。", "遮莫东墙带笑窥。", "行到寻常游冶处，慵归。", "只道看花似向时。"]'),
('song-ci-677','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','颇爱杨琼妆淡注。',70,'宋词/ci.song.18000.json','["颇爱杨琼妆淡注。", "犹理螺鬟，扰扰松云聚。", "两翦秋痕流不去。", "佯羞却把周郎顾。", "欲诉闲愁无说处。", "几过莺帘，听得间关语。", "昨夜月明香暗度。", "相思忽到梅花树。"]'),
('song-ci-678','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','仙子锄云亲手种。',70,'宋词/ci.song.18000.json','["仙子锄云亲手种。", "春闹枝头，消得微霜冻。", "可是东风吹不动。", "金铃悬网珊瑚重。", "社燕盟鸥诗酒共。", "未足游情，刚把斜阳送。", "今夜定应归去梦。", "青苹流水箫声弄。"]'),
('song-ci-679','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','巧结分枝黏翠艾。',70,'宋词/ci.song.18000.json','["巧结分枝黏翠艾。", "翦翦香痕，细把泥金界。", "小簇葵榴芳锦隘。", "红妆人见应须爱。", "午镜将拈开凤盖。", "倚醉凝娇，欲戴还慵戴。", "约臂犹馀朱索在。", "梢头添挂朱符袋。"]'),
('song-ci-680','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','暗香千树。',54,'宋词/ci.song.18000.json','["暗香千树。", "结屋中间住。", "明月一方流水护。", "梦入梨云深处。", "清冰隔断尘埃。", "无人踏碎苍苔。", "一似逋仙归后，吟诗不下山来。"]'),
('song-ci-681','烛影摇红','张炎','宋','宋词','song-ci','烛影摇红','[]','闲苑深迷，趁香随粉都行遍。',116,'宋词/ci.song.18000.json','["闲苑深迷，趁香随粉都行遍。", "隔窗花气暖扶春，只许莺莺占。", "烛焰晴烘醉脸。", "想东邻、偷窥笑眼。", "欲寻无处，暗掐新声，银屏斜掩。", "一片云闲，那知顾曲周郎怨。", "看花犹自未分明，毕竟何时见。", "已信仙缘较浅。", "谩凝思、风帘倒卷。", "出门一笑，月落江横，数峰天远。"]'),
('song-ci-682','露华','张炎','宋','宋词','song-ci','露华','[]','乱红自雨，正翠蹊误晓，玉洞明春。',115,'宋词/ci.song.18000.json','["乱红自雨，正翠蹊误晓，玉洞明春。", "蛾眉淡扫，背风不语盈盈。", "莫恨小溪流水，引刘郎、不是飞琼。", "罗扇底，从教净冶，远障歌尘。", "一掬莹然生意，伴压架酴醿，相恼芳吟。", "玄都观里，几回错认梨云。", "花下可怜仙子，醉东风、犹自吹笙。", "残照晚，渔翁正迷武陵。"]'),
('song-ci-683','解语花','张炎','宋','宋词','song-ci','解语花','[]','行歌趁月，唤酒延秋，多买莺莺笑。',124,'宋词/ci.song.18000.json','["行歌趁月，唤酒延秋，多买莺莺笑。", "蕊枝娇小。", "浑无奈、一掬醉乡怀抱。", "筹花斗草。", "几曾放、好春闲了。", "芳意阑，可惜香心，一夜酸风扫。", "海上仙山缥缈。", "问玉环何事，苦无分晓。", "旧愁空杳。", "蓝桥路、深掩半庭斜照。", "馀情暗恼。", "都缘是、那时年少。", "惊梦回、懒说相思，毕竟如今老。"]'),
('song-ci-684','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','及春游，卜夜饮，人醉万花醒。',95,'宋词/ci.song.18000.json','["及春游，卜夜饮，人醉万花醒。", "转眼年华，白发半垂领。", "与鸥同一清波，风苹月树，又何事、浮踪不定。", "静中省。", "便须门掩柴桑，黄卷伴孤隐。", "一粟生涯，乐事在瓢饮。", "爱闲休说山深，有梅花处，更添个、暗香疏影。"]'),
('song-ci-685','瑶台聚八仙・新雁过妆楼','张炎','宋','宋词','song-ci','瑶台聚八仙・新雁过妆楼','[]','楚竹闲挑。',119,'宋词/ci.song.18000.json','["楚竹闲挑。", "千日酒、乐意稍稍渔樵。", "那回轻散，飞梦便觉迢遥。", "似隔芙蓉无路到，如何共此可怜宵。", "旧愁消。", "故人念我，来问寂寥。", "登临试开笑口，看垂垂短发，破帽休飘。", "款语微吟，清气顿扫花妖。", "明朝柳岸醉醒，又知在烟波第几桥。", "怀人处，任满身风露，踏月吹箫。"]'),
('song-ci-686','满江红','张炎','宋','宋词','song-ci','满江红','[]','傅粉何郎，比玉树、琼枝谩夸。',115,'宋词/ci.song.18000.json','["傅粉何郎，比玉树、琼枝谩夸。", "看生子、东涂西抹，笑语浮华。", "蝴蝶一生花里活，似花还却似非花。", "最可人、娇艳正芳年，如破瓜。", "离别恨，生叹嗟。", "欢情事，起喧哗。", "听歌喉清润，片玉无瑕。", "洗尽人间笙笛耳，赏音多向五侯家。", "好思量、都在步莲中，裙翠遮。"]'),
('song-ci-687','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','带飘飘，衣楚楚。',95,'宋词/ci.song.18000.json','["带飘飘，衣楚楚。", "空谷饮甘露。", "一转花风，萧艾遂如许。", "细看息影云根，淡然诗思，曾□被、生香轻误。", "此中趣。", "能消几笔幽奇，羞掩众芳谱。", "薜老苔荒，山鬼竟无语。", "梦游忘了江南，故人何处，听一片、潇湘夜雨。"]'),
('song-ci-688','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','老枝无著秋声处，萧萧倦听风雨。',123,'宋词/ci.song.18000.json','["老枝无著秋声处，萧萧倦听风雨。", "暗饮春腴，欣荣晚节，不载天河人去。", "心存太古。", "喜冰雪相看，此君欲语。", "共倚云根，岁寒羞并岁寒所。", "当年曾见汉馆，卷帘频坐对，飞梦湘楚。", "叹我重来，何堪如此，落叶空江无数。", "盘桓屡抚。", "似冉冉吹衣，颇疑非雾。", "素壁高堂，晋人清几许。"]'),
('song-ci-689','长亭怨・长亭怨慢','张炎','宋','宋词','song-ci','长亭怨・长亭怨慢','["\u897f\u6e56"]','跨匹马、东瀛烟树。',121,'宋词/ci.song.18000.json','["跨匹马、东瀛烟树。", "转首十年，旅愁无数。", "此日重逢，故人犹记旧游否。", "雨今云古。", "更秉烛、浑疑梦语。", "衮衮登台，叹野老、白头如许。", "归去。", "问当初鸥鹭。", "几度西湖霜露。", "漂流最苦。", "便一似、断蓬飞絮。", "情可恨、独棹扁舟，浩歌向、清风来处。", "有多少相思，都在一声南浦。"]'),
('song-ci-690','忆旧游','张炎','宋','宋词','song-ci','忆旧游','[]','笑铭崖笔倦，访雪舟寒，觅里寻邻。',124,'宋词/ci.song.18000.json','["笑铭崖笔倦，访雪舟寒，觅里寻邻。", "半掩闲门草，看长松落荫，旧榻悬尘。", "自怜此来何事，不为忆鲈莼。", "但回首当年，芙蓉城里，胜友如云。", "思君。", "度遥夜，谩疑是梅花，檐下空巡。", "蝶与周俱梦，折一枝聊寄，古意殊真。", "渺然望极来雁，传与异乡春。", "尚记得行歌，阳关西出无故人。"]'),
('song-ci-691','踏莎行','张炎','宋','宋词','song-ci','踏莎行','[]','花引春来，手擎春住。',68,'宋词/ci.song.18000.json','["花引春来，手擎春住。", "芳心一点谁分付。", "微歌微笑蓦思量，瞥然抛与东流去。", "带润偷拈，和香密护。", "归时自有留连处。", "不随烟水不随风，不教轻把刘郎误。"]'),
('song-ci-692','浪淘沙','张炎','宋','宋词','song-ci','浪淘沙','[]','香雾湿云环。',64,'宋词/ci.song.18000.json','["香雾湿云环。", "蕊佩珊珊。", "酒醒微步晚波寒。", "金鼎尚存丹已化，雪冷虚坛。", "游冶未知还。", "鹤怨空山。", "潇湘无梦绕丛兰。", "碧海茫茫归不去，却在人间。"]'),
('song-ci-693','西江月','张炎','宋','宋词','song-ci','西江月','[]','落落奇花未吐，离离瑶草偏幽。',58,'宋词/ci.song.18000.json','["落落奇花未吐，离离瑶草偏幽。", "蓬山元是不知秋。", "却笑人间春瘦。", "潇丽寒犀麈尾，玲珑润玉搔头。", "半窗晴日水痕收。", "不怕杜鹃啼后。"]'),
('song-ci-694','珍珠令','张炎','宋','宋词','song-ci','珍珠令','[]','桃花扇底歌声杳。',60,'宋词/ci.song.18000.json','["桃花扇底歌声杳。", "愁多少。", "便觉道花阴闲了。", "因甚不归来，甚归来不早。", "满院飞花休要扫。", "待留与、薄情知道。", "怕一似飞花，和春都老。"]'),
('song-ci-695','壶中天・念奴娇','张炎','宋','宋词','song-ci','壶中天・念奴娇','[]','波明昼锦，看芳莲迎晓，风弄晴碧。',120,'宋词/ci.song.18000.json','["波明昼锦，看芳莲迎晓，风弄晴碧。", "乔木千年长润屋，清荫图书琴瑟。", "龟甲屏开，虾须帘卷，瑶草秋无色。", "和熏兰麝，彩衣欢拥诗伯。", "溪上燕往鸥还，笔床茶灶，筇竹随游屐。", "闲似神仙闲最好，未必如今闲得。", "书染芝香，驿传梅信，次第来云北。", "金尊须满，月光长照歌席。"]'),
('song-ci-696','摸鱼子','张炎','宋','宋词','song-ci','摸鱼子','["\u9ec4\u6cb3"]','溯空明、霁蟾飞下，湖湘难辨遥树。',140,'宋词/ci.song.18000.json','["溯空明、霁蟾飞下，湖湘难辨遥树。", "流来那得清如许，不与众流东注。", "浮净宇。", "任消息虚盈，壶内藏今古。", "停杯问取。", "甚玉笛移宫，银桥散影，依旧广寒府。", "休凝伫。", "鼓枻渔歌在否。", "沧浪浑是烟雨。", "黄河路接银河路。", "炯炯近天尺五。", "还自语。", "奈一寸闲心，不是安愁处。", "凌风远举。", "趁冰玉光中，排云万里，秋艇载诗去。"]'),
('song-ci-697','好事近','张炎','宋','宋词','song-ci','好事近','[]','葱倩满身云，酒晕浅融香颊。',53,'宋词/ci.song.18000.json','["葱倩满身云，酒晕浅融香颊。", "水调数声娴雅，把芳心偷说。", "风吹裙带下阶迟，惊散双蝴蝶。", "佯拈花枝微笑，溜晴波一瞥。"]'),
('song-ci-698','小重山','张炎','宋','宋词','song-ci','小重山','[]','阴过云根冷不移。',70,'宋词/ci.song.18000.json','["阴过云根冷不移。", "古林疏又密，色依依。", "何须喷饭笑当时。", "篔筜谷，盈尺小鹅溪。", "展玩似堪疑。", "楚山从此去，望中迷。", "不知何处倚湘妃。", "空江晚，长笛一声吹。"]'),
('song-ci-699','蝶恋花','张炎','宋','宋词','song-ci','蝶恋花','[]','求友林泉深密处。',70,'宋词/ci.song.18000.json','["求友林泉深密处。", "弄舌调簧，如问春何许。", "燕子先将雏燕去。", "凄凉可是歌来暮。", "乔木萧萧梧叶雨。", "不似寻芳，翻落花心露。", "认取门前杨柳树。", "数声须入新年语。"]'),
('song-ci-700','南楼令・唐多令','张炎','宋','宋词','song-ci','南楼令・唐多令','[]','天净雨初晴。',74,'宋词/ci.song.18000.json','["天净雨初晴。", "秋清人更清。", "满吟窗、柳思周情。", "一片香来松桂下，长听得，读书声。", "闲处卷黄庭。", "年年两鬓青。", "佩芳兰、不系尘缨。", "傍取溪边端正月，对玉兔、话长生。"]'),
('song-ci-701','风入松','张炎','宋','宋词','song-ci','风入松','[]','新篁依约佩初摇。',90,'宋词/ci.song.18000.json','["新篁依约佩初摇。", "老石润山腰。", "逸人未必犹酣酒，正溪头、风雨潇潇。", "砺齿犹随市隐，虚心肯受春招。", "从教三径入渔樵。", "对此觉尘消。", "娟枝冷叶无多子，伴明窗、书卷诗瓢。", "清过炎天梅蕊，淡欺雪里芭蕉。"]'),
('song-ci-702','踏莎行','张炎','宋','宋词','song-ci','踏莎行','["\u897f\u6e56"]','水落槎枯，田荒玉碎。',68,'宋词/ci.song.18000.json','["水落槎枯，田荒玉碎。", "夜阑秉烛惊相对。", "故家人物已无传，一灯却照清江外。", "色展天机，光摇海贝。", "锦囊日月奚童背。", "重逢何处抚孤松，共吟风月西湖醉。"]'),
('song-ci-703','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','因风整帽，借柳维舟，休登故苑荒台。',119,'宋词/ci.song.18000.json','["因风整帽，借柳维舟，休登故苑荒台。", "去岁何年，游处半入苍苔。", "白鸥旧盟未冷，但寒沙、空与愁堆。", "谩叹息，问西门洒泪，不忍徘徊。", "眼底江山犹在，把冰弦弹断，苦忆颜回。", "一点归心，分付布袜青鞋。", "相寻已期到老，那知人、如此情怀。", "怅望久，海棠开、依旧燕来。"]'),
('song-ci-704','声声慢','张炎','宋','宋词','song-ci','声声慢','["\u6d1e\u5ead\u6e56"]','□声短棹，柳色长条，无花但觉风香。',119,'宋词/ci.song.18000.json','["□声短棹，柳色长条，无花但觉风香。", "万境天开，逸兴纵我清狂。", "白鸥更闲似我，趁平芜、飞过斜阳。", "重叹息，却如何不□，梦里黄梁。", "一自三高非旧，把诗囊酒具，千古凄凉。", "近日烟波，乐事尽逐渔忙。", "山横洞庭夜月，似潇湘、不似潇湘。", "归未得，数清游、多在水乡。"]'),
('song-ci-705','声声慢','张炎','宋','宋词','song-ci','声声慢','[]','百花洲畔，十里湖边，沙鸥未许盟寒。',119,'宋词/ci.song.18000.json','["百花洲畔，十里湖边，沙鸥未许盟寒。", "旧隐琴书，犹记渭水长安。", "苍云数千万叠，却依然、一笑人间。", "似梦里，对清尊白发，秉烛更阑。", "渺渺烟波无际，唤扁舟欲去，且与凭阑。", "此别何如，能消几度阳关。", "江南又听夜雨，怕梅花、零落孤山。", "归最好，甚闲人，犹自未闲。"]'),
('song-ci-706','木兰花慢','张炎','宋','宋词','song-ci','木兰花慢','["\u897f\u6e56"]','二分春是雨，采香径、绿阴铺。',124,'宋词/ci.song.18000.json','["二分春是雨，采香径、绿阴铺。", "正私语晴蛙，于飞晚燕，闲掩纹疏。", "流光惯欺病酒，问杨花、过了有花无。", "啼鴂初闻院宇，钓船犹系菰蒲。", "林逋。", "树老山孤。", "浑忘却、隐西湖。", "叹扇底歌残，蕉间梦醒，难寄中吴。", "秋痕尚悬鬓影，见莼丝、依旧也思鲈。", "黏壁蜗涎几许，清风只在樵渔。"]'),
('song-ci-707','清平乐','张炎','宋','宋词','song-ci','清平乐','["\u897f\u6e56"]','□花一叶。',54,'宋词/ci.song.18000.json','["□花一叶。", "比似前时别。", "烟水茫茫无处说。", "冷却西湖□月。", "贞芳只合深山。", "红尘了不相关。", "留得许多清影，幽香不到人间。"]'),
('song-ci-708','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','□□不了。',54,'宋词/ci.song.18000.json','["□□不了。", "都被红尘老。", "一粒粟中休道好。", "弱水竟通蓬岛。", "孤云漂泊难寻。", "如今却在□□。", "莫趁清风出岫，此中方是无心。"]'),
('song-ci-709','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','平沙流水。',54,'宋词/ci.song.18000.json','["平沙流水。", "叶老芦花未。", "落雁无声还有字。", "一片潇湘古意。", "扁舟记得幽寻。", "相寻只在□□。", "莫趁春风飞去，玉关夜雪犹深。"]'),
('song-ci-710','临江仙','张炎','宋','宋词','song-ci','临江仙','["\u6d1e\u5ead\u6e56"]','翦翦春水出万壑，和春带出芳丛。',70,'宋词/ci.song.18000.json','["翦翦春水出万壑，和春带出芳丛。", "谁分弱水洗尘红。", "低回金叵罗，约略玉玲珑。", "昨夜洞庭云一片，朗吟飞过天风。", "戏将瑶草散虚空。", "灵根何处觅，只在此山中。"]'),
('song-ci-711','思佳客','张炎','宋','宋词','song-ci','思佳客','["\u897f\u6e56"]','梦里瞢腾说梦华。',64,'宋词/ci.song.18000.json','["梦里瞢腾说梦华。", "莺莺燕燕已天涯。", "蕉中覆处应无鹿，汉上从来不见花。", "今古事，古今嗟。", "西湖流水响琵琶。", "铜驼烟雨栖芳草，休向江南问故家。"]'),
('song-ci-712','清平乐','张炎','宋','宋词','song-ci','清平乐','["\u897f\u6e56"]','柳间花外。',54,'宋词/ci.song.18000.json','["柳间花外。", "日日离人泪。", "忆得楼心和月醉。", "落叶与愁俱碎。", "如今一笑吴中。", "眼青犹认衰翁。", "先泛扁舟烟水，西湖多定相逢。"]'),
('song-ci-713','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','□□晴树。',54,'宋词/ci.song.18000.json','["□□晴树。", "寒食无风雨。", "记得当时游冶处。", "桂底一身香露。", "神仙只在蓬莱。", "不知白鹤飞来。", "乘兴飘然归去，瞋人踏破青苔。"]'),
('song-ci-714','风入松','张炎','宋','宋词','song-ci','风入松','["\u897f\u6e56"]','满头风雪昔同游。',90,'宋词/ci.song.18000.json','["满头风雪昔同游。", "同载月明舟。", "回来又续西湖梦，绕江南、那处无愁。", "赢得如今老大，依然只是漂流。", "故人翦烛对花讴。", "不记此身浮。", "征衣冷落荷衣暖，径虽荒、也合归休。", "明□□□烟水，相思却在并州。"]'),
('song-ci-715','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□卯湾头屋数间。',32,'宋词/ci.song.18000.json','["□卯湾头屋数间。", "放船收尽一溪山。", "聊适兴，且怡颜。", "问天难买是真闲。"]'),
('song-ci-716','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□□溪流。',32,'宋词/ci.song.18000.json','["□□□□□溪流。", "紧系篱边一叶舟。", "沽酒去，闭门休。", "从此清闲不属鸥。"]'),
('song-ci-717','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□白云多。',32,'宋词/ci.song.18000.json','["□□□□白云多。", "童子贪眠枕绿蓑。", "莞尔笑，浩然歌。", "奈此萧萧落叶何。"]'),
('song-ci-718','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□半树梅。',32,'宋词/ci.song.18000.json','["□□□□半树梅。", "卷帘一色玉蓬莱。", "宜啸咏，莫徘徊。", "乘兴扁舟好去来。"]'),
('song-ci-719','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□□子同。',32,'宋词/ci.song.18000.json','["□□□□□子同。", "更无人识老渔翁。", "来往事，有无中。", "却恐桃源自此通。"]'),
('song-ci-720','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□□求鱼。',32,'宋词/ci.song.18000.json','["□□□□□求鱼。", "钓不得鱼还自如。", "尘事远，世人疏。", "何须更写绝交书。"]'),
('song-ci-721','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□濯尘缨。',32,'宋词/ci.song.18000.json','["□□□□濯尘缨。", "严濑磻溪有重轻。", "多少事，古今情。", "今人当似古人清。"]'),
('song-ci-722','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□□浮家。',32,'宋词/ci.song.18000.json','["□□□□□浮家。", "篷底光阴鬓未华。", "停短棹，舣平沙。", "流水恐是杏坛花。"]'),
('song-ci-723','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□□□孤村。',32,'宋词/ci.song.18000.json','["□□□□□孤村。", "路隔尘寰水到门。", "斜照散，远云昏。", "白鹭飞来老树根。"]'),
('song-ci-724','渔歌子','张炎','宋','宋词','song-ci','渔歌子','[]','□□□年酒半酣。',32,'宋词/ci.song.18000.json','["□□□年酒半酣。", "知鱼知我静中参。", "峰六六，径三三。", "此怀难与俗人谈。"]'),
('song-ci-725','一翦梅','张炎','宋','宋词','song-ci','一翦梅','[]','闷蕊惊寒减艳痕。',72,'宋词/ci.song.18000.json','["闷蕊惊寒减艳痕。", "蜂也消魂。", "蝶也消魂。", "醉归无月傍黄昏。", "知是花村。", "知是前村。", "留得闲枝叶半存。", "好似桃根。", "不似桃根。", "小楼昨夜雨声浑。", "春到三分。", "秋到三分。"]'),
('song-ci-726','南乡子','张炎','宋','宋词','song-ci','南乡子','[]','野色一桥分。',66,'宋词/ci.song.18000.json','["野色一桥分。", "活水流云直到门。", "落叶堆篱从不扫，开尊。", "醉里教儿诵楚文。", "隔断马蹄痕。", "商鼎熏花独自闻。", "吟思更添清绝处，黄昏。", "月白枝寒雪满村。"]'),
('song-ci-727','清平乐','张炎','宋','宋词','song-ci','清平乐','[]','五湖一叶。',54,'宋词/ci.song.18000.json','["五湖一叶。", "风浪何时歇。", "醉里不知花影别。", "依旧空山明月。", "夜深鹤怨归迟。", "此时那处堪归。", "门外一株杨柳，折来多少相思。"]'),
('song-ci-728','柳梢青','张炎','宋','宋词','song-ci','柳梢青','[]','一夜凝寒，忽成琼树，换却繁华。',61,'宋词/ci.song.18000.json','["一夜凝寒，忽成琼树，换却繁华。", "因甚春深，片红不到，绿水人家。", "眼惊白昼天涯。", "空望断、尘香钿车。", "独立回风，东阑惆怅，莫是梨花。"]'),
('song-ci-729','南歌子','张炎','宋','宋词','song-ci','南歌子','[]','窗密春声聚，花多水影重。',62,'宋词/ci.song.18000.json','["窗密春声聚，花多水影重。", "只留一路过东风。", "围得生香不断、锦熏笼。", "月地连金屋，云楼瞰翠蓬。", "惺忪笑语隔帘栊。", "知是谁调鹦鹉、柳阴中。"]'),
('song-ci-730','青玉案','张炎','宋','宋词','song-ci','青玉案','[]','万红梅里幽深处。',80,'宋词/ci.song.18000.json','["万红梅里幽深处。", "甚杖履、来何暮。", "草带湘香穿水树。", "尘留不住。", "云留却住。", "壶内藏今古。", "独清懒入终南去。", "有忙事、修花谱。", "骑省不须重作赋。", "园中成趣。", "琴中得趣。", "酒醒听风雨。"]'),
('song-ci-731','台城路・齐天乐','张炎','宋','宋词','song-ci','台城路・齐天乐','[]','当年不信江湖老，如今岁华惊晚。',123,'宋词/ci.song.18000.json','["当年不信江湖老，如今岁华惊晚。", "路改家迷，花空阴落，谁识重来刘阮。", "殊乡顿远。", "甚犹带羁怀，雁凄蛩怨。", "梦里忘归，乱浦烟浪片帆转。", "闭门休叹故苑。", "杖藜游冶处，萧艾都遍。", "雨色云西，晴光水北，一洗悠然心眼。", "行行渐懒。", "快料理幽寻，酒瓢诗卷。", "赖有湖边，旧时鸥数点。"]'),
('song-ci-732','菩萨蛮','张炎','宋','宋词','song-ci','菩萨蛮','[]','霜花铺岸浓如雪。',52,'宋词/ci.song.18000.json','["霜花铺岸浓如雪。", "田间水浅冰初结。", "林密乱鸦啼。", "山深雁过稀。", "风恬湖似镜。", "冷浸楼台影。", "梅不怕隆寒。", "疏葩正耐看。"]'),
('song-ci-733','尾犯','张炎','宋','宋词','song-ci','尾犯','["\u897f\u6e56"]','一白受春知。',115,'宋词/ci.song.18000.json','["一白受春知。", "独爱老来，疏瘦偏宜。", "古月黄昏，许松竹相依。", "晕藓枯槎半折，影浮波、渴龙倒窥。", "岁华凋谢，水边篱落，雪后忽横枝。", "百花头上立，且休问、向北开迟。", "老了何郎，不成便无诗。", "惟只有、西州倦客，怕说著、西湖旧时。", "难忘处，放鹤山空人未归。"]'),
('song-ci-734','祝英台近','张炎','宋','宋词','song-ci','祝英台近','[]','水空流，心不竞，门掩柳阴早。',95,'宋词/ci.song.18000.json','["水空流，心不竞，门掩柳阴早。", "芸暖书芗，声压四檐悄。", "断尘飞远清风，人间醒醉，任蝶梦、何时分晓。", "古音少。", "素琴久已无弦，俗子未知道。", "听雨看云，依旧静中好。", "但教春风融融，一般意思，小窗外、不除芳草。"]'),
('song-ci-735','华胥引','张炎','宋','宋词','song-ci','华胥引','[]','碧浮春盖，黄点秋旗，细芳泛月。',104,'宋词/ci.song.18000.json','["碧浮春盖，黄点秋旗，细芳泛月。", "露委残钗，烟梳高髻曾戏折。", "几度宿寄山房，□曲尘云屑。", "香入蜂须，蜜房风味应别。", "蒭酒浮汤，爱霏霏、粉黄清绝。", "嫩苞新子，凭谁香歌五粒。", "只怕东风吹尽，长萧萧黄发。", "独鹤归来，满庭零乱金雪。"]'),
('song-ci-736','甘州・八声甘州','张炎','宋','宋词','song-ci','甘州・八声甘州','[]','想不劳、添竹引龙须，断梗忽传芳。',118,'宋词/ci.song.18000.json','["想不劳、添竹引龙须，断梗忽传芳。", "记珠悬润碧，飘飘秋影，曾印禅窗。", "诗外片云落莫，错认是花光。", "无色空尘眼，雾老烟荒。", "一翦静中生意，任前看冷淡，真味深长。", "有清风如许，吹断万红香。", "且休教夜深人见，怕误他、看月上银床。", "凝眸久，却愁卷去，难博西凉。"]'),
('song-ci-737','沁园春','韩信同','宋','宋词','song-ci','沁园春','[]','望紫云翁，启明在东，长庚在西。',139,'宋词/ci.song.18000.json','["望紫云翁，启明在东，长庚在西。", "但空有寸心，荆州江汉，未能百里，弱水沙黎。", "菊底秋深，樵边信至，一曲阳春草木知。", "长吟咏，觉声如韩操，骨似陶诗。", "不应鬓发能稀。", "七十寿强如六十耆。", "想高谈倾坐，风斯下矣，微辞漱物，清且涟漪。", "谩说磻翁，休夸淇叟，用舍行藏各有时。", "真修养，有近思家学，字字参芝。"]'),
('song-ci-738','沁园春','王炎午','宋','宋词','song-ci','沁园春','[]','又是年时，杏红欲脸，柳绿初芽。',139,'宋词/ci.song.18000.json','["又是年时，杏红欲脸，柳绿初芽。", "奈寻春步远，马嘶湖曲，卖花声过，人唱窗纱。", "暖日晴烟，轻衣罗扇，看遍王孙七宝车。", "谁知道，十年魂梦，风雨天涯。", "休休何必伤嗟。", "谩赢得、青青两鬓华。", "且不知门外，桃花何代，不知江左，燕子谁家。", "世事无情，天公有意，岁岁东风岁岁花。", "拚一笑、且醒来杯酒，醉后杯茶。"]'),
('song-ci-739','点绛唇','徐瑞','宋','宋词','song-ci','点绛唇','[]','多事春风，年年绿遍江南草。',50,'宋词/ci.song.18000.json','["多事春风，年年绿遍江南草。", "罗裙色好。", "莫把相如恼。", "梦入瑶台，搔背麻姑爪。", "还惊觉。", "杜鹃啼早。", "一夜相思老。"]'),
('song-ci-740','菩萨蛮','王去疾','宋','宋词','song-ci','菩萨蛮','[]','吴波深处波声急。',52,'宋词/ci.song.18000.json','["吴波深处波声急。", "栏干下瞰鱼龙宅。", "江北与江南。", "斜阳山外山。", "十洲三岛地。", "梦里身曾至。", "今日醉危亭。", "神仙邀我盟。"]'),
('song-ci-741','踏莎行','刘将孙','宋','宋词','song-ci','踏莎行','["\u897f\u6e56"]','水际轻烟，沙边微雨。',68,'宋词/ci.song.18000.json','["水际轻烟，沙边微雨。", "荷花芳草垂杨渡。", "多情移徙忽成愁，依稀恰是西湖路。", "血染红笺，泪题锦句。", "西湖岂忆相思苦。", "只应幽梦解重来，梦中不识从何去。"]'),
('song-ci-742','阮郎归','刘将孙','宋','宋词','song-ci','阮郎归','[]','斜阳江路柳青青。',56,'宋词/ci.song.18000.json','["斜阳江路柳青青。", "传杯那放停。", "上船不记送人行。", "南风吹酒醒。", "江曲曲，路萦萦。", "月明潮水生。", "送将残梦作浮萍。", "角声何处城。"]'),
('song-ci-743','南乡子','刘将孙','宋','宋词','song-ci','南乡子','[]','山色泛秋光。',66,'宋词/ci.song.18000.json','["山色泛秋光。", "点点东篱菊又黄。", "岁月欺人如此去，堂堂。", "一事无成两鬓霜。", "佳节共持觞。", "无限杯供有限狂。", "明月明年诗句苦，茫茫。", "细把茱萸感慨长。"]'),
('song-ci-744','八声甘州','刘将孙','宋','宋词','song-ci','八声甘州','[]','不看萸、把酒对名山，无帽厌西风。',119,'宋词/ci.song.18000.json','["不看萸、把酒对名山，无帽厌西风。", "渺四海故人，一尊今雨，万里长空。", "宇宙此山此日，今夕几人同。", "举世谁不醉，独属陶公。", "当日白衣几许，漫凄其寄兴，落日篱东。", "抚停云六合，借醉托孤踪。", "□吊古、不须多感，□古人、那得共杯中。", "拚酩酊，明年此会，谁此从容。"]'),
('song-ci-745','八声甘州','刘将孙','宋','宋词','song-ci','八声甘州','[]','看东风、天上放梅开，经岁又新成。',119,'宋词/ci.song.18000.json','["看东风、天上放梅开，经岁又新成。", "笑柳眼迷青，桃腮改白，蝶舞尘惊。", "任是万红千紫，无力与春争。", "想建章鳷鹊，犹是残霙。", "不比腊前憔悴，拨寒炉榾柮，茶薄烟清。", "快玉龙战罢，四野迥收兵。", "望红花、扶桑国里，玉玲珑、□□海天平。", "晴窗下，疏疏花雨，滴滴春声。"]'),
('song-ci-746','八声甘州','刘将孙','宋','宋词','song-ci','八声甘州','[]','又江南、三月更明朝，便已是南风。',119,'宋词/ci.song.18000.json','["又江南、三月更明朝，便已是南风。", "拟强驻韶光，狂追柳絮，卧占残红。", "早向尊前沈醉，莫听五更钟。", "赢得春工笑，恼杀渠侬。", "只道春风不改，□年来岁去，柳密花浓。", "但沈腰潘鬓，无复旧时容。", "春还是、多情多恨，便不教、绿满洛阳宫。", "只消得，无情风雨，断送匆匆。"]'),
('song-ci-747','满江红','刘将孙','宋','宋词','song-ci','满江红','[]','正好花时，忽办得、匆匆来去。',114,'宋词/ci.song.18000.json','["正好花时，忽办得、匆匆来去。", "道一往无情，却又别颦愁妩。", "四海云鬟高样髻，长思红袖□分路。", "怪近来、不怨客毡寒，婵娟误。", "黄花约，终难据。", "曾未肯，清园住。", "只昼思夜梦，浅斟低诉。", "莲子擘开谁在意，徐娘一笑来何暮。", "又争知、寂寞白头吟，寒机素。"]'),
('song-ci-748','满江红','刘将孙','宋','宋词','song-ci','满江红','[]','南浦绿波，只断送、行人行色。',115,'宋词/ci.song.18000.json','["南浦绿波，只断送、行人行色。", "虽只是、鹏抟九万，天池春碧。", "鸾侣凤朋争快睹，鸥盟鹭宿空曾识。", "到玉堂、天上念西江，今非昔。", "公去也，宁怀别。", "人感旧，情空切。", "但岁寒松柏，相期茂悦。", "好在莫偿尘土债，风流宁可金门客。", "俯人间、大暑少清风，多炎热。"]'),
('song-ci-749','满江红','刘将孙','宋','宋词','song-ci','满江红','[]','千里酸风，茂陵客、咸阳古道。',115,'宋词/ci.song.18000.json','["千里酸风，茂陵客、咸阳古道。", "宫门夜、马嘶无迹，东关云晓。", "牵上魏车将汉月，忆君清泪知多少。", "怅土花、三十六宫墙，秋风袅。", "浥露兰，啼痕绕。", "画阑桂，雕香早。", "便天还知道，和天也老。", "独出携盘谁送客，刘郎陵上烟迷草。", "悄渭城、已远月荒凉，波声小。"]'),
('song-ci-750','摸鱼儿','刘将孙','宋','宋词','song-ci','摸鱼儿','[]','又匆匆、一番元夕，无灯更愁风雨。',140,'宋词/ci.song.18000.json','["又匆匆、一番元夕，无灯更愁风雨。", "人间天上无归梦，惟有春来春去。", "愁不语。", "漫泪湿香绡，□草人何许。", "百年胜处。", "还更有琉璃，春棚月架，万眼蝶罗否。", "风流事，孤负后来儿女。", "可怜薄命三五。", "千金无买吴呆处，更说龙飞凤舞。", "今又古。", "便剩有才情，无分登楼赋。", "春醪独抚。", "也难觅阿瞒，肯容狂客，醉里试歌舞。"]'),
('song-ci-751','摸鱼儿','刘将孙','宋','宋词','song-ci','摸鱼儿','[]','雨萧萧、春寒欲暮。',140,'宋词/ci.song.18000.json','["雨萧萧、春寒欲暮。", "杜鹃声转□□。", "东风与汝何恩怨，强管人间去住。", "行且去。", "漫憔悴十年，愁得身成树。", "青青故宇。", "看浩荡灵修，徘徊落日，不乐复何故。", "曾听处。", "少日京华行路。", "青灯梦断无语。", "风林飒飒鸡声乱，摇落壮心如土。", "今又古。", "任啼到天明，清血流红雨。", "人生几许。", "且赢得刘郎，看花眼惯，懒复赋前度。"]'),
('song-ci-752','摸鱼儿','刘将孙','宋','宋词','song-ci','摸鱼儿','[]','甚平生、风流谢客，刀头梦送酸楚。',140,'宋词/ci.song.18000.json','["甚平生、风流谢客，刀头梦送酸楚。", "不堪又得花间曲，猛忆云英霜杵。", "闲情赋。", "谁催就月明，云鬓犀梳吐。", "才情几许。", "待遗策重来，吹箫一弄，鸾凤共轻举。", "留春住。", "买得绿波南浦。", "黄金□散如土。", "蔷薇洞口三生路。", "无奈春光顿阻。", "新□绪。", "也待见东邻，花艳墙低处。", "东风看取。", "便娇送飞梭，半携编贝，笑咏尚高古。"]'),
('song-ci-753','金缕曲・贺新郎','刘将孙','宋','宋词','song-ci','金缕曲・贺新郎','[]','我老无能矣。',142,'宋词/ci.song.18000.json','["我老无能矣。", "叹人生、得开笑口，一年闲几。", "去景悠悠如有待，白发已非春事。", "便一笑、何曾是喜。", "我本渔樵孟诸野，向举家、尽叹今如是，空自苦，有谁似。", "堆堆独坐文书里。", "是无能、爱闲爱静，清时有味。", "出处古今无真是，往往君言有理。", "看攘臂、后来锋起。", "汉晋唐虞一杯水，只鲁连、犹未知之耳。", "况碌碌，共馀子。"]'),
('song-ci-754','江城子','刘将孙','宋','宋词','song-ci','江城子','[]','云涛白凤贺瑶池。',86,'宋词/ci.song.18000.json','["云涛白凤贺瑶池。", "仗葳蕤。", "路芳菲。", "十月温汤，赐浴卸罗衣。", "半点檀心天一笑，琼奴弱，玉环肥。", "风流谁合婿金闺。", "露将晞。", "雪争晖。", "贝阙珠宫，环佩月中归。", "误杀洛滨狂子建，情脉脉，恨依依。"]'),
('song-ci-755','江城梅花引','刘将孙','宋','宋词','song-ci','江城梅花引','[]','明霞回雨霁秋空。',108,'宋词/ci.song.18000.json','["明霞回雨霁秋空。", "笑难逢。", "步城东。", "直上翠微，客有可人同。", "回首向来轻节序，筋力异，心犹在，愧鬓蓬。", "悲年冉冉江滚滚。", "骑台平，蒋陵冷。", "天高年晚，山河险，烟雾冥濛。", "一幅乌纱，闲著傲西风。", "古往今来只如此，便潦倒，渺乾坤，醉眼中。"]'),
('song-ci-756','六州歌头','刘将孙','宋','宋词','song-ci','六州歌头','[]','天涯倦客，如梦说今宵。',180,'宋词/ci.song.18000.json','["天涯倦客，如梦说今宵。", "承平事，车尘涨，马鸣萧。", "火城朝。", "狂歌闲嬉笑，平康客，五陵侠，闲相待，沙河路，灞陵桥。", "万眼琉璃，目眩去闲买，一翦梅烧。", "数金蛾彩蝶，簇带那人娇。", "说著魂销。", "掩鲛绡。", "波翻海，尘换世，铜仙泪，铁心娆。", "渺何地，跢朱履，解金貂。", "步宫腰。", "瑶池惊燕罢，瓶落井，箭离弨。", "灯楼倒，吴儿老，绛都迢。", "点点梅梢残雪，似东风、吹恨难消。", "悄山村渔火，风鬓立春宵。", "绕寒潮。"]'),
('song-ci-757','水调歌头','刘将孙','宋','宋词','song-ci','水调歌头','[]','摇风犹似旆，倾雨不成盘。',114,'宋词/ci.song.18000.json','["摇风犹似旆，倾雨不成盘。", "西风未禁十日，早作背时看。", "寂寞六郎秋扇，牵补灵均破屋，风露半襟寒。", "坐感青年晚，不但翠云残。", "叹此君，深隐映，早阑珊。", "人间受尽炎热，暑夕几恁阑。", "待得良宵灏气，正是好天良月，红到绿垂乾。", "摇落从此始，感慨不能闲。"]'),
('song-ci-758','沁园春','刘将孙','宋','宋词','song-ci','沁园春','[]','壬戌之秋，七夕既望，苏子泛舟。',139,'宋词/ci.song.18000.json','["壬戌之秋，七夕既望，苏子泛舟。", "正赤壁风清，举杯属客，东山月上，遗世乘流。", "桂棹叩舷，洞箫倚和，何事呜呜怨泣幽。", "悄危坐，抚苍苍东望，渺渺荆州。", "客云天地蜉蝣。", "记千里舳舻旗帜浮。", "叹孟德周郎，英雄安在，武昌夏口，山水相缪。", "客亦知夫，盈虚如彼，山月江风有尽不。", "喜更酌，任东方既白，与子遨游。"]'),
('song-ci-759','沁园春','刘将孙','宋','宋词','song-ci','沁园春','[]','十月雪堂，将归临皋，二客从坡。',139,'宋词/ci.song.18000.json','["十月雪堂，将归临皋，二客从坡。", "适薄暮得鱼，细鳞巨口，新霜脱叶，月步行歌。", "有客无肴，有肴无酒，如此风清月白何。", "归谋妇，得旧藏斗酒，重载婆娑。", "登虬踞虎嵯峨。", "更凭醉攀翻栖鹘窠。", "曾岁月几何，江流断岸，山川非昔，夜啸扪萝。", "孤鹤横江，羽衣入梦，应悟飞鸣昔我过。", "开户视，但寂寥四顾，万顷烟波。"]'),
('song-ci-760','沁园春','刘将孙','宋','宋词','song-ci','沁园春','[]','流水断桥，坏壁春风，一曲韦娘。',138,'宋词/ci.song.18000.json','["流水断桥，坏壁春风，一曲韦娘。", "记宰相开元，弄权疮痏，全家骆谷，追骑仓皇。", "彩凤随鸦，琼奴失意，可似人间白面郎。", "知他是，燕南牧马，塞北驱羊。", "啼痕自诉衷肠。", "尚把笔低徊愧下堂。", "叹国手无棋，危涂何策，书窗如梦，世路方长。", "青冢琵琶，穹庐笳拍，未比渠侬泪万行。", "二十载，竟何时委玉，何地埋香。"]'),
('song-ci-761','忆旧游','刘将孙','宋','宋词','song-ci','忆旧游','[]','正落花时节，憔悴东风，绿满愁痕。',124,'宋词/ci.song.18000.json','["正落花时节，憔悴东风，绿满愁痕。", "悄客梦惊呼伴侣，断鸿有约，回泊归云。", "江空共道惆怅，夜雨隔篷闻。", "尽世外纵横，人间恩怨，细酌重论。", "叹他乡异县，渺旧雨新知，历落情真。", "匆匆那忍别，料当君思我，我亦思君。", "人生自非麋鹿，无计久同群。", "此去重销魂，黄昏细雨人闭门。"]'),
('song-ci-762','水龙吟','陈恕可','宋','宋词','song-ci','水龙吟','[]','素姬初宴瑶池，佩环误落云深处。',126,'宋词/ci.song.18000.json','["素姬初宴瑶池，佩环误落云深处。", "分香华井，洗妆湘渚，天姿淡泞。", "碧盖吹凉，玉冠迎晓，盈盈笑语。", "记当时乍识，江明夜静，只愁被、婵娟误。", "几点沙边飞鹭。", "旧盟寒、远迷烟雨。", "相思未尽，纤罗曳水，清铅泣露。", "玉镜台空，银瓶绠绝，断魂何许。", "待今宵试探，中流一叶，共凌波去。"]'),
('song-ci-763','齐天乐','陈恕可','宋','宋词','song-ci','齐天乐','[]','碧柯摇曳声何许，阴阴晚凉庭院。',123,'宋词/ci.song.18000.json','["碧柯摇曳声何许，阴阴晚凉庭院。", "露湿身轻，风生翅薄，昨夜绡衣初翦。", "琴丝宛转。", "弄几曲新声，几番凄惋。", "过雨高槐，为渠一洗故宫怨。", "清虚襟度漫与，向人低诉处，幽思无限。", "败叶枯形，残阳绝响，消得西风肠断。", "尘情已倦。", "任翻鬓云寒，缀貂金浅。", "蜕羽难留，顿觉仙梦远。"]'),
('song-ci-764','齐天乐','陈恕可','宋','宋词','song-ci','齐天乐','[]','蜕仙飞佩流空远，珊珊数声林杪。',123,'宋词/ci.song.18000.json','["蜕仙飞佩流空远，珊珊数声林杪。", "薄暑眠轻，浓阴听久，勾引凄凉多少。", "长吟未了。", "想犹怯高寒，又移深窈。", "与整绡衣，满身风露正清晓。", "微薰庭院昼永，那回曾记得，如诉幽抱。", "断响难寻，馀悲独省，叶底还惊秋早。", "齐宫路杳。", "叹往事魂消，夜阑人悄。", "谩省轻盈，粉奁双鬓好。"]'),
('song-ci-765','桂枝香','陈恕可','宋','宋词','song-ci','桂枝香','[]','西风故国。',124,'宋词/ci.song.18000.json','["西风故国。", "记乍免内黄，归梦溪曲。", "还是秦星夜映，楚霜秋足。", "无肠枉抱东流恨，任年年、褪匡微绿。", "草汀篝火，芦洲纬箔，早寒渔屋。", "叙旧别、芳蒭荐玉。", "正香擘新橙，清泛佳菊。", "依约行沙乱雪，误惊窗竹。", "江湖岁晚相思远，对寒灯、谩怀幽独。", "嫩汤浮眼，枯形蜕壳，断魂重续。"]'),
('song-ci-766','水龙吟','陈深','宋','宋词','song-ci','水龙吟','[]','此翁疑是香山，老来愈觉才情富。',126,'宋词/ci.song.18000.json','["此翁疑是香山，老来愈觉才情富。", "天孙借与，金刀玉尺，裁云缝雾。", "一曲阳春，樽前惟欠，柳蛮樱素。", "对苍松翠竹，江空岁晚，伴明月、倾芳醑。", "深谷修兰楚楚。", "续离骚、载歌初度。", "麻姑素约，天寒相访，遗余琼露。", "拟借青鸾，吹笙碧落，采芝玄圃。", "奈玉堂催召，文园醉叟，草凌云赋。"]'),
('song-ci-767','贺新郎','陈深','宋','宋词','song-ci','贺新郎','[]','丹凤翔云表。',142,'宋词/ci.song.18000.json','["丹凤翔云表。", "览德辉、翩然飞下，翠蓬仙岛。", "银汉无声天似水，昨夜新凉多少。", "听一曲、琼箫音渺。", "千尺秦台凌空峻，见一双、翠羽先飞到。", "披紫雾，揽瑶草。", "风流别乘当英妙。", "对江山、掀髯把酒，浩歌长啸。", "绿发公候何足浼，自是无双才调。", "况槐阴、青青天杪。", "月殿姮娥云深处，近清秋、丹桂催开早。", "斟绿醑，戴花帽。"]'),
('song-ci-768','沁园春','陈深','宋','宋词','song-ci','沁园春','[]','浪迹烟霞，有酒千锺，有书五车。',141,'宋词/ci.song.18000.json','["浪迹烟霞，有酒千锺，有书五车。", "任从来萧散，闲心似水，何堪妩媚，笑面如花。", "濯发沧浪，放歌江海，肯被红尘半点遮。", "谁知道，抱无名钜璞，重价难赊。", "嘻嗟。", "大泽龙蛇。", "且蟠屈、深潜得计些。", "看淋漓醉墨，神情自足，摩挲雄剑，肝胆无邪。", "渭水烟蓑，营丘绣衮，出处何尝有异耶。", "今何在，但素蟾东出，红日西斜。"]'),
('song-ci-769','齐天乐','陈深','宋','宋词','song-ci','齐天乐','[]','秋涛欲涨西陵渡，江亭晓来雄观。',123,'宋词/ci.song.18000.json','["秋涛欲涨西陵渡，江亭晓来雄观。", "帝子吹笙，洛妃起舞，应喜蓬宫仙诞。", "斗墟东畔。", "望缥缈星槎，来从河汉。", "明月楼台，绣筵重启曼桃宴。", "庄椿一树翠色，五枝芳桂长，金蕊玉干。", "自笑狂疏，尊前起寿，不似卫郎温润。", "一卮泛满。", "羡彭泽风流，醉巾长岸。", "老圃黄花，清香宜岁晚。"]'),
('song-ci-770','西江月','陈深','宋','宋词','song-ci','西江月','[]','龙沫流芳旎旎，犀沈锯削霏霏。',58,'宋词/ci.song.18000.json','["龙沫流芳旎旎，犀沈锯削霏霏。", "薇心玉露练香泥。", "厌尽人间花气。", "银叶初温火缓，金猊静袅烟微。", "此时清赏只心知。", "难向人前举似。"]'),
('song-ci-771','虞美人','陈深','宋','宋词','song-ci','虞美人','[]','玉搔斜压乌云堕。',66,'宋词/ci.song.18000.json','["玉搔斜压乌云堕。", "拄颊看书卧。", "开元天子惜娉婷。", "一笑嫣然何事、便倾城。", "马嵬风雨归时路。", "艳骨销黄土。", "多情谁写书画中。", "江水江花千古、恨无穷。"]'),
('song-ci-772','洞仙歌','陈深','宋','宋词','song-ci','洞仙歌','[]','银波湛碧，遥泛仙槎早。',100,'宋词/ci.song.18000.json','["银波湛碧，遥泛仙槎早。", "婺宿荧煌瑞云晓。", "庆芳传丹桂，欢动连枝，称寿处，一簇蓬莱翠窈。", "步虚声宛转，清澈瑶坛，疑是钧霄凤音渺。", "正金姥、礼虚皇，天阶净，凉入绡衣风袅。", "想金书、秘字赐长生，进九酝霞卮，练颜长好。"]'),
('song-ci-773','少年游','刘铉','宋','宋词','song-ci','少年游','[]','石榴花下薄罗衣。',60,'宋词/ci.song.18000.json','["石榴花下薄罗衣。", "睡起却寻棋。", "未省高低，被伊春笋，拈了白玻璃。", "钏脱钗斜浑不省，意重子声迟。", "对面痴心，只愁收局，肠断欲输时。"]'),
('song-ci-774','蝶恋花','刘铉','宋','宋词','song-ci','蝶恋花','[]','人自怜春春未去。',70,'宋词/ci.song.18000.json','["人自怜春春未去。", "萱草石榴，也解留春住。", "只道送春无送处。", "山花落得红成路。", "高处莺啼低蝶舞。", "何况日长，燕子能言语。", "付与光阴相客主。", "晴云又卷西边雨。"]'),
('song-ci-775','乌夜啼','刘铉','宋','宋词','song-ci','乌夜啼','[]','垂杨影里残红。',45,'宋词/ci.song.18000.json','["垂杨影里残红。", "甚匆匆。", "只有榴花、全不怨东风。", "暮雨急。", "晓鸦湿。", "绿玲珑。", "比似茜裙初染、一般同。"]'),
('song-ci-776','贺新郎','梁明夫','宋','宋词','song-ci','贺新郎','["\u5e90\u5c71"]','万里朝天去。',141,'宋词/ci.song.18000.json','["万里朝天去。", "见浔阳江上，风引仙舟淮浦。", "到得玉阶方寸地，历历苍生辛苦。", "要尽活、江南一路。", "昼绣归来沾御渥，听邦人、箫鼓迎初度。", "龟与鹤，亦掀舞。", "前身定是磻溪吕。", "笑当时、八十始卜，非熊非虎。", "试数行年逢革卦，革命正逢汤武。", "真千载、风云会遇。", "拟向庐山招五老，诣道山、同献蓬莱赋。", "仍剪菊，荐秋露。"]'),
('song-ci-777','鹊桥仙','梅坡','宋','宋词','song-ci','鹊桥仙','[]','华桐日永，泛兰风细，节近朱明十日。',68,'宋词/ci.song.18000.json','["华桐日永，泛兰风细，节近朱明十日。", "玉麟何事吐书来，瑞世应、文章东壁。", "绿衣戏彩，金樽酌醴，兰玉阶庭森列。", "更看千岁树青青，管取并、三槐手植。"]'),
('song-ci-778','满江红','梅坡','宋','宋词','song-ci','满江红','[]','天佑生贤，安排个、麦秋六日。',114,'宋词/ci.song.18000.json','["天佑生贤，安排个、麦秋六日。", "人尽道、英雄慷慨，中兴人物。", "佛祖庆生宜后两，洞宾初度犹迟七。", "欲急流勇退作神仙，如何得。", "州县考，劳书绩。", "东西府，今虚席。", "看台星北拱，寿星南极。", "即见紫泥书下逮，须还玉笋班头立。", "愿得君、千载庆风云，齐箕翼。"]'),
('song-ci-779','水调歌头','梅坡','宋','宋词','song-ci','水调歌头','[]','五月进农黍，三叶换阶蓂。',114,'宋词/ci.song.18000.json','["五月进农黍，三叶换阶蓂。", "不知今夕何夕，嵩岳庆生申。", "莲幕泮宫小试，花悬二车遍历，所至蔼芳声。", "一札颁明诏，千里寄专城。", "席方温，边报警，塞飞尘。", "腹中数万兵甲，笑却狄人兵。", "金印明年如斗，黄阁有人引类，阔步到公卿。", "遥拜祝椿算，长愿侍枫宸。"]'),
('song-ci-780','千秋岁引','梅坡','宋','宋词','song-ci','千秋岁引','[]','两叶蓂开，千年桃熟，恰近秋期十三日。',98,'宋词/ci.song.18000.json','["两叶蓂开，千年桃熟，恰近秋期十三日。", "寿星辉映福星现，寿山高对城山立。", "蕊宫仙，王母宴，瑶池客。", "齐劝芳樽斟玉液。", "齐唱新词翻玉笛。", "岁岁今朝陪燕集。", "荣华富贵长年出，重重锦上花添色。", "谢庭兰，燕山桂，登科必。"]'),
('song-ci-781','蓦山溪','徐观国','宋','宋词','song-ci','蓦山溪','[]','儒官措大，是官曰都得做。',100,'宋词/ci.song.18000.json','["儒官措大，是官曰都得做。", "宰相故崇下，呼召也须同，太原公子，能武又能文，闲暇里，抱琴书，车马时相过。", "樽开北海，减请还知麽。", "叵耐这点徒，刚入词、把人点污。", "儒冠屈辱，和我被干连，累告讦，孟尝君，带累三千个。"]'),
('song-ci-782','渔家傲','某邑妓','宋','宋词','song-ci','渔家傲','[]','十月小春梅蕊破。',8,'宋词/ci.song.18000.json','["十月小春梅蕊破。"]'),
('song-ci-783','失调名','阮郎中','宋','宋词','song-ci','失调名','[]','东风捻就，腰儿纤细。',71,'宋词/ci.song.18000.json','["东风捻就，腰儿纤细。", "系的粉裙儿不起。", "近来只惯掌中看，忍教在、烛花影里。", "更阑应是，酒红微褪。", "暗蹙损、眉儿娇翠。", "夜深著两小鞋儿，靠那个、屏风立地。"]'),
('song-ci-784','失调名','吴某','宋','宋词','song-ci','失调名','[]','剪罗幡儿，斜插真珠髻。',11,'宋词/ci.song.18000.json','["剪罗幡儿，斜插真珠髻。"]'),
('song-ci-785','南乡子','吴某','宋','宋词','song-ci','南乡子','[]','楼台里、东风淡荡。',9,'宋词/ci.song.18000.json','["楼台里、东风淡荡。"]'),
('song-ci-786','南乡子','吴某','宋','宋词','song-ci','南乡子','[]','乍卷珠帘新燕入。',8,'宋词/ci.song.18000.json','["乍卷珠帘新燕入。"]'),
('song-ci-787','多丽','吴某','宋','宋词','song-ci','多丽','[]','几声天外归鸿。',7,'宋词/ci.song.18000.json','["几声天外归鸿。"]'),
('song-ci-788','渔家傲','吴某','宋','宋词','song-ci','渔家傲','[]','鶗鴂一声初报晓。',8,'宋词/ci.song.18000.json','["鶗鴂一声初报晓。"]'),
('song-ci-789','蝶恋花','俞克成','宋','宋词','song-ci','蝶恋花','[]','梦断池塘惊乍晓。',70,'宋词/ci.song.18000.json','["梦断池塘惊乍晓。", "百舌无端，故作枝头闹。", "报道不禁寒料峭。", "未教舒展闲花草。", "尽日帘垂人不到。", "老去情疏，底事伤春瘦。", "相对一樽归计早。", "玉山不减巫山好。"]'),
('song-ci-790','万年欢','胡浩然','宋','宋词','song-ci','万年欢','[]','灯月交光，渐轻风布暖，先到南国。',122,'宋词/ci.song.18000.json','["灯月交光，渐轻风布暖，先到南国。", "罗绮娇容，十里绛纱笼烛。", "花艳惊郎醉目。", "有多少、佳人如玉。", "春衫袂，整整齐齐，内家新样妆束。", "欢情未足。", "更阑谩勾牵旧恨，萦乱心曲。", "怅望归期，应是紫姑频卜。", "暗想双眉对蹙。", "断弦待、鸾胶重续。", "休迷恋，野草闲花，凤箫人在金谷。"]'),
('song-ci-791','东风齐著力','胡浩然','宋','宋词','song-ci','东风齐著力','[]','残腊收寒，三阳初转，已换年华。',114,'宋词/ci.song.18000.json','["残腊收寒，三阳初转，已换年华。", "东君律管，迤逦到山家。", "处处笙簧鼎沸，会佳宴、坐列仙娃。", "花丛里，金炉满爇，龙麝烟斜。", "此景转堪夸。", "深意祝、寿山福海增加。", "玉觥满泛，且莫厌流霞。", "幸有迎春寿酒，银瓶浸、几朵梅花。", "休辞醉，园林秀色，百草萌芽。"]'),
('song-ci-792','送入我门来','胡浩然','宋','宋词','song-ci','送入我门来','[]','荼垒安扉，灵馗挂户，神傩烈竹轰雷。',124,'宋词/ci.song.18000.json','["荼垒安扉，灵馗挂户，神傩烈竹轰雷。", "动念流光，四序式周回。", "须知今岁今宵尽，似顿觉明年明日催。", "向今夕，是处迎春送腊，罗绮筵开。", "今古遍同此夜，贤愚共添一岁，贵贱仍偕。", "互祝遐龄，山海固难摧。", "石崇富贵篯铿寿，更潘岳仪容子建才。", "仗东风尽力，一齐吹送，入此门来。"]'),
('song-ci-793','春霁・秋霁','胡浩然','宋','宋词','song-ci','春霁・秋霁','[]','迟日融和，乍雨歇东郊，嫩草凝碧。',128,'宋词/ci.song.18000.json','["迟日融和，乍雨歇东郊，嫩草凝碧。", "紫燕双飞，海棠相衬，妆点上林春色。", "黯然望极。", "因人天气浑无力。", "又听得。", "园苑，数声莺啭柳阴直。", "当此暗想，故国繁华，俨然游人，依旧南陌。", "院深沈、梨花乱落，那堪如练点衣白。", "酒量顿宽洪量窄。", "算此情景，除非殢酒狂欢，恣歌沈醉，有谁知得。"]'),
('song-ci-794','满庭芳','胡浩然','宋','宋词','song-ci','满庭芳','[]','潇洒佳人，风流才子，天然分付成双。',118,'宋词/ci.song.18000.json','["潇洒佳人，风流才子，天然分付成双。", "兰堂绮席，烛影耀荧煌。", "数辐红罗绣帐，宝妆篆、金鸭焚香。", "分明是，芙蕖浪里，一对浴鸳鸯。", "欢娱，当此际，山盟海誓，地久天长。", "愿五男二女，七子成行。", "男作公卿将相，女须嫁、君宰侯王。", "从兹去，荣华富贵，福禄寿无疆。"]'),
('song-ci-795','小冲山・小重山','宋丰之','宋','宋词','song-ci','小冲山・小重山','[]','花样妖娆柳样柔。',70,'宋词/ci.song.18000.json','["花样妖娆柳样柔。", "眼波流不断、满眶秋。", "窥人佯整玉搔头。", "娇无力，舞罢却成羞。", "无计与迟留。", "满怀禁不得、许多愁。", "一溪春水送行舟。", "无情月，偏照水东楼。"]'),
('song-ci-796','风中柳・谢池春','孙夫人','宋','宋词','song-ci','风中柳・谢池春','[]','销灭芳容，端的为郎烦恼。',82,'宋词/ci.song.18000.json','["销灭芳容，端的为郎烦恼。", "鬓慵梳、宫妆草草。", "别离情绪，待归来都告。", "怕伤郎、又还休道。", "利锁名缰，几阻当年欢笑。", "更那堪、鳞鸿信杳。", "蟾枝高折，愿从今须早。", "莫辜负、凤帏人老。"]'),
('song-ci-797','满庭芳','陈若晦','宋','宋词','song-ci','满庭芳','[]','五洞深沈，九峰回抱，望中云汉相侵。',118,'宋词/ci.song.18000.json','["五洞深沈，九峰回抱，望中云汉相侵。", "暮春天气，宫殿翠烟深。", "一片山光澹净，溪月上、碧水浮金。", "环楼杪，仙人度曲，空外响虚音。", "龙香，时暗引，青鸾白鹤，飞下秋阴。", "露华冷、环珠点缀瑶林。", "犹记华胥梦断，从别后、几许追寻。", "人间世，逝川东注，红日又西沈。"]'),
('song-ci-798','摸鱼儿','徐一初','宋','宋词','song-ci','摸鱼儿','[]','对茱萸、一年一度。',140,'宋词/ci.song.18000.json','["对茱萸、一年一度。", "龙山今在何处。", "参军莫道无勋业，消得从容尊俎。", "君看取。", "便破帽飘零，也博名千古。", "当年幕府。", "知多少时流，等闲收拾，有个客如许。", "追往事，满目山河晋土。", "征鸿又过边羽。", "登临莫上高层望，怕见故宫禾黍。", "觞绿醑。", "浇万斛牢愁，泪阁新亭雨。", "黄花无语。", "毕竟是西风，朝来披拂，犹忆旧时主。"]'),
('song-ci-799','声声慢','吴叔','宋','宋词','song-ci','声声慢','[]','烟横山腹，雁点秋容。',10,'宋词/ci.song.18000.json','["烟横山腹，雁点秋容。"]'),
('song-ci-800','沁园春','陈彦章妻','宋','宋词','song-ci','沁园春','[]','记得爷爷，说与奴奴，陈郎俊哉。',136,'宋词/ci.song.18000.json','["记得爷爷，说与奴奴，陈郎俊哉。", "笑世人无眼，老夫得法，官人易聘，国士难媒。", "印信乘龙，夤绿叶凤，选似扬鞭选得来。", "果然是，西雍人物，京样官坯。", "送郎上马三杯。", "莫把离愁恼别怀。", "那孤灯只砚，郎君珍重，离愁别恨，奴自推排。", "白发夫妻，青衫事业，两句微吟当折梅。", "彦章去，早归则个，免待相催。"]'),
('song-ci-801','忆秦娥','郑文妻','宋','宋词','song-ci','忆秦娥','[]','花深深。',56,'宋词/ci.song.18000.json','["花深深。", "一钩罗袜行花阴。", "行花阴。", "闲将柳带，细结同心。", "日边消息空沈沈。", "画眉楼上愁登临。", "愁登临。", "海棠开后，望到如今。"]'),
('song-ci-802','鹧鸪天','刘鼎臣妻','宋','宋词','song-ci','鹧鸪天','[]','金屋无人夜剪缯。',64,'宋词/ci.song.18000.json','["金屋无人夜剪缯。", "宝钗翻作齿痕轻。", "临行执手殷勤送，衬取萧郎两鬓青。", "听嘱付，好看承。", "千金不抵此时情。", "明年宴罢琼林晚，酒面微红相映明。"]'),
('song-ci-803','柳梢青','张任国','宋','宋词','song-ci','柳梢青','[]','挂起招牌。',58,'宋词/ci.song.18000.json','["挂起招牌。", "一声喝采，旧店新开。", "熟事孩儿，家怀老子，毕竟招财。", "当初合下安排。", "又不豪门买呆。", "自古道、正身替代，见任添差。"]'),
('song-ci-804','卜算子','福建士子','宋','宋词','song-ci','卜算子','[]','月上小楼西，鸡唱霜天晓。',54,'宋词/ci.song.18000.json','["月上小楼西，鸡唱霜天晓。", "泪眼相看话别时，把定纤纤手。", "伊道不忘人，伊却都忘了。", "我若无情似你时，瞒不得、桥头柳。"]'),
('song-ci-805','水调歌头','钟辰翁','宋','宋词','song-ci','水调歌头','[]','皓皓一何洁，更暴以秋阳。',114,'宋词/ci.song.18000.json','["皓皓一何洁，更暴以秋阳。", "秋毫尘滓，如何浣得这肝肠。", "况对金风初度，酌彼银河静浴，六月凛冰霜。", "精白生来别，日月许争光。", "清明朝，清要路，遍流芳。", "澄清闽峤，姑命申伯式南邦。", "洗得甲兵静了，去作读书元帅，却入相吾皇。", "清问同天老，俾尔寿而昌。"]'),
('song-ci-806','齐天乐','钟辰翁','宋','宋词','song-ci','齐天乐','[]','南墙槐竹风摇翠。',123,'宋词/ci.song.18000.json','["南墙槐竹风摇翠。", "欢声为谁吹起。", "水秀龟神，松清鹤健，人在蓬壶深处。", "金猊喷雾。", "睹鬓雪青归，脸霞红驻。", "一点寿星，分明光照梅花树。", "三年冰蘖清苦。", "这长生富贵，天应分付。", "经阅黄庭，鼎烹丹井，心事澹然如水。", "东山霖雨。", "正出洗太虚，未容别墅。", "紫诏飞来，玉堂锵步武。"]'),
('song-ci-807','沁园春','萧仲芮','宋','宋词','song-ci','沁园春','[]','五马南来。',139,'宋词/ci.song.18000.json','["五马南来。", "一骑东驰，诏黄已催。", "正寻幽择胜，闲边点检，吟风弄月，忙处徘徊。", "玉井莲房，碧筒酒熟，趁得长年千岁杯。", "杯浮处，正芒寒南极，色映三台。", "明光殿北屏门，记御笔亲题名姓来。", "看河东召入，韩侯归觐，通班玉笋。", "稳上鸾台。", "作汉元功，继唐八叶，绿鬓依然昼绣回。", "安排了，待秋风先看，双桂联魁。"]'),
('song-ci-808','沁园春','陈士豪','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','把酒西湖，问梅一笑，为谁试花。',139,'宋词/ci.song.18000.json','["把酒西湖，问梅一笑，为谁试花。", "有淡庵人品，精忠许国，文昌地位，清白传家。", "鸾检封芝，麟符剖竹，立马嘶风催戍瓜。", "从今好，听夜郎江上，谯鼓喧歈。", "雌堂玉暖吴娃。", "向燕寝香中早放衙。", "但一麾十里，风清画戟，五溪六诏、云拥高牙。", "褒玺疏荣，锋车趣召，万寿杯中色翠霞。", "何须更，问武陵玉屑，勾漏丹砂。"]'),
('song-ci-809','沁园春','赵通判','宋','宋词','song-ci','沁园春','[]','贺白文章，英卫规模，簪缨世家。',139,'宋词/ci.song.18000.json','["贺白文章，英卫规模，簪缨世家。", "更襟怀，芳润光风齐月，笔端奇伟，春藻天葩。", "课最严城，升班清禁，蔽芾棠阴人竞夸。", "争知道，富恩波衮衮，万顷无涯。", "清辉庭桂方花。", "映潋滟仙杯浮紫霞。", "庆云龙风虎，明良际会，鸿动骏业，重叠辉华。", "寿挹南峰，福迎庐水，未羡还丹九转砂。", "从此去，看腰黄眼赤，迤逦堤沙。"]'),
('song-ci-810','念奴娇','赵汝恂','宋','宋词','song-ci','念奴娇','[]','金塘瑞溢，爱琉璃十顷，风漪摇碧。',120,'宋词/ci.song.18000.json','["金塘瑞溢，爱琉璃十顷，风漪摇碧。", "玉女三千擎翠盖，簇拥芙蓉仙伯。", "鸾鹤回翔，龙蛇飞动，醉墨挥仙笔。", "磨崖书寿，分明知是今日。", "应为今日生申，银钩照坐，光满图书壁。", "竹马儿童传好语，小住湖山开国。", "玉玺成文，金莲赐封，剑履登玄石。", "丹砂九转，功成依旧头黑。"]'),
('song-ci-811','贺新凉・贺新郎','石麟','宋','宋词','song-ci','贺新凉・贺新郎','[]','一骑飞来速。',142,'宋词/ci.song.18000.json','["一骑飞来速。", "报平山、将颁凤检，宠分符竹。", "自是平淮勋名在，姓字屏风纪录。", "正欲革、潢池风俗。", "古括久思贤太守，待东山、一起苍生福。", "唐李段，追芳躅。", "横舟竹下凭青鹿。", "庆生朝、称觞蔼蔼，履珠簪玉。", "争奈回溪民望切，计日带牛佩犊。", "便合早、秣驺脂毂。", "圣眷处公犹未惬，俟朱幡、才下锋车趣。", "符已兆，台星六。"]'),
('song-ci-812','金缕词・贺新郎','石麟','宋','宋词','song-ci','金缕词・贺新郎','[]','欲上南楼寿。',142,'宋词/ci.song.18000.json','["欲上南楼寿。", "记当年、祥占玉燕。", "一阳生候。", "今数书云犹七日，宫线未添刺绣。", "便草就、寿词盈袖。", "合捧金荷称鹤算，想华堂、剩醉眉春酒。", "惭斐句，为觞侑。", "功名八稚年方少。", "自归来、陶庐蒋径，菊松为友。", "轩筑易安栽花药，不坠家声五柳。", "况满砌、芝兰争秀。", "岁岁斑斓衣戏处，老人星、一点辉南斗。", "顾对此，共长久。"]'),
('song-ci-813','水调歌头','石麟','宋','宋词','song-ci','水调歌头','[]','九叶仙茅秀，旬浃一阳生。',114,'宋词/ci.song.18000.json','["九叶仙茅秀，旬浃一阳生。", "中山瑞气和暖，融作玉壶春。", "昨夜洪临跨鹤，翌早绿华骖凤，今日岳生申。", "须信神仙侣，引从降蓬瀛。", "文中虎，寿中鹤，酒中鲸。", "一门盛事相继，桥梓奋鹏程。", "应羡华堂燕处，许大规摹涵养，大器晚方成。", "醒后宫花句，伫看赋琼林。"]'),
('song-ci-814','鹧鸪天','石麟','宋','宋词','song-ci','鹧鸪天','[]','欲寿中山不老仙。',64,'宋词/ci.song.18000.json','["欲寿中山不老仙。", "寿词更拟办千篇。", "九蓂日秀尧阶地，五色云祥鲁观天。", "吟逸老，醉逃禅。", "香传丹桂子孙贤。", "莫言大器韬藏久，犹是梁魁擢第年。"]'),
('song-ci-815','水调歌头','石麟','宋','宋词','song-ci','水调歌头','[]','日暖唐宫绣，云绚鲁台观。',114,'宋词/ci.song.18000.json','["日暖唐宫绣，云绚鲁台观。", "九叶仙茅方茂，瑞气霭中山。", "逸老堂前戏彩，新抱玄孙弥月，红字写眉间。", "八十庆公寿，添撇更成千。", "寿中星，人中杰，酒中仙。", "功名富贵，事业分付子孙贤。", "赢得濠梁真乐，剩有陶园佳趣，杖屦日安闲。", "第恐非熊兆，好事逼新年。"]'),
('song-ci-816','满江红','黄通判','宋','宋词','song-ci','满江红','[]','太守风流，管领尽、十分春色。',115,'宋词/ci.song.18000.json','["太守风流，管领尽、十分春色。", "开藩了、万花妆就，舒长化国。", "太白方观宫锦样，老人又现端门侧。", "听螺州、千里沸观声，春无极。", "龙种贵，蟾宫客。", "熊轼彦，鱼书直。", "更精神天赋，寒光停碧。", "宝篆定膺铜狄数，金樽好按梁州拍。", "待予环、赤舄映貂蝉，头方黑。"]'),
('song-ci-817','念奴娇','高子芳','宋','宋词','song-ci','念奴娇','[]','葱葱佳气，人都道、今日垂弧令旦。',120,'宋词/ci.song.18000.json','["葱葱佳气，人都道、今日垂弧令旦。", "怪得欢声如鼎沸，准拟华堂开宴。", "三虎容仪，二乔态度，争捧金杯劝。", "瑶池王母，何妨引领仙眷。", "况有道骨仙风，灵丹秘决，钟鼎何心恋。", "却笑玉阶轩冕客，难脱功名羁绊。", "萧散陶篱，徜徉裴野，风月堪为伴。", "拳拳祝颂，寿龄期等龟算。"]'),
('song-ci-818','菩萨蛮','高子芳','宋','宋词','song-ci','菩萨蛮','[]','去年曾祝夫人寿。',52,'宋词/ci.song.18000.json','["去年曾祝夫人寿。", "今岁也又还依旧。", "鬓绿与颜朱。", "神仙想不如。", "骨相真难老。", "疑是居蓬岛。", "那更舞霓裳。", "笙歌溢画堂。"]'),
('song-ci-819','沁园春','萧仲','宋','宋词','song-ci','沁园春','[]','笑问鸥盟，所不同心，有如大江。',140,'宋词/ci.song.18000.json','["笑问鸥盟，所不同心，有如大江。", "念渊明漫仕，虽轻斗粟，弦歌有得，难慕柴桑。", "相业流芳，元枢新躅，拈作先生一瓣香。", "长生酒，仗西风桂子，吹到河阳。", "湘江。", "笑绾铜章。", "便好筑绵州六一堂。", "看千年辽鹤，重归故里，一般明月，又上潇湘。", "橐紫翻荷，官黄书诏，不待阴成蔽芾棠。", "中书考，更侯封酂国，汤沐宁乡。"]'),
('song-ci-820','洞仙歌','熊德修','宋','宋词','song-ci','洞仙歌','[]','洪崖仙裔，接武浮丘袂。',99,'宋词/ci.song.18000.json','["洪崖仙裔，接武浮丘袂。", "佩玉长裾下尘世。", "东寻山水，独抱一琴来锦里。", "不犯人间宫祉。", "城山堂宇静，百丈楼高，湖海元龙浩然气。", "初度启初筵，昼永堂垂，笙鹤铿、轰出云际。", "问雅乐、何时献三雍，待汉殿明年，日长风细。"]'),
('song-ci-821','满江红','范飞','宋','宋词','song-ci','满江红','[]','律转黄钟，尧蓂尚、零星一叶。',115,'宋词/ci.song.18000.json','["律转黄钟，尧蓂尚、零星一叶。", "人尽道、当年此日，诞生豪杰。", "我是君家门下士，三年屡献阳春雪。", "更此行、骑鹤上扬州，恩稠叠。", "君有子，文章伯。", "君有女，夸才色。", "更风流酝藉，东床佳客。", "胥祝长生儿祝寿，玉杯举罢金杯接。", "愿年年、长醉腊前梅，梅梢月。"]'),
('song-ci-822','沁园春','程和仲','宋','宋词','song-ci','沁园春','[]','呼伯雅来，满进松精，致寿于公。',139,'宋词/ci.song.18000.json','["呼伯雅来，满进松精，致寿于公。", "况富矣锦囊，吟边得句，森然武库，书里称雄。", "亭长新封，亩宫雅趣，一笑侯王名位穹。", "闲官守，任平章批抹，明月清风。", "年年申庆桑蓬。", "幸至节今晨恰又逢。", "想霭霭其祥，瑞云闓兆，绵绵之算，线日增红。", "一段文章，三千功行，名在长生宝箓中。", "人间窄，待骖鸾驾鹤，上祝融峰。"]'),
('song-ci-823','贺新郎','咏槐','宋','宋词','song-ci','贺新郎','[]','绿长阶蓂九。',142,'宋词/ci.song.18000.json','["绿长阶蓂九。", "近黄锺、薰晴爱日，渐添宫绣。", "乾鹊檐头声声喜，催与东屏祝寿。", "怪一点、星明南斗。", "玉燕当年储瑞气，记垂弧、共醉蓬莱酒。", "无杰语，为觞侑。", "英风耿耿拿云手。", "向青春、蟾宫已步，桂香盈袖。", "却要诗书成曲糵，酝酿锦心绣口。", "待匣里、青萍雷吼。", "今日功名乘机会，笑谈间、首入英雄彀。", "看父子，继蓝绶。"]'),
('song-ci-824','渡江云','陈梦协','宋','宋词','song-ci','渡江云','[]','瑞云浓，缥缈弦月当庭，天香满院。',120,'宋词/ci.song.18000.json','["瑞云浓，缥缈弦月当庭，天香满院。", "玉女传言，把真珠帘卷。", "拥鹊桥仙，引江城子，醉蓬莱宴。", "吹紫玉箫，唱黄金缕，按拍声声慢。", "昼锦堂前，倾杯为寿，祝快活年，应天长远。", "喜似娘儿，解称人心愿。", "梦兰蕙芳，种宜男草，丹凤吟非晚。", "更步蟾宫，宴琼林日，汉宫春暖。"]'),
('song-ci-825','鹧鸪天','刘清之','宋','宋词','song-ci','鹧鸪天','[]','柳色青青罩翠烟。',64,'宋词/ci.song.18000.json','["柳色青青罩翠烟。", "花光灼灼映临川。", "欲知窈窕呈祥日，恰近清明淑景天。", "浮瑞霭，庆真仙。", "不须男女祝椿年。", "异时早约西王母，剩折蟠桃荐寿筵。"]'),
('song-ci-826','菩萨蛮','王绍','宋','宋词','song-ci','菩萨蛮','[]','天正朔旦开新历。',52,'宋词/ci.song.18000.json','["天正朔旦开新历。", "吾家伯父长生日。", "兰玉傍庭阶。", "称觞特地来。", "后年逢七十。", "今岁瞻南极。", "南极寿星宫。", "分明矍铄翁。"]'),
('song-ci-827','清平乐','程节斋','宋','宋词','song-ci','清平乐','[]','吾家三母。',54,'宋词/ci.song.18000.json','["吾家三母。", "先后相为寿。", "管领诸郎尽明秀。", "都是婺女星宿。", "华筵今日居先。", "适逾甲子周天。", "敬以庄椿为祝，举觞我愿年年。"]'),
('song-ci-828','木兰花・玉楼春','程节斋','宋','宋词','song-ci','木兰花・玉楼春','[]','瑶池开宴后，问甚处、赋蟠桃。',121,'宋词/ci.song.18000.json','["瑶池开宴后，问甚处、赋蟠桃。", "有砌底芝兰，涧边苹藻，淑德方高。", "闺中秀、林下气，是寻常空委蓬蒿。", "相映鱼轩黄绶，行膺鸾锦金罗。", "自惭半子误恩多。", "所祝意如何。", "愿台星旁映，寿星齐照，乐自陶陶。", "芝田阆风何在，但从今、岁岁此高歌。", "敬上一卮为寿，神仙九酝香醪。"]'),
('song-ci-829','沁园春','程节斋','宋','宋词','song-ci','沁园春','[]','髧彼两髦，未几见兮，突而弁兮。',139,'宋词/ci.song.18000.json','["髧彼两髦，未几见兮，突而弁兮。", "记昔年犀玉，奇资秀质，今朝簪佩，丰颊修眉。", "满面春风，一团和气，发露胸中书与诗。", "人都羡，是君家驹子，天上麟儿。", "画堂人物熙熙。", "会簪履雍容举庆宜。", "看筮日礼宾，陈锺列俎，三加致祝，一献成仪。", "绿鬓貂蝉，朱颜豸角，早有君臣庆会期。", "荣冠带，看绶悬若若，印佩累累。"]'),
('song-ci-830','水调歌头','程节斋','宋','宋词','song-ci','水调歌头','[]','秋色正潇洒，佳气夜充闾。',114,'宋词/ci.song.18000.json','["秋色正潇洒，佳气夜充闾。", "人传好语，君家门左正垂弧。", "毕万从来有后，释氏果然抱送，丹穴凤生雏。", "未作汤饼客，先写弄獐书。", "参军妇，贤相敌，古来无。", "锺奇毓秀，应是积善庆之馀。", "想见珠庭玉角，表表出群英物，我已预知渠。", "他日容相顾，啼看定何如。"]'),
('song-ci-831','沁园春','程节斋','宋','宋词','song-ci','沁园春','[]','自古人言，庆在子孙，端有由来。',138,'宋词/ci.song.18000.json','["自古人言，庆在子孙，端有由来。", "看长庚孕李，昴星佐汉，福从人召，瑞自天开。", "曾忆当年，乃翁熊梦，岂在区区春祀禖。", "祗凭个、仁心积累，厚德栽培。", "天工信巧安排。", "试说与君当一笑哉。", "记年时此际，嗷嗷万口，俾之粒食，活及婴孩。", "岁始星周，事还好在，故遣麒麟出此胎。", "何须问，是兴宗必矣，业广基恢。"]'),
('song-ci-832','沁园春','程节斋','宋','宋词','song-ci','沁园春','[]','三百篇诗，三十六篇，以祈寿言。',139,'宋词/ci.song.18000.json','["三百篇诗，三十六篇，以祈寿言。", "惟上天所佑，锡之君子，中心岂弟，盖有仁存。", "允矣我公，韦平世胄，学问于兹有本原。", "临民处，看精神秋彻，气宇春温。", "由来淑景中分。", "第一日桑弧挂左门。", "是赋受不凡，仁而宜寿，笑渠谄子，徒费辞繁。", "命匪在天，算非由数，我只把公心地论。", "从今去，管亟登槐棘，福遍乾坤。"]'),
('song-ci-833','木兰花慢','程节斋','宋','宋词','song-ci','木兰花慢','[]','西风吹昨梦，直飞上、广寒宫。',122,'宋词/ci.song.18000.json','["西风吹昨梦，直飞上、广寒宫。", "见绛节霓旌，常娥延伫，玉立双童。", "殷勤桂枝分付，却为言、当日有仙翁。", "谪堕人间几载，只今恰挂桑蓬。", "佳音未返碧楼空。", "青鸟耗难通。", "闻洞府已成，南州占断，皓月光风。", "前期十日佳席，倩一言、为写此清衷。", "三岛十洲佳致，奈何携近尘笼。"]'),
('song-ci-834','水调歌・水调','程节斋','宋','宋词','song-ci','水调歌・水调','[]','养气兼养勇，岂不丈夫哉。',114,'宋词/ci.song.18000.json','["养气兼养勇，岂不丈夫哉。", "何人刚欲斗力，谩向此间来。", "莫论施身文绣，看取兼人胆谅，胸次尽嵬嵬。", "独步登坛后，诸子尽舆台。", "笑渠侬，身贲育，伎婴孩。", "虚娇自恃，未识金德木鸡才。", "始也旁观退听，少则直前交臂，智与力俱摧。", "世有赏音者，为唱凯歌回。"]'),
('song-ci-835','水调歌・水调','程节斋','宋','宋词','song-ci','水调歌・水调','[]','都尉部千弩，旧事汉材官。',114,'宋词/ci.song.18000.json','["都尉部千弩，旧事汉材官。", "连拳一臂三石，夜半破阴山。", "曾使中有扪足，造次摧坚挫锐，分白辱宠涓。", "省括一机耳，人未识黄间。", "锦为标，虽有戏，技为难。", "疾飞两箭，兄弟齐夺姓名还。", "虎帐有筹第一，龙榜预占双捷，底事足荣观。", "未数蹶张辈，容易立朝端。"]'),
('song-ci-836','步蟾宫','张仲殊','宋','宋词','song-ci','步蟾宫','[]','笙歌喜庆争催晓。',72,'宋词/ci.song.18000.json','["笙歌喜庆争催晓。", "篆烟舞、龙鸾缥缈。", "香罗上、不画寿仙人，献一段、长生寿草。", "一心一意同欢笑。", "两心事、卒难得了。", "教传语、天上太白星，剩借取、几千年好。"]'),
('song-ci-837','好事近','吴氏2','宋','宋词','song-ci','好事近','[]','腊近渐知春，已有早梅堪折。',53,'宋词/ci.song.18000.json','["腊近渐知春，已有早梅堪折。", "况是诞辰佳宴，拥笙簧罗列。", "玉杯休惜十分斟，金炉更频爇。", "连理愿同千岁。", "看蟠桃重结。"]'),
('song-ci-838','贺新凉・贺新郎','吴编修','宋','宋词','song-ci','贺新凉・贺新郎','[]','出处男儿事。',142,'宋词/ci.song.18000.json','["出处男儿事。", "甚从前、说著渊明，放高头地。", "点检柴桑无剩粟，未肯低头为米。", "算此事、非难非易。", "三十年间如昨日，秀才瞒、撰到专城贵。", "饱共暖，已不翅。", "旁人问我归耶未。", "数痴年、平头六十，更须三岁。", "把似如今高一著，更好闻鸡禁市。", "总不似、长伸脚睡。", "六月荷风芗州路，北螺山、别是般滋味。", "今不去，视江水。"]'),
('song-ci-839','八声甘州','吴编修','宋','宋词','song-ci','八声甘州','[]','系酒船、夜入古江楼，浑莫辨西东。',118,'宋词/ci.song.18000.json','["系酒船、夜入古江楼，浑莫辨西东。", "叹从前眼底，一丁不识，四海曾空。", "老去休休莫莫，谁识旧元龙。", "尚解被襟去，赋大王雄。", "回首演仙高处，问赤松无恙，舍子何从。", "便不然学稼，犹有相牛翁。", "小婆娑、东家故舍，也著侬、四下二之中。", "芗州外溪风山月，鸥鹭盟同。"]'),
('song-ci-840','摸鱼儿','吴编修','宋','宋词','song-ci','摸鱼儿','[]','予何人、此何时节，驾言我欲行志。',140,'宋词/ci.song.18000.json','["予何人、此何时节，驾言我欲行志。", "青原煮豆然萁后，谁豢龙蛇赤子。", "心为碎。", "宽底是、翻疑又怕严底是。", "吾方左计。", "冷眼别人看，畏首畏尾，身复尚馀几。", "陶元亮，自古真奇男子。", "督邮尚若人耳。", "秋风一曲柴桑路，新秫炊香正美。", "黄鹄起。", "见说道、山光潭影皆欢喜。", "晴窗静倚。", "还我向来高，仙人羽客，别有一天地。"]'),
('song-ci-841','念奴娇','赵龙图','宋','宋词','song-ci','念奴娇','[]','吾今老矣。',120,'宋词/ci.song.18000.json','["吾今老矣。", "好归来、了取青山活计。", "甲子一周馀半纪，谙尽人间物理。", "婚嫁随缘，田舍粗给，知足生惭愧。", "心田安逸，自然绰有馀地。", "还是初度来临，葛巾野服，不减貂蝉贵。", "门外风波烟浪恶，我已收心无累。", "弟劝兄酬，儿歌女舞，落得醺醺醉。", "满堂一笑，大家百二十岁。"]'),
('song-ci-842','沁园春','竹林亭长','宋','宋词','song-ci','沁园春','[]','自笑生身，历事以来，垂六十年。',139,'宋词/ci.song.18000.json','["自笑生身，历事以来，垂六十年。", "今浮湛闾里，半非识面，交游朋友，各色华颠。", "富贵不来，少年已去，空见悠悠岁月迁。", "虽然是，只壮心一点，犹自依然。", "新阳又长天边。", "人指似山间诗酒仙。", "算胸次崔嵬，不胜百榼，笔端枯槁，难足千篇。", "隐几杖藜，相耕听诵，聊看诸郎相后先。", "馀何□，但读书煮茗，日晏高眠。"]'),
('song-ci-843','满庭芳','杨樵云','宋','宋词','song-ci','满庭芳','[]','只道空烟，又疑流水，依依却是行云。',118,'宋词/ci.song.18000.json','["只道空烟，又疑流水，依依却是行云。", "了然相对，又是梦纷纭。", "半面春风图画，黄金在、难铸昭君。", "溪桥断，梅花晴雪，端的白三分。", "真真。", "难唤醒，三年抽藕，织得榴裙。", "甚徘徊窥镜，交翼鸾文。", "一片飞花来去，并刀快、翦取晴纹。", "无情处，分明著眼，强半带春醺。"]'),
('song-ci-844','水龙吟','杨樵云','宋','宋词','song-ci','水龙吟','[]','多情不在分明，绣窗日日花阴午。',127,'宋词/ci.song.18000.json','["多情不在分明，绣窗日日花阴午。", "依依云絮，溶溶香雪，觑他寻路。", "一滴东风，怎生消得，翠苞红栩。", "被疏钟敲断，流莺唤起，但长记、弓弯舞。", "定是相思入骨，到如今、月痕同醉。", "教人枉了，若还真个，匆匆如此。", "全未惺松，缬纹生眼，胡床犹据。", "算从前、总是无凭，待说与、如何寄。"]'),
('song-ci-845','小楼连苑・水龙吟','杨樵云','宋','宋词','song-ci','小楼连苑・水龙吟','[]','一枝斜堕墙腰，向人颤袅如相媚。',126,'宋词/ci.song.18000.json','["一枝斜堕墙腰，向人颤袅如相媚。", "是谁翦取，断云零玉，轻轻妆缀。", "不是幽人，如何能到，水边沙际。", "又匆匆过了，春风半面，尽长把、重门闭。", "只管相思成梦，道无情、又关乡意。", "苍苔半亩，如今已是，鹿胎田地。", "甚欲追陪，却嫌花下，翠环解语。", "待何时月转，幽房醉了，不教归去。"]'),
('song-ci-846','木兰花慢','刘应雄','宋','宋词','song-ci','木兰花慢','[]','梅妆堪点额，觉残雪、未全消。',124,'宋词/ci.song.18000.json','["梅妆堪点额，觉残雪、未全消。", "忽春递南枝，小窗明透，渐褪寒骄。", "天公似怜人意，便挽回、和气做元宵。", "太守公家事了，何妨银烛高烧。", "旋开铁锁粲星桥。", "快灯市、客相邀。", "且同乐时平，唱弹弦索，对舞纤腰。", "传柑记陪佳宴，待说来、须更换金貂。", "只恐出关人早，鸡鸣又报趣朝。"]'),
('song-ci-847','锁窗寒・琐寒窗','曾隶','宋','宋词','song-ci','锁窗寒・琐寒窗','[]','绣额云横，银钩月小，绿杨庭院。',122,'宋词/ci.song.18000.json','["绣额云横，银钩月小，绿杨庭院。", "疏明满幅，永昼未忺高卷。", "爱空纹、巧匀曲波，弄晴日色花阴转。", "任筛金影碎，轻敲檐玉，碍双飞燕。", "凝见。", "窗留篆影，六曲雕阑，翠深绛浅。", "香风暗度，不隔娇松莺啭。", "似无情、重雾下垂，嫩桃想像添笑脸。", "望瑶阶、窣地双鸳，注盻金莲远。"]'),
('song-ci-848','解连环','黄水村','宋','宋词','song-ci','解连环','[]','凤楼倚倦。',128,'宋词/ci.song.18000.json','["凤楼倚倦。", "正海棠睡足，锦香衾软。", "似不似、雾阁云窗，拥绝妙灵君，霎时曾见。", "屏里吴山，又依约、兽环半掩。", "到教人觑了，非假非真，一种春怨。", "游丝落花满院。", "料当时、错怪杏梁归燕。", "记得栩栩多情，似蝴蝶飞来，扑翻轻扇。", "偷眼帘帷，早不见、画眉人面。", "但凝红生半脸，枕痕一线。"]'),
('song-ci-849','霓裳中序第一','姜个翁','宋','宋词','song-ci','霓裳中序第一','[]','园林罢组织。',125,'宋词/ci.song.18000.json','["园林罢组织。", "树树东风翠云滴。", "草满旧家行迹。", "时听得声声，晓莺如觅。", "愁红半湿。", "煞憔悴、墙根堪惜。", "可念我、飘零如此，一地送岑寂。", "龟石。", "当年第一。", "也似老、人间风日。", "馀葩选甚颜色。", "羞拈江南，断肠词笔。", "留春浑未得。", "翻些入、啼鹃夜泣。", "清江晚，绿杨归思，隔岸数峰出。"]'),
('song-ci-850','满江红','彭芳远','宋','宋词','song-ci','满江红','[]','愁满关山，又吹得、芦花雪深。',115,'宋词/ci.song.18000.json','["愁满关山，又吹得、芦花雪深。", "西楼外、天低水涌，龙挟秋吟。", "回首人间无此曲，数峰江上落馀音。", "似断云、飞絮两悠悠，何处寻。", "江南路，晴又阴，声韵改，泪盈襟。", "自中郎去后，羽泛商沈。", "牛背斜阳添别恨，鸾胶秋月续琴心。", "待醉骑、黄鹤度苍寒，霜满林。"]'),
('song-ci-851','满江红','戴山隐','宋','宋词','song-ci','满江红','[]','醉倚江楼，长空外、行云遥驻。',112,'宋词/ci.song.18000.json','["醉倚江楼，长空外、行云遥驻。", "甚凄凉孤吹，含商引羽。", "薄夜冷侵沙浦雁，老龙吟彻寒潭雨。", "蓦凉飚、一阵卷潮来，惊飞去。", "重欲听，知何处。", "谁为我，胡床据。", "谩寻寻觅觅，凝情如许。", "旧日山阳空有恨，杏花明月今谁赋。", "恐凭阑、人有爱梅心，空愁伫。"]'),
('song-ci-852','摸鱼儿','李裕翁','宋','宋词','song-ci','摸鱼儿','[]','计江南、许多风景，繁华只在晴昼。',140,'宋词/ci.song.18000.json','["计江南、许多风景，繁华只在晴昼。", "些儿淡沲冲融意，到处粘花著柳。", "疏雨后。", "更艳艳绵绵，泼眼浓如酒。", "飞浮宇宙。", "但借日浮香，随烟著物，巧笔画难就。", "惆怅处，曾记苏堤携手。", "十年惊觉回首。", "苍埃霁景成阴晦，湖水湖烟依旧。", "凝望久。", "问燕燕莺莺，识此年华否。", "长门别有。", "脉脉断肠人，柔情荡漾，长是为伊瘦。"]'),
('song-ci-853','忆旧游','龙端是','宋','宋词','song-ci','忆旧游','[]','问南楼月色，十载相疏，何似今宵。',124,'宋词/ci.song.18000.json','["问南楼月色，十载相疏，何似今宵。", "旧雨菰蒲国，想波光雁影，远撼沅潇。", "拟苏堤上杨柳，烟碧为谁摇。", "叹庾扇尘深，胡床梦浅，翠减香销。", "迢迢。", "谩回首，记酹酒江山，曾共金镳。", "暮色沈西垒，几狂朋来往，舟叶招招。", "浩歌拍手归去，风月两长桥。", "算此会何时，刘郎去后多嫩桃。"]'),
('song-ci-854','齐天乐','萧东父','宋','宋词','song-ci','齐天乐','[]','扇鸾收影惊秋晚，梧桐又供疏雨。',123,'宋词/ci.song.18000.json','["扇鸾收影惊秋晚，梧桐又供疏雨。", "翠箔凉多，绣囊香减，陡觉簟冰如许。", "温存谁与。", "更禁得荒苔，露蛩相诉。", "恨结愁萦，风刀难翦几千缕。", "闲思前事易远，怅旧欢无据，月堕湘浦。", "软玉分裯，腻云侵枕，犹忆喷兰低语。", "如今最苦。", "甚怕见灯昏，梦游间阻。", "怨杀娇痴，绿窗还嚏否。"]'),
('song-ci-855','昭君怨','王从叔','宋','宋词','song-ci','昭君怨','[]','门外春风几度。',48,'宋词/ci.song.18000.json','["门外春风几度。", "马上行人何处。", "休更卷朱帘。", "草连天。", "立尽海棠花月。", "飞到荼䕷香雪。", "莫怪梦难成。", "梦无凭。"]'),
('song-ci-856','阮郎归','王从叔','宋','宋词','song-ci','阮郎归','[]','风中柳絮水中萍。',56,'宋词/ci.song.18000.json','["风中柳絮水中萍。", "聚散两无情。", "斜阳路上短长亭。", "今朝第几程。", "何限事，可怜生。", "能消几度春。", "别时言语总伤心。", "何曾一字真。"]'),
('song-ci-857','南柯子・南歌子','王从叔','宋','宋词','song-ci','南柯子・南歌子','[]','碧树留云湿，青山似笠低。',62,'宋词/ci.song.18000.json','["碧树留云湿，青山似笠低。", "鹧鸪啼罢竹鸡啼。", "不晓天天何意、要梅肥。", "昨日穿新葛，今朝御夹衣。", "思家怀抱政难为。", "只恐归来憔悴、却羞归。"]'),
('song-ci-858','浣溪沙','王从叔','宋','宋词','song-ci','浣溪沙','[]','水月精神玉雪胎。',48,'宋词/ci.song.18000.json','["水月精神玉雪胎。", "乾坤清气化生来。", "断桥流水领春回。", "昨夜醉眠苔上石，天香冉冉下瑶台。", "起来窗外见花开。"]'),
('song-ci-859','秋蕊香','王从叔','宋','宋词','song-ci','秋蕊香','[]','薄薄罗衣乍暖，红入酒痕潮面。',56,'宋词/ci.song.18000.json','["薄薄罗衣乍暖，红入酒痕潮面。", "絮花舞倦带娇眼。", "昨夜平堤水浅。", "故人信断风筝线。", "误归燕。", "梦魂不怕山路远。", "无奈棋声隔院。"]'),
('song-ci-860','凤凰台上忆吹箫','吴元可','宋','宋词','song-ci','凤凰台上忆吹箫','[]','更不成愁，何曾是醉，豆花雨后轻阴。',119,'宋词/ci.song.18000.json','["更不成愁，何曾是醉，豆花雨后轻阴。", "似此心情自可，多了闲吟。", "秋在西楼西畔，秋较浅、不似情深。", "夜来月，为谁瘦小，尘镜羞临。", "弹筝，旧家伴侣，记雁啼秋水，下指成音。", "听未稳、当时自误，又况如今。", "那是柔肠易断，人间事、独此难禁。", "雕笼近，数声别似春禽。"]'),
('song-ci-861','杨州慢','吴元可','宋','宋词','song-ci','杨州慢','[]','露叶犹青，岩花迟动，幽幽未似秋阴。',120,'宋词/ci.song.18000.json','["露叶犹青，岩花迟动，幽幽未似秋阴。", "似梅风带溽，吹度长林。", "记当日、西廊共月，小屏轻扇，人语凉深。", "对清觞，醉笑醒颦，何似如今。", "临高欲赋，甚年来、渐减狂心。", "为谁倚多才，难凭易感，早付销沈。", "解事张郎风致，鲈鱼好、归听吴音。", "又夜阑闻笛，故人忽到幽襟。"]'),
('song-ci-862','采桑子','吴元可','宋','宋词','song-ci','采桑子','[]','江南二月春深浅，芳草青时，燕子来迟。',52,'宋词/ci.song.18000.json','["江南二月春深浅，芳草青时，燕子来迟。", "翦翦轻寒不满衣。", "清宵欲寐还无寐，顾影颦眉。", "整带心思。", "一样东风两样吹。"]'),
('song-ci-863','浪淘沙','吴元可','宋','宋词','song-ci','浪淘沙','[]','浅约未曾来。',64,'宋词/ci.song.18000.json','["浅约未曾来。", "一迳苍苔。", "缃桃无数棘花开。", "怪得闭门机杼静，挑菜初回。", "幽树鸟声催。", "欲去徘徊。", "□□别久易相猜。", "幽绪一晴无处著，戏打青梅。"]'),
('song-ci-864','永遇乐','李太古','宋','宋词','song-ci','永遇乐','[]','玉砌标鲜，雪园风致，似曾相识。',126,'宋词/ci.song.18000.json','["玉砌标鲜，雪园风致，似曾相识。", "蝉锦霞香，乌丝云湿，吹渴蟾蜍滴。", "青青白白，关关滑滑，寒损铢衣狂客。", "尽声声、不如归去，归也怎生归得。", "含桃红小，香芹翠软，惆怅宜城山色。", "百折浮岚，几湾流水，那一些儿直。", "落花情味，露花魂梦，蒲花消息。", "抚纤眉，织乌西下，为君凝碧。"]'),
('song-ci-865','恋绣衾','李太古','宋','宋词','song-ci','恋绣衾','[]','桔花风信满院香。',68,'宋词/ci.song.18000.json','["桔花风信满院香。", "摘青梅、犹自怕尝。", "向绿密、红疏处，喜相逢、飞下一双。", "堪怜堪惜还堪爱，唤青衣、推上绣窗。", "暗记得、凭肩语，对菱花、啼损晚妆。"]'),
('song-ci-866','南歌子','李太古','宋','宋词','song-ci','南歌子','[]','月下秦淮海，花前晏小山。',62,'宋词/ci.song.18000.json','["月下秦淮海，花前晏小山。", "二仙仙去几时还。", "留得月魂花魄、在人间。", "河汉流旌节，天风袅珮环。", "满空香雾湿云鬟。", "何处一声横笛、杏花寒。"]'),
('song-ci-867','虞美人','李太古','宋','宋词','song-ci','虞美人','[]','西风海色秋无际。',66,'宋词/ci.song.18000.json','["西风海色秋无际。", "双泪如铅水。", "白羊成队梦初平。", "挂杖敲云、云外晓鸿惊。", "小琼闲抱银筝笑。", "问有芳卿否。", "玉书分付莫开封。", "明日人间临水、拾流红。"]'),
('song-ci-868','卜算子','李太古','宋','宋词','song-ci','卜算子','[]','尽道是伤春，不似悲秋怨。',56,'宋词/ci.song.18000.json','["尽道是伤春，不似悲秋怨。", "门外分明见远山，人不见，空肠断。", "朝来一霎晴，薄暮西风远。", "却忆黄花小雨声，误落下、三四点。"]'),
('song-ci-869','西湖月','黄子行','宋','宋词','song-ci','西湖月','[]','湖光冷浸玻璃，荡一饷薰风，小舟如叶。',124,'宋词/ci.song.18000.json','["湖光冷浸玻璃，荡一饷薰风，小舟如叶。", "藕花十丈，云梳雾洗，翠娇红怯。", "壶觞围坐处，正酒醁吹波红映颊。", "尚记得、玉臂生凉，不放汗香轻浃。", "殢人小摘墙榴，为碎掐猩红，细认裙褶。", "旧游如梦，新愁似织，泪珠盈睫。", "秋娘风味在，怎得对银釭生笑靥。", "消瘦沈约诗腰，彷佛堪捻。"]'),
('song-ci-870','西湖月','黄子行','宋','宋词','song-ci','西湖月','[]','初弦月挂林梢，又一番西园，探梅消息。',126,'宋词/ci.song.18000.json','["初弦月挂林梢，又一番西园，探梅消息。", "粉墙朱户，苔枝露蕊，淡匀轻饰。", "玉儿应有恨，为怅望东昏相记忆。", "便解珮、飞入云阶，长伴此花倾国。", "诗腰瘦损刘郎，记立马攀条，倚阑横笛。", "少年风味，拈花弄蕊，爱香怜色。", "扬州何逊在，试点染吟笺留醉墨。", "谩赢得、疏影寒窗，夜深孤寂。"]'),
('song-ci-871','贺新郎','黄子行','宋','宋词','song-ci','贺新郎','[]','开遍寒梅萼。',142,'宋词/ci.song.18000.json','["开遍寒梅萼。", "正东皇、排酥砌玉，幻成楼阁。", "十万琼琚仙女队，来趁春光游乐。", "向醉里、玉簪轻落。", "零乱不知何处去，甚人间、一夜东风恶。", "吹起在，画檐角。", "参差向晓森如削。", "似吴姬、妆残粉指，向人垂著。", "好似西园春笋瘦，红锦䙀儿乍剥。", "且莫遣、儿童敲却。", "拟办羔儿香瓮酒，唤刘叉、来醉尊前约。", "吟好句，再描摸。"]'),
('song-ci-872','满江红','黄子行','宋','宋词','song-ci','满江红','[]','津鼓匆匆，犹记得、故人相送。',115,'宋词/ci.song.18000.json','["津鼓匆匆，犹记得、故人相送。", "春江上、鸟啼花影，马嘶香鞚。", "情逐阳关金缕断，泪和杨柳春丝重。", "算别来、几度月明时，相思梦。", "山万垒，愁眉耸。", "春一点，归心动。", "问风俦月侣，有谁游从。", "百里家山明日到，一尊芳酒今宵共。", "任楼头、吹尽五更风，梅花弄。"]'),
('song-ci-873','花心动','黄子行','宋','宋词','song-ci','花心动','[]','谁倚青楼，把谪仙长笛，数声吹裂。',127,'宋词/ci.song.18000.json','["谁倚青楼，把谪仙长笛，数声吹裂。", "一片乍零，千点还飞，正是雨晴时节。", "水晶帘外东风起，卷不尽、满庭香雪，画阑小，斜铺乱飐，翠苔成缬。", "袅袅馀香未歇。", "空怅望音尘，两眉愁切。", "翠袖泪乾，粉额妆寒，此恨有谁同说。", "江南春信无痕迹，馀情在、冷烟残月。", "梦魂远，兰灯伴人易灭。"]'),
('song-ci-874','小重山','黄子行','宋','宋词','song-ci','小重山','[]','一点斜阳红欲滴。',70,'宋词/ci.song.18000.json','["一点斜阳红欲滴。", "白鸥飞不尽，楚天碧。", "渔歌声断晚风急。", "搅芦花，飞雪满林湿。", "孤馆百忧集。", "家山千里远，梦难觅。", "江湖风月好休拾。", "故溪云，深处著蓑笠。"]'),
('song-ci-875','齐天乐','龙紫蓬','宋','宋词','song-ci','齐天乐','[]','雨帘云栋重寻处，青红半空飞去。',123,'宋词/ci.song.18000.json','["雨帘云栋重寻处，青红半空飞去。", "槛影侵鸥，檐光送雁，摇荡秋容千里。", "歌珠舞翠。", "怎禁得无情，一江流水。", "可是西山，半眉新绿向人觑。", "千年留下剩赏，尽登临无限，须付才思。", "坏堞闲愁，危樯往恨，欲拍阑干无路。", "新碑旧记。", "更今古匆匆，一番兴废。", "立尽斜阳，共谁评半语。"]'),
('song-ci-876','渡江云','萧允之','宋','宋词','song-ci','渡江云','[]','蔷薇开欲谢，峭寒渐少，轩槛俯晴沙。',124,'宋词/ci.song.18000.json','["蔷薇开欲谢，峭寒渐少，轩槛俯晴沙。", "先来愁未了，又听一声，新阕落渔家。", "徘徊伫立，似玉笛、三弄昭华。", "春昼长、暗怀谁写，戏墨乱翻鸦。", "吁嗟。", "诗情犹隽，酒兴偏豪，记南楼月下。", "曾共乐、沈烟绮席，烛影窗纱。", "秾香秀色知何处，甚忘却、堤柳汀葭。", "空惆怅，无人共采苹花。"]'),
('song-ci-877','满江红','萧允之','宋','宋词','song-ci','满江红','[]','冷逼疏帘，浑不似、今春寂寞。',115,'宋词/ci.song.18000.json','["冷逼疏帘，浑不似、今春寂寞。", "风雨横，赏心欢事，总如云薄。", "柳眼花须空点缀，莺情蝶思应萧索。", "但绕庭、流水碧潺潺，车音邈。", "怀往事，孤素约。", "酒未饮，愁先觉。", "甚中年滋味，共谁商略。", "芳草易添闲客恨，垂杨难系行人脚。", "谩几回、吟遍夕阳红，阑干角。"]'),
('song-ci-878','琐窗寒','萧允之','宋','宋词','song-ci','琐窗寒','[]','细雨收尘，轻寒弄日，柳丝掠道。',121,'宋词/ci.song.18000.json','["细雨收尘，轻寒弄日，柳丝掠道。", "桃边杏处，犹记玉骢曾到。", "对东风、回首旧游，香销艳歇无音耗。", "怅佳人、有约难来，绿遍满庭芳草。", "愁抱。", "沈吟久，翠珥金钿，为何人好。", "回文细字，尘暗当年纤缟。", "倚阑干、斜阳又西，欢期易失春易老。", "待何时、再觅珍丛，共把清尊倒。"]'),
('song-ci-879','蝶恋花','萧允之','宋','宋词','song-ci','蝶恋花','[]','十幅归帆风力满。',70,'宋词/ci.song.18000.json','["十幅归帆风力满。", "记得来时，买酒朱桥畔。", "远树平芜空目断。", "乱山惟见斜阳半。", "谁把新声翻玉管。", "吹过沧洲，多少伤春怨。", "已是客怀如絮乱。", "画楼人更回头看。"]'),
('song-ci-880','虞美人','萧允之','宋','宋词','song-ci','虞美人','[]','朱楼曾记回娇盼。',66,'宋词/ci.song.18000.json','["朱楼曾记回娇盼。", "满坐春风转。", "红潮生面酒微醺。", "一曲清歌留往、半窗云。", "大都咫尺无消息。", "望断青鸾翼。", "夜长香短烛花红。", "多少思量只在、雨声中。"]'),
('song-ci-881','点绛唇','萧允之','宋','宋词','song-ci','点绛唇','[]','花径相逢，眼期心诺情如昨。',50,'宋词/ci.song.18000.json','["花径相逢，眼期心诺情如昨。", "怕人疑著。", "佯弄秋千索。", "知有而今，何似留初莫。", "愁难托。", "雨铃风铎。", "梦断灯花落。"]'),
('song-ci-882','洞仙歌','段宏章','宋','宋词','song-ci','洞仙歌','[]','一庭晴雪，了东风孤注。',100,'宋词/ci.song.18000.json','["一庭晴雪，了东风孤注。", "睡起浓香占窗户。", "对翠蛟盘雨，白凤迎风，知谁见、愁与飞红流处。", "想飞琼弄玉，共驾苍烟，欲向人间挽春住。", "清泪满檀心，如此江山，都付与、斜阳杜宇。", "是曾约梅花带春来，又自共梨花，送春归去。"]'),
('song-ci-883','满庭芳','刘贵翁','宋','宋词','song-ci','满庭芳','[]','宫鸟西飞，杨花北去，春风飘向伊谁。',118,'宋词/ci.song.18000.json','["宫鸟西飞，杨花北去，春风飘向伊谁。", "盈盈小小，轻薄不堪肥。", "天付风流到骨，消不尽、流落青池。", "谁知道，踏歌朝暮，痴绝待渠归。", "愔愔，春似酒，日痕生绀，裙色明漪。", "笑东家西沼，到处依依。", "同是东风种得，独无据，飘泊年时。", "青梅落，水光帘影，小翠立横枝。"]'),
('song-ci-884','水龙吟','黄霁宇','宋','宋词','song-ci','水龙吟','[]','丽华一握青丝，金珠粟粟香环里。',126,'宋词/ci.song.18000.json','["丽华一握青丝，金珠粟粟香环里。", "春窥绮阁，新妆风舞，铢衣如碎。", "翠凤苍虬，骑来下界，蝶惊蜂避。", "甚三生富贵，垂垂晓露，犹凝满身珠翠。", "谁共那人结发，问何时、蹇修为理。", "对花一笑，香茸易翦，碎金难缀。", "半点芳心，乱愁如织，缕丝传意。", "倩东皇、拂拭新条，更与作、来生计。"]'),
('song-ci-885','齐天乐','刘天迪','宋','宋词','song-ci','齐天乐','[]','瑞麟香软飞瑶席，吟仙笑陪欢宴。',123,'宋词/ci.song.18000.json','["瑞麟香软飞瑶席，吟仙笑陪欢宴。", "桐影吹香，梅阴弄碧，一味微凉堪荐。", "停杯缓劝。", "记罗帕求诗，琵琶遮面。", "十载扬州，梦回前事楚云远。", "人生总是逆旅，但相逢一笑，如此何限。", "采石宫袍，沈香醉笔，何似轻衫小扇。", "流年暗换。", "甚新雨情怀，故园心眼。", "明日西江，斜阳帆影转。"]'),
('song-ci-886','一萼红','刘天迪','宋','宋词','song-ci','一萼红','[]','拥孤衾，正朔风凄紧，毡帐夜生寒。',133,'宋词/ci.song.18000.json','["拥孤衾，正朔风凄紧，毡帐夜生寒。", "春梦无凭，秋期又误，迢递烟水云山。", "断肠处、黄茅瘴雨，恨骢马、憔悴只空还。", "揉翠盟孤，啼红怨切，暗老朱颜。", "堪叹扬州十里，甚倡条冶叶，不省春残。", "蔡琰悲笳，昭君怨曲，何预当日悲欢。", "谩赢得、西邻倦客，空惆怅、今古上眉端。", "梦破梅花，角声又报春阑。"]'),
('song-ci-887','虞美人','刘天迪','宋','宋词','song-ci','虞美人','[]','子规解劝春归去。',66,'宋词/ci.song.18000.json','["子规解劝春归去。", "春亦无心住。", "江南风景正堪怜。", "到得而今不去、待何年。", "无端往事萦心曲。", "两鬓先惊绿。", "蔷薇花发望春归。", "谢了蔷薇、又见楝花飞。"]'),
('song-ci-888','蝶恋花','刘天迪','宋','宋词','song-ci','蝶恋花','[]','日暮杨花飞乱雪。',70,'宋词/ci.song.18000.json','["日暮杨花飞乱雪。", "宝镜慵拈，强整双鸳结。", "烧罢夜香愁万叠。", "穿花暗避阶前月。", "凤尾罗衾寒尚怯，却悔当时，容易成分别。", "闷对枕鸾谁共说。", "柔情一点蔷薇血。"]'),
('song-ci-889','凤栖梧・蝶恋花','刘天迪','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','一翦晴波娇欲溜。',69,'宋词/ci.song.18000.json','["一翦晴波娇欲溜。", "绿怨红愁，长为春风瘦。", "舞罢金杯眉黛皱。", "背人倦倚晴窗绣。", "脸晕潮生微带酒。", "催唱新词，不应频摇手。", "闲把琶调未就。", "羞郎却又垂红袖。"]'),
('song-ci-890','点绛唇','刘天迪','宋','宋词','song-ci','点绛唇','[]','一笑相逢，依稀似是桃根旧。',50,'宋词/ci.song.18000.json','["一笑相逢，依稀似是桃根旧。", "娇波频溜。", "悄可灵犀透。", "扶过危桥，轻引纤纤手。", "频回首。", "何时还又。", "微月黄昏后。"]'),
('song-ci-891','满江红','张半湖','宋','宋词','song-ci','满江红','[]','新绿池塘，一两点、荷花微雨。',115,'宋词/ci.song.18000.json','["新绿池塘，一两点、荷花微雨。", "人正静，桐阴竹影，半侵庭户。", "敧枕未圆蝴蝶梦，隔窗时听幽禽语。", "卷沙帏、随意理琴丝，黄金缕。", "鲛绡扇，轻轻举。", "龙涎饼，微微炷。", "向水晶宫里，坐消袢暑。", "剥啄谁敲棋子响，莺儿林里惊飞去。", "最好是、活水瀹新茶，醒春醑。"]'),
('song-ci-892','扫花游・扫地游','张半湖','宋','宋词','song-ci','扫花游・扫地游','[]','柳丝曳绿，正豆雨初晴，水天朱夏。',117,'宋词/ci.song.18000.json','["柳丝曳绿，正豆雨初晴，水天朱夏。", "石榴绽也。", "看猩红万点，倚亭敧榭。", "锁闼深中，料想酒阑歌罢。", "日将下。", "是那处藕花，香胜沈麝。", "窗外风竹打。", "似戛玉敲金，送声潇洒。", "共观古画。", "唤石鼎烹茶，细商幽话。", "宝鸭烟消，天外新蟾低挂。", "凉无价。", "又丁东、数声檐马。"]'),
('song-ci-893','念奴娇','刘景翔','宋','宋词','song-ci','念奴娇','[]','甚情幻化，似流酥围暖，酣春娇寐。',120,'宋词/ci.song.18000.json','["甚情幻化，似流酥围暖，酣春娇寐。", "不数锦篝烘古篆，沁入屏山沈水。", "笑吐丁香，紫绡衬粉，房列还同蒂。", "翠球移影，媚人清晓风细。", "依约玉骨盈盈，小春暖逗，开到灯宵际。", "疑是九华仙梦冷，误落人间游戏。", "比雪情多，评梅香浅。", "三白还堪瑞。", "尘缘洗尽，醒来还又葱翠。"]'),
('song-ci-894','小重山','刘景翔','宋','宋词','song-ci','小重山','[]','山翠晴岚曲曲偎。',68,'宋词/ci.song.18000.json','["山翠晴岚曲曲偎。", "红香浮玉醉窝颓。", "不烦人筑避风台。", "潇湘路，随意自徘徊。", "春倦怕频催。", "琵琶私语近、问谁来。", "春风那隔锦云堆。", "梦中蝶，飞去又飞来。"]'),
('song-ci-895','玉楼春','刘景翔','宋','宋词','song-ci','玉楼春','[]','可怜又误江南景。',64,'宋词/ci.song.18000.json','["可怜又误江南景。", "雨腻风喧愁入暝。", "依稀碧玉水边魂，憔悴绿珠楼外影。", "点点随人飞远近。", "薄幸相逢情怎忍。", "年年三月化香尘，天上人间看梦醒。"]'),
('song-ci-896','如梦令','刘景翔','宋','宋词','song-ci','如梦令','[]','独立荷汀烟渚。',40,'宋词/ci.song.18000.json','["独立荷汀烟渚。", "一霎锦云香雨。", "似为我无情，惊起鸳鸯飞去。", "飞去。", "飞去。", "却在绿杨深处。"]'),
('song-ci-897','摸鱼儿','周伯阳','宋','宋词','song-ci','摸鱼儿','[]','又匆匆、月鞭露镫，梅花江上归路。',140,'宋词/ci.song.18000.json','["又匆匆、月鞭露镫，梅花江上归路。", "海图破碎来时线，何似彩衣低舞。", "风雪暮。", "正望断青山，一发云横处。", "浩歌独举。", "便想见迎门，牵衣儿女，总是旧眉妩。", "阳关曲，挥洒紫薇花露。", "妙音清远高古。", "经寒杨柳休轻折，摇动一溪霜雾。", "邯郸步。", "笑布袜青鞋，去住知何许。", "汀鸥沙鹭。", "若问我重来，明年有约，今日是前度。"]'),
('song-ci-898','春从天上来','周伯阳','宋','宋词','song-ci','春从天上来','[]','浩荡青冥。',126,'宋词/ci.song.18000.json','["浩荡青冥。", "正凉露如洗，万里虚明。", "鼓角悲健，秋入重城。", "彷佛石上三生。", "指蓬莱云路，渺何许、月冷风清。", "倚南楼、一声长笛，几点残星。", "西风旧年有约，听候蛩语夜，客里心惊。", "红树山深，翠苔门掩，想见露草疏萤。", "便乘风归去，阑干外、河汉西倾。", "笑淹留，划然孤啸，云白天青。"]'),
('song-ci-899','尉迟杯','尹公远','宋','宋词','song-ci','尉迟杯','[]','冰弦语。',129,'宋词/ci.song.18000.json','["冰弦语。", "在竹树、院落深深处。", "当年野草闲花，何许浮云飞絮。", "征鸿止止，纵汗漫、游人远回顾。", "迟琼楼、五色帘开，唤醒玄鹤飞舞。", "何事梦断湖山，尚九里松声，八月潮怒。", "三十年馀池台泪，应不为、花奴羯鼓。", "想天上、群仙老矣，甚比似、人间更愁苦。", "倩画阑、留住西风，莫教愁入云去。"]'),
('song-ci-900','齐天乐','尹公远','宋','宋词','song-ci','齐天乐','[]','江湖千里秋风客，翩然白云黄鹄。',123,'宋词/ci.song.18000.json','["江湖千里秋风客，翩然白云黄鹄。", "石鼎烟霏，篆书红湿，随处菊香泉绿。", "幅巾野服。", "尽扫叶开门，抱琴听瀑。", "何事蓬壶，归来独待海涛陆。", "卢鸿旧时隐处，想斜阳草树，水榭云屋。", "麈尾玄玄，笔花语语，剪尽雨窗残烛。", "黄庭误读。", "且东老留诗，采和歌曲。", "后日重寻，洞天三十六。"]'),
('song-ci-901','摸鱼儿','李天骥','宋','宋词','song-ci','摸鱼儿','[]','又何须、向明还灭，寒花点缀孤影。',140,'宋词/ci.song.18000.json','["又何须、向明还灭，寒花点缀孤影。", "玉龙度海吹鱼浪，烟淡宝钗横鬓。", "斜又整。", "是虫滴骊珠、两两相交颈。", "夜长人静。", "恁玉果低抛，金钱暗卜，此意有谁领。", "欢娱事，料想凭伊先应。", "帕绡新泪独凝。", "银篦未忍轻挑下，只恐暗风吹烬。", "重记省。", "怕莫是、明朝有个青鸾信。", "怎知无定。", "算只解窥人，人孤影只，成瘦又成病。"]'),
('song-ci-902','忆旧游','刘应几','宋','宋词','song-ci','忆旧游','[]','记铜驼载酒，翠陌吹箫，曾听相呼。',122,'宋词/ci.song.18000.json','["记铜驼载酒，翠陌吹箫，曾听相呼。", "不尽离离意，觉柔肠如剪，立马踟蹰。", "人生似此苍鬓，禁得几声疏。", "想怨入秋深，愁随天远，满目平芜。", "音书未曾寄，正人在燕台，忘却回车。", "奈菰蒲旧地，山空木落，霜老泉枯。", "月明仙掌何处，转首失栖乌。", "待说与云间，潇湘近日风卷湖。"]'),
('song-ci-903','木兰花慢','周孚先','宋','宋词','song-ci','木兰花慢','[]','访梅江路远，喜春在、剑川湄。',122,'宋词/ci.song.18000.json','["访梅江路远，喜春在、剑川湄。", "正雁碛云深，渔村笛晚，茸帽斜敧。", "旧游不堪回首，更文园、多病减腰围。", "惟有秋娘声价，风流仍似前时。", "依稀壁粉旧曾题。", "烟草半凄迷。", "叹单父台荒，黄公垆寂，难觅佳期。", "谁家歌楼催雪，遣夜来、风雨紧些儿。", "醉后唾壶敲缺，龙光摇动晴漪。"]'),
('song-ci-904','鹧鸪天','周孚先','宋','宋词','song-ci','鹧鸪天','[]','曾唱阳关送客时。',64,'宋词/ci.song.18000.json','["曾唱阳关送客时。", "临岐借酒话分离。", "如今酒被多情苦，却唱阳关去别伊。", "欢会远，渺难期。", "黄垆门掩昼阴迟。", "青楼更有痴儿女，谩忆胡姬捧劝词。"]'),
('song-ci-905','蝶恋花','周孚先','宋','宋词','song-ci','蝶恋花','[]','舟舣津亭何处树。',70,'宋词/ci.song.18000.json','["舟舣津亭何处树。", "晓起珑璁，回首迷烟雾。", "江上离人来又去。", "飘零只似风前絮。", "倦倚蓬窗谁共语。", "野草闲花，一一伤情绪。", "明日重来须记取。", "绿杨门巷深深处。"]'),
('song-ci-906','念奴娇','彭泰翁','宋','宋词','song-ci','念奴娇','[]','九华惊觉，又偷承雨露，羞匀春色。',120,'宋词/ci.song.18000.json','["九华惊觉，又偷承雨露，羞匀春色。", "岸蓼汀苹成色界，未必天香人识。", "粉涴脂凝，霜销雾薄，娇颤浑无力。", "黄昏月掩，山城那更闲笛。", "应是未了尘缘，重来迟暮，草草西风客。", "莺燕无情庭院悄，愁满阑干苔积。", "宫锦尊前，霓裳月下，梦亦无消息。", "嫣然一笑，江南如此风日。"]'),
('song-ci-907','忆旧游','彭泰翁','宋','宋词','song-ci','忆旧游','[]','玉环扶浅醉，翠袖笼寒，香汗初融。',124,'宋词/ci.song.18000.json','["玉环扶浅醉，翠袖笼寒，香汗初融。", "昨夜残妆在，最难胜珠络，都沁铅红。", "朝云低护深约，蜂蝶不知踪。", "奈燕子情多，斜飞轻触，泪洒羞容。", "重逢。", "记前度，解翦烛调笙，踏月鸣骢。", "风入人间远，待尘缘洗尽，飞珮凌空。", "丁宁为我留住，携酒寿东风。", "便花谱重修，高堂再赋疑梦中。"]'),
('song-ci-908','拜星月慢','彭泰翁','宋','宋词','song-ci','拜星月慢','[]','雾罥觚棱，尘侵团扇，恨满哀弹倦理。',123,'宋词/ci.song.18000.json','["雾罥觚棱，尘侵团扇，恨满哀弹倦理。", "控雨笼云，共闲情孤倚。", "敛娥黛、怕似流莺历历，惹得玉销琼碎。", "可惜阑干，但苔花沈穗。", "算天音、不入人间耳。", "何人谩、裛损青山泪。", "不是旧谱都忘，厌新腔娇脆。", "多生不得丹青意，重来又、花锁长门闭。", "到夜永、笙鹤归时，月明天似水。"]'),
('song-ci-909','水龙吟','曾允元','宋','宋词','song-ci','水龙吟','[]','日高深院无人，杨花扑帐春云暖。',126,'宋词/ci.song.18000.json','["日高深院无人，杨花扑帐春云暖。", "回文未就，停针不语，绣床倚遍。", "翠被笼香，绿鬟坠腻，伤春成怨。", "尽云山烟水，柔情一缕，又暗逐、金鞍远。", "鸾佩相逢甚处，似当年、刘郎仙苑。", "凭肩后约，画眉新巧，从来未惯。", "枕落钗声，帘开燕语，风流云散。", "甚依稀难记，人间天上，有缘重见。"]'),
('song-ci-910','月下笛','曾允元','宋','宋词','song-ci','月下笛','[]','又老杨花，浮萍点点，一溪春色。',123,'宋词/ci.song.18000.json','["又老杨花，浮萍点点，一溪春色。", "闲寻旧迹。", "认溪头、浣纱碛。", "柔条折尽成轻别，向空外、瑶簪一掷。", "算无情更苦，莺巢暗叶，啼破幽寂。", "凝立。", "阑干侧。", "记露饮东园，联镳西陌。", "容销鬓减，相逢应自难识。", "东风吹得愁似海，谩点染，空阶自碧。", "独归晚，解说心中事，月下短笛。"]'),
('song-ci-911','齐天乐','曾允元','宋','宋词','song-ci','齐天乐','[]','碧梧枝上占秋信，微闻雨声还惬。',123,'宋词/ci.song.18000.json','["碧梧枝上占秋信，微闻雨声还惬。", "虹影分晴，云光透晚，残日依依团箑。", "阑干一霎。", "又长笛归舟，乱鸦荒堞。", "两鬓西风，有人心事到红叶。", "娇莲相对欲语，奈莲茎有刺，愁不成折。", "天上欢期，人间巧意，今夜明河如雪。", "新宽带结。", "想宝篆频温，翠奁低揭。", "雾湿云鬟，浅妆深拜月。"]'),
('song-ci-912','点绛唇','曾允元','宋','宋词','song-ci','点绛唇','[]','一夜东风，枕边吹散愁多少。',50,'宋词/ci.song.18000.json','["一夜东风，枕边吹散愁多少。", "数声啼鸟。", "梦转纱窗晓。", "来是春初，去是春将老。", "长亭道。", "一般芳草。", "只有归时好。"]'),
('song-ci-913','沁园春','朱元夫','宋','宋词','song-ci','沁园春','[]','心上浮香，轩前度影，约久传梅。',139,'宋词/ci.song.18000.json','["心上浮香，轩前度影，约久传梅。", "奈月意风情，枝南枝北，云婚雨嫁，年去年来。", "几望溪桥，屡肥芳信，历尽冰霜春自回。", "朝来报，报梢头儿女，并蒂花开。", "佩环飞下妆台。", "喜今度佳期不用催。", "羡行李三千，金屏翠幄，仙姿第一，玉骨琼腮。", "雌蝶纷纷，雄蜂逐逐，争道工为使与媒。", "翁知麽，有西楼过雁，暗为徘徊。"]'),
('song-ci-914','壶中天・念奴娇','朱元夫','宋','宋词','song-ci','壶中天・念奴娇','[]','人生有酒，得闲处、便合开怀随意。',121,'宋词/ci.song.18000.json','["人生有酒，得闲处、便合开怀随意。", "况对寿、龟仙鹤舞，犹直壶天一醉。", "蚕麦江村，梅霖院落，立夏明朝是。", "樽前回首，去年四月十二。", "依旧洛里吟窝，华台书隐，心事无怀氏。", "偃鼠醯鸡空扰扰，海月天风谁寄。", "珠璧祯祥，斗牛光景，预可占斯世。", "先生出否，明年方六十岁。"]'),
('song-ci-915','沁园春','邵桂子','宋','宋词','song-ci','沁园春','[]','知是今年，一冬较暖，开遍梅花。',139,'宋词/ci.song.18000.json','["知是今年，一冬较暖，开遍梅花。", "有一朵妖娆，塘之东畔，东君爱惜，云幕低遮。", "小萼微红，香腮傅粉，把寿阳妆取自夸。", "谁知道，忽移来秀水，深处人家。", "清香扑透窗纱。", "渐仙李秾华无等差。", "这冰姿一样，玉颜双好，月明静夜，疏影横斜。", "传语曹林，须将止渴，结子今番早早些。", "梅自笑，嗔贺新郎曲，待拍红牙。"]'),
('song-ci-916','贺新郎','邵桂子','宋','宋词','song-ci','贺新郎','[]','新雨黄花路。',141,'宋词/ci.song.18000.json','["新雨黄花路。", "看清江、旌旗千骑，使君东去。", "万里归来城头角，吹彻家山旧处。", "惜洲鹭、留君不驻。", "白发遗民壶觞语，笑浣花邻里来襦裤。", "夸见早，恨来暮。", "故人只在山中住。", "记年时、肠断相望，天风海雨。", "满鬓星星华发少，君鬓尚今青否。", "休夸说、神仙官府。", "玉笥平生清入梦，会有时、乘兴携吾侣。", "就君醉，为君舞。"]'),
('song-ci-917','满江红','邵桂子','宋','宋词','song-ci','满江红','[]','离却京华，到这里、二千八百。',116,'宋词/ci.song.18000.json','["离却京华，到这里、二千八百。", "穷醋大、齐齐整整，岂无贷揭。", "随地平章花与柳，为天评品风和月。", "只留得、一管钝毛锥，一丸墨。", "初不是，丝绵帛。", "又不是，茶盐铁。", "更有苏州破砚，兔园旧册。", "一领征衣半尘土，两头箬笠几风雪。", "问栏头、直得几多钱，从头说。"]'),
('song-ci-918','百字令・念奴娇','邵桂子','宋','宋词','song-ci','百字令・念奴娇','[]','三年幕画，是小试相业，桐阴相谱。',120,'宋词/ci.song.18000.json','["三年幕画，是小试相业，桐阴相谱。", "协暂拥容心似佛，春在螺山螺浦。", "白玉无瑕，黄扉倚重，一府中流柱。", "箫然锦满，扁舟明日归去。", "此去南北才名，看青云隐驾，玉阶徐步。", "共说荆州老长史，宰相须还他做。", "沙路星明，甘棠人远，无计攀辕住。", "薰香三祝，苍生正望霖雨。"]'),
('song-ci-919','贺新郎','彭子翔','宋','宋词','song-ci','贺新郎','[]','一点阳春小。',142,'宋词/ci.song.18000.json','["一点阳春小。", "傍妆台、梅梢粉嫩，桃花红透。", "合卺樽前人笑语，银烛两行红补。", "云正暖、流苏香兽。", "金屋阿娇元共贮，待玄霜、杵就方成偶。", "□□□，□□□。", "西园扑蝶春风早。", "看浮花、浪蕊飞尽，娟娟闺秀。", "柳带菖蒲堪绾结，只绾同心未就。", "算今夜、心都同了。", "待阙鸳鸯情似海，锦衾温、说到鸡声晓。", "头白也，镇相守。"]'),
('song-ci-920','木兰花慢','彭子翔','宋','宋词','song-ci','木兰花慢','[]','仙家春不老，谁说到、牡丹休。',125,'宋词/ci.song.18000.json','["仙家春不老，谁说到、牡丹休。", "算蛮柳樊樱，怎生了得，白傅风流。", "枝头。", "摽梅实好，奈绿阴、庭户不禁愁。", "幸有琴中凤语，能通镜里鸾求。", "锵璆。", "杂佩下瀛洲。", "宝箑紫烟浮。", "望兰情红盼，三生曾识，一见如羞。", "绸缪。", "从今偕老，似柳郎、无负碧云秋。", "莫倚回文妙手，放教远觅封候。"]'),
('song-ci-921','千秋岁','彭子翔','宋','宋词','song-ci','千秋岁','[]','重阳来未。',87,'宋词/ci.song.18000.json','["重阳来未。", "谁领黄花意。", "斟玉醑，歌金缕。", "云山笼瑞彩，风月溶清气。", "北山顶，寿星一点光无际。", "六十今朝是。", "甲子从头起。", "堂堂去，千千岁。", "是非华表鹤，深浅蓬莱水。", "翁不管，年年先共黄花醉。"]'),
('song-ci-922','声声慢','彭子翔','宋','宋词','song-ci','声声慢','[]','萸房初荐，橙子新槎。',83,'宋词/ci.song.18000.json','["萸房初荐，橙子新槎。", "菊松图下捧金荷。", "看翁将息，后生似、去年些。", "更眼前、稚子又多。", "鬓绿颜酡。", "对花醉、把花歌。", "熙宁安乐好行窝。", "佳辰虽异，翁此兴、不输他。", "更如何、欢喜也呵。"]'),
('song-ci-923','临江仙','彭子翔','宋','宋词','song-ci','临江仙','[]','佛说波斯王此岁，衰颜羞见河流。',70,'宋词/ci.song.18000.json','["佛说波斯王此岁，衰颜羞见河流。", "翁今丹脸发光浮。", "毗卢金色界，烂熳菊花秋。", "七个明朝方九日，年年税在今朝。", "八千秋老又从头。", "明朝无尽在，蝴蝶不须愁。"]'),
('song-ci-924','暗香','彭子翔','宋','宋词','song-ci','暗香','[]','停云望极。',122,'宋词/ci.song.18000.json','["停云望极。", "问秀溪何似，英溪风月。", "劫火灰飞，又见雕檐照寒碧。", "何事归来归去，似熙载、江南江北。", "还又向、殊乡初度。", "故乡人，却为客。", "是则。", "家咫尺。", "不是有、莼羹鲈鲙堪忆。", "从心时节。", "消得山阴几双屐。", "莫把放翁笑我，又似忆、平泉花石。", "篱菊老，梅枝亚，不归怎得。"]'),
('song-ci-925','醉蓬莱','百兰','宋','宋词','song-ci','醉蓬莱','[]','怪柳吟翻雪，梅笑冲寒，郁葱如彩。',118,'宋词/ci.song.18000.json','["怪柳吟翻雪，梅笑冲寒，郁葱如彩。", "还是瑶池，宴神俦侣。", "罗幕轻掀，绣帘低揭，按霓裳宫羽。", "宝炷熏浓，佩环声颤，凤飞鸾舞。", "犹记年时，玉箫吹彻，并驾萧郎，共骖赢女。", "旋捧麒麟，种旧家前武。", "政了摘星天上，早约个、嫦娥住。", "妆点华堂，双扶醉玉，黑颠如许。"]'),
('song-ci-926','满庭芳','百兰','宋','宋词','song-ci','满庭芳','[]','有分非难，是缘终合，采来还换须臾。',117,'宋词/ci.song.18000.json','["有分非难，是缘终合，采来还换须臾。", "少年培植，春意已敷腴。", "毕竟花多驻果，坚牢是、蚌老生珠。", "君知否，今番定也，颠不破璠璵。", "遥知纷瑞霭，十分郎罢，黄溢眉须。", "便何妨燕喜，剩卖欢娱。", "况侍北堂难老，庭阶映、玉树森如。", "金荷劝，从教酩酊，扶醉看孙株。"]'),
('song-ci-927','雨中花・夜行船','百兰','宋','宋词','song-ci','雨中花・夜行船','[]','饤斗云山，挨排烟水，六丁午夜文移。',117,'宋词/ci.song.18000.json','["饤斗云山，挨排烟水，六丁午夜文移。", "道滁翁孙子，欲寄游嬉。", "高趁鹜霞舒啸，低群鸥鹭忘机。", "牢笼两下，楼乘汗漫，桥枕清漪。", "灞陵吟畅，岳阳登览，百色都副襟期。", "还好是、行天马渡，探月人归。", "倚柱荷香扑面，凭栏桂影侵衣。", "索梅无便，春风不碍，容我追随。"]'),
('song-ci-928','碧桃春・阮郎归','丁持正','宋','宋词','song-ci','碧桃春・阮郎归','[]','几年辛苦捣元霜。',56,'宋词/ci.song.18000.json','["几年辛苦捣元霜。", "一朝琼粉香。", "云英缥渺曳仙裳。", "相将骑凤凰。", "鍧帝乐，酌天浆。", "千年颜色芳。", "从兹归去白云乡。", "碧桃春昼长。"]'),
('song-ci-929','一箩金・蝶恋花','李石才','宋','宋词','song-ci','一箩金・蝶恋花','[]','武陵春色浓如酒。',69,'宋词/ci.song.18000.json','["武陵春色浓如酒。", "游冶才郎，初试花间手。", "绛蜡烛残人静后。", "眉峰便作伤春皱。", "一霎风狂和雨骤。", "柳嫩花柔，浑不禁僝僽。", "明日馀香知否。", "粉罗犹有残红透。"]'),
('song-ci-930','水调歌头','魏顺之','宋','宋词','song-ci','水调歌头','[]','人世斗南瑞，天上璧东星。',114,'宋词/ci.song.18000.json','["人世斗南瑞，天上璧东星。", "谁分佳种，锺作间世玉麒麟。", "本是南阳相种，来应瑞龙间气，试听即英声。", "若问贤相敌，君去问参军。", "质金浑，标玉立，气冰清。", "梅花时候，结子便可鼎调金。", "人谓丹山苞凤，天产渥洼骏骨，德毓窦家椿。", "来作汤饼客，何幸厕嘉宾。"]'),
('song-ci-931','贺新郎','伍梅城','宋','宋词','song-ci','贺新郎','[]','甲子头春雨。',142,'宋词/ci.song.18000.json','["甲子头春雨。", "知老天、净冼荆扬，十年烟雾。", "夜半堕中星一颗，飞下五云深处。", "帝亲敕、六丁呵护。", "须信斯人为世瑞，非人龙、定是文中虎。", "关世道，系天数。", "此儿殊怕人惊顾。", "况当家、廷评为祖，大中为父。", "料想廷评公一笑，笑对大中共语。", "应自把、小程夸取。", "会见九州熙白日，做状元、宰相荣门户。", "年正少，四亲具。"]'),
('song-ci-932','贺新郎','伍梅城','宋','宋词','song-ci','贺新郎','[]','梦到天宫里。',141,'宋词/ci.song.18000.json','["梦到天宫里。", "见长庚星颗，忽自月边飞至。", "直奏玉皇金阙道，臣已五年于此。", "今亦欲、过宫一次。", "福禄寿星齐赞叹，过宫时、须过廉泉位。", "帝首肯，从他意。", "朝来鹊送帘前喜。", "闻廉泉、似是紫岩，螟蛉兄子。", "是子南轩人物祥，功业行看相似。", "岂同祖、同闻而已。", "细把所闻详所梦，想天文、实应人间事。", "况真是，长庚李。"]'),
('song-ci-933','最高楼','伍梅城','宋','宋词','song-ci','最高楼','[]','知君久，勘破利名关。',100,'宋词/ci.song.18000.json','["知君久，勘破利名关。", "未老得先闲。", "今年最喜吟身健，生朝更觉酒肠宽。", "且随宜，将秫种，买花看。", "门外吏、催科无一迹。", "窗下客、谈诗常经日。", "儿玉树，弟金兰。", "华堂举案齐眉乐，锦天歌客笑声欢。", "问何如，福东海，寿南山。"]'),
('song-ci-934','醉蓬莱','伍梅城','宋','宋词','song-ci','醉蓬莱','[]','倚东风笑问。',120,'宋词/ci.song.18000.json','["倚东风笑问。", "落红啼鴂，清明来未。", "小雨弄晴，做轻寒天气。", "南极光中，五云深处，人庆千秋岁。", "翡翠屏间，琉璃帘下，彩衣明媚。", "九老风流，五候家数，如此乾坤，有人如此。", "天正烦君，作江南一瑞。", "世上今秦，山中古晋，尽不经吾意。", "但要牡丹，年年今日，伴人沈醉。"]'),
('song-ci-935','摸鱼儿','伍梅城','宋','宋词','song-ci','摸鱼儿','[]','极知君、腰骑鹤，此心与水相似。',138,'宋词/ci.song.18000.json','["极知君、腰骑鹤，此心与水相似。", "梧桐叶上黄昏雨，恨杀无情流水。", "滔滔地。", "今日大江头，明日人千里。", "君思往事。", "两袖淮云，一轮明月，要亦寻常耳。", "君去也，我亦扁舟东矣。", "尊前何惜同醉。", "五年未老君犹健，五十行当富贵。", "书频寄。", "报王粲、何时可决荆州计。", "俱胝一纸。", "更细算何时，五星同会，天下太平未。"]'),
('song-ci-936','贺新郎','伍梅城','宋','宋词','song-ci','贺新郎','[]','上界神仙府。',141,'宋词/ci.song.18000.json','["上界神仙府。", "谁移来、登瀛堂畔，五云深处。", "江水一弓山万朵，竹外梅花千树。", "看都入、高人庭户。", "南北两厅相对起，要门前、便是浮岚路。", "依暖翠，开吟圃。", "莺迁喜奉高堂母。", "向销金帐下，坐看秦歌赵舞。", "唐宋几年名阀阅，到此步高一步。", "君听取，邦人庆语。", "多少朱门随世化，独眼前、突兀新如许。", "真个是，擎天柱。"]'),
('song-ci-937','贺新郎','丁几仲','宋','宋词','song-ci','贺新郎','[]','喜溢蟾宫梦。',140,'宋词/ci.song.18000.json','["喜溢蟾宫梦。", "起推衣、平章宝桂，湿鸦飞动。", "果报佳音传络秀，丹穴雏生彩凤。", "想孔释、亲来抱送。", "不羡徐卿秋水澈，试闻声、识破真英种。", "培杞梓，待时用。", "当年绛帐承新宠。", "问何如归来，碧荷香重。", "都是刘郎看承处，多少温柔从臾。", "会起我嘉宾钦竦。", "左氏公羊，从初所学，看家传、声誉今腾涌。", "拚醉舞，与谁共。"]'),
('song-ci-938','百字谣・念奴娇','禅峰','宋','宋词','song-ci','百字谣・念奴娇','[]','中秋近也，正于门瑞气，葱葱时节。',120,'宋词/ci.song.18000.json','["中秋近也，正于门瑞气，葱葱时节。", "隔岁维熊占吉梦，今夕天生英杰。", "仙籍流芳，瑞龙毓秀，应是非凡骨。", "诗书勋业，妙龄行见英发。", "好是日满三朝，剩陈汤饼，投辖留宾客。", "玉果犀钱排绮宴，窈窕歌珠舞雪。", "枕玉凉时，屏山深处，好事权休说。", "小蛮杨柳，迩来还可攀折。"]'),
('song-ci-939','西江月','刘涧谷','宋','宋词','song-ci','西江月','[]','淑质生当良月，晬辰喜遇今朝。',58,'宋词/ci.song.18000.json','["淑质生当良月，晬辰喜遇今朝。", "掌心托个儒人苗。", "早晚夫人争叫。", "阿母神仙苗裔，阿爷宰相丰标。", "阿兄气宇更飘飘。", "阿弟看看速肖。"]'),
('song-ci-940','浣溪沙','游稚仙','宋','宋词','song-ci','浣溪沙','[]','晬日先联瑞日红。',48,'宋词/ci.song.18000.json','["晬日先联瑞日红。", "寿星明照寿筵中。", "庆门乐事正重重。", "明日贾逵添戏彩，异时李汉看乘龙。", "鱼轩玉轴定荣封。"]'),
('song-ci-941','沁园春','李团湖','宋','宋词','song-ci','沁园春','[]','六桂传家，三槐植庭，箕裘大儒。',140,'宋词/ci.song.18000.json','["六桂传家，三槐植庭，箕裘大儒。", "甚二郎意气，似同稷契，一时庆会，致主唐虞。", "百揆登庸，双亲未老，此乐人间还有无。", "那堪更、有棣华韡韡，听履亨衢。", "朝来天上传呼。", "便写作、衣冠盛事图。", "有声容备乐，传宣锡动，充庭牲饩，簇拥欢娱。", "整顿乾坤，巩安宗社，亦有臣功如此乎。", "中书考，愿年年此日，春满蓬壶。"]'),
('song-ci-942','满江红','黄诚之','宋','宋词','song-ci','满江红','[]','五岳三光，锺秀气、笃生人杰。',115,'宋词/ci.song.18000.json','["五岳三光，锺秀气、笃生人杰。", "天付与、心肠锦绣，精神冰雪。", "姓字早登龙虎榜，文书夜直丝纶阁。", "谢君王、特地掇鸾坡，来闽粤。", "几千顷，恩波阔。", "十万户，欢声浃。", "看致君尧舜，归班夔契。", "淡笑扫清沙漠净，弥缝补就苍天缺。", "愿年年、长醉腊前春，梅梢月。"]'),
('song-ci-943','洞仙歌','熊子默','宋','宋词','song-ci','洞仙歌','[]','春逢花好，一笑长相见。',103,'宋词/ci.song.18000.json','["春逢花好，一笑长相见。", "令似当年徊仙苑。", "况歌翻桃叶，香绕莱衣，须信道，人与千秋共远。", "不妨留绛节，看即沙堤，玉笋班高侍金辇。", "问人间、缘底事，犹欠河清，须妙手、鸿钧一传。", "待整顿乾坤、却归来，唤舞鹤翔云，洞天游伴。"]'),
('song-ci-944','水调歌头','陈惟哲','宋','宋词','song-ci','水调歌头','[]','近畿贤太守，陆地隐神仙。',114,'宋词/ci.song.18000.json','["近畿贤太守，陆地隐神仙。", "功高玉记，名通紫府自长年。", "拂拭壶中光景，游戏人间风月，富贵本青毡。", "十载五分牧，惠泽浸江天。", "把文章，做勋业，德才全。", "龟峰堂上，满城和气入歌筵。", "春在百花庭院，坐拥十眉珠翠，寿酒吸长川。", "来岁称觞处，稳向凤池边。"]'),
('song-ci-945','摸鱼儿','欧阳朝阳','宋','宋词','song-ci','摸鱼儿','[]','正当绂麟时候，秋香还弄清晓。',138,'宋词/ci.song.18000.json','["正当绂麟时候，秋香还弄清晓。", "双旌五马人间贵，千里共腾欢笑。", "人未老。", "看绿鬓朱颜，赢得花簪帽。", "兽炉篆袅。", "听檀板轻敲，歌珠一串，依约似蓬岛。", "青云步，九万论程未了。", "芹宫多世仪表。", "提封晋郡重拈出，留样他年称好。", "书上考。", "怕种满棠阴，丹诏催归早。", "安期献枣。", "对鹤健丹香，龟轻莲叶，起舞醉清醥。"]'),
('song-ci-946','贺新郎','碧虚','宋','宋词','song-ci','贺新郎','[]','兖兖登台阁。',141,'宋词/ci.song.18000.json','["兖兖登台阁。", "问诸公、谁讲谁明，诗书礼乐。", "前日毕星光焰里，有一濂渠伊洛。", "被翠玉、江山占却。", "天下国家多少事，好人才、半刺东南角。", "当路者，欠商确。", "寿杯端拜深深酌。", "把寻常、祝颂芜词，一时删削。", "引饮莱公同鼎轴，共定澟渊一著。", "二百载、无人能学。", "文简毕公真事业，非先生之托谁之托。", "龟鹤舞，蛟龙跃。"]'),
('song-ci-947','琐寒窗','彭正大','宋','宋词','song-ci','琐寒窗','[]','千里儒流，称觞此际，梅花三度。',120,'宋词/ci.song.18000.json','["千里儒流，称觞此际，梅花三度。", "书台最上，健羡一翁如许。", "问吴江、别来旧人，当时折柳凭谁语。", "但春在芹宫，芳滋兰畹，一帘今雨。", "凭阑、凝望处。", "有绿水青山，乾坤付与。", "百年家谱，曾是斯文宗主。", "世间好景相寻，墨客骚人为伴侣。", "待西风、桂子重开，又步青云去。"]'),
('song-ci-948','感皇恩','叶巽斋','宋','宋词','song-ci','感皇恩','[]','冬岭秀乔松，江南飞雪。',81,'宋词/ci.song.18000.json','["冬岭秀乔松，江南飞雪。", "数朵梅花弄春色。", "玉颜苍鬓，人似松梅标格。", "岁寒长不老，人奇绝。", "簿领馀间，长生有道，福寿从今更千百。", "孙枝浸盛，万卷家传方册。", "樽前频醉，此宵风月。"]'),
('song-ci-949','庆长春・念奴娇','铁笔翁','宋','宋词','song-ci','庆长春・念奴娇','[]','有洒如渑，便开怀痛饮，我歌君拍。',120,'宋词/ci.song.18000.json','["有洒如渑，便开怀痛饮，我歌君拍。", "世事轮云都莫问，只要颜红鬓黑。", "鹂燕风清，鸳鸯水暖，打当生申节。", "薰风来也，几人感戴翁德。", "好是驾海胸襟，屠龙手段，一笑乾坤窄。", "门外尘涛三百尺，不博剡溪一雪。", "绿幕红围，妙歌细舞，且醉三千客。", "问翁年纪，广成千有二百。"]'),
('song-ci-950','醉蓬莱','刘性初','宋','宋词','song-ci','醉蓬莱','[]','喜首夏清和，槐绿成阴，榴红正朵。',120,'宋词/ci.song.18000.json','["喜首夏清和，槐绿成阴，榴红正朵。", "仙鹤翩跹，来致千秋贺。", "南极长明，后天不老，瑞霭浮青琐。", "满树蟠桃，瑶池捧献，一年一颗。", "好敞亭台，胜添花柳，时醉时歌，时行时坐。", "受用黄庭，宝熟丹田火。", "晓对青山，日吟白发，尽功名江左。", "戏彩亭边，陶陶自得，有何不可。"]'),
('song-ci-951','齐天乐','刘学颜','宋','宋词','song-ci','齐天乐','[]','红冈小塔枫林路，曾见承平歌舞。',123,'宋词/ci.song.18000.json','["红冈小塔枫林路，曾见承平歌舞。", "舞罢人归，月斜影转，重见郎官星度。", "乡关境土，又二十馀年，桑麻深露。", "说与闾巷，少年知得当时否。", "如今苍颜白发，问耕聊尔耳，依稀农圃。", "父老吾伊，深山鸡黍，谁念乱离父母。", "村南昼午。", "谩对客烹茶，笑谈今古。", "千岁迢迢，竹风时扫户。"]'),
('song-ci-952','好事近','江史君','宋','宋词','song-ci','好事近','[]','耳顺恰当年，甲子方一数。',53,'宋词/ci.song.18000.json','["耳顺恰当年，甲子方一数。", "绛县老人曾纪，四百四十五。", "孙弘博士适遭逢，马援击蛮未遇。", "五福祝君全备，更尊荣安富。"]'),
('song-ci-953','最高楼','徐架阁','宋','宋词','song-ci','最高楼','[]','年高德劭，休叹老而传。',98,'宋词/ci.song.18000.json','["年高德劭，休叹老而传。", "纵白发，尚红颜。", "楚丘且谓吾始壮，大致仕亦宜然。", "更尊荣，安富贵，寿绵延。", "闻道生辰当月吉，万福千祥降自天。", "献春酒，展华筵。", "从心奚止不逾矩，绛人彭祖信齐肩。", "更殷勤，加颂祷，等椿年。"]'),
('song-ci-954','沁园春','立斋','宋','宋词','song-ci','沁园春','[]','表表耆英，松柏贞刚，冰霜洁清。',139,'宋词/ci.song.18000.json','["表表耆英，松柏贞刚，冰霜洁清。", "正持囊紫禁，急流勇退，步角巾绿野，闲处安身。", "里社鸡豚，家山猿鹤，物我相忘法从荣。", "东溪畔，似非熊尚父，在渭之滨。", "闲来袖手梅亭。", "似桃李纷纷谷自春。", "算高风难进，缙绅楷式，颓波立，乡曲仪刑。", "厚德清名，疏星碧落，屈指如公今几人。", "无他祝，但似山难老，镇压嚣尘。"]'),
('song-ci-955','酹江月・念奴娇','黄革','宋','宋词','song-ci','酹江月・念奴娇','[]','堂堂卿月，奉君恩来作，潜藩贤守。',121,'宋词/ci.song.18000.json','["堂堂卿月，奉君恩来作，潜藩贤守。", "喜遇慈闱年八十，特向新正称寿。", "千里春风，满堂和气，是处歌声奏。", "荷衣紫绶，捧觞齐上春酒。", "人道彭祖高年，寿高八百，管从来稀有。", "似此遐龄，屈指算、犹有十分之九。", "惠满梅山，宠新芝检，归展调羹手。", "疏封国号，天教富贵长久。"]'),
('song-ci-956','百字令・念奴娇','陈潜心','宋','宋词','song-ci','百字令・念奴娇','[]','梅峰孕秀，庆仙翁、咫尺元宵三夕。',119,'宋词/ci.song.18000.json','["梅峰孕秀，庆仙翁、咫尺元宵三夕。", "盛德温温如玉粹，多少殊勋嘉绩。", "两拥朱幡，独清节，高谊真难屈。", "景疏堂下，台星长伴南极。", "雅羡椿桂联芳，金章紫绶，拜舞欢声溢。", "福备宜高仁者寿，喜占人间八十。", "汉重申公，周登尚父，盛事今犹昔。", "九重注想，备车行聘遗逸。"]'),
('song-ci-957','三登乐','罗子','宋','宋词','song-ci','三登乐','[]','过了元宵，见七叶蓂又飞。',88,'宋词/ci.song.18000.json','["过了元宵，见七叶蓂又飞。", "恰今朝、昴宿降瑞。", "初度果生贤，尽道丰姿绝异。", "翰林人物，云霄富贵。", "自栖鸾展骥。", "迤逦黄堂，每登要路无留滞。", "暂归来，访松菊，趣装行用济。", "增崇福禄，寿延千百岁。"]'),
('song-ci-958','虞美人','刘公子','宋','宋词','song-ci','虞美人','[]','搀先四日花朝节。',66,'宋词/ci.song.18000.json','["搀先四日花朝节。", "红紫争罗列。", "传言玉女降生朝。", "箕宿光联婺宿、灿云霄。", "斒衣红袖齐歌舞。", "称颂椒觞举。", "群仙列侍宴瑶池。", "王母麻姑同寿、更无期。"]'),
('song-ci-959','百字谣・念奴娇','三槐','宋','宋词','song-ci','百字谣・念奴娇','[]','武夷秀气，萃君家、春色融和时节。',120,'宋词/ci.song.18000.json','["武夷秀气，萃君家、春色融和时节。", "赏了花朝才六日，曾记挺生英杰。", "量吸鲸川，志吞牛渚，标格冰壶洁。", "台星明处，年年辉映南极。", "须信早晚横翔，云霄直上，宁久栖鸾棘。", "富贵荣华年正少，谢砌芝兰秀发。", "行及瓜期，荣趋花县，百里民怀德。", "交腾荐剡，褒迁大振勋业。"]'),
('song-ci-960','沁园春','程东湾','宋','宋词','song-ci','沁园春','[]','毓德婺虚，联辉魁宿，天启儒英。',137,'宋词/ci.song.18000.json','["毓德婺虚，联辉魁宿，天启儒英。", "正仲春蓂阶，三留叶秀，晓来蓬矢，六挂门荣。", "星昴诞萧，神嵩降甫，怎似今朝记始生。", "当此际，有满城和气，万井欢声。", "龚黄政事勋名。", "镜里文书吏胆惊。", "况百年经界，于今修复，四贤道学，至此彰明。", "月对艳阳，日逢初度，紫诏行催觐玉京。", "黄堂上、寿觞称处，介福邦民。"]'),
('song-ci-961','百字谣・念奴娇','张倅','宋','宋词','song-ci','百字谣・念奴娇','[]','榆烟新起，正清明节过，翠蓂九叶。',120,'宋词/ci.song.18000.json','["榆烟新起，正清明节过，翠蓂九叶。", "欣会谪仙初度日，凤穴产真鸑鷟。", "心肠琅琅，文章锦绣，看镜期勋业。", "暂居马帐，后知有赖先觉。", "可想大器晚成，功名有志，未逊苏秦学。", "奈不在身先在子，果向秋风抟鹗。", "诗酒琴棋，风花雪月，养浩全真乐。", "寿觞五福，太公须遇文猎。"]'),
('song-ci-962','水调歌・水调','胡德芳','宋','宋词','song-ci','水调歌・水调','[]','湛湛玉清水，矗矗炼丹山。',114,'宋词/ci.song.18000.json','["湛湛玉清水，矗矗炼丹山。", "秀环侯泮，广文分得括苍仙。", "虞殿薰风初入。", "尧陛祥蓂七叶，此际诞真贤。", "学术瑞王国，声誉蔼人寰。", "绿槐宫，丹桂殿，杏花坛。", "英华粲发，聊将文教布龙藩。", "我亦执经北面，喜见发祥南斗，再拜祝长年。", "丹诏烂鸦墨，绿发映貂蝉。"]'),
('song-ci-963','声声慢','赵宰','宋','宋词','song-ci','声声慢','[]','洞宾仙客，诞节明朝，方斋今日称觞。',119,'宋词/ci.song.18000.json','["洞宾仙客，诞节明朝，方斋今日称觞。", "为有金丹，希年近也康强。", "平生铁石肺腑，肯依阿、贪恋朝行。", "芹溪上，把等闲出处，付与沧浪。", "花竹午桥葱倩，身退静、功名大耐偏长。", "济世经纶，暂时收敛何妨。", "黄扉有分须到，况玉皇、久待平章。", "康时了，万千年、姓字弥香。"]'),
('song-ci-964','满庭芳','张宰','宋','宋词','song-ci','满庭芳','[]','气吐虹霓，笔飞鸾凤，从来锦绣文章。',118,'宋词/ci.song.18000.json','["气吐虹霓，笔飞鸾凤，从来锦绣文章。", "谪仙才调，复见庆流芳。", "向自题名雁塔，不十载、德播河阳。", "慰民望，一麾出守，风月任平章。", "清和，时欲半，吕仙诞日，正此相当。", "欣逢初度旦，敢献椒觞。", "只恐经纶大手，应休期、便趣曹装。", "愿箕宿，照临南极，拱北远流光。"]'),
('song-ci-965','满江红','梁大年','宋','宋词','song-ci','满江红','[]','九十炎光，又过了、三分之一。',112,'宋词/ci.song.18000.json','["九十炎光，又过了、三分之一。", "记当年光际，诞生良弼。", "崧岳降神锺秀气，孕成间世真英杰。", "妙文章、拾芥立功名，谁能敌。", "周孔业，邹轲质。", "伊尹志，渊明节。", "袖经纶妙手，屡投班笔。", "富贵一朝知己逼，封候谈笑真堪觅。", "信功名、管取出长年，看箕翼。"]'),
('song-ci-966','水调歌头','梁大年','宋','宋词','song-ci','水调歌头','[]','南极寿星现，佳气蔼庭除。',114,'宋词/ci.song.18000.json','["南极寿星现，佳气蔼庭除。", "谁为绛人甲子，为我一轩渠。", "恰喜亥成二首，还庆阳来七日，和气渐舒徐。", "敬为图南祝，一瓣问兴居。", "傲松筠，抚龟鹤，乐蓬壶。", "斑衣戏舞，春满兰玉正森如。", "却忆杜陵老子，因羡碧山学士，茅屋换银鱼。", "何似温柔地，丝竹伴琴书。"]'),
('song-ci-967','烛影摇红','鼓峰','宋','宋词','song-ci','烛影摇红','[]','风入虞弦，麦秋向晚梅天润。',116,'宋词/ci.song.18000.json','["风入虞弦，麦秋向晚梅天润。", "彩丝长命斗新奇，还是端阳近。", "想见瑶池仙韵。", "对蟠桃、朱颜相映。", "篆飘宝鼎，酒满霞觞，黄堂深静。", "超悟真筌，凤归不作登台恨。", "庆馀有子在河图，详试龚黄政。", "好是棠阴清永。", "且游戏、壶中光景。", "会有飞诏，却奉轻轩，天朝归觐。"]'),
('song-ci-968','水龙吟','程霁岩','宋','宋词','song-ci','水龙吟','[]','夏秋晦朔之间，伊谁为作交承主。',126,'宋词/ci.song.18000.json','["夏秋晦朔之间，伊谁为作交承主。", "顒昂仙伯，挺生此日，宾凉饯暑。", "绛县老人，问将甲子，恰今岁数。", "举香山晏会，才先一载，愚深幸、获叨预。", "何以寿君初度。", "愿朱颜、年年如许。", "棘栖鸾凤，瑞浮鸂鶒，争如燕处。", "双桂渐香，灵椿好在，福全九五。", "向画堂深处，不妨重按，旧时歌舞。"]'),
('song-ci-969','满庭芳','程霁岩','宋','宋词','song-ci','满庭芳','[]','一叶鸣秋，五蓂纪瑞，申月还庆生申。',119,'宋词/ci.song.18000.json','["一叶鸣秋，五蓂纪瑞，申月还庆生申。", "巍巍郎宿，辉映寿星明。", "一段精神玉立，秋潭自、足副徽称。", "长生箓，只在公丹府，何待祝修龄。", "粉垣，才过了，便持荷橐，光近枫宸。", "况金瓯将启，庆满槐庭。", "朝旆行行入侍，彩衣映、衮冕辉新。", "从今去，相门出相，未数汉韦平。"]'),
('song-ci-970','水调歌头','翠微翁','宋','宋词','song-ci','水调歌头','[]','蓂荚绕开六，宝历已当千。',114,'宋词/ci.song.18000.json','["蓂荚绕开六，宝历已当千。", "人间收尽繁溽，凉意入琴弦。", "尽道荐衡交剡，更值生申时节，喜色动闾阎。", "终夜望银汉，文宿贯台躔。", "定燕秦，封晋魏，信当然。", "处处红莲开幕，曹掾岂能淹。", "见说玉堂飞诏，已许金闺通籍，蓬岛伴神仙。", "来岁寿卮酒，应醉御炉烟。"]'),
('song-ci-971','朝中措','菊翁','宋','宋词','song-ci','朝中措','[]','桂花庭院是蓬壶。',57,'宋词/ci.song.18000.json','["桂花庭院是蓬壶。", "行地列仙图。", "月姊搀先两日，捧觞来庆垂弧。", "埙箎伯仲，翁前再拜，彩袖嬉娱。", "人羡一经教子，君今满屋皆书。"]'),
('song-ci-972','水龙吟','赵佥判','宋','宋词','song-ci','水龙吟','[]','老人星照螺川，丽谯瑞霭笼晴昼。',126,'宋词/ci.song.18000.json','["老人星照螺川，丽谯瑞霭笼晴昼。", "使君初度，满城和气，欢声盈口。", "篱菊浮金，茱萸泛紫，重阳时候。", "算年年长是，节前八日，先满□、为公寿。", "一代文章山斗。", "拥朱幡、暂劳分守。", "崇墉万堞，浮梁千丈，此恩难朽。", "襦裤方谣，丝纶已下，即登班首。", "看明年今日，开筵凤池，赐黄封酒。"]'),
('song-ci-973','沁园春','李慧之','宋','宋词','song-ci','沁园春','[]','八九十翁，似婴儿戏，汉司马迁。',139,'宋词/ci.song.18000.json','["八九十翁，似婴儿戏，汉司马迁。", "记渭川垂钓，一年之长，龙山吹帽，七日之前。", "口角春风，襟期秋月，万事从来只任缘。", "随渠道，更登天富贵，陆地神仙。", "儿孙绿绶青编。", "看鼓舞云霄高刺天。", "但阶移花影，闲寻棋局，风斜竹径，缓起茶烟。", "心迹逾清，精神越健，不用金丹资节宣。", "洪崖老，笑将眉寿，祝我老人轩。"]'),
('song-ci-974','最高楼','留晚香','宋','宋词','song-ci','最高楼','["\u957f\u6c5f"]','西江水，分润到全闽。',100,'宋词/ci.song.18000.json','["西江水，分润到全闽。", "芹藻亦生春。", "秀锺东壁双躔瑞，祥开南极一星明。", "把紫阳、年月算，恰同庚。", "前十日、重阳秋正好。", "后十日、小阳春未透。", "梅与菊，此交承。", "酌公菊水来称寿，期公梅实去和羹。", "要教人，看久远，是功名。"]'),
('song-ci-975','八声甘州','杨守','宋','宋词','song-ci','八声甘州','[]','问梅边消息有还无，似微笑应人。',118,'宋词/ci.song.18000.json','["问梅边消息有还无，似微笑应人。", "道近来别有，相家一种，叶叶都新。", "趁得嫩寒轻暖，七日小阳春。", "一点和羹意，来做生辰。", "锦绣香中开国，向绮霞洞里，暂寄闲身。", "欠朝家多少，未了底经纶。", "便如何、偷闲去得，也须烦、妙手略调钧。", "归来也，恨寻棋局，点检园椿。"]'),
('song-ci-976','满江红','草夫人','宋','宋词','song-ci','满江红','[]','清晓新妆，鸾台畔、潜呼小玉。',112,'宋词/ci.song.18000.json','["清晓新妆，鸾台畔、潜呼小玉。", "问阿谁庭院，调长生曲。", "报道隔邻人庆寿，新来荣领金花轴。", "细推来、阳月已将周，惟三宿。", "陈□颂，年多祝。", "环珠翠，人如簇。", "奉金杯相庆，满斟醽醁。", "愿享麻姑难老福，屡餐王母蟠桃熟。", "更儿孙、岁岁献莱庭，蓝袍绿。"]'),
('song-ci-977','多丽','游慈','宋','宋词','song-ci','多丽','[]','约梅花，年年开向华筵。',119,'宋词/ci.song.18000.json','["约梅花，年年开向华筵。", "借清香，飞入寿杯中，永祝英贤。", "才履长、便登八帙，那须要、更待来年。", "和气先春，祥风破腊，蓂开七荚正敷妍。", "君不见，太公此际，犹欲钓磻川。", "争知道、副车已办，西伯来畋。", "驻东阳、清淡终日，种成桃李森然。", "向庭闱、绯衣戏彩，更孙。"]'),
('song-ci-978','摸鱼儿','静山','宋','宋词','song-ci','摸鱼儿','[]','晓峰高、飞泉如瀑，潜虬鞭驾轩翥。',137,'宋词/ci.song.18000.json','["晓峰高、飞泉如瀑，潜虬鞭驾轩翥。", "为他一片韩山石，直到红云天尺五。", "想应道、公皆安在来何暮。", "金川小渚。", "那韶石参天，郡纲宜录，为我分南顾。", "锦衣昼，满袖尚疑香雾。", "催人富贵如许。", "岭云见说今如砥，凤挟九成迎舞。", "烦道甫。", "问金镜铁胎，还记开元否。", "封词寄与。", "但目送河桥，吟消醉拍，载酒满江浒。"]'),
('song-ci-979','水龙吟','静山','宋','宋词','song-ci','水龙吟','[]','片帆天际归舟，好风动、吹来消息。',127,'宋词/ci.song.18000.json','["片帆天际归舟，好风动、吹来消息。", "浪间双浆，回头春杪，去来几日。", "十八滩头，水飞如舞，石巉如壁。", "把连樯白粲，等闲卸却，更呼取、艅艎入。", "不羡公家事了，羡二难、一番游历。", "江花江水，无边风月，不知行役。", "和郁孤词，倚崆峒剑，唤醒龙蛰。", "试问君，过我青原，听得几声羌笛。"]'),
('song-ci-980','满江红','刘守','宋','宋词','song-ci','满江红','[]','归去来兮，要待足、何时是足。',115,'宋词/ci.song.18000.json','["归去来兮，要待足、何时是足。", "荣对辱、饮河鼹鼠，无过满腹。", "浴月朝霞红赛锦，排云晚岫青如玉。", "更修筠、与合抱长松，依梅麓。", "森画戟，谩符竹。", "舞袖短，辕驹局。", "惟茧丝堡障，医疮剜肉。", "节对开炉应去也，钗头又有长生箓。", "算归程、恐到荔枝乡，已过熟。"]'),
('song-ci-981','江城子','逸民','宋','宋词','song-ci','江城子','[]','秀才落得甚乾忙。',86,'宋词/ci.song.18000.json','["秀才落得甚乾忙。", "冗中秋，闷重阳。", "百年三万，消得几科场。", "吟配十年灯火梦，新米粥，紫苏汤。", "如今且说世平康。", "收战场。", "息欃枪。", "路断邯郸，无复梦黄梁。", "浪说为农今决矣，新酒熟，菊花香。"]'),
('song-ci-982','江城子','无何有翁','宋','宋词','song-ci','江城子','[]','小年底死路槐忙。',87,'宋词/ci.song.18000.json','["小年底死路槐忙。", "叹蝉声，早斜阳。", "今夕何年，白骨照沙场。", "天上人间都是梦，石中火，镬中汤。", "人如今且免秀才康。", "驰大马，试长枪。", "说与儿门，书里有膏粱。", "万万古来同一月，斫不尽、广寒香。"]'),
('song-ci-983','沁园春','任翔龙','宋','宋词','song-ci','沁园春','[]','客有问余，号日汝水，逸民者谁。',139,'宋词/ci.song.18000.json','["客有问余，号日汝水，逸民者谁。", "是胸罗星斗，熟知天命，口分造化，妙泄天机。", "百十日前，再三地说，端的秋来攀桂枝。", "那时节，果鳌头高跨，鹗首横飞。", "君休说是谈非。", "是则是干支带得来。", "也要他有个、读书种子，一丁不识，富贵何为。", "报道长安，梅边春色，早趁东风掠马蹄。", "重逢处，办一封好纸，觅状元诗。"]'),
('song-ci-984','西江月','程梅斋','宋','宋词','song-ci','西江月','[]','刻木工夫最巧，舆梁底事尤精。',58,'宋词/ci.song.18000.json','["刻木工夫最巧，舆梁底事尤精。", "玉虹饮水映波明。", "彼此往来利济。", "真个作家手段，从今名播寰瀛。", "人从鳌背获安行。", "镇作城南景致。"]'),
('song-ci-985','沁园春','刘省斋','宋','宋词','song-ci','沁园春','[]','男子才生，桑弧蓬矢，志期古同。',139,'宋词/ci.song.18000.json','["男子才生，桑弧蓬矢，志期古同。", "况平生慷慨，胸襟磊落，弛张洞晓，经艺该通。", "笔扫云烟，腹储兵甲，志气天边万丈虹。", "行藏事，笑不侯李广，射石夸雄。", "仰天一问穷通。", "叹风虎云龙时未逢。", "羡傅岩版筑，终符求象，渭滨渔钓，果兆非熊。", "白额未除，长鲸未脍，臂健何嫌二石弓。", "天山定，任扶桑高挂，凌阁图功。"]'),
('song-ci-986','踏莎行','刘仁父','宋','宋词','song-ci','踏莎行','[]','不假牵丝，何劳刻木。',68,'宋词/ci.song.18000.json','["不假牵丝，何劳刻木。", "天然容貌施妆束。", "把头全仗姓刘人，就中学写秦城筑。", "伎俩优长，恢谐软熟。", "当场喝采醒群目。", "赠行无以表殷勤，特将谢意标芳轴。"]'),
('song-ci-987','如梦令','刘南翁','宋','宋词','song-ci','如梦令','[]','没计断春归路。',40,'宋词/ci.song.18000.json','["没计断春归路。", "借问春归何处。", "莺燕也含愁，总对落花无语。", "春去。", "春去。", "门掩一庭疏雨。"]'),
('song-ci-988','贺新郎','勿翁','宋','宋词','song-ci','贺新郎','[]','庭外潇潇雨。',142,'宋词/ci.song.18000.json','["庭外潇潇雨。", "对空山、再度端阳，悄无情绪。", "旧日文君今瘦损，寻旧曲、不成腔谱。", "更不周郎回顾。", "尚喜庭萱春未老，捧蒲觞、细细歌金缕。", "儿女醉，笑还语。", "醉馀更作婆娑舞。", "又谁知、灵均心事，菊英兰露。", "最苦当年哀郢意，因甚夫君未许。", "却枉使、蛾眉见妒。", "在再章台才十载，笑关河、失报应旁午。", "愁读到，楚辞句。"]'),
('song-ci-989','沁园春','李君行','宋','宋词','song-ci','沁园春','[]','三岛十洲，移掇者谁，玉城稚仙。',139,'宋词/ci.song.18000.json','["三岛十洲，移掇者谁，玉城稚仙。", "解运诗之巧，裁山剪水，用诗之力，斡地回天。", "大笑宋初，秀才屋子，著不得官家十万钱。", "又谁说，李膺豪放，门号龙门。", "我家呼喝山川。", "道今日山春莺已迁。", "汝南山顶上，虎毋久卧，秀溪底下，龙莫长眠。", "打起精神，护持诗府，推出诗城障山边。", "山川道，如稚仙肯出，当拜君言。"]'),
('song-ci-990','齐天乐','赋梅','宋','宋词','song-ci','齐天乐','[]','雕阑曲曲芙蓉水，天然一时潇洒。',123,'宋词/ci.song.18000.json','["雕阑曲曲芙蓉水，天然一时潇洒。", "露浥冰壶，风摇玉佩，缥缈蓬莱如画。", "银烛欲下。", "照藻桷翬飞，杏梁虹架。", "如此规模，杜陵何止万间厦。", "明年春燕归早，卷帘应认得，旧家王谢。", "袖里经纶，幕中佳话，高断云根谁写。", "青冥综靶。", "看人在金坡，炬莲盈把。", "句忆湘南，渌池明月夜。"]'),
('song-ci-991','临江仙','易少夫人','宋','宋词','song-ci','临江仙','[]','何处甘泉来席上，嫩黄初汤银瓶。',70,'宋词/ci.song.18000.json','["何处甘泉来席上，嫩黄初汤银瓶。", "月团尝罢有馀清。", "惠山名品在，歌舞暂留停。", "欲赏壑源新气味，不应兼进豨苓。", "此中端有淡交情。", "相如方病酒，一饮骨毛轻。"]'),
('song-ci-992','临江仙','易少夫人','宋','宋词','song-ci','临江仙','[]','记得高堂同饮散，一标汤罢分携。',70,'宋词/ci.song.18000.json','["记得高堂同饮散，一标汤罢分携。", "绛纱笼影簇行旗。", "更残银漏急，天淡玉绳低。", "只恐曲终人不见，歌声且为迟迟。", "如今车马各东西。", "画堂携手处，疑梦又疑非。"]'),
('song-ci-993','减字木兰花','胡平仲','宋','宋词','song-ci','减字木兰花','[]','天然标格。',52,'宋词/ci.song.18000.json','["天然标格。", "不问青枝和绿叶。", "彷佛吴姬。", "酒晕无端上玉肌。", "怕愁贪睡。", "谁会伤春无限意。", "乞与徐熙。", "画出横斜竹外枝。"]'),
('song-ci-994','减字木兰花','胡平仲','宋','宋词','song-ci','减字木兰花','[]','兰凋蕙歇。',52,'宋词/ci.song.18000.json','["兰凋蕙歇。", "野店酒初尝竹叶。", "绝艳幽姿。", "洗出铅华见雪肌。", "云阶月地。", "凭仗幽人须着意。", "一夜花飞。", "一点微酸已著枝。"]'),
('song-ci-995','宴桃源・如梦令','曹遇','宋','宋词','song-ci','宴桃源・如梦令','["\u897f\u6e56"]','西湖辟暑棹扁舟。',56,'宋词/ci.song.18000.json','["西湖辟暑棹扁舟。", "忘机狎白鸥。", "荷香十里供瀛洲。", "山光翠欲流。", "歌浩浩，思悠悠。", "诗成兴未休。", "清风明月解相留。", "琴声万籁幽。"]'),
('song-ci-996','宴桃源・如梦令','曹遇','宋','宋词','song-ci','宴桃源・如梦令','[]','廉纤小雨养花天。',56,'宋词/ci.song.18000.json','["廉纤小雨养花天。", "池光映远山。", "蕙兰风暖正暄妍。", "归梁燕翼偏。", "芳草碧，绿波涟。", "良辰近禁烟。", "酒酣午枕兴怡然。", "莺声惊梦仙。"]'),
('song-ci-997','蓦山溪','曹遇','宋','宋词','song-ci','蓦山溪','[]','鉴湖千顷，四序风光好。',102,'宋词/ci.song.18000.json','["鉴湖千顷，四序风光好。", "拔棹皱涟漪，极目处、青山缭绕。", "微茫烟霭，鸥鹭点菰蒲，云帆过，钓舟横，俱被劳生扰。", "知章请赐，独占心何小。", "风月本无私，同众乐、宁论多少。", "浮家泛宅，它日郊陶朱，烹鲈鳜，酌松醪，吟笔千篇扫。"]'),
('song-ci-998','水调歌头','曹遇','宋','宋词','song-ci','水调歌头','[]','造物巧能赋，新腊报花期。',114,'宋词/ci.song.18000.json','["造物巧能赋，新腊报花期。", "江梅清瘦，只是洁白逞芳姿。", "我欲超君绝类，故学仙家繁杏，秾艳映横枝。", "朱粉腻香脸，酒晕著冰肌。", "玉堂里，山驿畔，最希奇。", "谁将绛蜡笼玉，香雪染胭脂。", "好向歌台舞榭，斗取红妆娇面，偎依韵偏宜。", "羌管莫吹动，风月正相知。"]'),
('song-ci-999','西江月','曹遇','宋','宋词','song-ci','西江月','[]','秋霁嫦娥二八，寒光逼散浮云。',58,'宋词/ci.song.18000.json','["秋霁嫦娥二八，寒光逼散浮云。", "小山丛桂吐清芬，犹带蟾宫风韵。", "因念两登仙籍，恩沾雨露方新。", "汝今妙岁已能文。", "早折高枝荣奋。"]'),
('song-ci-0','满江红','白君瑞','宋','宋词','song-ci','满江红','[]','木落林疏，秋渐冷、芙蓉新拆。',115,'宋词/ci.song.19000.json','["木落林疏，秋渐冷、芙蓉新拆。", "傍碧水，晓妆初鉴，露匀妖色。", "故向霜前呈艳态，想应青女加怜惜。", "映朝阳、翠叶拥红苞，闲庭侧。", "岩桂香，随飘泊。", "篱菊嫩，陪幽寂。", "笑春红容易，被风吹落。", "满眼炯然宫锦烂，一身如寄神仙宅。", "把绿尊、莫惜醉相酬，春工力。"]'),
('song-ci-1','水调歌头','白君瑞','宋','宋词','song-ci','水调歌头','[]','凉吹佛衣袂，助我上高台。',112,'宋词/ci.song.19000.json','["凉吹佛衣袂，助我上高台。", "云檐风栋，窗户绝纤埃。", "四绕江山雄麓，万古盘龙踞虎，壮气销崖嵬。", "二水中分远，艇子自归来。", "望白云，迎碧汉，俯长淮。", "铎声到耳，亭亭孤塔现林隈。", "烟惹宫城深树，日照酒楼帘幕，物象眼前排。", "长啸下梯径，欲去更徘徊。"]'),
('song-ci-2','柳梢青','白君瑞','宋','宋词','song-ci','柳梢青','[]','玉骨冰姿，天然清楚，雪里曾看。',61,'宋词/ci.song.19000.json','["玉骨冰姿，天然清楚，雪里曾看。", "物外幽人，细窥天巧，收入毫端。", "一枝影落云笺。", "便似觉、清风夜寒。", "试向松窗，待闲一展，俗虑都捐。"]'),
('song-ci-3','风入松','白君瑞','宋','宋词','song-ci','风入松','[]','一冬不见雪花飞。',90,'宋词/ci.song.19000.json','["一冬不见雪花飞。", "爱日荡晴晖。", "腊残未解寒塘冻，东风细、已露春期。", "正是年时策马，相随村落寻梅。", "故人别久信音稀。", "排闷有新诗。", "雁声北去江城暖，暗舒展、花柳容仪。", "屈指烧灯不远，等闲休锁双眉。"]'),
('song-ci-4','念奴娇','白君瑞','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','江干蹭蹬，镇寻常、怀想京城春色。',120,'宋词/ci.song.19000.json','["江干蹭蹬，镇寻常、怀想京城春色。", "静倚山亭凝望处，惟见鸟飞云幕。", "拂面埃尘，跳□□□，老却风流格。", "年来却有，短蓑轻棹胸臆。", "闻与俊逸嬉游，笙歌丛里，眷恋中华国。", "况是韶阳将近也，应办青骢金勒。", "丰乐阑干，西湖烟水，遍赏苏堤侧。", "举觞须酹，天隅犀渚孤客。"]'),
('song-ci-5','水调歌头','贾应','宋','宋词','song-ci','水调歌头','[]','晚日浴鲸海，壁月挂鳌峰。',113,'宋词/ci.song.19000.json','["晚日浴鲸海，壁月挂鳌峰。", "不知今夕何夕，灯火万家同。", "楼外芙蕖开遍，人在琉璃里，语笑隔帘重。", "对景且行乐，一醉任东风。", "黄堂宴，春酒绿，艳妆红。", "文章太守，和气都在笑谈中。", "正此觥筹交错，只恐笙歌未散，温诏促追锋。", "来岁传柑处，侍宴自从容。"]'),
('song-ci-6','沁园春','杨元亨','宋','宋词','song-ci','沁园春','[]','一棹横江，问讯盟鸥，太守谓谁。',139,'宋词/ci.song.19000.json','["一棹横江，问讯盟鸥，太守谓谁。", "道皇华使者，光风洒落。", "元宵三五，乐与民俱。", "宝榼金鞯，玉梅钗燕，斗鸭阑干花影嬉。", "人迎笑，似玉京春浅，长是灯时。", "风流不减人知。", "算岳牧词人谁似之。", "把南楼风月，渚宫丘壑，竹西歌舞，行乐濡须。", "万斛金莲，满城开遍，朵朵留迎学士归。", "明年宴，看柑传天上，月在云西。"]'),
('song-ci-7','八声甘州','林实之','宋','宋词','song-ci','八声甘州','[]','客星堂下水，碧浮空、烟树几重重。',117,'宋词/ci.song.19000.json','["客星堂下水，碧浮空、烟树几重重。", "想故人当日，论情蓬藋，际会云龙。", "底事泥涂轩冕，不肯作三公。", "千仞钓江浒，此意谁同。", "应笑赤松黄石，效痴儿成事，犹自言功。", "怎知他箕颍，袖手独舂容。", "幸风月、有人料理，自家山叟与溪翁。", "鸣榔晚，一声长啸，相送冥鸿。"]'),
('song-ci-8','水调歌头','刘源','宋','宋词','song-ci','水调歌头','[]','几载沧江梦，此夕复经过。',114,'宋词/ci.song.19000.json','["几载沧江梦，此夕复经过。", "双台双峙如画，空翠滴晴波。", "不是先生高节，激起清风千古，汉鼎复如何。", "矫首望天际，烟树翠婆娑。", "危楼下，数不尽，去帆多。", "人人惊肉生髀，却日欲挥戈。", "谁识矶边泉石，别有壶中天地，烟雨一青蓑。", "自笑亦华发，三叹吊岩阿。"]'),
('song-ci-9','水调歌头','曾中思','宋','宋词','song-ci','水调歌头','[]','有客泛轻舸，迤逦到桐庐。',114,'宋词/ci.song.19000.json','["有客泛轻舸，迤逦到桐庐。", "山湾水曲，个中依约是仙区。", "试唤清江渔父，为问来今往古，兴废事如何。", "笑指寒烟里，此是子陵居。", "汉光武，兴皇运，握乾符。", "客星侵座，方见不与故人疏。", "自是先生高尚，无限经纶才略，飘泛寄江湖。", "凛凛亘千载，风月属樵渔。"]'),
('song-ci-10','水调歌头','黄子功','宋','宋词','song-ci','水调歌头','[]','绾纤钓台下，敛任谒严陵。',114,'宋词/ci.song.19000.json','["绾纤钓台下，敛任谒严陵。", "石矶封藓，一笑挟策独先登。", "山献修蛾几抹，江绕青罗千顷，今古富春声。", "行有二三子，心迹喜双清。", "吊羊裘，追往躅，尚仪型。", "丹青洒落三反，谁动紫垣星。", "重袖调元大手，归傲纶巾一线，志不在寒鲸。", "千载仰风节，鸿鹄自冥冥。"]'),
('song-ci-11','水调歌头','张嗣初','宋','宋词','song-ci','水调歌头','[]','名节本来重，轩冕亦何轻。',114,'宋词/ci.song.19000.json','["名节本来重，轩冕亦何轻。", "人间儿戏，刚自指点客星明。", "黄屋龙旗九仞，苍石渔丝千尺，谁辱又谁荣。", "会得傥来意，方识古交情。", "想当时，奇男子，汉真人。", "龙潜豹隐，胸中同是一经纶。", "公办中兴事业，我向沧浪学钓，各自寄吾真。", "谁信往来客，千古诵清名。"]'),
('song-ci-12','水调歌头','沈明叔','宋','宋词','song-ci','水调歌头','[]','汉事正犹豫，足迹正跫然。',114,'宋词/ci.song.19000.json','["汉事正犹豫，足迹正跫然。", "岩陵老子，当时底事动天顽。", "曾把丝纶一掷，藐视山河九鼎，高议凛人寒。", "竹帛非吾事，霄汉任腾骞。", "问云台，还得似，钓台巅。", "几年山下，使人犹识汉衣冠。", "寄语功名馀子，今日成尘何在，百战亦多艰。", "一笑桐江上，来往钓名船。"]'),
('song-ci-13','点绛唇','寇寺丞','宋','宋词','song-ci','点绛唇','[]','春睡腾腾，觉来鸳被堆香暖。',50,'宋词/ci.song.19000.json','["春睡腾腾，觉来鸳被堆香暖。", "起来慵懒。", "触目情何限。", "深院日斜，人静花阴转。", "柔肠断。", "凭高不见。", "芳草连天远。"]'),
('song-ci-14','减字木兰花','苏小小','宋','宋词','song-ci','减字木兰花','[]','别离情绪。',52,'宋词/ci.song.19000.json','["别离情绪。", "万里关山如底数。", "遣妾伤悲。", "未必郎家知不知。", "自从君去。", "数尽残冬春又暮。", "音信全乖。", "等到花开不见来。"]'),
('song-ci-15','减字木兰花','李秀兰','宋','宋词','song-ci','减字木兰花','[]','自从君去。',52,'宋词/ci.song.19000.json','["自从君去。", "晓夜萦牵肠断处。", "绿遍香阶。", "过夏经秋雁又来。", "想伊那里。", "应也情怀愁不止。", "渺渺书沈。", "直至如今没信音。"]'),
('song-ci-16','采桑子','胡夫人','宋','宋词','song-ci','采桑子','[]','与君别后愁无限，永远团圞，间阻多方。',52,'宋词/ci.song.19000.json','["与君别后愁无限，永远团圞，间阻多方。", "水远山遥寸断肠。", "终朝等候郎音耗，捱过春光。", "烟水茫茫。", "梅子青青又待黄。"]'),
('song-ci-17','失调名','窦夫人','宋','宋词','song-ci','失调名','[]','去时梅蕊全然少。',8,'宋词/ci.song.19000.json','["去时梅蕊全然少。"]'),
('song-ci-18','失调名','王娇姿','宋','宋词','song-ci','失调名','[]','兀自未归来。',6,'宋词/ci.song.19000.json','["兀自未归来。"]'),
('song-ci-19','御街行','洛阳女','宋','宋词','song-ci','御街行','[]','一身萍梗随邮转。',47,'宋词/ci.song.19000.json','["一身萍梗随邮转。", "恨归路、如天远。", "近来魂梦也疏人，不似旧时常见。", "剩衾馀枕，冷清清地，空恁闲一半。"]'),
('song-ci-20','渔家傲','丁羲叟','宋','宋词','song-ci','渔家傲','[]','十里寒塘初过雨。',72,'宋词/ci.song.19000.json','["十里寒塘初过雨。", "采莲舟上谁家女。", "秋水接云迷远树。", "天光暮。", "船头忘了回来路。", "却系兰舟深处住。", "歌声惊散鸳鸯侣。", "波上清风花上雾。", "无计去。", "月明肠断双栖去。"]'),
('song-ci-21','苏幕遮','陶氏','宋','宋词','song-ci','苏幕遮','[]','与君别，情易许。',76,'宋词/ci.song.19000.json','["与君别，情易许。", "执手相将，永远成鸳侣。", "一去音书千万里。", "望断阳关，泪滴如秋雨。", "到如今，成间阻。", "等候郎来，细把相思诉。", "看著梅花花不语。", "花已成梅，结就心中苦。"]'),
('song-ci-22','升平乐','吴奕','宋','宋词','song-ci','升平乐','[]','水阁层台，短亭深院，依稀万木笼阴。',125,'宋词/ci.song.19000.json','["水阁层台，短亭深院，依稀万木笼阴。", "飞暑无涯，行云有势，晚来细雨回晴。", "庭槐转影，纱厨两两蝉鸣。", "幽梦断枕，金猊旋热，兰炷微薰。", "堪命俊才俦侣，对华筵坐列，朱履红裙。", "檀板轻敲，金樽满泛，纵交畏日西沉。", "金丝玉管，间歌喉、时奏清音。", "唐虞景，尽陶陶沈醉，且乐升平。"]'),
('song-ci-23','选冠子','杨太尉','宋','宋词','song-ci','选冠子','["\u534e\u5c71"]','碧眼连车，黄头间座，望断故人何处。',139,'宋词/ci.song.19000.json','["碧眼连车，黄头间座，望断故人何处。", "当时胜丽，旧日繁华，都变虏言胡语。", "万里衔冤，几年埋恨，仔细向谁分诉。", "对南风凝眸，眺神旌、触目泪流如雨。", "今幸会，电扫雷驱，云开雾敛，一旦青天重睹。", "桃林卧草，华岳嘶风，行迓太平周武。", "洗尽腥膻巷陌。", "从此追欢，酒杯频举。", "任笙箫声里，花朝月夕，醉中歌舞。"]'),
('song-ci-24','多丽','李子申','宋','宋词','song-ci','多丽','[]','好人人。',170,'宋词/ci.song.19000.json','["好人人。", "去来欲见无因。", "记当时、藕香倚暖，岂期蝶散鹣分。", "到而今、漫劳梦想，嗟后会、惨啼痕。", "绣阁银屏，知他何处，一重山尽一重云。", "暮天杳、梗踪萍迹，还是寄孤村。", "寂寥月，今宵为谁，虚照黄昏。", "细追思深诚密意，黯然一饷消魂。", "仗游鱼、漫传尺素，望塞雁、空噎回纹。", "帐衾寒、香消尘满，博山沈水更谁薰。", "断肠也、无聊情味，惟有殢芳尊。", "沈吟久，移灯向壁，掩上重门。"]'),
('song-ci-25','朝中措','闾丘次杲','宋','宋词','song-ci','朝中措','[]','横江一抹是平沙。',57,'宋词/ci.song.19000.json','["横江一抹是平沙。", "沙上几千家。", "得到人家尽处，依然水接天涯。", "危栏送目，翩翩去鹢，点点归鸦。", "渔唱不知何处，多应只在芦花。"]'),
('song-ci-26','眼儿媚','危昂霄','宋','宋词','song-ci','眼儿媚','[]','晴云十丈跨杉溪。',58,'宋词/ci.song.19000.json','["晴云十丈跨杉溪。", "偏称夜凉时。", "我来正值，一滩月朗，万木霜飞。", "谪仙不住人间世，此恨有谁知。", "何人画我，倚阑得句，听水忘归。"]'),
('song-ci-27','水调歌头','万某','宋','宋词','song-ci','水调歌头','[]','卷尽风和雨，晴日照清秋。',114,'宋词/ci.song.19000.json','["卷尽风和雨，晴日照清秋。", "南山高处回首，潇洒一扁州。", "且向飞霞瀹茗，还归云间书院，何幸有从游。", "随分了公事，同乐与同忧。", "少年事，湖海气，百尺楼。", "萧萧华发，归兴只念故山幽。", "今日聊修故事，□岁大江东去，应念我穷愁。", "不但莼鲈□，杜若访芳洲。"]'),
('song-ci-28','金缕曲・贺新郎','蔡士裕','宋','宋词','song-ci','金缕曲・贺新郎','[]','怪得梅开早。',142,'宋词/ci.song.19000.json','["怪得梅开早。", "被何人、香罗剪就，天工奇巧。", "茅舍竹篱容不得，移向华堂深悄。", "别一样、风流格调。", "玉质冰姿依然在，算暗中、只欠香频到。", "著些子，更奇妙。", "有时来伴金尊倒。", "几徘徊、认成真后，又还误了。", "费尽东君回护力，空把芳心萦绕。", "竟不解、索他一笑。", "夜月纱窗黄昏后，为爱花、翻被花情恼。", "个恩爱，负多少。"]'),
('song-ci-29','浦湘曲','蔡士裕','宋','宋词','song-ci','浦湘曲','[]','功名早。',69,'宋词/ci.song.19000.json','["功名早。", "步武青云缭绕。", "斯文近有成效。", "绛纱拍拍春风满，香动一池芹藻。", "瓜期到。", "便勇撤皋比，此去应光耀。", "立登枢要。", "向红叶阶前紫薇阁，管不负年少。"]'),
('song-ci-30','水调歌头','覃怀高','宋','宋词','song-ci','水调歌头','[]','翠蕤插云表，初意隔仙凡。',114,'宋词/ci.song.19000.json','["翠蕤插云表，初意隔仙凡。", "临风据案一见，邂逅似开颜。", "几欲拿舟九曲，便拟扪参绝顶，直下俯尘寰。", "聊此税吾驾，赢得片时闲。", "问仙人，缘底事，去不还。", "长风浩浩，何许清梦杳难攀。", "只有苍烟古木，好在清湍白石，依旧画图间。", "回首武夷路，杳霭没云鬟。"]'),
('song-ci-31','水调歌头','巴州守','宋','宋词','song-ci','水调歌头','[]','霁色满空碧，爽气正横秋。',114,'宋词/ci.song.19000.json','["霁色满空碧，爽气正横秋。", "登高行乐，□来只说古巴州。", "扫□尘埃来坐，携取烟云杖履，容□□清游。", "坐上尽佳客，一醉破千忧。", "倚虚壁，绝临□，上层楼。", "黄花赤叶，鸟□啼断四山幽。", "醉里不知归去，空有乱云衰草，落日几多愁。", "舞鹤在霄汉，宿鹭点汀洲。"]'),
('song-ci-32','满江红','江无□','宋','宋词','song-ci','满江红','["\u6cf0\u5c71"]','使节行秋，算天也、知公风力。',115,'宋词/ci.song.19000.json','["使节行秋，算天也、知公风力。", "长啸罢、烟云尽卷，□□□□。", "重九汉峰黄泛酒，五更泰岳□观日。", "问扬公、去后有谁□，□朝集。", "大华□，□□□。", "今古□，□陈迹。", "甚牛山□□，□□□□。", "□□□嫌□愒薄，高怀□□□□□。", "□□□、黄鹤□□□，□相识。"]'),
('song-ci-33','头盏曲','无名氏','宋','宋词','song-ci','头盏曲','[]','黄阁方开。',13,'宋词/ci.song.19000.json','["黄阁方开。", "金鼎和羹正待梅。"]'),
('song-ci-34','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','倦客东归得自由。',48,'宋词/ci.song.19000.json','["倦客东归得自由。", "西风江上泛扁舟。", "夜寒霜月素光流。", "想得故人千里外，醉吟应上谢家楼。", "不多天气近中秋。"]'),
('song-ci-35','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','北固江头浪拍空。',48,'宋词/ci.song.19000.json','["北固江头浪拍空。", "归帆一夜趁秋风。", "月明初上荻花丛。", "渐入三吴烟景好，此身将过浙江东。", "梦魂先在鉴湖中。"]'),
('song-ci-36','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','小阁深沈，寸心怀感，暗忆旧时。',140,'宋词/ci.song.19000.json','["小阁深沈，寸心怀感，暗忆旧时。", "念母兄贫窘，姻亲劝诱，一身权作，七岁为期。", "及到门阑，小君猜忌，如履轻冰愁过违。", "多磨难，是房中诟骂，堂上鞭笞。", "堪悲。", "命运乖衰。", "甚长个孩儿朝夜啼。", "叹此生缘业，两餐淡薄，无时无泪，如醉如痴。", "暗里相逢，低声说与，此个恩情休谩为。", "须知道，联难为夏竦，不易张祁。"]'),
('song-ci-37','失调名','无名氏','宋','宋词','song-ci','失调名','[]','解下痴条。',5,'宋词/ci.song.19000.json','["解下痴条。"]'),
('song-ci-38','王子高六么大曲・自度曲','无名氏','宋','宋词','song-ci','王子高六么大曲・自度曲','[]','梦中共跨青鸾翼。',15,'宋词/ci.song.19000.json','["梦中共跨青鸾翼。", "……一簇楼台。"]'),
('song-ci-39','失调名','无名氏','宋','宋词','song-ci','失调名','[]','十五年来，从事风流府。',11,'宋词/ci.song.19000.json','["十五年来，从事风流府。"]'),
('song-ci-40','误桃源','无名氏','宋','宋词','song-ci','误桃源','[]','砥柱勒铭赋，本赞禹功勋。',44,'宋词/ci.song.19000.json','["砥柱勒铭赋，本赞禹功勋。", "试官亲处分，赞唐文。", "秀文冥子里，銮驾幸并汾。", "恰似郑州去，出曹门。"]'),
('song-ci-41','云鬓松令','无名氏','宋','宋词','song-ci','云鬓松令','[]','鬓云松，眉叶聚。',76,'宋词/ci.song.19000.json','["鬓云松，眉叶聚。", "一阕离歌，不为行人驻。", "檀板停时君看取。", "数尺鲛绡，果是梨花雨。", "鹭飞遥，天尺五。", "凤阁鸾坡，看即飞腾去。", "今夜长亭临别处。", "断梗飞云，尽是伤情绪。"]'),
('song-ci-42','胜胜慢・声声慢','无名氏','宋','宋词','song-ci','胜胜慢・声声慢','[]','严凝天气，近腊时节，寒梅暗绽疏枝。',119,'宋词/ci.song.19000.json','["严凝天气，近腊时节，寒梅暗绽疏枝。", "素艳琼苞，盈盈掩映亭池。", "雪中欺寒探暖，替东君、先报芳菲。", "暗香远，把荒林幽圃，景致妆迟。", "别是一般风韵，超群卉、不待淡荡风吹。", "雅态仪容，特地惹起相思。", "折来画堂宴赏，向尊前、吟咏怜伊。", "渐开尽，算闲花、野草怎知。"]'),
('song-ci-43','胜胜慢・声声慢','无名氏','宋','宋词','song-ci','胜胜慢・声声慢','[]','寒应消尽，丽日添长，百花未敢先拆。',119,'宋词/ci.song.19000.json','["寒应消尽，丽日添长，百花未敢先拆。", "冷艳幽香，分过溪南春色。", "调酥旋成素蕊，向碧琼、枝头匀滴。", "愁肠断，怕韶华三弄，雪映溪侧。", "应是酒阑人静，香散处、惟见玉肌冰格。", "细细疏风，清态为谁脉脉。", "芳心向人似语，也相怜、风流词客。", "待宴赏，伴娇娥、和月共摘。"]'),
('song-ci-44','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','梅萼知春，见南枝向暖，一朵初芳。',119,'宋词/ci.song.19000.json','["梅萼知春，见南枝向暖，一朵初芳。", "冰清玉丽，自然赋得幽香。", "烟庭水榭，更无花、争染春光。", "休谩说、桃夭杏冶，年年蝶闹蜂忙。", "立马伫、凝情久，念美人自别，鳞羽茫茫。", "临岐记伊，尚带宿酒残妆。", "云疏雨阔，怎知人、千里思量。", "除是托、多情驿使，殷勤折寄仙乡。"]'),
('song-ci-45','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','雪打风摧。',118,'宋词/ci.song.19000.json','["雪打风摧。", "正篱枯壁尽，却有寒梅。", "衰柳败蒲碍眼，喜见芳蕾。", "江村路曲，问青帘、与酌馀醅。", "须凭取，东君为我，一枝先寄春来。", "寂寞槿门牛巷，有清香自倚，不怕低回。", "终须会逢赏目，健步移栽。", "孤芳素艳，敢烦他、蜂蝶相陪。", "偏爱有、春风靳惜，同时不放花开。"]'),
('song-ci-46','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','点点江梅，对寒威强出，一弄新奇。',118,'宋词/ci.song.19000.json','["点点江梅，对寒威强出，一弄新奇。", "零珠碎玉，为谁密上南枝。", "幽香冷艳，纵孤高、却遣谁知。", "惟只有、江头驿畔，征鞍独为迟迟。", "聊拈粉香重问，问春来甚日，春去何时。", "移将院落，算应未肯头低。", "无人共折，傍溪桥、雪压霜欺。", "君不见、长安陌上，只夸桃李芳菲。"]'),
('song-ci-47','鼓笛慢・水龙吟','无名氏','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','雪霏冰结霜凝，是谁透得春工意。',126,'宋词/ci.song.19000.json','["雪霏冰结霜凝，是谁透得春工意。", "南枝向暖，江边岭上，独先众卉。", "闲态幽姿，绿窗红蒂，粉英金蕊。", "念冰肤秀骨，人间要见，除非是、真仙子。", "羌管且休横吹。", "待佳人、新妆初试。", "鸾台晓鉴，人花相对，何须更比。", "疏影横斜，暗香浮动，月低风细。", "又岂知，渐结枝头翠玉，有和羹美。"]'),
('song-ci-48','鼓笛慢・水龙吟','无名氏','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','去年今日关山路，疏雨断魂天气。',126,'宋词/ci.song.19000.json','["去年今日关山路，疏雨断魂天气。", "据鞍惊见，梅花的皪，篱边水际。", "一枝折得，雪妍冰丽，风梳雨洗。", "正水村山馆，倚阑愁寄，有多少、春情意。", "好是孤芳莫比。", "自不分、歌梁舞地。", "砌香砌影，高禅文友，清谈相对。", "琴韵初调，瀹瓯催渝，炉薰欲试。", "向此时，一段风流，付与晋人标致。"]'),
('song-ci-49','鼓笛慢・水龙吟','无名氏','宋','宋词','song-ci','鼓笛慢・水龙吟','[]','淡烟池馆，霜飚乍紧，又是年华暮。',127,'宋词/ci.song.19000.json','["淡烟池馆，霜飚乍紧，又是年华暮。", "黄花老尽，丹枫舞困，江梅初吐。", "点缀南枝，暗传春信，玉苞微露。", "凭危阑空断，谁家素脸，遥山远、空凝伫。", "昨夜一枝开处。", "正前村、雪深幽曙。", "看来只恐，瑶台云散，玉京人去。", "庾岭寒馀，汉宫妆晓，飞堆行雨。", "仗谁人惜取，孤芳雅致，作春光主。"]'),
('song-ci-50','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','雨肥红绽，把芳心轻吐，香喷清绝。',122,'宋词/ci.song.19000.json','["雨肥红绽，把芳心轻吐，香喷清绝。", "日暮天寒，独自倚修竹，冰清玉洁。", "待得春来，百花若见，掩面应羞杀。", "当风抵雨，犯寒则怕吹霎。", "潇潇爱出墙东，途中遥望，已慰人心渴。", "斗压阑干，人面共花面，难分优劣。", "嚼蕊寻香，凌波微步，雪沁吴绫袜。", "玉纤折了，殢人须要斜插。"]'),
('song-ci-51','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','岁华渐杪，又还是春也，难禁愁寂。',122,'宋词/ci.song.19000.json','["岁华渐杪，又还是春也，难禁愁寂。", "欲探疏梅，独自个、寻访山村水驿。", "路转溪斜，竹低墙短，应是瑶姬宅。", "玉蕤不动，月轮寒浸国色。", "回首故国风光，只因清好，重作江南客。", "堪笑广平，争解我、羁旅芳心脉脉。", "不借铅华，枝头雪霁，愈见香肌白。", "高楼且住，恁渠一弄羌笛。"]'),
('song-ci-52','念奴娇','无名氏','宋','宋词','song-ci','念奴娇','[]','兰枯蕙死，向竹斋深处，谁传消息。',121,'宋词/ci.song.19000.json','["兰枯蕙死，向竹斋深处，谁传消息。", "霜雪丛中浑似个，缥缈吴人标格。", "绛萼微深，琼苞不露，自与尘凡隔。", "黄昏遥见，一枝烟淡笼白。", "曾记雾阁云窗，轻飞香篆，佳句应难得。", "道韫能文，终未胜、潇洒风流姿质。", "待到春来，满城桃李，相并无颜色。", "殷勤祝付，画楼休品长笛。"]'),
('song-ci-53','洞庭春色・沁园春','无名氏','宋','宋词','song-ci','洞庭春色・沁园春','[]','绛萼欺寒，暗传春信，一枝乍芳。',137,'宋词/ci.song.19000.json','["绛萼欺寒，暗传春信，一枝乍芳。", "向篱边竹外，前村雪里，青梢犹瘦，疏影溪傍。", "惹露和烟凝酥艳，似潇洒玉人初试妆。", "江南路，有多情伫立，回尽柔肠。", "倚楼最难忘处，正皓月、千里流光。", "纵广平心劲，难思丽句，少陵诗兴，犹爱清香。", "休怪东君先留意，问他日和羹谁又强。", "还轻许，笑凌空桧影，松荫交相。"]'),
('song-ci-54','沁园春','无名氏','宋','宋词','song-ci','沁园春','[]','山驿萧疏，水亭清楚，仙姿太幽。',140,'宋词/ci.song.19000.json','["山驿萧疏，水亭清楚，仙姿太幽。", "望一枝颖脱，寒流林外，为传春信，风定香浮。", "断送光阴，还同昨夜，叶落从知天下秋。", "凭阑处，对冰肌玉骨，姑射来游。", "无端品笛悠悠。", "似怨感长门人泪流。", "奈微酸已寄，青青杪，助当年太液，调鼎和馐。", "樵岭渔桥，依稀精彩，又何藉纷纷俗士求。", "孤标在，想繁红闹紫，应与包羞。"]'),
('song-ci-55','真珠髻','无名氏','宋','宋词','song-ci','真珠髻','[]','重重山外，苒苒流光，又是残冬时节。',129,'宋词/ci.song.19000.json','["重重山外，苒苒流光，又是残冬时节。", "小圆幽径，池边楼畔，翠木嫩条春别。", "纤蕊轻苞，粉萼染、猩猩鲜血。", "乍几日，好景和风，次第一齐催发。", "天然香艳殊绝。", "比双成皎皎，倍增芳洁。", "去年因遇东归使，指远恨、意曾攀折。", "岂谓浮云，终不放、满枝明月。", "但叹息，时饮金锺，更绕丛丛繁雪。"]'),
('song-ci-56','远朝归','无名氏','宋','宋词','song-ci','远朝归','[]','新律才交，早旧梢南枝，朱污粉腻。',115,'宋词/ci.song.19000.json','["新律才交，早旧梢南枝，朱污粉腻。", "烟笼淡妆，恰值雨膏初细。", "而今看了，记他日、酸甜滋味。", "多应是，伴玉簪凤钗，低桠斜堕。", "迤逦。", "对酒当歌，眷恋得芳心，竟日何际。", "春光付与，尤是见欺桃李。", "叮咛寄语，且莫负、尊前花底。", "拚沈醉，尽铜壶、漏传三二。"]'),
('song-ci-57','击梧桐','无名氏','宋','宋词','song-ci','击梧桐','[]','雪叶红凋，烟林翠减，独有寒梅难并。',131,'宋词/ci.song.19000.json','["雪叶红凋，烟林翠减，独有寒梅难并。", "瑞雪香肌，碎玉奇姿，迥得佳人风韵。", "清标暗折芳心，又是轻泄，江南春信。", "最好山前水畔，幽闲自有，横斜疏影。", "尽日凭阑，寻思无语，可惜飘琼飞粉。", "但怅望、王孙未赏，空使清香成阵。", "怎得移根帝苑，开时不许众芳近。", "免教向、深岩暗谷，结成千万恨。"]'),
('song-ci-58','泛兰舟','无名氏','宋','宋词','song-ci','泛兰舟','[]','霜月亭亭时节，野溪开冰灼。',100,'宋词/ci.song.19000.json','["霜月亭亭时节，野溪开冰灼。", "故人信付江南，归也仗谁托。", "寒影低横，轻香暗度，疏篱幽院何在，秦楼朱阁。", "称帘幕。", "携酒共看，依依承醉更堪作。", "雅淡一种天然，如雪缀烟薄。", "肠断相逢，手拈嫩枝，追思浑似，那人浅妆梳掠。"]'),
('song-ci-59','十月梅・十月桃','无名氏','宋','宋词','song-ci','十月梅・十月桃','[]','千林凋尽，一阳未报，已绽南枝。',121,'宋词/ci.song.19000.json','["千林凋尽，一阳未报，已绽南枝。", "独对霜天，冒寒先占花期。", "清香映月浮动，临浅水、疏影斜敧。", "孤标不似，绿李夭桃，取次成蹊。", "纵寿阳、妆脸偏宜。", "应未笑、天然雅态冰肌。", "寄语高楼，凭栏羌管休吹。", "东君自是为主，调鼎鼐、终付他时。", "从今点缀，百草千花，须待春归。"]'),
('song-ci-60','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','冰肌玉骨，不与凡花数。',102,'宋词/ci.song.19000.json','["冰肌玉骨，不与凡花数。", "一点破清香，这心情、更谁为主。", "愁春归晚，时被雨廉纤，琼枝上，泪淋浪，似恨孤芳处。", "幽姿标格，独向江头路。", "拟待使君来，把芳心、丁宁分付。", "疏篱茅舍，回首试轻辞，争望远，嫁东风，对玉堂同处。"]'),
('song-ci-61','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','梅传春信，又报年华晚。',102,'宋词/ci.song.19000.json','["梅传春信，又报年华晚。", "昨夜半开时，似雪到、梢头未遍。", "凝酥缀粉，绰约玉肌肤，香黯淡，月朦胧，谁是黄昏伴。", "故园深处，想见孤根暖。", "千里未归人，向此际、只回泪眼。", "凭谁为我，折寄一枝来，凝睇久，俯层楼，忍更闻羌管。"]'),
('song-ci-62','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','素苞淡注。',102,'宋词/ci.song.19000.json','["素苞淡注。", "自是东君试。", "占断陇头光，正雪里、前村独步。", "一枝竹外，日暮怯轻寒，山色远，水声长，寂寞江头路。", "小桥斜渡。", "人静销魂处。", "淡月破黄昏，影浮疏、清香暗度。", "竹篱茅舍，斜倚为谁愁，应有恨，负幽情，惟恐风姨妒。"]'),
('song-ci-63','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','沙塘水浅，又一番春信。',102,'宋词/ci.song.19000.json','["沙塘水浅，又一番春信。", "玉骨不知寒，亲修篁、几苞隐映。", "幽香荏苒，不让洒蔷薇，弯月冷，漫涟漪，云断暗香影。", "朱扉深处。", "谢绝尘埃境。", "百草未开花，□茕然、教伊孤冷。", "东风世态，只恋碧桃枝，曲玉管，且休吹，免使成遗恨。"]'),
('song-ci-64','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','前村昨夜，先报春消息。',102,'宋词/ci.song.19000.json','["前村昨夜，先报春消息。", "庾岭一枝开，见行人、频频顾惜。", "东君布巧，妆蕊似裁□，疏竹外，小溪边，雪里藏春色。", "朔风吹绽，不假和风拆。", "根暖独亨嘉，向百花、头先占得。", "高楼羌笛，且劝莫凄然，协帝梦，起商岩，须尽调羹力。"]'),
('song-ci-65','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','冰肌玉骨，不假铅黄借。',101,'宋词/ci.song.19000.json','["冰肌玉骨，不假铅黄借。", "岂是占年芳，又只恐、嫌春不嫁。", "十分清瘦，可有闲愁，沙路晚，雪村晴，半幅江南画。", "林间系马，曾忆关山夜。", "醉袖惹香归，误几回、灯前娇雅。", "如今老矣，无计奈春何，人去后，独来时，风月闲亭榭。"]'),
('song-ci-66','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','前村雪里，度一枝春信。',102,'宋词/ci.song.19000.json','["前村雪里，度一枝春信。", "况自占年芳，淡妆梳、常嫌脂粉。", "樱唇轻捧，何似鹤头红，香阵阵。", "回舆认。", "摘有金卮酝。", "佳人嗅处，微把香尘喷。", "懊恼故无言，使人□、重重再问。", "它年寄与，惟有陇头人，春未困。", "香尤嫩。", "好与添风韵。"]'),
('song-ci-67','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','郊居牢落，一水流清浅。',102,'宋词/ci.song.19000.json','["郊居牢落，一水流清浅。", "忆得去年冬，数枝梅、低临水畔。", "今朝重见，把酒祝东风，和雪看。", "整凝眸，宛若江南岸。", "浮生瞥尔，劝汝休嗟叹。", "不觉失芳心，柳腰□、纤纤仍换。", "一朝光景，休恁作浑闲，春不远。", "且追游，又办寻芳宴。"]'),
('song-ci-68','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','["\u897f\u6e56"]','重黎默运，可意萦人处。',102,'宋词/ci.song.19000.json','["重黎默运，可意萦人处。", "清楚玉蕤仙，独幽栖、村溪月坞。", "冰腮露鬓，佳致在西湖，月出早，雪消迟，立马红墙序。", "寒梢微萼，点点蝇头许。", "欲露小檀心，似生怕、施朱红紫。", "返魂香细，堪吊独醒人，临泽国，袭清风，且咏离骚句。"]'),
('song-ci-69','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','前村雪里，漏泄春光早。',102,'宋词/ci.song.19000.json','["前村雪里，漏泄春光早。", "似待故人来，束芳心、幽香未老。", "溪边昨夜，雨过却参横，云旖旎，玉玲珑，不遣纤尘到。", "无情有意，寂寞谁知道。", "幽梦觉来时，淡无言、风清月暸。", "何郎去后，憔悴少新诗，空怅望，倚楼人，玉笛霜天晓。"]'),
('song-ci-70','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','["\u897f\u6e56"]','竹篱茆舍，底是藏春处。',102,'宋词/ci.song.19000.json','["竹篱茆舍，底是藏春处。", "玉蓓锁檀心，带黄昏、轻烟细雨。", "神清骨莹，端似雪堂仙，临岁晚，傲寒威，寂寞江村住。", "琼林阆苑，有信终归去。", "冷暖笑凡情，辨南枝、北枝几许。", "灵芳绝艳，知肯为谁容，东阁里，西湖畔，总与花为主。"]'),
('song-ci-71','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','岁寒辽邈，望断江南信。',102,'宋词/ci.song.19000.json','["岁寒辽邈，望断江南信。", "墙外一枝斜，对兰堂、绮罗隐映。", "水清月淡，疑是寿阳妆，烟浪急，小桥横，点点疏清影。", "天姿潇洒，不减瑶台韵。", "占断玉楼春，被松筠、笑他孤冷。", "幽人何在，无处觅馀寒，疏雨过，泪痕深，枉了衷肠恨。"]'),
('song-ci-72','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','危栏独倚，往事思量遍。',102,'宋词/ci.song.19000.json','["危栏独倚，往事思量遍。", "回首掩朱扉，敛云鬓、闲拈针线。", "轻罗碎翦，缝个小梅花，灯闪闪，夜沈沈，玉指轻轻拈。", "寒苞素艳，浑似枝头见。", "半拆与初开，谁赢得、江南手段。", "玉冠斜插，惟恨欠清香，风动处，月明时，不怕吹羌管。"]'),
('song-ci-73','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','孤村冬杪，有景真堪画。',102,'宋词/ci.song.19000.json','["孤村冬杪，有景真堪画。", "茅舍绕疏篱，见一枝、寒梅潇洒。", "欲将诗句，拟待说包容，辞未尽，意悠悠，难把精神写。", "临溪疏影，都是前人话。", "此外更何如，更须索、良工描下。", "明窗净几，长做小图看，高楼笛，尽教吹，不怕随声谢。"]'),
('song-ci-74','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','梅梢破萼，已见春心了。',102,'宋词/ci.song.19000.json','["梅梢破萼，已见春心了。", "别有淡容仪，又不与、嫣然同笑。", "东风翦蜡，簇作闹蛾儿，冰未泮，水犹寒，散在千林表。", "轻衫小帽，行尽荒山道。", "一点麝脐香，恼著人、多多少少。", "月斜门掩，消损怕黄昏，清影乱，翠帏深，且喜归来早。"]'),
('song-ci-75','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','小山苍翠，竹影横窗畔。',102,'宋词/ci.song.19000.json','["小山苍翠，竹影横窗畔。", "青缕断薰炉，觉身居、风台月观。", "清香招近，谁为植幽丛，金作蓓，蕾成花，尚带鹅黄浅。", "汉宫半额，未许人间见。", "不比岭前梅，问无因、天高水远。", "宜烟宜雨，淡淡一枝春，乘好兴，缀新诗，只恐冰生砚。"]'),
('song-ci-76','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','江南春信，已过长安路。',102,'宋词/ci.song.19000.json','["江南春信，已过长安路。", "柳眼尚贪眠，又争知、先传春去。", "东风漏泄，休更殢垂杨，深雪里，一枝开，谁占先春处。", "当时马上，回首曾凝顾。", "水浅月黄昏，倚琼枝、谁家亭户。", "一声羌管，遗恨到如今，凭栏处，赏花时，莫使花轻负。"]'),
('song-ci-77','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','当时曾见，上苑东风暖。',102,'宋词/ci.song.19000.json','["当时曾见，上苑东风暖。", "今岁却相逢，向烟村、亭边驿畔。", "垂鞭立马，一晌黯无言，江南信，寿阳人，怅望成断肠。", "琼妆雪缀，满野空零乱。", "谁是倚阑干，更那堪、胡笳羌管。", "疏枝残蕊，犹懒不娇春，水清浅，月黄昏，冷淡从来惯。"]'),
('song-ci-78','梅花引','无名氏','宋','宋词','song-ci','梅花引','[]','园林静。',140,'宋词/ci.song.19000.json','["园林静。", "萧索景。", "寒梅漏泄东君信。", "探春回。", "探春回。", "四时却被，伊家苦相催。", "江村畔。", "开烂熳。", "看看又近年光晚。", "绽芬芳。", "喷清香。", "寿阳宫里，爱学靓梳妆。", "夭桃红杏夸颜色。", "争似情怀雪中拆。", "冒严寒。", "冒严寒。", "游蜂戏蝶，莫作等闲看。", "故人别后知何处。", "春色岭头逢驿使。", "赠新诗。", "折高枝。", "楼上一声，羌管不须吹。"]'),
('song-ci-79','绿头鸭・多丽','无名氏','宋','宋词','song-ci','绿头鸭・多丽','[]','敛同云。',174,'宋词/ci.song.19000.json','["敛同云。", "破腊雪霁前村。", "占阳和、孤根先暖，数枝已报新春。", "如青女、谩同素质，笑姑射、难并天真。", "疏影横斜，澄波清浅，暗香浮动月黄昏。", "山驿畔，行人立马，回首几销魂。", "江南远，陇使趁程，踏尽冰痕。", "有个人人，玉肌偏似，移我常对金尊。", "拈纤枝、鬓边斜戴，嗅芳蕊、眉晕潜分。", "素脸笼霞，香心喷日，寿阳妆罢酒初醒。", "待调鼎、须贪结子，忍见落纷纷。", "霜天晓，愁闻画角，声断谯门。"]'),
('song-ci-80','金盏倒垂莲','无名氏','宋','宋词','song-ci','金盏倒垂莲','[]','依约疏林，见盈盈春意，几点霜蕤。',114,'宋词/ci.song.19000.json','["依约疏林，见盈盈春意，几点霜蕤。", "应是东君，试手作芳菲。", "粉面倚、天风微笑，是日暖、雪已晴时。", "人静么凤翩翩，踏碎残枝。", "幽香浑无著处，甚一般雨露，独占清奇。", "淡月疏云，何处不相宜。", "陌上报春来也，但绿暗、青子离离。", "桃杏应仗先容，次第追随。"]'),
('song-ci-81','梅香慢','无名氏','宋','宋词','song-ci','梅香慢','[]','高阁寒轻，映万朵芳梅，乱堆香雪。',125,'宋词/ci.song.19000.json','["高阁寒轻，映万朵芳梅，乱堆香雪。", "未待江南，早冠成花，先占一阳佳节。", "翦彩凝酥，无处学、天然奇绝。", "便寿阳妆，工夫费尽，艳姿终别。", "风里弄轻盈，掩珠英明莹，待腊飘烈。", "莫放芳菲歇。", "剩永宵欢赏，酒酣吟折。", "倒玉何妨，且听取、樽前新阕。", "怕笛声长，行云散尽，谩悲风月。"]'),
('song-ci-82','马索','无名氏','宋','宋词','song-ci','马索','[]','晓窗明，庭外寒梅向残月。',130,'宋词/ci.song.19000.json','["晓窗明，庭外寒梅向残月。", "吴溪庾岭，一枝偷把阳和泄。", "冰姿素艳，自然天赋，品格真殊常别。", "奈北人、不识南枝，唤作腊前杏先发。", "奇绝。", "照溪临水，素禽飞下，玉羽琼芳斗清洁。", "懊恨春来何晚，伤心邻妇争先折。", "多情立马，待得黄昏，疏影斜斜微酸结。", "恨马融、一声羌笛起处，纷纷落如雪。"]'),
('song-ci-83','定风波慢','无名氏','宋','宋词','song-ci','定风波慢','[]','漏新春、消息前村，数枝楚梅轻绽。',125,'宋词/ci.song.19000.json','["漏新春、消息前村，数枝楚梅轻绽。", "□雪艳精神，冰肤淡伫，姑射依稀见。", "冷香凝，金蕊浅。", "青女饶伊妒无限。", "堪羡。", "似寿阳妆阁，初匀粉面。", "纤条绿染。", "异群葩、不似和风扇。", "向深冬、免使游蜂舞蝶，撩拨春心乱。", "水亭边，山驿畔。", "立马行人暗肠断。", "吟恋。", "又忍随羌管，飘零千片。"]'),
('song-ci-84','庆春泽','无名氏','宋','宋词','song-ci','庆春泽','[]','晓风严，正萧然兔园，薄雾微罩。',121,'宋词/ci.song.19000.json','["晓风严，正萧然兔园，薄雾微罩。", "梅渐弄白，耸危苞、匀胜胭脂，半点琼瑰小。", "望江南、信息何杳。", "纵寿阳妍姿，学就新妆，暗香须少。", "幽艳满寒梢，更游蜂舞蝶，浑无飞绕。", "天赋品格，借东皇施巧。", "孤根占得春前俊，笑雪霜、谩欺容貌。", "况此花高强，终待和羹，肯饶芳草。"]'),
('song-ci-85','尉迟杯','无名氏','宋','宋词','song-ci','尉迟杯','[]','岁云暮。',127,'宋词/ci.song.19000.json','["岁云暮。", "叹光阴苒苒能几许。", "江梅尚怯馀寒，长安信音犹阻。", "春风无据。", "凭阑久，欲去还凝伫。", "忆溪边月下徘徊，暗香疏影庭户。", "朝来冻解霜消，南枝上，香英数点微露。", "把酒看花，无言有泪，还是那时情绪。", "花依旧、晨妆何处。", "谩赢得、花前愁千缕。", "尽高楼、画角频吹，任教纷纷飞絮。"]'),
('song-ci-86','木兰花慢','无名氏','宋','宋词','song-ci','木兰花慢','[]','望阳生渐布，见梅萼、暖初回。',122,'宋词/ci.song.19000.json','["望阳生渐布，见梅萼、暖初回。", "向雪里、一枝才苞，素艳已占春台。", "烟笼半含粉面，透清香、暗触满襟怀。", "可惜前村望断，魏林庾岭栽培。", "皑皑。", "嫩蕊清光，凝笑也恁风猥。", "但折取行人，途中对酒，不用尊罍。", "芬芳正当岁暮，谩休夸桃李苦相催。", "早报明年律应，又还依旧先开。"]'),
('song-ci-87','木兰花慢','无名氏','宋','宋词','song-ci','木兰花慢','[]','饱经霜古树，怕春寒、趁腊引青枝。',123,'宋词/ci.song.19000.json','["饱经霜古树，怕春寒、趁腊引青枝。", "逗一点阳和，隔年信息，远报佳期。", "凄葩未容易吐，但凝酥半面点胭脂。", "山路相逢驻马，暗香微染征衣。", "风前袅袅含情，虽不语、引长思。", "似怨感芳姿，山高水远，折赠何迟。", "分明为传驿使，寄一枝春色写新词。", "寄语市桥官柳，此先占了芳菲。"]'),
('song-ci-88','最高楼','无名氏','宋','宋词','song-ci','最高楼','[]','梅花好，千万君须爱。',98,'宋词/ci.song.19000.json','["梅花好，千万君须爱。", "比杏兼桃犹百倍。", "分明学得嫦娥样，不施朱粉天然态。", "蟾宫里，银河畔，风霜耐。", "岭上故人千里外。", "寄去一枝君要会。", "表江南信相思□。", "清香素艳应难对。", "满头宜向尊前戴。", "岁寒心，春消息，年年在。"]'),
('song-ci-89','尾犯','无名氏','宋','宋词','song-ci','尾犯','[]','轻风淅淅，正园林萧索，未回暖律。',124,'宋词/ci.song.19000.json','["轻风淅淅，正园林萧索，未回暖律。", "岭头昨夜，寒梅初发，一枝消息。", "香苞渐拆。", "天不许、雪霜欺得。", "望东吴，驿使西来，为谁折赠春色。", "玉莹冰清容质。", "迥不同、群花品格。", "如晓妆匀罢，寿阳香脸，徐妃粉额。", "好把琼英摘。", "频醉赏、舞筵歌席。", "休待听，呜咽临风，数声月下羌笛。"]'),
('song-ci-90','望远行','无名氏','宋','宋词','song-ci','望远行','[]','重阴未解，又早是、年时梅花争绽。',129,'宋词/ci.song.19000.json','["重阴未解，又早是、年时梅花争绽。", "暗香浮动，疏影横斜，月淡水清亭院。", "好是前村，雪里一枝开处，昨夜东风布暖。", "动行人、多少离愁肠断。", "凝恋。", "天赋自然雅态，似寿阳、初匀粉面。", "故人折赠，欣逢驿使，只恐陇头春晚。", "寄与高楼，休学龙吟三弄，留取琼花烂熳。", "正有人、同倚阑干争看。"]'),
('song-ci-91','宝鼎现','无名氏','宋','宋词','song-ci','宝鼎现','[]','东君著意，化工恩被，灼灼妖艳。',192,'宋词/ci.song.19000.json','["东君著意，化工恩被，灼灼妖艳。", "袅嫩梢轻蓓，萦风惹露，偏早香英绽。", "似向人、故矜夸标致，倚阑全如顾盼。", "尚困怯馀寒，柔情弱态，天真无限。", "断桥压柳时非浅。", "先百花、风光独占。", "当送腊初归，迎春欲至，芳姿偏婉娈。", "料碎翦就，缯纨辉丽，更把胭脂重染。", "自赋得、一般容冶，宛胜神仙妆脸。", "折送小阁幽窗，酷爱处、令亲几砚。", "尽孜孜观赏，不枉人称妙选。", "待密付、如膏雨泽。", "金玉仍妆点。", "任扰扰、百卉千花掩迹，一时羞见。"]'),
('song-ci-92','望梅花','无名氏','宋','宋词','song-ci','望梅花','[]','寒梅堪羡。',84,'宋词/ci.song.19000.json','["寒梅堪羡。", "堪羡轻苞初展。", "被天人、制巧妆素艳。", "群芳皆贱。", "碎翦月华千万片。", "缀向琼枝欲遍。", "小庭幽院。", "雪月相交无辨。", "影玲珑、何处临溪见。", "谢家新宴。", "别有清香风际转。", "缥缈著人头面。"]'),
('song-ci-93','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','南枝向暖。',125,'宋词/ci.song.19000.json','["南枝向暖。", "乍秀出庾岭，梅英初吐。", "玉颊轻匀，琼腮微抹，姑射冰容相许。", "几回立马凝伫，影映寒光霜妒。", "□尽占，在百花头上，严冬独步。", "芳华春意早，昨夜一番，雪里开无数。", "万蕊千梢，铅堆粉污，总是化工偏赋。", "月明暗香浮动，休使龙吟声苦。", "且留取。", "待时时，频倚阑干重顾。"]'),
('song-ci-94','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','腊残春未。',126,'宋词/ci.song.19000.json','["腊残春未。", "正候馆梅开，墙阴雪里。", "冷艳凝寒，孤根回暖，昨夜一枝春至。", "素苞暗香浮动，别有风流标致。", "谢池月，最相宜，疏影横斜临水。", "谁为。", "传驿骑。", "陇上故人，不见今千里。", "寄与东君，徒教知人，别后岁寒清意。", "乱山万叠何在，但有飞云天际。", "故园好，早归来，休恋繁桃秾李。"]'),
('song-ci-95','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','霜凝雪沍，正斗标临丑，三阳将近。',126,'宋词/ci.song.19000.json','["霜凝雪沍，正斗标临丑，三阳将近。", "万木凋零，群芳消歇，禁苑有梅初盛。", "异香似薰沈水，素色瑞如玉莹。", "人尽道，第一番，天遣先占春信。", "标韵。", "尤耿耿。", "月观水亭，谁解怜疏影。", "何逊扬州，拾遗东阁，一见便生清兴。", "望林止渴功就，不数夭桃繁杏。", "岁寒意，看结成秀子，归调商鼎。"]'),
('song-ci-96','喜迁莺','无名氏','宋','宋词','song-ci','喜迁莺','[]','一阳初起。',126,'宋词/ci.song.19000.json','["一阳初起。", "渐庾岭梅雪，才苞香蕊。", "品格清高，姿容闲雅，别受化工深意。", "放开独占严景，不使混同凡卉。", "微雨霁。", "似玉容寂寞，无言有泪。", "难比。", "凝素态，不共艳阳，桃杏争妍丽。", "疑是佳人，巧拈香酥，枝上玉纤轻缀。", "前村可惜无赏，好近天庭阶砌。", "成实后，有调和鼎鼐，一般滋味。"]'),
('song-ci-97','折红梅','无名氏','宋','宋词','song-ci','折红梅','[]','陇上残雪，曲水流断，淑气潜通。',133,'宋词/ci.song.19000.json','["陇上残雪，曲水流断，淑气潜通。", "群花冷未吐，夜来梅萼，数枝繁红。", "光夺化工。", "发艳色、不染东风。", "信凭晓风，难压精神，占青春未上，别是标容。", "天香渐杳，似蓬阙玉妃，酒困娇慵。", "只愁恐、上阳爱惜，和种移向瑶宫。", "西归驿使，折赠处、庾岭溪东。", "又须寄与，多感多情，道此花开早，未识游蜂。"]'),
('song-ci-98','折红梅','无名氏','宋','宋词','song-ci','折红梅','[]','倚花阑清晓，裴回探得，南枝初绽。',134,'宋词/ci.song.19000.json','["倚花阑清晓，裴回探得，南枝初绽。", "通春意、漏巧斗奇，东君首先回暖。", "盈盈素面。", "刚强点、胭脂深浅。", "是他自有，标格清香，恣千种妖饶，万般闲雅。", "移时细看。", "算浓雪严霜，怎生拘管。", "也拟是、小桃未蕊，依约杏添清伴。", "笛声休怨。", "怕恐使、群芳零乱。", "待须把酒，守著花枝，愿期与花枝，久长相见。"]'),
('song-ci-99','折红梅','无名氏','宋','宋词','song-ci','折红梅','[]','忆笙歌筵上，匆匆见了，□□相别。',132,'宋词/ci.song.19000.json','["忆笙歌筵上，匆匆见了，□□相别。", "红炉暖、画帘绣阁，曾共鬓边斜插。", "南枝向暖，北槛里、春风犹怯。", "也应别后，不减芳菲，念咫尺阑干，甚时重折。", "清风间发，如天与浓香，粉匀檀颊。", "纱窗影、故人凝处，冷落暮天残雪。", "一轩明月。", "怅望花争清切。", "便教尽放，都不思量，也须有，蓦然上心时节。"]'),
('song-ci-100','折红梅','无名氏','宋','宋词','song-ci','折红梅','[]','睹南翔征雁，疏林败叶，凋霜零乱。',134,'宋词/ci.song.19000.json','["睹南翔征雁，疏林败叶，凋霜零乱。", "独红梅、自守岁寒，天教最后开绽。", "盈盈水畔。", "疏影蘸、横斜清浅。", "化工似把，深色胭脂，怪姑射冰姿，剩与红间。", "谁人宠眷。", "待金锁不开，凭阑先看。", "曾飞落、寿阳粉额，妆成汉宫传遍。", "江南风暖。", "春信喜、一枝清远。", "对酒便好，折取奇苞，拈清香重嗅，举杯重劝。"]'),
('song-ci-101','满庭霜・满庭芳','无名氏','宋','宋词','song-ci','满庭霜・满庭芳','[]','一种江梅，偷传春信，夜来先绽南枝。',118,'宋词/ci.song.19000.json','["一种江梅，偷传春信，夜来先绽南枝。", "嫩苞寒萼，妆点缀胭脂。", "雪里浑迷素质，明月下、惟有香肌。", "山村路，人家舍窄，低亚水边篱。", "偏宜。", "寿阳女，新妆淡淡，粉面曾施。", "更胡笛羌管，塞曲争吹。", "陌上行人暂听，香风动、都入愁眉。", "音书杳，天涯望断，折寄拟凭谁。"]'),
('song-ci-102','满庭霜・满庭芳','无名氏','宋','宋词','song-ci','满庭霜・满庭芳','[]','园林萧索，亭台寂静，万木皆冻凋伤。',118,'宋词/ci.song.19000.json','["园林萧索，亭台寂静，万木皆冻凋伤。", "晓来初见，一品蜡梅芳。", "疑是黄酥点缀，超群卉、独占中央。", "堪闲玩，檀心紫蕊，清雅喷幽香。", "华堂。", "欢会处，陶陶共醉，相劝瑶觞。", "逞风流开早，不畏严霜。", "才子佳人属意，搜新句、吟咏诗章。", "歌筵罢，醺醺归去，蟾影照回廊。"]'),
('song-ci-103','黄莺儿','无名氏','宋','宋词','song-ci','黄莺儿','[]','香梢匀蕊先回暖，点点胭脂轻衬。',115,'宋词/ci.song.19000.json','["香梢匀蕊先回暖，点点胭脂轻衬。", "红苞隐映疏篁，红翠相间。", "方瑞雪乍晴时，爱日初添线。", "五云楼上遥看，似睹溪边，仙子妆面。", "堪羡。", "影转玉枝斜，艳拂朝霞浅。", "就中妖娆，独得芬芳，偏教容易琼苑。", "闻又报一阳时，不似莺声唤。", "肯与梅脸争春，靓笑群芳晚。"]'),
('song-ci-104','锦堂春・锦堂春慢','无名氏','宋','宋词','song-ci','锦堂春・锦堂春慢','[]','腊雪初晴，冰销凝泮，寻幽闲赏名园。',123,'宋词/ci.song.19000.json','["腊雪初晴，冰销凝泮，寻幽闲赏名园。", "时向长亭登眺，倚遍朱阑。", "拂面严风冻薄，满阶前、霜叶声乾。", "见小台深处，数叶江梅，漏泄春权。", "百花休恨开晚，奈韶华瞬息，常放教先。", "非是东君私语，和煦恩偏。", "欲寄江南音耗，念故人、隔阔云烟。", "一枝赠春色，待把金刀，翦倩人传。"]'),
('song-ci-105','瑶台月','无名氏','宋','宋词','song-ci','瑶台月','[]','严风凛冽，万木冻，园林肃静如洗。',143,'宋词/ci.song.19000.json','["严风凛冽，万木冻，园林肃静如洗。", "寒梅占早，争先暗吐香蕊。", "逞素容、探暖欺寒，遍妆点、亭台佳致。", "通一气，超群卉。", "值腊后，雪清丽。", "开筵共赏，南枝宴会。", "好折赠、东君驿使。", "把岭头信息远寄。", "遇诗朋酒侣，尊前吟缀。", "且优游，对景欢娱，更莫厌、陶陶沈醉。", "羌管怨，琼花缀。", "结子用调鼎饵。", "将军止渴，思得此味。"]'),
('song-ci-106','玉梅香慢','无名氏','宋','宋词','song-ci','玉梅香慢','[]','寒色犹高，春力尚怯。',117,'宋词/ci.song.19000.json','["寒色犹高，春力尚怯。", "微律先催梅拆。", "晓日轻烘，清风烦触，凝散数枝残雪。", "嫩英妒粉，嗟素艳、有蜂蝶。", "全似人人，向我依然，顿成离缺。", "裴回寸肠万结。", "又因花、暗成凝咽。", "拈蕊怜香，不禁恨深难绝。", "若是芳心解语，应共把、此情细细说。", "泪满阑干，无言强折。"]'),
('song-ci-107','双头莲','无名氏','宋','宋词','song-ci','双头莲','[]','触目庭台，当岁晚凋残，恁时方见。',122,'宋词/ci.song.19000.json','["触目庭台，当岁晚凋残，恁时方见。", "琼英细蕊，似美玉碾就，轻冰裁翦。", "暗想蜂蝶不知，有清香为援。", "深疑是，傅粉酡颜，何殊寿阳妆面。", "惟恐易落难留，仗何人巧把，名词褒羡。", "狂风横雨，枉堕落、细蕊纷纷千片。", "异日结实成阴，托称殊非浅。", "调鼎鼐，试作和羹，佳名方显。"]'),
('song-ci-108','夏云峰','无名氏','宋','宋词','song-ci','夏云峰','[]','琼结苞，酥凝蕊，粉心轻点胭脂。',113,'宋词/ci.song.19000.json','["琼结苞，酥凝蕊，粉心轻点胭脂。", "疑是素娥妆罢，玉翠低垂。", "化工深意，巧付与、别个标仪。", "怎奈向，风寒景里，独是开时。", "缘何不与春期。", "此花又、岂肯争竟芳菲。", "疑雨恨烟，忍见岭畔江湄。", "冷烟幽艳，曾不许、霜雪相欺。", "只恐向，笛声怨处，吹落残枝。"]'),
('song-ci-109','庆清朝','无名氏','宋','宋词','song-ci','庆清朝','[]','北陆严凝，东郊料峭，化工争付归期。',118,'宋词/ci.song.19000.json','["北陆严凝，东郊料峭，化工争付归期。", "前村夜来雪里，先见纤枝。", "想像靓妆淡伫，钗头翡翠茧蛾儿。", "冰壶莹，坐间静对，姑射仙姿。", "潇洒处，非艳冶最奇。", "是名赋、处士新诗。", "尊前坐曲，忍听羌管频吹。", "试问占先众卉，微笑不奈苦寒欺。", "何须问，定应未羡，桃李芳菲。"]'),
('song-ci-110','烛影摇红','无名氏','宋','宋词','song-ci','烛影摇红','[]','点点飞香，见梅知道春心透。',116,'宋词/ci.song.19000.json','["点点飞香，见梅知道春心透。", "怕寒不卷玉楼帘，羞与花同瘦。", "手拈青枝频嗅。", "诮冷落、蔷薇金斗。", "翻惊绿鬓，不似芳姿，年年依旧。", "绕破凝酥，满园桃李看看又。", "江南幽梦了无痕，啼晕残襟袖。", "鸳被有谁温绣。", "怎敢更、十分殢酒。", "伴君独自，几个黄昏，月明时候。"]'),
('song-ci-111','凤凰台忆吹箫・凤凰台上忆吹箫','无名氏','宋','宋词','song-ci','凤凰台忆吹箫・凤凰台上忆吹箫','[]','红蓓珠圆，素蕤玉净，南荒已报春还。',120,'宋词/ci.song.19000.json','["红蓓珠圆，素蕤玉净，南荒已报春还。", "便迤逦，云开五岭，雪霁群蛮。", "喜见东君信息，应不管、潘鬓新班。", "凭谁寄，心萦秋水，目断春山。", "长记小桥斜渡，潇洒处，苇篱茅舍三间。", "肯伴我、风光赏遍，月影疑残。", "好为调羹结子，玉弦冷、金鼎空闲。", "北枝畔，谁念嶰律犹寒。"]'),
('song-ci-112','东风第一枝','无名氏','宋','宋词','song-ci','东风第一枝','[]','腊雪犹凝，东风递暖，江南梅早先拆。',123,'宋词/ci.song.19000.json','["腊雪犹凝，东风递暖，江南梅早先拆。", "一枝经晓芬芳，几处漏春信息。", "孤根寒艳，料化工、别施恩力。", "迥不与、桃李争妍，自称寿阳妆饰。", "雪烂熳、怨蝶未知，嗟燕孤、画楼绮陌。", "暗香空写银笺，素艳谩传妙笔。", "王孙轻顾，便好与、移栽京国。", "更免逐、羌管凋零，冷落暮山寒驿。"]'),
('song-ci-113','东风第一枝','无名氏','宋','宋词','song-ci','东风第一枝','[]','溪侧风回，前村雾散，寒梅一枝初绽。',124,'宋词/ci.song.19000.json','["溪侧风回，前村雾散，寒梅一枝初绽。", "雪艳凝酥，冰肌莹玉，嫩条细软。", "歌台舞榭，似万斛、珠玑飘散。", "异众芳，独占东风，第一点装琼苑。", "青萼点、绛唇疏影，潇洒喷、紫檀龙麝。", "也知青女娇羞，寿阳懒匀粉面。", "江梅腊尽，武陵人、应知春晚。", "最苦是，皎月临风，画楼一声羌管。"]'),
('song-ci-114','昼夜乐','无名氏','宋','宋词','song-ci','昼夜乐','[]','一阳生后风光好。',118,'宋词/ci.song.19000.json','["一阳生后风光好。", "百花瘁，群木槁。", "南枝探暖欺寒，嘉卉争先占早。", "晓来风送清香杳。", "映园林、报春来到。", "素艳自超群，似姑射容貌。", "画堂开宴邀朋友，赏琼英，同欢笑。", "陇头寄信丁宁，楼上新妆斗巧。", "对景乘兴倾芳酒，拚沈醉、玉山频倒。", "结实用和羹，是真奇国宝。"]'),
('song-ci-115','柳初新','无名氏','宋','宋词','song-ci','柳初新','[]','千林凋谢严凝日。',102,'宋词/ci.song.19000.json','["千林凋谢严凝日。", "青帝许、梅花拆。", "孤根回暖，前村雪里，昨夜一枝凝白。", "天匠与、雕琼镂玉，淡然非、人间标格。", "别有神仙第宅。", "绣帘垂、碧纱窗隔。", "月明风送，清香苒苒，著摸美人词客。", "向晓来、芳苞乍摘。", "对菱花、倍添姿色。"]'),
('song-ci-116','蜡梅香','无名氏','宋','宋词','song-ci','蜡梅香','[]','爱日初长。',125,'宋词/ci.song.19000.json','["爱日初长。", "正园林才见，万木凋黄。", "槛外朝来，已见数枝，复欲掩映回廊。", "赐与东皇。", "付芳信、妆点江乡。", "想玉楼中，谁家艳质，试学新妆。", "桃杏苦寻芳。", "纵成蹊，岂能似恁清香。", "素艳妖娆，应是尽夜，曾与明月添光。", "瑞雪冰霜。", "浑疑是、粉蝶轻狂。", "待拚吟赏，休听画楼，横管悲伤。"]'),
('song-ci-117','满江红','无名氏','宋','宋词','song-ci','满江红','[]','林外溪边，深深见、一林寒雪。',116,'宋词/ci.song.19000.json','["林外溪边，深深见、一林寒雪。", "惟觉有、袭人襟袖，暗香不绝。", "天与风流标格在，肯同桃杏开时节。", "也须烦、玉手折将来，和明月。", "调鼎事，君休说。", "龙笛韵，空悲咽。", "将何助清赏，待传佳阕。", "君不见广平词赋丽，挥毫弄翰心如铁。", "便直饶、何逊在扬州，成虚设。"]'),
('song-ci-118','选冠子','无名氏','宋','宋词','song-ci','选冠子','[]','憔悴江山，凄凉古道，寒日澹烟残雪。',138,'宋词/ci.song.19000.json','["憔悴江山，凄凉古道，寒日澹烟残雪。", "行人立马，手折江梅，红萼素英初发。", "月下瑶台，弄玉飞琼，不老年年春色。", "被东君、唤遣娆红，高韵且饶清白。", "因动感、野水溪桥，竹篱茅舍，何似玉堂金阙。", "天教占了，第一枝春，何处不宜风月。", "休问庾岭止渴，金鼎调羹，有谁如得。", "傲冰霜、雅态清香，花里自称三绝。"]'),
('song-ci-119','选冠子','无名氏','宋','宋词','song-ci','选冠子','[]','庾岭烟光，江南风景，冷落岁寒庭院。',138,'宋词/ci.song.19000.json','["庾岭烟光，江南风景，冷落岁寒庭院。", "疏林万木冻折，孤根独犯，晓霜回暖。", "萼点胭脂，粉凝芳叶，依稀几枝初绽。", "上层楼、月夜凭阑，风送暗香清远。", "嗟往昔、汉妃临鸾，新妆才饰，艳绝人间金钿。", "东君信息，造化工夫，却笑众葩开晚。", "若是芳菲迅速，终与和羹，凤池仙馆。", "愿楼头、羌笛休吹，免使为花肠断。"]'),
('song-ci-120','落梅慢・落梅','无名氏','宋','宋词','song-ci','落梅慢・落梅','[]','带烟和雪，繁枝澹伫，谁将粉融酥滴。',126,'宋词/ci.song.19000.json','["带烟和雪，繁枝澹伫，谁将粉融酥滴。", "疏枝冷蕊厌群芳，年年常占春色。", "江路溪桥谩倒，袅袅风中无力。", "暗香浮动冰姿，明月里，想无花比高格。", "争奈光阴瞬息。", "动幽怨、潜生羌笛。", "新花斗巧，有天然闲态，倚阑堪惜。", "零乱残英片片，飞上舞筵歌席。", "断肠忍泪念前期，经岁还有芳容隔。"]'),
('song-ci-121','早梅香','无名氏','宋','宋词','song-ci','早梅香','[]','北帝收威，又探得早梅，漏春消息。',121,'宋词/ci.song.19000.json','["北帝收威，又探得早梅，漏春消息。", "粉蕊琼苞，拟将胭脂，轻染颜色。", "素质盈盈，终不许、雪霜欺得。", "奈化工、偏宜赋与，寿阳妆饰。", "独自逞冰姿，比夭桃繁杏，迥然殊别。", "为报山翁，逢此有花，樽前须攀折。", "醉赏吟恋，莫辜负、好天风月。", "恐笛声悲，纷纷便似，乱飞香雪。"]'),
('song-ci-122','马家春慢','无名氏','宋','宋词','song-ci','马家春慢','[]','珠箔风轻，绣帘浪卷，乍入人间蓬岛。',124,'宋词/ci.song.19000.json','["珠箔风轻，绣帘浪卷，乍入人间蓬岛。", "斗玉阑干，渐庭馆帘栊春晓。", "天许奇葩贵品，异繁杏、夭桃轻巧。", "命化工、倾国风流，□与一枝纤妙。", "樽前五陵年少。", "纵丹青异格，难别颜貌。", "悲露凝烟，困红娇额，微鼙低笑。", "须信浓香易歇，更莫惜、醉攀吟绕。", "待舞蝶游蜂，细把芳心都告。"]'),
('song-ci-123','望梅','无名氏','宋','宋词','song-ci','望梅','[]','画阑人寂，喜轻盈照水，犯寒先拆。',132,'宋词/ci.song.19000.json','["画阑人寂，喜轻盈照水，犯寒先拆。", "袅芳枝、云缕鲛绡，露浅浅涂黄，汉宫娇额。", "翦玉裁冰，已占断、江南春色。", "恨风前素艳，雪里暗香，偶成抛掷。", "如今眼穿故国。", "待拈花嗅蕊。", "时话思忆。", "想陇头、依约飘零，甚千里芳心，杳无消息。", "粉怯珠愁，又只恐、吹残羌笛。", "正斜飞、半窗晓月，梦回陇驿。"]'),
('song-ci-124','望梅','无名氏','宋','宋词','song-ci','望梅','[]','小寒时节，正同云暮惨，劲风朝烈。',131,'宋词/ci.song.19000.json','["小寒时节，正同云暮惨，劲风朝烈。", "信早梅、偏占阳和，向日暖临溪，一枝先发。", "时有香来，望明艳、瑶枝非雪。", "想玲珑嫩蕊，绰约横斜，旖旎清绝。", "仙姿更谁并列。", "有幽香映水，疏影笼月。", "且大家、留倚阑干，对绿醑飞觥，锦笺吟阅。", "桃李繁华，奈比此、芬芳俱别。", "等和羹大用，休把翠条谩折。"]'),
('song-ci-125','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','蓬莱宫殿。',103,'宋词/ci.song.19000.json','["蓬莱宫殿。", "去人间三万。", "玉体仙娥有谁见。", "被月朋雪友，邀下琼楼，溪桥畔。", "相对寒光浅浅。", "一般天上格，独带真香，冰麝犹嫌未清远。", "似太真望幸，一饷销凝，愁未惯。", "消瘦难禁素练。", "又只恐、东风破寒来，伴神女同归，阆峰仙苑。"]'),
('song-ci-126','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','摧残万物，不忍临轩槛。',105,'宋词/ci.song.19000.json','["摧残万物，不忍临轩槛。", "待得春来是早晚。", "向纷纷、雪里开，一枝见。", "清香满。", "漏泄东君先绽。", "暗香浮动、疏影横斜，只这些儿意不浅。", "怎禁他，澹澹地、匀粉弹红，争些儿、羞杀桃腮杏脸。", "为传语、东风共垂杨，奈辛苦，千丝万丝撩乱。"]'),
('song-ci-127','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','断云疏雨，冷落空山道。',105,'宋词/ci.song.19000.json','["断云疏雨，冷落空山道。", "匹马骎骎又重到。", "望孤村，两三间、茅屋疏篱，溪水畔、一簇芦花晚照。", "寻思行乐地，事去无痕，回首湘波与天杳。", "叹人生几度，能醉金钗，青镜里、赢得朱颜未老。", "又枝头、一点破黄昏，问客路春风，为谁开早。"]'),
('song-ci-128','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','梳风洗雨，兰蕙摧残后。',103,'宋词/ci.song.19000.json','["梳风洗雨，兰蕙摧残后。", "玉蕊檀芳做霜晓。", "板桥平，溪岸小。", "月下归来、乘露冷，赢得清香满抱。", "一枝春在手，细嗅重看，风味人间自然少。", "拟欲问东君，妙语难寻，搜索尽、池塘春草。", "想不是、诗人赏幽姿，纵竹外横斜，是谁知道。"]'),
('song-ci-129','摸鱼儿','无名氏','宋','宋词','song-ci','摸鱼儿','[]','岁华向晚，遥天布同云，霁雪轻飞。',140,'宋词/ci.song.19000.json','["岁华向晚，遥天布同云，霁雪轻飞。", "前村昨夜漏春光，楚梅先放南枝。", "叹东君运巧思。", "裁琼镂玉妆繁蕊。", "花中偏异。", "解向严冬逞芳菲。", "免使游蜂粉蝶戏。", "梁台上，汉宫里。", "殷勤仗、高楼羌管休吹。", "何妨留取凭阑干，大家吟玩欢醉。", "待明年，念芳草、王孙万里。", "归未得、仙源应是。", "又被花、开向天涯，泪洒东风对桃李。"]'),
('song-ci-130','春雪间早梅','无名氏','宋','宋词','song-ci','春雪间早梅','[]','梅将雪共春。',146,'宋词/ci.song.19000.json','["梅将雪共春。", "彩艳灼灼不相因。", "逐吹霏霏能争密，排枝碎碎巧妆新。", "谁令香来满坐，独使净敛无尘。", "芳意饶呈瑞，寒光助照人。", "玲珑次第开已遍，点缀坐来频。", "那是俱怀疑似，须知造化，两各逼天真。", "荧煌清影初乱眼，浩荡逸气忽迷神。", "未许琼花并重，将从玉树相亲。", "先期迎献岁，更同歌酒占兹辰。", "六华蜡蒂相辉映，轻盈敢自珍。"]'),
('song-ci-131','万年欢','无名氏','宋','宋词','song-ci','万年欢','[]','北陆风回，顿园林凋尽，庭院岑寂。',122,'宋词/ci.song.19000.json','["北陆风回，顿园林凋尽，庭院岑寂。", "潇洒寒梅，偷报艳阳消息。", "素澹英姿粹质。", "天赋与、出伦标格。", "一枝向、雪里初开，纤说清香寻得。", "神仙乍离姑射。", "更琼妆翠佩，冰莹肌骨。", "仿佛华清浴罢，懒匀脂泽。", "陇上休轰怨笛。", "且留取、累累成实。", "终须待、金鼎调羹，偏与群芳春色。"]'),
('song-ci-132','万年欢','无名氏','宋','宋词','song-ci','万年欢','[]','天气严凝，乍寒梅数枝，岭上开拆。',122,'宋词/ci.song.19000.json','["天气严凝，乍寒梅数枝，岭上开拆。", "傅粉凝脂，疑是素娥妆饰。", "先报阳和信息。", "更雪月、交光一色。", "因追念，往日欢游，共君携手同摘。", "别来又经岁隔。", "奈高楼梦断，无计寻觅。", "冷艳寒容，啼雨恨烟愁湿。", "似向人前泪滴。", "怎不使、伊家思忆。", "惟只恐，寂寞空枝，又随昨夜羌笛。"]'),
('song-ci-133','雨中花・夜行船','无名氏','宋','宋词','song-ci','雨中花・夜行船','[]','梦破江南春信，渐入江梅，暗香初发。',119,'宋词/ci.song.19000.json','["梦破江南春信，渐入江梅，暗香初发。", "乞与横斜疏影，为怜清绝。", "梁苑相如，平生有赋，未甘华发。", "便广寒争遣，韶华惊怨，讵妨轻折。", "扬州二十四桥歌吹，不道画楼声歇。", "生怕有、江边一树，要堆轻雪。", "老去苦无欢事，凌波空有纤袜。", "恨无好语，何郎风味，定教谁说。"]'),
('song-ci-134','早梅芳・喜迁莺','无名氏','宋','宋词','song-ci','早梅芳・喜迁莺','[]','冰唯清，玉唯润。',100,'宋词/ci.song.19000.json','["冰唯清，玉唯润。", "清润无风韵。", "此花风韵，自然清润传香粉。", "故应春意别，不使凡英恨。", "到春前腊后，长是寄芳信。", "此情闲，此意远。", "一点萦方寸。", "风亭水馆，解与行人破离恨。", "广寒宫未有，姑射仙曾认。", "向雪中月下，吟未尽。"]'),
('song-ci-135','婆罗门・婆罗门引','无名氏','宋','宋词','song-ci','婆罗门・婆罗门引','[]','江南地暖，数枝先得岭头春。',92,'宋词/ci.song.19000.json','["江南地暖，数枝先得岭头春。", "分付似、翦玉裁冰。", "素质偏怜匀澹，羞杀寿阳人。", "算多情留意，偏在东君。", "暗香旋生。", "对澹月与黄昏。", "寂寞谁家院宇，斜掩重门。", "墙头半开，却望雕鞍无故人。", "断肠处、容易飘零。"]'),
('song-ci-136','踏青游','无名氏','宋','宋词','song-ci','踏青游','[]','岭上梅残，堤畔柳眠娇小。',104,'宋词/ci.song.19000.json','["岭上梅残，堤畔柳眠娇小。", "绽数枝、横烟临沼。", "既大雅，且秾丽，繁而不扰。", "冒寒来、游蜂红蝶尚阻，年年占得春早。", "澹白轻红，清香迎芳道。", "更情与、碧天如扫。", "魏台妆，吴姬袖，妖妍多少。", "为传语、无言分付甘桃李，不比闲花浪草。"]'),
('song-ci-137','绛都春','无名氏','宋','宋词','song-ci','绛都春','[]','东君运巧。',121,'宋词/ci.song.19000.json','["东君运巧。", "向枝头点缀，琼英虽小。", "全是一般，风味花中最轻妙。", "横斜疏影当池沼。", "似弄粉、初临鸾照。", "众芳皆有，深红浅白，岂能争早。", "莫厌金樽频倒。", "把芳酒赏花，追陪欢笑。", "有愿告天，愿天多情休教老。", "奇花也愿休残了。", "免乐事、离多欢少。", "易老难叙衷肠，算天怎表。"]'),
('song-ci-138','雪梅香','无名氏','宋','宋词','song-ci','雪梅香','[]','岁将暮，云帆风卷正凄凉。',113,'宋词/ci.song.19000.json','["岁将暮，云帆风卷正凄凉。", "见梅花呈瑞，素英澹薄含芳。", "千片逞姿向江国，一枝无力倚邻墙。", "凝眸望，昨夜前村，雅态难忘。", "争妍斗鲜洁，皓彩寒辉，冷艳清香。", "姑射真人，更兼粉傅容光。", "梁苑奇才动佳句，汉宫娇态学严妆。", "无憀恨，独对光辉，别岸垂杨。"]'),
('song-ci-139','雪梅香','无名氏','宋','宋词','song-ci','雪梅香','[]','冻云深，六出瑶花满长空。',114,'宋词/ci.song.19000.json','["冻云深，六出瑶花满长空。", "渐飘来呈瑞，皑皑万里皆同。", "荒野枯冰竦欲折，小亭寒梅吐轻红。", "香清□，疏影横斜，照水熔熔。", "临风。", "传芳信，驿使来自，庾岭南峰。", "占早争先，总无粉蝶游蜂。", "妆点鲜妍汉宫里，羌笛呜咽画楼东。", "赏南枝，倚阑凝望，时见征鸿。"]'),
('song-ci-140','千秋岁','无名氏','宋','宋词','song-ci','千秋岁','[]','腊残春近。',87,'宋词/ci.song.19000.json','["腊残春近。", "江上梅开粉。", "一枝漏泄东君信。", "寿阳妆面靓，姑射冰姿莹。", "似浅杏。", "清香试与分明认。", "只恐霜侵破，又怕风吹损。", "待折取，还不忍。", "莫将花上貌，来点多情鬓。", "凝睇久，行人立马成遗恨。"]'),
('song-ci-141','月上海棠','无名氏','宋','宋词','song-ci','月上海棠','[]','南枝昨夜先回暖。',86,'宋词/ci.song.19000.json','["南枝昨夜先回暖。", "便临寒、开花暗香远。", "化工忒□，把琼瑶、恣情裁翦。", "皑皑的、点缀梢头又遍。", "横斜影蘸清溪浅。", "似玉人、临鸾照粉面。", "大家休折，且迟留、对花开宴。", "祝东风、吹作和羹未晚。"]'),
('song-ci-142','眼儿媚','无名氏','宋','宋词','song-ci','眼儿媚','[]','前时同醉曲江滨。',58,'宋词/ci.song.19000.json','["前时同醉曲江滨。", "初样小梅春。", "花残人远，几经风雨，结子青青。", "谁知别后无肠断，行尽水云程。", "修峰万仞，邮亭息鞚，独对黄昏。"]'),
('song-ci-143','相见欢','无名氏','宋','宋词','song-ci','相见欢','[]','月明疏影林间。',45,'宋词/ci.song.19000.json','["月明疏影林间。", "水潺潺。", "一点浓香十里、渡关山。", "且莫负。", "好分付。", "冷无眠。", "只怕笛声呜咽、到愁边。"]'),
('song-ci-144','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅枝。',32,'宋词/ci.song.19000.json','["捣练子，赋梅枝。", "暖借东风次第吹。", "自是百花留不住，让教先发放春归。"]'),
('song-ci-145','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅芳。',32,'宋词/ci.song.19000.json','["捣练子，赋梅芳。", "柳绿桃红谩点妆。", "试问仙标横竹外，敢同高节伴冰霜。"]'),
('song-ci-146','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅红。',32,'宋词/ci.song.19000.json','["捣练子，赋梅红。", "玉体凝酥半醉中。", "诗酒兴来须要早，忍看红雨落西东。"]'),
('song-ci-147','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅香。',32,'宋词/ci.song.19000.json','["捣练子，赋梅香。", "蕙魄兰魂又再阳。", "只为人间无著处，借他龙笛返仙乡。"]'),
('song-ci-148','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅英。',32,'宋词/ci.song.19000.json','["捣练子，赋梅英。", "枝上商量细细生。", "不是根株贪结子，被吹羌笛两三声。"]'),
('song-ci-149','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅妆。',32,'宋词/ci.song.19000.json','["捣练子，赋梅妆。", "镜里佳人傅粉忙。", "额子画成终未是，更须插向鬓云傍。"]'),
('song-ci-150','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅音。',32,'宋词/ci.song.19000.json','["捣练子，赋梅音。", "云底江南树树深。", "怅望故人千里远，故将春色寄芳心。"]'),
('song-ci-151','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','捣练子，赋梅青。',32,'宋词/ci.song.19000.json','["捣练子，赋梅青。", "休共檀梨取次争。", "叶底青青如豆小，已知金鼎待和羹。"]'),
('song-ci-152','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','冷落人间昼掩门。',64,'宋词/ci.song.19000.json','["冷落人间昼掩门。", "泠泠残粉縠成纹。", "几枝疏影溪边见，一拂清香马上闻。", "冰作质，月为魂。", "萧萧细雨入黄昏。", "人间暂识东风信，梦绕江南云水村。"]'),
('song-ci-153','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','梦草池塘春意回。',64,'宋词/ci.song.19000.json','["梦草池塘春意回。", "巧传消息是寒梅。", "北枝休羡南枝暖，凭仗东风次第开。", "酥点萼，粉匀腮。", "未攀已得好香来。", "西邻且莫吹羌笛，留待行春把酒杯。"]'),
('song-ci-154','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','雪屋冰床深闭门。',64,'宋词/ci.song.19000.json','["雪屋冰床深闭门。", "缟衣应笑织成纹。", "雨中清泪无人见，月下幽香只自闻。", "长在眼，远销魂。", "玉奴那忍负东昏。", "隅然谪堕行云去，不入春风花柳村。"]'),
('song-ci-155','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','小槛冬深未破梅。',64,'宋词/ci.song.19000.json','["小槛冬深未破梅。", "孤枝清瘦耐风埃。", "月中寂寞无人管，雪里萧疏近水栽。", "微雨过，早春回。", "阳和消息自天来。", "才根多谢东君力，琼蕊苞红一夜开。"]'),
('song-ci-156','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','春入江梅破晚寒。',64,'宋词/ci.song.19000.json','["春入江梅破晚寒。", "冻枝惊鹊语声乾。", "离愁满抱人谁问，病耳初闻心也宽。", "风细细，露珊珊。", "可堪驿使道漫漫。", "斜梢待得人来后，簪向乌云仔细看。"]'),
('song-ci-157','鹧鸪天','无名氏','宋','宋词','song-ci','鹧鸪天','[]','别得东皇造化恩。',64,'宋词/ci.song.19000.json','["别得东皇造化恩。", "黛消铅褪自天真。", "耻随庾岭花争白，疑是东篱菊返魂。", "风淡淡，月盈盈。", "麝煤沈馥动孤根。", "寒蝉冷蝶知何处，惟有蜂房不待春。"]'),
('song-ci-158','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','水净烟闲不染尘。',48,'宋词/ci.song.19000.json','["水净烟闲不染尘。", "小山斜卧几枝春。", "夜寒香惹一溪云。", "粉淡朱轻妆未了，十分孤迥好精神。", "为伊清瘦却愁人。"]'),
('song-ci-159','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','苒苒飞云横画阑。',48,'宋词/ci.song.19000.json','["苒苒飞云横画阑。", "黄昏烟雨满江干。", "小梅香浅不禁寒。", "楼上风轻帘不卷，酒红销尽昼妆残。", "玉人斜拈一枝看。"]'),
('song-ci-160','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','十月开花是子真。',48,'宋词/ci.song.19000.json','["十月开花是子真。", "小春分付与精神。", "折来含露晓妆新。", "暖意便从窗下见，粉容何待鉴中匀。", "宛然长似玉华清。"]'),
('song-ci-161','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','梅粉初娇拟嫩腮。',48,'宋词/ci.song.19000.json','["梅粉初娇拟嫩腮。", "一枝春信腊前开。", "玉英珠颗傍妆台。", "明月泛将疏影去，暗香疑是那人来。", "消魂独自立空阶。"]'),
('song-ci-162','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','翦碎红娘舞旧衣。',48,'宋词/ci.song.19000.json','["翦碎红娘舞旧衣。", "汉宫妆粉满琼枝。", "东风来晚未曾知。", "颜色不同香小异，瑶台春近宴回时。", "宝灯相引素娥归。"]'),
('song-ci-163','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','梅与为名蜡与容。',48,'宋词/ci.song.19000.json','["梅与为名蜡与容。", "寒枝偏缀小金钟。", "插时只恐鬓边熔。", "疑是佳人薰麝月，起来风味入怀浓。", "暗香依旧月朦胧。"]'),
('song-ci-164','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','梅与称名蜡与黄。',48,'宋词/ci.song.19000.json','["梅与称名蜡与黄。", "枝无袅娜色无光。", "掩檀欺麝冠群芳。", "结处定缘蜂力就，开时微带蜜脾香。", "风标不减寿阳妆。"]'),
('song-ci-165','太常引','无名氏','宋','宋词','song-ci','太常引','[]','行云踪迹杳无期。',62,'宋词/ci.song.19000.json','["行云踪迹杳无期。", "梅梢上、又春归。", "不道久别离。", "这一度、清香为谁。", "多情嘱付，庾楼羌管，凭仗且休吹。", "留取两三枝。", "待和泪、封将寄伊。"]'),
('song-ci-166','太常引','无名氏','宋','宋词','song-ci','太常引','[]','江梅开似蕊珠宫。',62,'宋词/ci.song.19000.json','["江梅开似蕊珠宫。", "报桃李、又春风。", "蓦岫看前峰。", "待摘取、横斜盏中。", "魏林楚岭，素妆清绝，不与众芳同。", "和月映帘栊。", "羡几点、施朱太红。"]'),
('song-ci-167','小重山','无名氏','宋','宋词','song-ci','小重山','[]','竹里清香帘影明。',68,'宋词/ci.song.19000.json','["竹里清香帘影明。", "一枝照水弄精神。", "楼头横管罢龙吟。", "休三弄，留为与调羹。", "紫陌与青门。", "溪边浮动处，绝纤尘。", "等闲休付寿阳人。", "潇洒处，月淡又黄昏。"]'),
('song-ci-168','小重山','无名氏','宋','宋词','song-ci','小重山','["\u6d1e\u5ead\u6e56"]','不是蛾儿不是酥。',68,'宋词/ci.song.19000.json','["不是蛾儿不是酥。", "化工应道也难摹。", "花儿清瘦影儿孤。", "多情处，时有暗香浮。", "试问玉肌肤。", "夜来霜雪重，怕寒无。", "一枝欲寄洞庭姝。", "可惜许，只有雁衔芦。"]'),
('song-ci-169','小重山','无名氏','宋','宋词','song-ci','小重山','[]','天际春来都为君。',70,'宋词/ci.song.19000.json','["天际春来都为君。", "依稀丹萼动，泛红云。", "恼人天气近黄昏。", "霜月底，山麝斗微薰。", "标格自天真。", "寿阳仙骨瘦，玉无纹。", "芳容临鉴洗馀醺。", "双蛾稳，花面两难分。"]'),
('song-ci-170','西地锦','无名氏','宋','宋词','song-ci','西地锦','[]','不与群花相续。',56,'宋词/ci.song.19000.json','["不与群花相续。", "独占春光速。", "幽香远远散西东，惟竹篱茅屋。", "羌管谁调一曲。", "送月夜、犹芬馥。", "凭君折取向玉堂，只这些清福。"]'),
('song-ci-171','西地锦','无名氏','宋','宋词','song-ci','西地锦','[]','岭上初消残雪。',56,'宋词/ci.song.19000.json','["岭上初消残雪。", "有梅花先坼。", "东君造化多成翠，巧风韵奇绝。", "小院黄昏时节。", "暗香浮、疏影横斜。", "寄取和羹未晚，却免教攀折。"]'),
('song-ci-172','踏歌','无名氏','宋','宋词','song-ci','踏歌','[]','带雪。',102,'宋词/ci.song.19000.json','["带雪。", "向南枝，一朵江梅坼。", "许多时、甚处收香白。", "占千葩百卉、先春色。", "拟莹洁。", "正广寒宫殿人窥隔。", "销魂处、画角数声彻。", "暗香浮动黄昏月。", "最潇洒处最奇绝。", "孤标迥、不与群芳列。", "吟赏竟连宵，痛饮无休歇。", "输有心牧童偷折。"]'),
('song-ci-173','感皇恩','无名氏','宋','宋词','song-ci','感皇恩','[]','翦玉蹙花苞，腊寒时候。',81,'宋词/ci.song.19000.json','["翦玉蹙花苞，腊寒时候。", "间竹横溪自清瘦。", "黄昏时候，拂拂暗香微透。", "寿阳妆面恨，眉频斗。", "堪赏占断，三春先手。", "不是东君意偏有。", "百花羞尽，故教孤芳独秀。", "只愁明月夜，笛声奏。"]'),
('song-ci-174','枕屏儿','无名氏','宋','宋词','song-ci','枕屏儿','[]','江国春来，留得素英肯住。',94,'宋词/ci.song.19000.json','["江国春来，留得素英肯住。", "月笼香，风弄粉，诗人尽许。", "酥蕊嫩，檀心小，不禁风雨。", "须东君、与他做主。", "繁杏夭桃，颜色浅深难驻。", "奈芳容，全不称，冰姿伴侣。", "水亭边，山驿畔，一枝风措。", "十分似、那人淡伫。"]'),
('song-ci-175','忆秦娥','无名氏','宋','宋词','song-ci','忆秦娥','[]','瑶台月。',56,'宋词/ci.song.19000.json','["瑶台月。", "寒光零乱蒙香雪。", "蒙香雪。", "横枝疏影，动人清彻。", "分明姑射神仙骨。", "冰姿雪里难埋没。", "难埋没。", "百花头上，为春先发。"]'),
('song-ci-176','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','梅花好，满树锦江边。',64,'宋词/ci.song.19000.json','["梅花好，满树锦江边。", "不似武陵曾见日，清香冷艳扶尊前。", "销得醉留连。", "凭造化，分付与花权。", "已共雪光争腊早，且将春信为君传。", "桃李莫夸先。"]'),
('song-ci-177','望江南・忆江南','无名氏','宋','宋词','song-ci','望江南・忆江南','[]','梅花好，依约透春光。',64,'宋词/ci.song.19000.json','["梅花好，依约透春光。", "记得佳人初睡起，巧临鸾鉴试新妆。", "粉面斗琼芳。", "江亭上，绕树嗅清香。", "拟把一枝传信去，不知何处是兰房。", "独自暗凄凉。"]'),
('song-ci-178','品令','无名氏','宋','宋词','song-ci','品令','[]','山重云起。',80,'宋词/ci.song.19000.json','["山重云起。", "断桥外、池塘水。", "晓来风定，竹枝相亚，残阳影里。", "多少风流，都在冷香疏蕊。", "江南千里。", "问折得、谁能寄。", "几番归去，酒醒月满，阑干十二。", "且隐深溪，免笑等闲桃李。"]'),
('song-ci-179','品令','无名氏','宋','宋词','song-ci','品令','[]','一阳生暖。',80,'宋词/ci.song.19000.json','["一阳生暖。", "见庾岭、梅初绽。", "琼枝玉树，浑如傅粉，寿阳妆面。", "疏影横斜，隐隐月溪清浅。", "前村雪里，向雪里、真难辨。", "倩谁说与，高楼人道，休吹羌管。", "且与从容，来岁和羹未晚。"]'),
('song-ci-180','品令','无名氏','宋','宋词','song-ci','品令','[]','雪花飞堕。',80,'宋词/ci.song.19000.json','["雪花飞堕。", "有人报、江南意。", "博山炉畔，砚屏风里，铜盘寒水。", "赋得幽香，疏淡数枝相倚。", "绛肤黄蕊。", "另一种、高标致。", "笛中芳信，岭头春色，不传紫红。", "寂寞闲亭，月下夜阑影碎。"]'),
('song-ci-181','相思引','无名氏','宋','宋词','song-ci','相思引','[]','笑盈盈，香喷喷。',58,'宋词/ci.song.19000.json','["笑盈盈，香喷喷。", "姑射仙人风韵。", "天与肌肤常素嫩。", "玉面犹嫌粉。", "斜倚小楼凝远信。", "多少往来人恨。", "只恐乘云春雨困。", "迤逦娇容褪。"]'),
('song-ci-182','相思引','无名氏','宋','宋词','song-ci','相思引','[]','半苞红，微露粉。',58,'宋词/ci.song.19000.json','["半苞红，微露粉。", "潇洒早梅犹嫩。", "香入梦魂残酒醒。", "芳意相牵引。", "不畏晓霜侵手冷。", "欲折一枝芳信。", "折得却无人寄问。", "争信相思损。"]'),
('song-ci-183','庆金枝','无名氏','宋','宋词','song-ci','庆金枝','[]','新春入旧年，绽梅萼、一枝先。',62,'宋词/ci.song.19000.json','["新春入旧年，绽梅萼、一枝先。", "陇头人待信音传。", "算楚岸、未香残。", "小枕风雪凭栏干。", "下帘幕、护轻寒。", "年华永占入芳筵。", "付尊前、渐成欢。"]'),
('song-ci-184','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','天威乱糁琼蕤密。',52,'宋词/ci.song.19000.json','["天威乱糁琼蕤密。", "一光吞尽千山碧。", "梅与雪争妍。", "孤香风暗传。", "玉骨从来瘦。", "不奈春僝僽。", "羌管一声残。", "水乡生暮寒。"]'),
('song-ci-185','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','黄昏月暗清溪色。',52,'宋词/ci.song.19000.json','["黄昏月暗清溪色。", "帘垂小阁霜华白。", "一夜玉玲珑。", "横斜水月中。", "小行孤影动。", "生怕惊花梦。", "半夜得春归。", "屏山人未归。"]'),
('song-ci-186','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','霜天不管青山瘦。',52,'宋词/ci.song.19000.json','["霜天不管青山瘦。", "轻云浅拂修眉皱。", "烟树隔潇湘。", "隔帆吹异香。", "影残春恨小。", "淡墨敧斜倒。", "无处著消愁。", "笛寒人倚楼。"]'),
('song-ci-187','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','梅蕊露鲜妍。',66,'宋词/ci.song.19000.json','["梅蕊露鲜妍。", "雪态冰恣巧耐寒。", "南北枝头香不断，堪观。", "露浥琼苞粉未乾。", "画手写应难。", "横管休吹恐易残。", "留得佳人临晓际，凭栏。", "试把新妆比并看。"]'),
('song-ci-188','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','把酒对江梅。',66,'宋词/ci.song.19000.json','["把酒对江梅。", "个是花中第一枝。", "冰雪肌肤潇洒态，须知。", "姑射仙人正似伊。", "东阁赋新诗。", "惭愧当年杜拾遗。", "月里何人横玉笛，休吹。", "正是芳梢著子时。"]'),
('song-ci-189','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','莫作俗花看。',66,'宋词/ci.song.19000.json','["莫作俗花看。", "珠有清香雪太寒。", "拟把千锺酬国艳，林间。", "醉倒犹嫌酒量悭。", "欲去更重攀。", "送尽斜阳未忍还。", "争得重城休上销，留连。", "借取冰轮照玉颜。"]'),
('song-ci-190','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','醉拈一枝春。',66,'宋词/ci.song.19000.json','["醉拈一枝春。", "此意谁人会得君。", "嫩白轻红才入手，盈盈。", "一似前时酒半醺。", "心眼两相亲。", "绝代风流恼杀人。", "粉蝶霜禽休怅望，叮咛。", "只要扬州作主盟。"]'),
('song-ci-191','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','栏槛对幽堂，翠叶枝头万朵霜。',66,'宋词/ci.song.19000.json','["栏槛对幽堂，翠叶枝头万朵霜。", "檀口乍开龙麝喷，非常。", "体胜佳人异骨香。", "花与月争光。", "偏引蜂儿戏绕墙。", "不与群英争艳丽，芬芳。", "溪落东君只淡妆。"]'),
('song-ci-192','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','凛冽苦寒时。',66,'宋词/ci.song.19000.json','["凛冽苦寒时。", "万木凋枯力渐衰。", "昨夜前村深雪里，春回。", "庾岭南枝绽早梅。", "映月与清辉。", "驿使加鞭喜探回。", "风送馨香来小院，芳时。", "料想群花尚未知。"]'),
('song-ci-193','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','把酒祝江梅。',66,'宋词/ci.song.19000.json','["把酒祝江梅。", "春到南枝早早开。", "人在陇头凝望久，徘徊。", "驿使如今尚未来。", "寄语莫相催。", "直待东风细剪裁。", "只恐未能传信息，妆台。", "先要飞来衬粉腮。"]'),
('song-ci-194','戛金钗','无名氏','宋','宋词','song-ci','戛金钗','[]','梅蕊破初寒，春来何太早。',78,'宋词/ci.song.19000.json','["梅蕊破初寒，春来何太早。", "轻傅粉、向人先笑。", "比并年时较些少。", "愁底事，十分清瘦了。", "影静野塘空，香寒霜月晓。", "风韵减、酒醒花老。", "可杀多情要人道。", "疏竹外、一枝斜更好。"]'),
('song-ci-195','人月圆','无名氏','宋','宋词','song-ci','人月圆','[]','园林已有春消息，寻待岭头梅。',59,'宋词/ci.song.19000.json','["园林已有春消息，寻待岭头梅。", "一枝清淡，疏疏带雪，昨夜初开。", "芳心几点，东风多少，先为传来。", "不随红紫，纷纷闹闹，蝶妒蜂猜。"]'),
('song-ci-196','一斛珠','无名氏','宋','宋词','song-ci','一斛珠','[]','寒冰初泮。',67,'宋词/ci.song.19000.json','["寒冰初泮。", "岭头一朵香苞绽。", "菡萏如画真堪羡。", "休逞随风、柳絮垂金线。", "月宫每嫖开较晓。", "寿阳又喜匀妆面。", "更闻何处鸣羌管。", "一曲一声、惹起神撩乱。"]'),
('song-ci-197','解佩令','无名氏','宋','宋词','song-ci','解佩令','[]','蕙兰无韵，桃李堪扫。',84,'宋词/ci.song.19000.json','["蕙兰无韵，桃李堪扫。", "都不数、凡花闲草。", "对月临风，长是伊、故来相恼。", "和魂梦、被他香到。", "江头陇畔，争先占早。", "一枝枝、看来总好。", "似凭风标，待发愿、春前祈祷。", "祝东君、放教不老。"]'),
('song-ci-198','醉花阴','无名氏','宋','宋词','song-ci','醉花阴','["\u897f\u6e56"]','粉妆一捻和香聚。',62,'宋词/ci.song.19000.json','["粉妆一捻和香聚。", "教露华休妒。", "今日在尊前，只为情多，脉脉都无语。", "西湖雪过留难住。", "指广寒归去。", "去后又明年，人在江南。", "梦到花开处。"]'),
('song-ci-199','醉花阴','无名氏','宋','宋词','song-ci','醉花阴','[]','霓裳浅艳来何处。',62,'宋词/ci.song.19000.json','["霓裳浅艳来何处。", "不是闲云雨。", "雪苑旧精神，燕席吟窗，昨夜生轻素。", "阑珊岂是东风妒。", "惜暗香分付。", "香在玉清宫，不惹年华，只带春寒去。"]'),
('song-ci-200','扫地舞','无名氏','宋','宋词','song-ci','扫地舞','[]','酥点萼。',74,'宋词/ci.song.19000.json','["酥点萼。", "玉碾萼。", "点时碾时香雪薄。", "才折得。", "春方弱。", "半掩朱扉，垂绣幕。", "怕吹落。", "拈一饷。", "嗅一饷。", "拈时嗅时宿酒忘。", "春争上。", "不忍放。", "待对菱花，斜插向。", "宝钗上。"]'),
('song-ci-201','玉楼人','无名氏','宋','宋词','song-ci','玉楼人','[]','去年寻处曾持酒。',66,'宋词/ci.song.19000.json','["去年寻处曾持酒。", "还是向、南枝见后。", "宜霜宜雪精神，没些儿、风味减旧。", "先春似与群芳斗。", "暗度香、不待频嗅。", "有人笑折归来，玉纤长、尽露罗袖。"]'),
('song-ci-202','燕归梁','无名氏','宋','宋词','song-ci','燕归梁','[]','月里云装冷艳裁。',62,'宋词/ci.song.19000.json','["月里云装冷艳裁。", "独秀在岩隈。", "雪中昨夜一枝开。", "探春色、岁前来。", "清香折得，多情寄与，人向陇头回。", "凭君移取近瑶台。", "伴桃李、日边栽。"]'),
('song-ci-203','忆人人・鹊桥仙','无名氏','宋','宋词','song-ci','忆人人・鹊桥仙','[]','密传春信。',68,'宋词/ci.song.19000.json','["密传春信。", "微妆晓景，淡伫香苞欲绽。", "临风虽未吐芳心，奈暗露、盈盈粉面。", "何人月下，一声长笛，即是飞英凌乱。", "凭阑无惜赏芳姿，更莫待、倾筐已满。"]'),
('song-ci-204','忆人人・鹊桥仙','无名氏','宋','宋词','song-ci','忆人人・鹊桥仙','[]','前村深雪，难寻幽艳，无奈清香漏绽。',68,'宋词/ci.song.19000.json','["前村深雪，难寻幽艳，无奈清香漏绽。", "烟梢霜萼出墙时，似暗妒、寿阳妆面。", "幽香浮动，无缘攀赏，但只心劳魂乱。", "不辞他日醉琼姿，又只恐、阴成子满。"]'),
('song-ci-205','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','阳和欲报春来也，先上南枝。',52,'宋词/ci.song.19000.json','["阳和欲报春来也，先上南枝。", "桃李休疑。", "折遍香梢人未知。", "黄昏小院谁攀折，疏影斜敧。", "半掩朱扉。", "旋嗅清香月下归。"]'),
('song-ci-206','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','江南春信梅先赋，休道春迟。',52,'宋词/ci.song.19000.json','["江南春信梅先赋，休道春迟。", "映竹开时。", "姑射仙人雪作肌。", "青楼且莫吹羌管，留劝金卮。", "折取高枝。", "香满名园蝶未知。"]'),
('song-ci-207','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','南枝淡伫无妖艳，蜡蕊羞黄。',52,'宋词/ci.song.19000.json','["南枝淡伫无妖艳，蜡蕊羞黄。", "争似红妆。", "不假施朱弄晓光。", "雪融日暖琼肌腻，酒晕生香。", "桃脸相当。", "尤笑桃花混众芳。"]'),
('song-ci-208','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','幽芳莹白前村里，岂藉春工。',52,'宋词/ci.song.19000.json','["幽芳莹白前村里，岂藉春工。", "胜尽群红。", "琼拈凝酥向不同。", "一声羌管愁人处，片片西东。", "睹此遗踪。", "不怨狂风怨马融。"]'),
('song-ci-209','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','东君有意观群卉，故放争先。',52,'宋词/ci.song.19000.json','["东君有意观群卉，故放争先。", "带露含烟。", "对月偏宜映水边。", "琼苞素蕊胭脂淡，雪后风前。", "堪赏堪怜。", "曾与歌楼佐管弦。"]'),
('song-ci-210','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','群芳尽老园林烬，独有寒梅。',52,'宋词/ci.song.19000.json','["群芳尽老园林烬，独有寒梅。", "探得春回。", "昨夜前村一朵开。", "轻盈雪里孤根秀，素脸香腮。", "羌管休催。", "留取琼葩佐酒杯。"]'),
('song-ci-211','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','霜风漏泄春消息，折破孤芳。',52,'宋词/ci.song.19000.json','["霜风漏泄春消息，折破孤芳。", "野兴彷徨。", "姑射神仙触处藏。", "新妆不假施朱粉，雪月交光。", "欲赠东皇。", "冷淡龙涎点点香。"]'),
('song-ci-212','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','烟笼淡月寒宵永，悄悄帘栊。',52,'宋词/ci.song.19000.json','["烟笼淡月寒宵永，悄悄帘栊。", "微度香风。", "几点梅开小院中。", "拥衾敧枕难成寐，萧寺初钟。", "雁响遥空。", "家在青山千万重。"]'),
('song-ci-213','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','飞琼欲赴瑶台宴，先具威仪。',52,'宋词/ci.song.19000.json','["飞琼欲赴瑶台宴，先具威仪。", "云驾霓衣。", "从者皆骑白凤飞。", "人间尽变为银海，此景偏奇。", "姑射冰姿。", "昨夜前村见一枝。"]'),
('song-ci-214','采桑子','无名氏','宋','宋词','song-ci','采桑子','[]','熔金脱得花钿小，点缀琼枝。',52,'宋词/ci.song.19000.json','["熔金脱得花钿小，点缀琼枝。", "月淡风微。", "露浥香肌自是奇。", "玉人呵手昂头翦，纤鬓边垂。", "似簇蜂儿。", "春入芳容不肯飞。"]'),
('song-ci-215','寻梅','无名氏','宋','宋词','song-ci','寻梅','[]','幽香浅浅湿未透。',72,'宋词/ci.song.19000.json','["幽香浅浅湿未透。", "认雪底、思来始有。", "翦裁尚觉琼瑶皱。", "苦寒中、越恁骨清肌瘦。", "东风气象园林旧。", "又去年、而今时候。", "急宜小摘当尊酒。", "选一枝、且付玉人纤手。"]'),
('song-ci-216','红','无名氏','宋','宋词','song-ci','红','[]','粉香尤嫩，衾寒可惯。',76,'宋词/ci.song.19000.json','["粉香尤嫩，衾寒可惯。", "怎奈向、春心已转。", "玉容别是，一般闲婉。", "悄不管、桃红香浅。", "月影帘栊，金琼波面。", "渐细细、香风满院。", "一枝折寄，故人虽远，辄莫使、江南信断。"]'),
('song-ci-217','武林春・武陵春','无名氏','宋','宋词','song-ci','武林春・武陵春','[]','昨夜前村深雪里，春信为谁传。',56,'宋词/ci.song.19000.json','["昨夜前村深雪里，春信为谁传。", "风送清香满座间。", "不用热沈檀。", "竹外一枝斜更好，偏称玉人攀。", "休放游蜂去又还。", "嫌怕损芳颜。"]'),
('song-ci-218','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','临鸾常恁整妆梅。',76,'宋词/ci.song.19000.json','["临鸾常恁整妆梅。", "枝枝仙艳月中开。", "可杀天心、故与多端丽，那更罗衣峭窄裁。", "几回瞻觑魂消黯，芙蕖匀透双腮。", "好将心事、都分付与，时暂到、小庭来。", "玉砌红芳点绿苔。"]'),
('song-ci-219','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','汉宫铅粉净无痕。',64,'宋词/ci.song.19000.json','["汉宫铅粉净无痕。", "蜡点寒梢水畔村。", "忍犯冰霜欺竹柏，肯同雪月吊兰荪。", "骚人咏去清诗健，驿使传来旧典存。", "病眼浑疑春思早，一枝聊洗画图昏。"]'),
('song-ci-220','瑞鹧鸪','无名氏','宋','宋词','song-ci','瑞鹧鸪','[]','柳未回青兰未芽。',64,'宋词/ci.song.19000.json','["柳未回青兰未芽。", "谁知此物在君家。", "绿窗借得先春手，黄蜡吹成耐冻花。", "衣麝暗薰香仿佛，山峰误认影横斜。", "凭君说与徐熙道，翰墨从今不足夸。"]'),
('song-ci-221','一落索','无名氏','宋','宋词','song-ci','一落索','[]','腊后东风微透。',52,'宋词/ci.song.19000.json','["腊后东风微透。", "越梅时候。", "一枝芳信到江南，来报先春秀。", "宿醉频拈轻嗅。", "堪醒残酒。", "笛声容易莫相催，留待纤纤手。"]'),
('song-ci-222','鬓边华','无名氏','宋','宋词','song-ci','鬓边华','[]','小梅香细艳浅。',68,'宋词/ci.song.19000.json','["小梅香细艳浅。", "过楚岸、尊前偶见。", "爱闲淡，天与精神，掠青鬓、开人醉眼。", "如今抛掷经春，恨不见、芳枝寄远。", "向心上、谁解相思，赖长对、妆楼粉面。"]'),
('song-ci-223','御阶行・御街行','无名氏','宋','宋词','song-ci','御阶行・御街行','[]','平生有个风流愿。',91,'宋词/ci.song.19000.json','["平生有个风流愿。", "愿长与梅为伴。", "问伊因甚破寒来，只恐百花先绽。", "比兰比麝，比酥比玉，休恁闲撩乱。", "瑶台月下分明见。", "依旧残妆浅。", "不知分得几多香，一片清如一片。", "直须遮断，恐人眼毒，不解轻轻看。"]'),
('song-ci-224','西江月','无名氏','宋','宋词','song-ci','西江月','[]','北岭天饶瑞雪，南枝地段红苞。',58,'宋词/ci.song.19000.json','["北岭天饶瑞雪，南枝地段红苞。", "朦胧霁月映寒梢。", "谁把玉人纱罩。", "香胜炉薰龙麝，奇过庭拥琼瑶。", "一杯清酒愿相招。", "慰我茅堂清瘦。"]'),
('song-ci-225','西江月','无名氏','宋','宋词','song-ci','西江月','[]','翡翠枝头晚萼，婵娟月里飘香。',58,'宋词/ci.song.19000.json','["翡翠枝头晚萼，婵娟月里飘香。", "春兰秋蕙作寻常。", "不与夭桃朋党。", "笑见深红浅白，从教蝶舞蜂忙。", "风流标致道家妆。", "潇洒得来别样。"]'),
('song-ci-226','西江月','无名氏','宋','宋词','song-ci','西江月','[]','黄蜡谁将点缀，红膏不许施妆。',58,'宋词/ci.song.19000.json','["黄蜡谁将点缀，红膏不许施妆。", "孤根来自水云乡。", "风味天然酝酿。", "看取玉奴呵手，摘来珠露沾裳。", "翠环斜插一枝香。", "似簇蜂儿头上。"]'),
('song-ci-227','西江月','无名氏','宋','宋词','song-ci','西江月','[]','万木经霜冻折，孤根独报春来。',58,'宋词/ci.song.19000.json','["万木经霜冻折，孤根独报春来。", "前村雪里一枝开。", "将缓月华光彩。", "一点唇红不褪，妆如傅粉皑皑。", "和羹端的禀天才。", "终入庖人鼎鼐。"]'),
('song-ci-228','蝶恋花','无名氏','宋','宋词','song-ci','蝶恋花','[]','暖发黄宫和气软。',70,'宋词/ci.song.19000.json','["暖发黄宫和气软。", "雪里精神，巧借东君翦。", "嫩蕊商量春色浅。", "青枝疑是香酥溅。", "谁道和羹芳信远。", "点点微酸，已向枝头见。", "休待玉英飞四散。", "且移疏影横金盏。"]'),
('song-ci-229','桃源忆故人','无名氏','宋','宋词','song-ci','桃源忆故人','[]','园林万木凋零尽。',56,'宋词/ci.song.19000.json','["园林万木凋零尽。", "惟是寒梅香喷。", "不许雪霜欺损。", "迥有天然性。", "南枝渐吐红苞嫩。", "冠绝夭桃繁杏。", "不记故人音信。", "对景成离恨。"]'),
('song-ci-230','桃源忆故人','无名氏','宋','宋词','song-ci','桃源忆故人','[]','江天雪意云飞重。',56,'宋词/ci.song.19000.json','["江天雪意云飞重。", "却倚阑干初冻。", "回傍小楼独拥。", "尽日无人共。", "墙梅未落春先纵。", "欲寄一枝谁送。", "月夜暗香浮动。", "似作离人梦。"]'),
('song-ci-231','桃源忆故人','无名氏','宋','宋词','song-ci','桃源忆故人','[]','南枝向暖清香喷。',56,'宋词/ci.song.19000.json','["南枝向暖清香喷。", "谁付骚人词咏。", "一种陇头春信。", "不借胭脂晕。", "梢头谁把轻黄搵。", "浑似不忺施粉。", "疑是寿阳孤冷。", "染得相思病。"]'),
('song-ci-232','桃源忆故人','无名氏','宋','宋词','song-ci','桃源忆故人','[]','寒苞初吐黄金莹。',56,'宋词/ci.song.19000.json','["寒苞初吐黄金莹。", "色染蔷薇犹嫩。", "枝上紫檀香喷。", "洒落饶风韵。", "南枝一种同春信。", "何事不忺朱粉。", "自称霓裳孤冷。", "怨感宫腰恨。"]'),
('song-ci-233','添字浣溪沙・山花子','无名氏','宋','宋词','song-ci','添字浣溪沙・山花子','[]','雪态冰姿好似伊。',56,'宋词/ci.song.19000.json','["雪态冰姿好似伊。", "料应尝笑水仙迟。", "驿使初传芳信早，赏佳期。", "暗想花神多巧妙，黏酥缀玉压纤枝。", "粉面临鸾宜月殿，整妆时。"]'),
('song-ci-234','添字浣溪沙・山花子','无名氏','宋','宋词','song-ci','添字浣溪沙・山花子','[]','谁染深红酥缀来。',56,'宋词/ci.song.19000.json','["谁染深红酥缀来。", "意浓含笑美颜开。", "误认浣溪人饮罢，上香腮。", "辨杏疑桃称好句，名园色异占多才。", "折得一枝斜插鬓，坠金钗。"]'),
('song-ci-235','添字浣溪沙・山花子','无名氏','宋','宋词','song-ci','添字浣溪沙・山花子','[]','取次匀妆粉有痕。',56,'宋词/ci.song.19000.json','["取次匀妆粉有痕。", "参差玉软淡精神。", "姑射重绡风卷乱，喜相迎。", "蝶戏飞层双翅重，清中富贵最多情。", "全似寿阳当日事，点残英。"]'),
('song-ci-236','添字浣溪沙・山花子','无名氏','宋','宋词','song-ci','添字浣溪沙・山花子','[]','蜜室蜂房别有香。',56,'宋词/ci.song.19000.json','["蜜室蜂房别有香。", "腊前偏会泄春光。", "凝伫清容何所似，笑姚黄。", "蜡注金锺诚得意，风飘气味压群芳。", "不似寿阳夸粉面，道家妆。"]'),
('song-ci-237','玉交枝・忆秦娥','无名氏','宋','宋词','song-ci','玉交枝・忆秦娥','[]','胆样瓶儿几点春。',54,'宋词/ci.song.19000.json','["胆样瓶儿几点春。", "翦来犹带水云痕。", "且移孤冷，相伴最深樽。", "每为惜花无晓夜，教人甚处不销魂。", "为君惆怅，独自倚黄昏。"]'),
('song-ci-238','玉交枝・忆秦娥','无名氏','宋','宋词','song-ci','玉交枝・忆秦娥','[]','蕙子兰孙小样儿。',54,'宋词/ci.song.19000.json','["蕙子兰孙小样儿。", "化工簇就寄南枝。", "笑他兰蕙，虽韵带轻肥。", "香霭紫檀和雾重，色攒黄蜡界金徽。", "有人潇洒，插向鬓边宜。"]'),
('song-ci-239','玉交枝・忆秦娥','无名氏','宋','宋词','song-ci','玉交枝・忆秦娥','[]','谁道花房采蜜脾。',54,'宋词/ci.song.19000.json','["谁道花房采蜜脾。", "翦成黄蜡小花儿。", "恶嫌朱粉，不肯肖青枝。", "檀吐暗香兰许韵，月移芳影雪生肌。", "不妨花蕊，羌笛尽教吹。"]'),
('song-ci-240','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','迢递前村深雪里。',64,'宋词/ci.song.19000.json','["迢递前村深雪里。", "望断行云香细细。", "笛中宫里慕芳姿，怨曲啼妆长见泪。", "不会同心荣落易。", "冷艳翻随分岭水。", "有谁曾念陇头人，远寄江南春日意。"]'),
('song-ci-241','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','萧萧海上风长起。',64,'宋词/ci.song.19000.json','["萧萧海上风长起。", "也有梅花开玉蕊。", "爱君风措莹如冰，伴我情怀清似水。", "诗人纵复工难似。", "莫把闲花容易比。", "浓香吹尽不须愁，细雨微风催结子。"]'),
('song-ci-242','玉楼春','无名氏','宋','宋词','song-ci','玉楼春','[]','腊前先报东君信。',64,'宋词/ci.song.19000.json','["腊前先报东君信。", "清似龙涎香得润。", "黄轻不肯整齐开，比着红梅仍旧韵。", "纤枝瘦绿天生嫩。", "可惜轻寒摧挫损。", "刘郎只解误桃花，怅恨今年春又尽。"]'),
('song-ci-243','捣练子','无名氏','宋','宋词','song-ci','捣练子','[]','欺万木，怯寒时。',48,'宋词/ci.song.19000.json','["欺万木，怯寒时。", "倚阑初认月宫姬。", "拭新妆，披素衣。", "孤标韵，暗香奇。", "冰容玉艳缀琼枝。", "借阳和，天付伊。"]'),
('song-ci-244','喜团圆','无名氏','宋','宋词','song-ci','喜团圆','[]','轻攒碎玉，玲珑竹外，脱去繁华。',60,'宋词/ci.song.19000.json','["轻攒碎玉，玲珑竹外，脱去繁华。", "尤殢东君，最先点破，压倒群花。", "瘦影生香，黄昏月馆，清浅溪沙。", "仙标淡伫，偏宜么凤，肯带栖鸦。"]'),
('song-ci-245','愁倚栏・春光好','无名氏','宋','宋词','song-ci','愁倚栏・春光好','[]','冰肌玉骨精神。',51,'宋词/ci.song.19000.json','["冰肌玉骨精神。", "不风尘。", "昨夜窗前都折尽，忽疑君。", "清泪拂拂沾巾。", "谁相念、折赠芳春。", "羌管休吹别塞曲，有人听。"]'),
('song-ci-246','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','庭梅初绽。',52,'宋词/ci.song.19000.json','["庭梅初绽。", "风递幽香清更远。", "别有孤根。", "不待阳和一点恩。", "雪中风韵。", "皓质冰姿真莹静。", "月下精神。", "来到窗前疑是君。"]'),
('song-ci-247','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','疏梅风韵。',52,'宋词/ci.song.19000.json','["疏梅风韵。", "不许游蜂飞蝶近。", "要识芳容。", "除向瑶台月下逢。", "尊前一见。", "换尽平生桃李眼。", "却笑襄王。", "楚梦无踪空断肠。"]'),
('song-ci-248','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','山城驿近。',52,'宋词/ci.song.19000.json','["山城驿近。", "又报寒梅传驿信。", "远水孤村。", "月下何人与断魂。", "幽芳在手。", "花木无情那得瘦。", "似此天真。", "好赠东阳姓沈人。"]'),
('song-ci-249','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','香肌清瘦。',52,'宋词/ci.song.19000.json','["香肌清瘦。", "泪湿轻红疏雨后。", "笑靥微开。", "宿雨微醺越女腮。", "多情无奈。", "玉管休吹帘影外。", "薄晚池台。", "惆怅繁华梦里来。"]'),
('song-ci-250','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','东君有待。',52,'宋词/ci.song.19000.json','["东君有待。", "留得一枝香雪在。", "晚日融融。", "只恐轻酥暖渐熔。", "歌催管送。", "芳酒一尊谁与共。", "寂寞墙东。", "潇洒黄昏满院风。"]'),
('song-ci-251','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','鹅黄初吐。',52,'宋词/ci.song.19000.json','["鹅黄初吐。", "无数蜂儿飞不去。", "别有香风。", "不与南枝斗浅红。", "凭谁折取。", "拟把玉人分付与。", "碧玉搔头。", "淡淡霓裳人倚楼。"]'),
('song-ci-252','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','园林衰槁。',52,'宋词/ci.song.19000.json','["园林衰槁。", "一品梅花开太早。", "紫蕊檀心。", "独占中央色似金。", "幽香清远。", "对景开尊同赏玩。", "雅称仙姿。", "莫是多情染相思。"]'),
('song-ci-253','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','漏出春光三四朵，冰肌玉骨偏宜。',70,'宋词/ci.song.19000.json','["漏出春光三四朵，冰肌玉骨偏宜。", "乍开应笑百花迟。", "将军曾止渴，画角已先知。", "素艳不容蜂蝶采，清香自有人知。", "而今虽被霜雪欺。", "和羹终待手，金鼎自逢时。"]'),
('song-ci-254','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','陇首云收天色暮，寒光射月初开。',70,'宋词/ci.song.19000.json','["陇首云收天色暮，寒光射月初开。", "崑荆山玉莫疑猜。", "琳琅疑此地，仙子不红腮。", "丽质霜裾真性雅，馀香暗送人来。", "乱将碎玉缀枝排。", "雪中寻不见，青萼辨奇才。"]'),
('song-ci-255','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','昨夜新阳回候馆，芳菲正满霜林。',70,'宋词/ci.song.19000.json','["昨夜新阳回候馆，芳菲正满霜林。", "此时珍赏重千金。", "谁知红粉艳，还有岁寒心。", "风动霞衣香散漫，酒醺丹脸深沈。", "妖娆偏称美人簪。", "一枝无处赠，折得自孤吟。"]'),
('song-ci-256','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','爱日新添春一线，化工先到寒梅。',70,'宋词/ci.song.19000.json','["爱日新添春一线，化工先到寒梅。", "不随桃李傍熙台。", "前村深雪里，昨夜一枝开。", "姑射仙人标格韵，凝墙粉谢香腮。", "数家清弄笛声衰。", "愁人不怨听，自向枕边来。"]'),
('song-ci-257','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','玉貌香腮天赋与，清姿不假铅华。',70,'宋词/ci.song.19000.json','["玉貌香腮天赋与，清姿不假铅华。", "素芳寻在五陵家。", "欲知春信息，庾岭一枝斜。", "别有玲珑潇洒处，月梢淡影笼遮。", "休教羌笛一声嗟。", "宫妆犹未似，留取意无涯。"]'),
('song-ci-258','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','枝绿初匀，萼红犹浅。',68,'宋词/ci.song.19000.json','["枝绿初匀，萼红犹浅。", "化工妆点年华晚。", "暗香疏影水亭边，黄昏月下依稀见。", "十二危楼，谁人倚遍。", "只愁羌笛声幽怨。", "少留情意待春来，东君准拟长拘管。"]'),
('song-ci-259','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','萼破前村，枝横江路。',68,'宋词/ci.song.19000.json','["萼破前村，枝横江路。", "铁心应也频凝伫。", "怕愁惟恐不禁愁，宁教雪月相分付。", "不测春来，难追香去。", "无人知我心先误。", "多情总道是东君，东君也有无情处。"]'),
('song-ci-260','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','点点琼酥，初寒乍结。',68,'宋词/ci.song.19000.json','["点点琼酥，初寒乍结。", "看来未忍轻轻折。", "园林正告久萧条，春工著意饶先发。", "眼底不凡，枝头自别。", "也知彻苦宜霜雪。", "这般风味凭馨香，怎教桃李同时节。"]'),
('song-ci-261','踏莎行','无名氏','宋','宋词','song-ci','踏莎行','[]','玉母池边，曾记旧识。',68,'宋词/ci.song.19000.json','["玉母池边，曾记旧识。", "玉京仙苑新移得。", "素娥青女好精神，比看终是无颜色。", "传入汉宫，偷拟妆饰。", "寿阳空恁劳心力。", "寒香都不为春来，莫将远寄春消息。"]'),
('song-ci-262','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','蕙死兰枯篱菊槁。',72,'宋词/ci.song.19000.json','["蕙死兰枯篱菊槁。", "返魂香入江南早。", "竹外一枝斜更好。", "谁解道。", "只今惟有东坡老。", "去岁花前人醉倒。", "酒醒花落嫌人扫。", "人去不来春又到。", "愁满抱。", "青山一带连芳草。"]'),
('song-ci-263','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','雪点江梅才可可。',72,'宋词/ci.song.19000.json','["雪点江梅才可可。", "梅心暗弄纤纤朵。", "疑是月娥庭下过。", "仙翘亸。", "云衫密缀真珠颗。", "玉斝金瓯连臂坐。", "芳辰莫把离魂挫。", "一曲绣筵娇婀娜。", "情无那。", "阳关声里樱桃破。"]'),
('song-ci-264','定风波','无名氏','宋','宋词','song-ci','定风波','[]','又是春归烟雨村。',73,'宋词/ci.song.19000.json','["又是春归烟雨村。", "一枝香雪度黄昏。", "竹外云低疏影亚。", "潇洒。", "水清沙浅见天真。", "瘦玉欺寒香不暖。", "堪羡。", "冰姿照夜月无痕。", "楼上笛声休听取。", "说与。", "江南人远易销魂。"]'),
('song-ci-265','定风波','无名氏','宋','宋词','song-ci','定风波','[]','一树寒梅傍小溪。',73,'宋词/ci.song.19000.json','["一树寒梅傍小溪。", "夜来陡觉绽南枝。", "冷艳冰姿金蕊浅。", "堪羡。", "凝明因与雪霜期。", "折赠美人临宝鉴。", "云脸。", "鬓边斜插最相宜。", "凭仗高楼频祝付。", "说与。", "马融羌管且停吹。"]'),
('song-ci-266','鹊踏枝・蝶恋花','无名氏','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','南国寒轻山自碧。',70,'宋词/ci.song.19000.json','["南国寒轻山自碧。", "庭际梅花，先报春消息。", "绮萼玉英何忍摘。", "真堪树下陈瑶席。", "旋嗅清香消酒力。", "翦采无功，粉笔争描得。", "一曲新欢须共惜。", "等闲零落随羌笛。"]'),
('song-ci-267','鹊踏枝・蝶恋花','无名氏','宋','宋词','song-ci','鹊踏枝・蝶恋花','[]','故里山遥春霭碧。',70,'宋词/ci.song.19000.json','["故里山遥春霭碧。", "为想繁枝，清梦何曾息。", "缧带霜英人不摘。", "纷纷日暮飘絪席。", "休抱离肠凭酒力。", "只有轻纨，依约应传得。", "白发未归空自惜。", "柔肠寄尽平阳笛。"]'),
('song-ci-268','清平乐','无名氏','宋','宋词','song-ci','清平乐','[]','寒溪过雪。',54,'宋词/ci.song.19000.json','["寒溪过雪。", "梅蕊春前发。", "照影弄姿香苒苒，临水一枝风月。", "梦游仿佛仙乡。", "绿窗曾见幽芳。", "事往无人共说，愁闻玉笛声长。"]'),
('song-ci-269','春光好','无名氏','宋','宋词','song-ci','春光好','[]','看看腊尽春回。',58,'宋词/ci.song.19000.json','["看看腊尽春回。", "消息到、江南早梅。", "昨夜前村深雪里，一朵花开。", "盈盈玉蕊如裁。", "更风细、清香暗来。", "空使行人肠欲断，驻马裴回。"]'),
('song-ci-270','人娇','无名氏','宋','宋词','song-ci','人娇','[]','玉瘦香浓，檀深雪散。',80,'宋词/ci.song.19000.json','["玉瘦香浓，檀深雪散。", "今年恨、探梅较晚。", "江楼楚馆。", "云闲水远。", "清昼永，凭阑翠帘低卷。", "坐上客来，尊中酒满。", "歌声共、水流云断。", "南枝可插，便须频翦。", "莫直待、西楼数声羌管。"]'),
('song-ci-271','二色宫桃','无名氏','宋','宋词','song-ci','二色宫桃','[]','镂玉香苞酥点萼。',67,'宋词/ci.song.19000.json','["镂玉香苞酥点萼。", "正万木、园林萧索。", "惟有一枝雪里开，江南有信凭谁托。", "前年记赏登高阁。", "叹年来、旧欢如昨。", "听取乐天一句云，花开处、且须行乐。"]'),
('song-ci-272','河传','无名氏','宋','宋词','song-ci','河传','[]','香苞素质。',73,'宋词/ci.song.19000.json','["香苞素质。", "天赋与、倾城标格。", "应是晓来，暗传东君消息。", "把孤芳、回暖律。", "寿阳粉面增妆饰。", "说与高楼，休更吹羌笛。", "花下醉赏，留取时倚阑干，斗清香、添酒力。"]'),
('song-ci-273','七娘子','无名氏','宋','宋词','song-ci','七娘子','[]','清香浮动到黄昏，向水边、疏影梅开尽。',74,'宋词/ci.song.19000.json','["清香浮动到黄昏，向水边、疏影梅开尽。", "溪边畔，轻蕊，有如浅杏。", "一枝喜得东君信。", "风吹只怕霜侵损。", "更新来、插向多情鬓。", "寿阳妆鉴，雪肌玉莹。", "岭头别后微添粉。"]'),
('song-ci-274','忆少年','无名氏','宋','宋词','song-ci','忆少年','[]','疏疏整整，斜斜淡淡，盈盈脉脉。',56,'宋词/ci.song.19000.json','["疏疏整整，斜斜淡淡，盈盈脉脉。", "徒怜暗香句，笑梨花颜色。", "羁马萧萧行又急。", "空回首、水寒沙白。", "天涯倦牢落，忍一声羌笛。"]'),
('song-ci-275','浪淘沙','无名氏','宋','宋词','song-ci','浪淘沙','[]','春色入横塘。',64,'宋词/ci.song.19000.json','["春色入横塘。", "变尽凄凉。", "青梢弄粉雪溪傍。", "疑是化工偏著意，欲试新妆。", "玉蓓锁春藏。", "占断寒芳。", "他时鼎鼐不须忙。", "泄漏清香方有思，别是春光。"]'),
('song-ci-276','浪淘沙','无名氏','宋','宋词','song-ci','浪淘沙','[]','雪里暗香浓。',64,'宋词/ci.song.19000.json','["雪里暗香浓。", "乍吐琼英。", "横斜疏影月明中。", "学傅胭脂桃与杏，虚废春工。", "素艳有谁同。", "不并妖红。", "应如褒姒笑时容。", "绝胜梨花春带雨，旖旎春风。"]'),
('song-ci-277','浪淘沙','无名氏','宋','宋词','song-ci','浪淘沙','[]','村左小溪傍。',64,'宋词/ci.song.19000.json','["村左小溪傍。", "粉黛宜芳。", "寒添潇洒冷添霜。", "清瘦几枝堪入画，竹映苔墙。", "疏影浸横塘。", "月暗浮香。", "当时曾伴寿阳妆。", "不似东君先倚栏，泄漏春光。"]'),
('song-ci-278','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','破萼江梅，迥然标格冰肌莹。',50,'宋词/ci.song.19000.json','["破萼江梅，迥然标格冰肌莹。", "暗香疏影。", "月张银塘静。", "折取一枝，与插多情鬓。", "临鸾镜。", "粉容相并。", "试问谁端正。"]'),
('song-ci-279','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','烟淡黄昏，小移疏影横斜去。',50,'宋词/ci.song.19000.json','["烟淡黄昏，小移疏影横斜去。", "暗香微度。", "点缀梢头雨。", "玉管休吹，更要留春住。", "人何处。", "对花无语。", "望断江南路。"]'),
('song-ci-280','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','点点江梅，向疏篱处香风逗。',50,'宋词/ci.song.19000.json','["点点江梅，向疏篱处香风逗。", "未容春透。", "花亦知人瘦。", "姑射山头，谁伴黄昏后。", "君知否。", "自然孤秀。", "横玉休三奏。"]'),
('song-ci-281','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','雪里芳丛，岭头还报东君信。',50,'宋词/ci.song.19000.json','["雪里芳丛，岭头还报东君信。", "寿阳妆靓。", "姑射冰肌莹。", "曲岸横斜，清浅波相应。", "风不定。", "暗香疏影。", "占断花中韵。"]'),
('song-ci-282','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','万木凋残，早梅独占孤根暖。',50,'宋词/ci.song.19000.json','["万木凋残，早梅独占孤根暖。", "前村雪满。", "昨夜南枝绽。", "堪恨倚栏，容易吹羌管。", "飘琼片。", "翠蛾争选。", "贴向桃花面。"]'),
('song-ci-283','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','昨夜寒梅，一枝雪里多风措。',50,'宋词/ci.song.19000.json','["昨夜寒梅，一枝雪里多风措。", "幽香无数。", "不与群花语。", "最是凝情，月夜交光处。", "谁为主。", "待须折取。", "羌管休轻举。"]'),
('song-ci-284','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','[]','春日芳心，暗香偏向黄昏逗。',50,'宋词/ci.song.19000.json','["春日芳心，暗香偏向黄昏逗。", "玉肌寒透。", "抵死添清瘦。", "影落横塘，月淡人归后。", "君知否。", "一枝先秀。", "应向东君奏。"]'),
('song-ci-285','点绛唇','无名氏','宋','宋词','song-ci','点绛唇','["\u897f\u6e56"]','赋雪归来，绿窗一夜霜风紧。',50,'宋词/ci.song.19000.json','["赋雪归来，绿窗一夜霜风紧。", "也知春信。", "消息南枝近。", "隐映斜阳，玉暖香成阵。", "西湖景。", "繁英有恨。", "只□□□□。"]'),
('song-ci-286','惜双双・惜分飞','无名氏','宋','宋词','song-ci','惜双双・惜分飞','[]','冒雪披风开数点。',68,'宋词/ci.song.19000.json','["冒雪披风开数点。", "万花厌、欺寒探暖。", "掩映闲庭院。", "月下疏影横斜，幽香远。", "命友开尊同宴玩。", "听丽质、歌声宛转。", "对景侧金盏。", "任他结实和羹，归仙馆。"]'),
('song-ci-287','朝中措','无名氏','宋','宋词','song-ci','朝中措','[]','山城水隘小桥傍。',57,'宋词/ci.song.19000.json','["山城水隘小桥傍。", "竹里早梅芳。", "纵有丹青图画，难描幽韵清香。", "妖娆天赋，偏宜素淡，杨氏宫妆。", "雅态何须艳丽，孤标不在春光。"]'),
('song-ci-288','虞美人','无名氏','宋','宋词','song-ci','虞美人','[]','清江一曲君应见。',66,'宋词/ci.song.19000.json','["清江一曲君应见。", "昨夜潮头浅。", "不争落落斗奇奇。", "看取水边寒蕊、雪边枝。", "日斜疏影还敧倒。", "沙上娇鶄老。", "只今何处有新诗。", "好在小春十月、醉翁辞。"]'),
('song-ci-289','醉落魄・一斛珠','无名氏','宋','宋词','song-ci','醉落魄・一斛珠','[]','琼搓粉滴。',67,'宋词/ci.song.19000.json','["琼搓粉滴。", "南枝只报江南坼。", "横斜疏影溪边窄。", "翦碎白云，分付陇头客。", "冰肌绰约疑姑射。", "铅华消尽见真色。", "不随桃李开红白。", "我为东君，来报春消息。"]'),
('song-ci-290','醉落魄・一斛珠','无名氏','宋','宋词','song-ci','醉落魄・一斛珠','[]','梅花似雪。',67,'宋词/ci.song.19000.json','["梅花似雪。", "赏花记得同欢悦。", "更阑犹自贪攀折。", "不怯春寒，须要待明月。", "如今月上花争发。", "疏枝冷蕊对离缺。", "人心只道花争别。", "不道人心，不似旧时节。"]'),
('song-ci-291','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','宝香瓶，桐叶卷。',58,'宋词/ci.song.19000.json','["宝香瓶，桐叶卷。", "荡水痕微还远。", "思乡信，觉春迟。", "野梅初见时。", "上潮风，临晚渡。", "人欲过西江去。", "吹寒管，陇云低。", "江南花未知。"]'),
('song-ci-292','更漏子','无名氏','宋','宋词','song-ci','更漏子','[]','绛纱笼，金叶盖。',58,'宋词/ci.song.19000.json','["绛纱笼，金叶盖。", "向晓灯花犹在。", "冰未结，小琉璃。", "陇梅香满枝。", "雪无香，花有意。", "不是江南新寄。", "霜月尽，碧天寒。", "玉楼人倚阑。"]'),
('song-ci-293','落梅风・落梅','无名氏','宋','宋词','song-ci','落梅风・落梅','[]','宫烟如水湿芳晨。',54,'宋词/ci.song.19000.json','["宫烟如水湿芳晨。", "寒梅似雪相亲。", "玉楼侧畔数枝春。", "惹香尘。", "寿阳娇面偏怜惜，妆成一面花新。", "镜中重把玉纤匀。", "酒初醺。"]'),
('song-ci-294','古记・如梦令','无名氏','宋','宋词','song-ci','古记・如梦令','[]','一枕厌厌春困。',40,'宋词/ci.song.19000.json','["一枕厌厌春困。", "记得小梅风韵。", "何处最关情，嫩蕊初传芳信。", "堪恨。", "堪恨。", "谁傍横斜疏影。"]'),
('song-ci-295','古记・如梦令','无名氏','宋','宋词','song-ci','古记・如梦令','[]','腊半雪梅初绽。',40,'宋词/ci.song.19000.json','["腊半雪梅初绽。", "玉屑琼英碎翦。", "素艳与清香，别有风流堪羡。", "苞嫩。", "蕊嫩。", "羞破寿阳人面。"]'),
('song-ci-296','古记・如梦令','无名氏','宋','宋词','song-ci','古记・如梦令','[]','疑是水晶宫殿。',40,'宋词/ci.song.19000.json','["疑是水晶宫殿。", "云女天仙宝宴。", "吟赏欲黄昏，风送一声羌管。", "烟淡。", "霜淡。", "月在画楼西畔。"]'),
('song-ci-297','生查子','无名氏','宋','宋词','song-ci','生查子','[]','朔风吹冻云，云破天容碧。',48,'宋词/ci.song.19000.json','["朔风吹冻云，云破天容碧。", "新月过溪来，隐见横云色。", "天与水争妍，花与月争白。", "一倩管城君，寄此春消息。"]'),
('song-ci-298','蓦山溪','无名氏','宋','宋词','song-ci','蓦山溪','[]','青春三月。',5,'宋词/ci.song.19000.json','["青春三月。"]'),
('song-ci-299','失调名','无名氏','宋','宋词','song-ci','失调名','[]','夜寒斗觉罗衣薄。',8,'宋词/ci.song.19000.json','["夜寒斗觉罗衣薄。"]'),
('song-ci-300','失调名','无名氏','宋','宋词','song-ci','失调名','[]','深诚杳隔无疑。',7,'宋词/ci.song.19000.json','["深诚杳隔无疑。"]'),
('song-ci-301','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','千里。',45,'宋词/ci.song.19000.json','["千里。", "楚江水。", "明月楼高愁独倚。", "井梧宫殿生秋意。", "望断巫山十二。", "雪肌花貌参差是。", "朱阁五云仙子。"]'),
('song-ci-302','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','相误。',45,'宋词/ci.song.19000.json','["相误。", "桃源路。", "万里苍苍烟水暮。", "留君不住君须去。", "秋月春风闲度。", "桃花零乱如红雨。", "人面不知何处。"]'),
('song-ci-303','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','非雾。',45,'宋词/ci.song.19000.json','["非雾。", "花无语。", "远似朝云何处去。", "凌波不过横塘路。", "燕燕莺莺飞舞。", "风吹仙袂飘飘举。", "拟倩游丝惹住。"]'),
('song-ci-304','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','相忆。',45,'宋词/ci.song.19000.json','["相忆。", "无消息。", "目断遥天云自白。", "寒山一带伤心碧。", "风土萧疏胡国。", "长安不见浮云隔。", "纵使君来争得。"]'),
('song-ci-305','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','来见。',45,'宋词/ci.song.19000.json','["来见。", "蕊宫殿。", "记得随班迎凤辇。", "馀花落尽苍苔院。", "斜掩金铺一片。", "千金买笑无方便。", "和泪盈盈娇眼。"]'),
('song-ci-306','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','君去。',45,'宋词/ci.song.19000.json','["君去。", "逐鸳侣。", "斜倚绿窗鸳鉴女。", "琴弹秋思明心素。", "一寸还成千缕。", "锦城春色知何许。", "那似远山眉妩。"]'),
('song-ci-307','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','无处。',45,'宋词/ci.song.19000.json','["无处。", "难轻诉。", "锦瑟华年谁与度。", "黄昏更下潇潇雨。", "况是青春将暮。", "花虽无语莺能语。", "来道曾逢郎否。"]'),
('song-ci-308','调笑・调笑令','无名氏','宋','宋词','song-ci','调笑・调笑令','[]','衫湿。',45,'宋词/ci.song.19000.json','["衫湿。", "情何极。", "上下花间声转急。", "满船明月芦花白。", "秋水长天一色。", "芳年未老时难得。", "目断远空凝碧。"]'),
('song-ci-309','九张机','无名氏','宋','宋词','song-ci','九张机','[]','一张机。',36,'宋词/ci.song.19000.json','["一张机。", "织梭光景去如飞。", "兰房夜永愁无寐。", "呕呕轧轧，织成春恨，留著待郎归。"]'),
('song-ci-310','九张机','无名氏','宋','宋词','song-ci','九张机','[]','两张机。',36,'宋词/ci.song.19000.json','["两张机。", "月明人静漏声稀。", "千丝万缕相萦系。", "织成一段，回纹锦字。", "将去寄呈伊。"]'),
('song-ci-311','九张机','无名氏','宋','宋词','song-ci','九张机','[]','三张机。',36,'宋词/ci.song.19000.json','["三张机。", "中心有朵耍花儿。", "娇红嫩绿春明媚。", "君须早折，一枝浓艳，莫待过芳菲。"]'),
('song-ci-312','九张机','无名氏','宋','宋词','song-ci','九张机','[]','四张机。',36,'宋词/ci.song.19000.json','["四张机。", "鸳鸯织就欲双飞。", "可怜未老头先白，春波碧草，晓寒深处，相对浴红衣。"]'),
('song-ci-313','九张机','无名氏','宋','宋词','song-ci','九张机','[]','五张机。',36,'宋词/ci.song.19000.json','["五张机。", "芳心密与巧心期。", "合欢树上枝连理。", "双头花下，两同心处，一对化生儿。"]'),
('song-ci-314','九张机','无名氏','宋','宋词','song-ci','九张机','[]','六张机。',36,'宋词/ci.song.19000.json','["六张机。", "雕花铺锦半离披。", "兰房别有留春计。", "炉添小篆，日长一线，相对绣工迟。"]'),
('song-ci-315','九张机','无名氏','宋','宋词','song-ci','九张机','[]','七张机。',36,'宋词/ci.song.19000.json','["七张机。", "春蚕吐尽一生丝。", "莫教容易裁罗绮。", "无端翦破，仙鸾彩凤，分作两般衣。"]'),
('song-ci-316','九张机','无名氏','宋','宋词','song-ci','九张机','[]','八张机。',36,'宋词/ci.song.19000.json','["八张机。", "纤纤玉手住无时。", "蜀江濯尽春波媚。", "香遗囊麝，花房绣被。", "归去意迟迟。"]'),
('song-ci-317','九张机','无名氏','宋','宋词','song-ci','九张机','[]','九张机。',36,'宋词/ci.song.19000.json','["九张机。", "一心长在百花枝。", "百花共作红堆被。", "都将春色，藏头里面，不怕睡多时。"]'),
('song-ci-318','九张机','无名氏','宋','宋词','song-ci','九张机','[]','轻丝。',35,'宋词/ci.song.19000.json','["轻丝。", "象床玉手出新奇。", "千花万草光凝碧。", "裁缝衣著，春天歌舞，飞蝶语黄鹂。"]'),
('song-ci-319','九张机','无名氏','宋','宋词','song-ci','九张机','[]','春衣。',35,'宋词/ci.song.19000.json','["春衣。", "素丝染就已堪悲。", "尘世昏污无颜色。", "应同秋扇，从兹永弃。", "无复奉君时。"]'),
('song-ci-320','九张机','无名氏','宋','宋词','song-ci','九张机','[]','一张机。',36,'宋词/ci.song.19000.json','["一张机。", "采桑陌上试春衣。", "风晴日暖慵无力。", "桃花枝上，啼莺言语，不肯放人归。"]'),
('song-ci-321','九张机','无名氏','宋','宋词','song-ci','九张机','[]','两张机。',36,'宋词/ci.song.19000.json','["两张机。", "行人立马意迟迟。", "深心未忍轻分付，回头一笑，花间归去，只恐被花知。"]'),
('song-ci-322','九张机','无名氏','宋','宋词','song-ci','九张机','[]','三张机。',36,'宋词/ci.song.19000.json','["三张机。", "吴蚕已老燕雏飞。", "东风宴罢长洲苑，轻绡催趁，馆娃宫女，要换舞时衣。"]'),
('song-ci-323','九张机','无名氏','宋','宋词','song-ci','九张机','[]','四张机。',36,'宋词/ci.song.19000.json','["四张机。", "咿哑声里暗颦眉。", "回梭织朵垂莲子。", "盘花易绾，愁心难整，脉脉乱如丝。"]'),
('song-ci-324','九张机','无名氏','宋','宋词','song-ci','九张机','[]','五张机。',36,'宋词/ci.song.19000.json','["五张机。", "横纹织就沈郎诗。", "中心一句无人会。", "不言愁恨，不言憔悴。", "只恁寄相思。"]'),
('song-ci-325','九张机','无名氏','宋','宋词','song-ci','九张机','[]','六张机。',36,'宋词/ci.song.19000.json','["六张机。", "行行都是耍花儿。", "花间更有双蝴蝶，停梭一晌，闲窗影里。", "独自看多时。"]'),
('song-ci-326','九张机','无名氏','宋','宋词','song-ci','九张机','[]','七张机。',36,'宋词/ci.song.19000.json','["七张机。", "鸳鸯织就又迟疑。", "只恐被人轻裁剪，分飞两处，一场离恨，何计再相随。"]'),
('song-ci-327','九张机','无名氏','宋','宋词','song-ci','九张机','[]','八张机。',36,'宋词/ci.song.19000.json','["八张机。", "回纹知是阿谁诗。", "织成一片凄凉意。", "行行读遍，厌厌无语，不忍更寻思。"]'),
('song-ci-328','九张机','无名氏','宋','宋词','song-ci','九张机','[]','九张机。',36,'宋词/ci.song.19000.json','["九张机。", "双花双叶又双枝。", "薄情自古多离别。", "从头到底。", "将心萦系。", "穿过一条丝。"]'),
('song-ci-329','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','席近浑如远，帘高故放低。',62,'宋词/ci.song.19000.json','["席近浑如远，帘高故放低。", "偏它能画斗头眉。", "戴顶烧香铺翠、小冠儿。", "酒伴残妆在，花随秀鬓垂。", "薄罗小扇写新诗。", "解下双双罗带、要重题。"]'),
('song-ci-330','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','象戏红牙局，琵琶绿锦绦。',62,'宋词/ci.song.19000.json','["象戏红牙局，琵琶绿锦绦。", "小窗方簟困香醪。", "帘外拂檐宫柳、翠阴交。", "烟媚莺莺近，风微燕燕高。", "更将乳酪伴樱桃。", "要共那人一递、一匙抄。"]'),
('song-ci-331','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','小小生金屋，盈盈向凤帏。',62,'宋词/ci.song.19000.json','["小小生金屋，盈盈向凤帏。", "斜枝石竹绣罗衣。", "为怕春来风日、卷帘稀。", "金殿承恩久，兰堂得梦回。", "薰炉空惹御香归。", "今夜花前还是、日平西。"]'),
('song-ci-332','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','阁儿虽不大，都无半点俗。',62,'宋词/ci.song.19000.json','["阁儿虽不大，都无半点俗。", "窗儿根底数竿竹。", "画展江南山景、两三幅。", "彝鼎烧异香，胆瓶插嫩菊。", "け然无事净心目。", "共那人人相对、弈棋局。"]'),
('song-ci-333','南歌子','无名氏','宋','宋词','song-ci','南歌子','[]','风动槐龙舞，花深禁漏传。',62,'宋词/ci.song.19000.json','["风动槐龙舞，花深禁漏传。", "一竿红日照花砖。", "走马晨晖门里、快行宣。", "百五开新火，清明尚禁烟。", "鱼符不请便朝天。", "醉里归来疑是、梦游仙。"]'),
('song-ci-334','感皇恩','无名氏','宋','宋词','song-ci','感皇恩','[]','暖律破寒威，春回宫柳。',81,'宋词/ci.song.19000.json','["暖律破寒威，春回宫柳。", "晴景初曦上元候。", "禁城烟火，移下一天星斗。", "素娥凝碧汉，明如昼。", "绣毂电转，锦鞯飞骤。", "九踏笙歌按新奏。", "胜游方凝，忽听晓钟银漏。", "两两归去也，应回首。"]'),
('song-ci-335','鱼游春水','无名氏','宋','宋词','song-ci','鱼游春水','[]','秦楼东风里。',105,'宋词/ci.song.19000.json','["秦楼东风里。", "燕子还来寻旧垒。", "馀寒微透，红日薄侵罗绮。", "嫩笋才抽碧玉簪，细柳轻窣黄金蕊。", "莺啭上林，鱼游春水。", "屈曲阑干遍倚。", "又是一番新桃李。", "佳人应念归期，梅妆淡洗。", "凤箫声杳沈孤雁，目断澄波无双鲤。", "云山万重，寸心千里。"]'),
('song-ci-336','五彩结同心','无名氏','宋','宋词','song-ci','五彩结同心','[]','珠帘垂户。',133,'宋词/ci.song.19000.json','["珠帘垂户。", "金索悬窗，家接浣沙溪路。", "相见桐阴下，一钩月、恰在凤凰栖处。", "素琼拈就宫腰小。", "花枝袅、盈盈娇步。", "新妆浅，满腮红雪，绰约片云欲度。", "尘寰岂能留住。", "唯只愁、化作彩云飞去。", "蝉翼衫儿，薄冰肌莹，轻罩一团香雾。", "彩笺巧缀相思苦。", "脉脉动、怜才心绪。", "好作个、秦楼活计，吹箫伴侣。"]'),
('song-ci-337','侍香金童','无名氏','宋','宋词','song-ci','侍香金童','[]','宝台蒙绣，瑞兽高三尺。',77,'宋词/ci.song.19000.json','["宝台蒙绣，瑞兽高三尺。", "玉殿无风烟自直。", "迤逦传杯盈绮席。", "苒苒菲菲，断处凝碧。", "是龙涎凤髓，恼人情意极。", "想韩寿、风流应暗识。", "去似彩云无处觅。", "惟有多情，袖中留得。"]'),
('song-ci-338','洞仙歌','无名氏','宋','宋词','song-ci','洞仙歌','[]','溶溶泄泄，似飘扬愁绪。',101,'宋词/ci.song.19000.json','["溶溶泄泄，似飘扬愁绪。", "不是因风等闲度。", "道无心用甚，却又情多，行未驻，还作高阳暮雨。", "襄王情尚浅，会少离多，空自朝朝又暮暮。", "肠断晓光中，一缕归时，销散后、不知何处。", "试密锁、琼楼洞房深，与遮断江皋，楚台归路。"]'),
('song-ci-339','永遇乐','无名氏','宋','宋词','song-ci','永遇乐','[]','功名闲事，利禄休问，莫系心上。',128,'宋词/ci.song.19000.json','["功名闲事，利禄休问，莫系心上。", "幸有衣食，随缘过得，著甚乾劳攘。", "风前月下，三杯两盏，撞著即莫与放。", "且与个、山庄道友，退闲故人来往。", "新来做得，一个宽袖布衫，著来也畅。", "出户迎宾，入城干事，恰似王保长。", "我咱忺后，神歌鬼舞，任尔万般毁谤。", "死来后，一家一个，那底怎向。"]'),
('song-ci-340','西江月','无名氏','宋','宋词','song-ci','西江月','[]','灯火楼台欲下，笙歌院落将归。',58,'宋词/ci.song.19000.json','["灯火楼台欲下，笙歌院落将归。", "冰瓷金缕胜琉璃。", "春笋捧来纤细。", "饮罢高阳人散，曲终巫峡云飞。", "千万修合斗新奇。", "须带别离滋味。"]'),
('song-ci-341','水调歌头','无名氏','宋','宋词','song-ci','水调歌头','[]','帆落松陵浦，枯柳缆琼艘。',114,'宋词/ci.song.19000.json','["帆落松陵浦，枯柳缆琼艘。", "杖策无人独步，浪厌百花桥。", "我挂风裳水佩，一笑波寒月白，馀韵触惊涛。", "绝景有谁赏，雾暮闭三高。", "不须臾，千古事，一萧条。", "鲈鱼纵有，泽荒甫里失溪桥。", "更吾名高业茂，终归荒田野草，且稳一枝巢。", "举酒酹空阔，烟远路迢迢。"]'),
('song-ci-342','菩萨蛮','无名氏','宋','宋词','song-ci','菩萨蛮','[]','江城烽火连三月。',52,'宋词/ci.song.19000.json','["江城烽火连三月。", "不堪对酒江亭别。", "休作断肠声。", "老来无泪倾。", "风高帆影疾。", "目送舟痕碧。", "锦字几时来。", "薰风无雁回。"]'),
('song-ci-343','减字木兰花','无名氏','宋','宋词','song-ci','减字木兰花','[]','啬薇叶暗。',52,'宋词/ci.song.19000.json','["啬薇叶暗。", "满架浓阴风不乱。", "午酒才醒。", "历历黄鹂枕上听。", "此情难遣。", "不比红蕉心易展。", "要识离愁。", "只似杨花不自由。"]'),
('song-ci-344','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','梦入瑶台千步芳。',48,'宋词/ci.song.19000.json','["梦入瑶台千步芳。", "万妃相向玉为装。", "同心鞶带翠罗长。", "浓艳只宜供枕席，醉魂长是傍壶觞。", "绀纱囊薄为谁香。"]'),
('song-ci-345','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','白玉楼中白雪歌。',48,'宋词/ci.song.19000.json','["白玉楼中白雪歌。", "更将白纻衬春罗。", "软红香里最么麽。", "桃叶桃根随处有，江南江北见来多。", "风前月底奈愁何。"]'),
('song-ci-346','临江仙','无名氏','宋','宋词','song-ci','临江仙','[]','竹里行厨草草，花边系马匆匆。',68,'宋词/ci.song.19000.json','["竹里行厨草草，花边系马匆匆。", "使君移传意何穷。", "儿童随骑火，猿鹤避歌钟。", "梅雪自欺舞态，烛花先放春红。", "酒醒人散夜堂空。", "殷勤松上月，独照老仙翁。"]'),
('song-ci-347','阮郎归','无名氏','宋','宋词','song-ci','阮郎归','[]','山池芳草绿初匀。',56,'宋词/ci.song.19000.json','["山池芳草绿初匀。", "柳寒眉尚颦。", "东风吹雨细如尘。", "一庭花脸皴。", "莺共蝶，怨还嗔。", "眼前无好春。", "这番天气杀愁人。", "人愁旋旋新。"]'),
('song-ci-348','浣溪沙','无名氏','宋','宋词','song-ci','浣溪沙','[]','春院无人花自香。',48,'宋词/ci.song.19000.json','["春院无人花自香。", "飞来蜂蝶意何狂。", "玉钩帘卷日偏长。", "笑又不成愁未是，曲屏闲倚绣鸳鸯。", "归时应供□□妆。"]'),
('song-ci-349','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','李郭共仙舟。',66,'宋词/ci.song.19000.json','["李郭共仙舟。", "准拟苏台烂熳游。", "风雪为谁留住也，沧洲。", "一尺银沙未肯收。", "无语只关愁。", "强殢金卮不计筹。", "想得人人梳洗懒，妆楼。", "只窣帘儿不上钩。"]'),
('song-ci-350','凤栖梧・蝶恋花','无名氏','宋','宋词','song-ci','凤栖梧・蝶恋花','[]','姑射仙人游汗漫。',70,'宋词/ci.song.19000.json','["姑射仙人游汗漫。", "白凤翩翩，银海光凌乱。", "龟手儿童贪戏玩。", "风檐更折梅梢看。", "漠漠银沙平晚岸。", "笑拥寒蓑，聊作渔翁伴。", "横玉愁云吹不断。", "归舟又载苹花满。"]'),
('song-ci-351','归自谣','无名氏','宋','宋词','song-ci','归自谣','[]','愁冉冉。',40,'宋词/ci.song.19000.json','["愁冉冉。", "目送书空鸿数点。", "落霞风剪江分染。", "胜处屏云犹未掩。", "羞娥敛。", "红潮怕上春风脸。"]'),
('song-ci-352','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','曾约再来时，花暗春风树。',52,'宋词/ci.song.19000.json','["曾约再来时，花暗春风树。", "今日人来花未开，春未知人处。", "坐客有疏狂，彩笔题新语。", "浑为玉人颓玉山，忘了阳关路。"]'),
('song-ci-353','卜算子','无名氏','宋','宋词','song-ci','卜算子','[]','烟髻绾层巅，云叶生寒树。',52,'宋词/ci.song.19000.json','["烟髻绾层巅，云叶生寒树。", "斜日行人窈窕村，愁阵纵横处。", "细细写蛮笺，道寄相思语。", "会倩春风展柳眉，回马章台路。"]'),
('song-ci-354','好事近','无名氏','宋','宋词','song-ci','好事近','[]','潇洒小楼东，斜亚一枝梅雪。',53,'宋词/ci.song.19000.json','["潇洒小楼东，斜亚一枝梅雪。", "若在玉溪仙馆，更风流奇绝。", "花神应为护芳心，付与何人折。", "行客几回搔首，认暗香浮月。"]'),
('song-ci-355','谒金门','无名氏','宋','宋词','song-ci','谒金门','[]','江上路。',54,'宋词/ci.song.19000.json','["江上路。", "依约数家烟树。", "一枕归心村店暮。", "更乱山深处。", "梦过江南芳草渡。", "晓色又催人去。", "愁似游丝千万缕。", "倩东风约住。"]'),
('song-ci-356','杜韦娘','无名氏','宋','宋词','song-ci','杜韦娘','[]','华堂深院，霜笼月采生寒晕。',133,'宋词/ci.song.19000.json','["华堂深院，霜笼月采生寒晕。", "度翠幄、风触梅香喷。", "渐岁晚、春光将近。", "惹离恨万种，多情易感，欢难聚少愁成阵。", "拥红炉，凤枕慵敧，银灯挑尽。", "当此际，争忍前期后约，度岁无凭准。", "对好景、空积相思恨。", "但自觉、恹恹方寸。", "拟蛮笺象管，丹青好手，写出寄与伊教信。", "尽千工万巧，唯有心期难问。"]'),
('song-ci-357','摸鱼儿','无名氏','宋','宋词','song-ci','摸鱼儿','[]','被谁家、数声弦管，惊回好梦难省。',140,'宋词/ci.song.19000.json','["被谁家、数声弦管，惊回好梦难省。", "起来无语疏雨过，芳草嫩苔侵径。", "春昼永。", "迟日暮，碧沼浪浸红楼影。", "卷帘人静。", "被风触，一叶两叶，杏花零乱对残景。", "依前是，撩拨春心堪恨。", "檀郎言约无定。", "不知何处贪欢笑，恣纵酒迷歌逞。", "珠泪迸。", "自别后，每忆翠黛凭谁整。", "芳年相称。", "又到得今来，却成病了，羞懒对鸾镜。"]'),
('song-ci-358','满庭芳','无名氏','宋','宋词','song-ci','满庭芳','[]','五斗相逢，千锺一饮，古今乐事无过。',118,'宋词/ci.song.19000.json','["五斗相逢，千锺一饮，古今乐事无过。", "香生银瓮，浮蚁浴春波。", "潋滟光凝盏面，轻风皱、浅碧宫罗。", "乘欢处，倾罍痛饮，珠贯引清歌。", "云何。", "君不饮，良辰美景，聚少离多。", "忍怎放春风，容易蹉跎。", "但愿一樽常共，花阴下、急景如梭。", "须乘醉，雕鞍归去，争看醉颜酡。"]'),
('song-ci-359','潇湘静・湘江静','无名氏','宋','宋词','song-ci','潇湘静・湘江静','[]','画帘微卷香风逗。',128,'宋词/ci.song.19000.json','["画帘微卷香风逗。", "正明月、乍圆时候。", "金盘露冷，玉炉篆消，渐红鳞生酒。", "娇唱倚繁弦，琼枝碎、轻回云袖。", "风台歌短、铜壶漏永，人欲醉、夜如昼。", "因念流年迅景，被浮名、暗辜欢偶。", "人生大抵，离多会少，更相将白首。", "何似猛寻芳，都莫问、积金过斗。", "歌阑宴阕，云窗凤枕，钗横麝透。"]'),
('song-ci-360','十月桃','无名氏','宋','宋词','song-ci','十月桃','[]','东篱菊尽，遍园林败叶，满地寒荄。',121,'宋词/ci.song.19000.json','["东篱菊尽，遍园林败叶，满地寒荄。", "露井平明，破香笼粉初开。", "佳人共喜芳意，呵手剪、密插鸾钗。", "无言有艳，不避繁霜，变作春媒。", "问武陵溪上谁栽。", "分付与南园，舞榭歌台。", "恰似凝酥衬玉，点缀装裁。", "东君自是为主，先暖信、律管飞灰。", "从今雪里，第一番花，休话江梅。"]'),
('song-ci-361','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','江月初圆，正新春夜永，灯市行乐。',117,'宋词/ci.song.19000.json','["江月初圆，正新春夜永，灯市行乐。", "芙蕖万朵，向晚为谁开却。", "层楼画阁。", "尽卷上、东风帘幕。", "罗绮拥，欢声和气，惊破柳梢梅萼。", "绰约。", "暗尘浮动，正鱼龙曼衍，戏车交作。", "高牙影里，缓控玉羁金络。", "铅华间错。", "更一部、笙歌围著。", "香散处，厌厌醉听，南楼画角。"]'),
('song-ci-362','汉宫春','无名氏','宋','宋词','song-ci','汉宫春','[]','玉减香销，被婵娟误我，临镜妆慵。',118,'宋词/ci.song.19000.json','["玉减香销，被婵娟误我，临镜妆慵。", "无聊强开强解，蹙破眉峰。", "凭高望远，但断肠、残月初钟。", "须信道，承恩在貌，如何教妾为容。", "风暖鸟声和碎，更日高院静，花影重重。", "愁来待只殢酒，酒困愁浓。", "长门怨感，恨无金、卖赋临邛。", "翻动念，年年女伴，越溪共采芙蓉。"]'),
('song-ci-363','风流子','无名氏','宋','宋词','song-ci','风流子','[]','淑景皇州满，和风渐、催促柳花飞。',135,'宋词/ci.song.19000.json','["淑景皇州满，和风渐、催促柳花飞。", "过清明骤雨，五候台榭，青烟散入，新火开时。", "绣帘外、傍人飞燕子，映叶语黄鹂。", "秋千昼永，绮罗人散，花阴笑隔，红粉墙低。", "青门多行乐，寻芳处、何计强逐轻肥。", "空对旧游满目，谁共开眉。", "遇有时系马，垂杨影下，风前伫立，惆怅佳期。", "回望故园桃李，应待人归。"]'),
('song-ci-364','夏日宴黉堂・夏日燕黉堂','无名氏','宋','宋词','song-ci','夏日宴黉堂・夏日燕黉堂','[]','日初长。',121,'宋词/ci.song.19000.json','["日初长。", "正园林换叶，瓜李飘香。", "帘外雨过，送一霎微凉。", "萍芜迳，曲凝珠颗，衬汀沙、细簇蜂房。", "被晚风轻飐，圆荷翻水，泼觉鸳鸯。", "此景最难忘。", "趁芳樽泛蚁，筠簟铺湘。", "兰舟棹稳，倚何处垂杨。", "岂能文字成狂饮，更红裙、闲也何妨。", "任醉归明月，虾须帘筛，几线馀霜。"]'),
('song-ci-365','渔家傲','无名氏','宋','宋词','song-ci','渔家傲','[]','轻拍红牙留客住。',72,'宋词/ci.song.19000.json','["轻拍红牙留客住。", "韩家石鼎联新句。", "珍重龙团并凤髓。", "君王与。", "春风吹破黄金缕。", "往事不须凭陆羽。", "且看盏面浓如乳。", "若是蓬莱鳌稳负。", "知何处。", "玉川一枕清风去。"]'),
('song-ci-366','醉春风','无名氏','宋','宋词','song-ci','醉春风','[]','陌上清明近。',78,'宋词/ci.song.19000.json','["陌上清明近。", "行人难借问。", "风流何处不来归，闷闷闷。", "回雁峰前，戏鱼波上，试寻芳信。", "夜久兰膏烬。", "春睡何曾稳。", "枕边珠泪几时乾，恨恨恨。", "惟有窗前，过来明月，照人方寸。"]'),
('song-ci-367','卓牌儿・卓牌子','无名氏','宋','宋词','song-ci','卓牌儿・卓牌子','[]','当年早梅芳，曾邂逅、飞琼侣。',115,'宋词/ci.song.19000.json','["当年早梅芳，曾邂逅、飞琼侣。", "肌云莹玉，颜开嫩桃，腰支轻袅，未胜金缕。", "佯羞整云环，频向人、娇波寄语。", "湘佩笑解，韩香暗传，幽欢后期难诉。", "梦魂顿阻。", "似一枕、高唐云雨。", "蕙心兰态，知何计重遇。", "试问春蚕丝多少，未抵离愁半缕。", "凝伫。", "望凤楼何处。"]'),
('song-ci-368','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','晓日压重檐。',66,'宋词/ci.song.19000.json','["晓日压重檐。", "斗帐犹寒起未忺。", "天气困人梳洗倦，眉尖。", "淡画春山不喜添。", "闲把绣丝撏。", "紝得金针又怕拈。", "陌上行人归也未，恹恹。", "满院杨花不卷帘。"]'),
('song-ci-369','南乡子','无名氏','宋','宋词','song-ci','南乡子','[]','深结花工知。',66,'宋词/ci.song.19000.json','["深结花工知。", "赐与衣裳尽是绯。", "曾向玉盘深处见，隈随。", "两个心肠一片儿。", "从小便相依。", "酒伴歌筵不暂离。", "只恐被人分擘破，东西。", "怎得团圆似旧时。"]'),
('song-ci-370','望远行','无名氏','宋','宋词','song-ci','望远行','[]','当时云雨梦，不负楚王期。',93,'宋词/ci.song.19000.json','["当时云雨梦，不负楚王期。", "翠峰中、高楼十二掩瑶扉。", "尽人间欢会，只有两心自知。", "渐玉困花柔香汗挥。", "歌声翻别怨，云驭欲回时。", "这无情红日，何似且休西。", "但涓涓珠泪，滴湿仙郎羽衣。", "怎忍见、双鸳相背飞。"]'),
('song-ci-371','归田乐','无名氏','宋','宋词','song-ci','归田乐','[]','水绕溪桥绿。',86,'宋词/ci.song.19000.json','["水绕溪桥绿。", "泛苹汀、步迷花曲。", "衣巾散馀馥。", "种竹更洗竹。", "咏竹题竹。", "日暮无人伴幽独。", "光阴双转毂。", "可惜许、等闲愁万斛。", "世间种种，只是荣和辱。", "念足又愿足。", "意足心足。", "忘了眉头怎生蹙。"]');
